# =========================
# Global helpers (Codes / Schema)
# =========================

def normalize_code(v: str) -> str:
    """Normalize any master-data code (item/wh/supplier/equipment/project/cost center).
    - trims
    - collapses internal whitespace
    - uppercases (ERP-style)
    Keeps separators like '-' '/' '_' '.'.
    """
    if v is None:
        return ""
    s = str(v)
    s = s.replace("\u200f", "").replace("\u200e", "")  # remove bidi marks if any
    s = s.strip()
    if not s:
        return ""
    s = re.sub(r"\s+", " ", s)  # collapse whitespace
    return s.upper()

_SCHEMA_CACHE = {"ready": False, "tables": {}, "ts": None}
_SCHEMA_LOCK = threading.Lock()

def schema_probe(con=None):
    """Probe DB schema once and cache columns per table.
    This prevents 'no such column' surprises and enables safe SQL branching.
    """
    global _SCHEMA_CACHE
    with _SCHEMA_LOCK:
        if _SCHEMA_CACHE.get("ready") and _SCHEMA_CACHE.get("tables"):
            return _SCHEMA_CACHE
    close_after = False
    if con is None:
        con = db_connect()
        close_after = True
    try:
        tables = {}
        rows = con.execute("SELECT name FROM sqlite_master WHERE type='table';").fetchall()
        for r in rows:
            t = r[0] if not isinstance(r, sqlite3.Row) else r["name"]
            try:
                cols = [c["name"] if isinstance(c, sqlite3.Row) else c[1]
                        for c in con.execute(f"PRAGMA table_info({t});").fetchall()]
            except Exception:
                cols = []
            tables[t] = set(cols)
        with _SCHEMA_LOCK:
            _SCHEMA_CACHE = {"ready": True, "tables": tables, "ts": _now().isoformat(timespec="seconds")}
        return _SCHEMA_CACHE
    finally:
        if close_after:
            try: con.close()
            except Exception: pass

def has_col(table: str, col: str) -> bool:
    try:
        sch = schema_probe()
        return col in (sch.get("tables", {}).get(table, set()) or set())
    except Exception:
        return False

def clear_schema_cache():
    """Drop cached schema info after migrations or tests mutate the DB layout."""
    global _SCHEMA_CACHE
    with _SCHEMA_LOCK:
        _SCHEMA_CACHE = {"ready": False, "tables": {}, "ts": None}

def ensure_critical_indexes(con=None):
    """Best-effort safety net for critical indexes/constraints on live upgraded DBs."""
    sqls = [
        "CREATE INDEX IF NOT EXISTS idx_txn_item_ts ON Transactions(item_id, ts DESC);",
        "CREATE INDEX IF NOT EXISTS idx_txn_type_voided_ts ON Transactions(txn_type, voided, ts DESC);",
        "CREATE INDEX IF NOT EXISTS idx_txn_eq_ts ON Transactions(eq_id, ts DESC);",
        "CREATE INDEX IF NOT EXISTS idx_txn_supplier_ts ON Transactions(supplier_id, ts DESC);",
        "CREATE INDEX IF NOT EXISTS idx_txn_ts_id ON Transactions(ts DESC, id DESC);",
        "CREATE INDEX IF NOT EXISTS idx_txn_voided_ts_id ON Transactions(voided, ts DESC, id DESC);",
        "CREATE INDEX IF NOT EXISTS idx_txn_req_no ON Transactions(req_no);",
        "CREATE INDEX IF NOT EXISTS idx_txn_doc_no ON Transactions(doc_no);",
        "CREATE INDEX IF NOT EXISTS idx_txn_item_whfrom_ts ON Transactions(item_id, wh_from_id, ts DESC);",
        "CREATE INDEX IF NOT EXISTS idx_txn_item_whto_ts ON Transactions(item_id, wh_to_id, ts DESC);",
        "CREATE UNIQUE INDEX IF NOT EXISTS uq_items_item_name_norm ON Items(UPPER(TRIM(item_name)));",
    ]
    close_after = False
    if con is None:
        con = db_connect()
        close_after = True
    try:
        for sql in sqls:
            try:
                con.execute(sql)
            except Exception:
                pass
        try:
            con.commit()
        except Exception:
            pass
    finally:
        clear_schema_cache()
        if close_after:
            try:
                con.close()
            except Exception:
                pass

# =========================
# CORE / ARCH LAYERS (Modular Internal)
# =========================
# NOTE:
# - This project remains single-file for deployment simplicity.
# - Internally, we enforce a layered structure:
#     HTTP Layer  -> Router -> Services -> Repositories -> DB Engine
# - Legacy routes still work; new/critical paths can be migrated gradually.
#
# Design rules:
#   1) HTTP layer must NOT execute raw SQL directly (new code).
#   2) Services encapsulate business rules (validation, stock rules, permissions).
#   3) Repositories encapsulate SQL (single place to optimize/index).
#   4) DB engine is the only place that opens connections / sets pragmas.
#
# If you find code violating #1, prefer moving it into Repo/Service below.

class DBEngine:
    """Thin DB wrapper. New code should use DBEngine instead of sqlite3 directly."""
    def __init__(self, db_path: str):
        self.db_path = db_path

    @contextmanager
    def tx(self):
        conn = self.connect()
        try:
            yield conn
            conn.commit()
        except Exception:
            try:
                conn.rollback()
            except Exception:
                pass
            raise
        finally:
            try:
                conn.close()
            except Exception:
                pass

    def connect(self):
        # Reuse existing db_connect() if present (keeps WAL/busy_timeout/retry logic).
        try:
            return db_connect()
        except NameError:
            conn = sqlite3.connect(self.db_path, timeout=30, check_same_thread=False)
            conn.row_factory = sqlite3.Row
            conn.execute("PRAGMA foreign_keys=ON;")
            conn.execute("PRAGMA journal_mode=WAL;")
            conn.execute("PRAGMA busy_timeout=5000;")
            return conn

    def query_all(self, sql: str, params=()):
        with self.connect() as conn:
            return conn.execute(sql, params).fetchall()

    def query_one(self, sql: str, params=()):
        with self.connect() as conn:
            return conn.execute(sql, params).fetchone()

    def exec(self, sql: str, params=()):
        with self.connect() as conn:
            return conn.execute(sql, params)

# --- Repositories (SQL only) ---
class SystemRepo:
    def __init__(self, db: DBEngine):
        self.db = db

    def table_exists(self, name: str) -> bool:
        r = self.db.query_one("SELECT name FROM sqlite_master WHERE type='table' AND name=?;", (name,))
        return bool(r)

    def sqlite_integrity_check(self) -> str:
        r = self.db.query_one("PRAGMA integrity_check;")
        try:
            return (r[0] if r else "unknown")
        except Exception:
            return "unknown"

class AuditRepo:
    def __init__(self, db: DBEngine):
        self.db = db

    def recent(self, limit: int = 50):
        if not self.db.query_one("SELECT 1 FROM sqlite_master WHERE type='table' AND name='AuditLog';"):
            return []
        return self.db.query_all("SELECT * FROM AuditLog ORDER BY id DESC LIMIT ?;", (int(limit),))


# --- Domain Repositories (SQL only) ---
class TxnRepo:
    def __init__(self, db: DBEngine):
        self.db = db

    def get_by_id(self, txn_id: int):
        row = self.db.query_one("SELECT * FROM Transactions WHERE id=?", (int(txn_id),))
        return dict(row) if row else None

    def _insert_txn_conn(self, conn, *, ts: str, base: dict, scrap_qty_val, unit_price_val, req_no: str, po_no: str, doc_no: str, notes: str, username: str) -> int:
        cur = conn.execute(
            """
            INSERT INTO Transactions(
                ts, txn_type, item_id, qty, scrap_qty, unit_price,
                wh_from_id, wh_to_id, eq_id, supplier_id, project_id, issue_type, cost_allocation,
                req_no, po_no, doc_no, notes, username, voided, void_reason
            )
            VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,0,NULL)
            """,
            (
                ts,
                base["txn_type"],
                base["item_id"],
                base["qty"],
                scrap_qty_val,
                unit_price_val,
                base["wh_from_id"],
                base["wh_to_id"],
                base["eq_id"],
                base["supplier_id"],
                base.get("project_id"),
                base.get("issue_type"),
                base.get("cost_allocation"),
                (req_no or "").strip() or None,
                (po_no or "").strip() or None,
                (doc_no or "").strip() or None,
                (notes or "").strip() or None,
                username,
            ),
        )
        return int(getattr(cur, "lastrowid", 0) or 0)

    def insert_txn(self, *, ts: str, base: dict, scrap_qty_val, unit_price_val, req_no: str, po_no: str, doc_no: str, notes: str, username: str) -> int:
        with self.db.tx() as conn:
            return self._insert_txn_conn(conn, ts=ts, base=base, scrap_qty_val=scrap_qty_val, unit_price_val=unit_price_val, req_no=req_no, po_no=po_no, doc_no=doc_no, notes=notes, username=username)

    def _update_txn_conn(self, conn, *, txn_id: int, base: dict, scrap_qty_val, unit_price_val, req_no: str, po_no: str, doc_no: str, notes: str, username: str) -> None:
        conn.execute(
            """
            UPDATE Transactions
               SET txn_type=?, item_id=?, qty=?, scrap_qty=?, unit_price=?,
                   wh_from_id=?, wh_to_id=?, eq_id=?, supplier_id=?, project_id=?, issue_type=?, cost_allocation=?,
                   req_no=?, po_no=?, doc_no=?, notes=?, username=?
             WHERE id=?
            """,
            (
                base["txn_type"],
                base["item_id"],
                base["qty"],
                scrap_qty_val,
                unit_price_val,
                base["wh_from_id"],
                base["wh_to_id"],
                base["eq_id"],
                base["supplier_id"],
                base.get("project_id"),
                base.get("issue_type"),
                base.get("cost_allocation"),
                (req_no or "").strip() or None,
                (po_no or "").strip() or None,
                (doc_no or "").strip() or None,
                (notes or "").strip() or None,
                username,
                int(txn_id),
            ),
        )

    def update_txn(self, *, txn_id: int, base: dict, scrap_qty_val, unit_price_val, req_no: str, po_no: str, doc_no: str, notes: str, username: str) -> None:
        with self.db.tx() as conn:
            self._update_txn_conn(conn, txn_id=txn_id, base=base, scrap_qty_val=scrap_qty_val, unit_price_val=unit_price_val, req_no=req_no, po_no=po_no, doc_no=doc_no, notes=notes, username=username)

    def _void_txn_conn(self, conn, txn_id: int, reason: str = "") -> bool:
        cur = conn.execute(
            "UPDATE Transactions SET voided=1, void_reason=? WHERE id=? AND COALESCE(voided,0)=0",
            ((reason or "").strip() or None, int(txn_id)),
        )
        return int(getattr(cur, "rowcount", 0) or 0) > 0

    def void_txn(self, txn_id: int, reason: str = "") -> bool:
        with self.db.tx() as conn:
            return self._void_txn_conn(conn, txn_id, reason)

    def _hard_delete_txn_conn(self, conn, txn_id: int) -> bool:
        cur = conn.execute("DELETE FROM Transactions WHERE id=?", (int(txn_id),))
        return int(getattr(cur, "rowcount", 0) or 0) > 0

    def hard_delete_txn(self, txn_id: int) -> bool:
        with self.db.tx() as conn:
            return self._hard_delete_txn_conn(conn, txn_id)

    def clear_all(self) -> None:
        with self.db.tx() as conn:
            conn.execute("DELETE FROM Transactions")
            try:
                conn.execute("DELETE FROM sqlite_sequence WHERE name='Transactions'")
            except Exception:
                pass
            try:
                conn.execute("DELETE FROM BalancesSnapshot")
            except Exception:
                pass
            try:
                conn.execute("DELETE FROM BalancesSnapshotInfo")
            except Exception:
                pass

    def _set_attachment_path_conn(self, conn, txn_id: int, fs_path: str | None):
        conn.execute("UPDATE Transactions SET attachment_path=? WHERE id=?", (fs_path, int(txn_id)))

    def set_attachment_path(self, txn_id: int, fs_path: str | None):
        with self.db.tx() as conn:
            self._set_attachment_path_conn(conn, txn_id, fs_path)

    def _clear_attachment_path_conn(self, conn, txn_id: int):
        conn.execute("UPDATE Transactions SET attachment_path=NULL WHERE id=?", (int(txn_id),))

    def clear_attachment_path(self, txn_id: int):
        with self.db.tx() as conn:
            self._clear_attachment_path_conn(conn, txn_id)



# --- Item repository (SQL only) ---
class ItemRepo:
    def __init__(self, db: DBEngine):
        self.db = db

    def _try_query_one(self, sql: str, params=()):
        try:
            return self.db.query_one(sql, params)
        except Exception as e:
            safe_log_exception("ITEM_REPO_QUERY_ONE", e)
            return None

    def _item_code_column(self) -> str | None:
        if has_col("Items", "item_code"):
            return "item_code"
        if has_col("Items", "code"):
            return "code"
        return None

    def _item_pk_column(self) -> str | None:
        if has_col("Items", "id"):
            return "id"
        if has_col("Items", "item_id"):
            return "item_id"
        return None

    def get_by_code(self, code: str):
        code = normalize_code(code)
        if not code:
            return None
        code_col = self._item_code_column()
        if code_col:
            row = self._try_query_one(f"SELECT * FROM Items WHERE {code_col}=? LIMIT 1;", (code,))
            if row:
                return row
        # Fallback to legacy helper if available.
        try:
            return _db_get_item_by_code(code)
        except Exception as e:
            safe_log_exception("ITEM_REPO_GET_BY_CODE", e)
            return None

    def set_image_path(self, item_id: int, fs_path: str):
        pk_col = self._item_pk_column()
        if not pk_col:
            raise RuntimeError("Items primary key column not found")
        if not has_col("Items", "image_path"):
            raise RuntimeError("Items.image_path column not found")
        try:
            self.db.exec(f"UPDATE Items SET image_path=? WHERE {pk_col}=?;", (fs_path, int(item_id)))
            clear_schema_cache()
            return
        except Exception as e:
            safe_log_exception("ITEM_REPO_SET_IMAGE_PATH", e)
            raise

    def clear_image_path(self, item_id: int):
        pk_col = self._item_pk_column()
        if not pk_col:
            raise RuntimeError("Items primary key column not found")
        if not has_col("Items", "image_path"):
            raise RuntimeError("Items.image_path column not found")
        try:
            self.db.exec(f"UPDATE Items SET image_path=NULL WHERE {pk_col}=?;", (int(item_id),))
            clear_schema_cache()
            return
        except Exception as e:
            safe_log_exception("ITEM_REPO_CLEAR_IMAGE_PATH", e)
            raise

# --- App Container (Dependency Injection / singletons) ---
_APP_CONTAINER = None
_APP_CONTAINER_LOCK = threading.Lock()

class AppContainer:
    def __init__(self):
        # Single DB engine instance used across router/services.
        self.db = DBEngine(DB_FILE)
        self.system_repo = SystemRepo(self.db)
        self.audit_repo = AuditRepo(self.db)
        self.txn_repo = TxnRepo(self.db)
        self.system_service = SystemService(self.system_repo)
        self.item_repo = ItemRepo(self.db)
        self.item_service = ItemService(self.item_repo)
        self.txn_service = TxnService(self.txn_repo)

def get_container() -> AppContainer:
    global _APP_CONTAINER
    if _APP_CONTAINER is not None:
        return _APP_CONTAINER
    with _APP_CONTAINER_LOCK:
        if _APP_CONTAINER is None:
            _APP_CONTAINER = AppContainer()
    return _APP_CONTAINER

# --- Services (business logic) ---
class SystemService:
    def __init__(self, sys_repo: SystemRepo):
        self.sys_repo = sys_repo

    def health(self) -> dict:
        integrity = self.sys_repo.sqlite_integrity_check()
        return {
            "ok": (str(integrity).strip().lower() == "ok"),
            "integrity": integrity,
            "has_txn": self.sys_repo.table_exists("Transactions"),
        }

