# --- Additional Services (migrated modules) ---
class ItemService:
    def __init__(self, item_repo: "ItemRepo" = None):
        self.item_repo = item_repo

    def save(self, *, rid: str, form: dict, user: str, role: str, ip: str, lang: str) -> str:
        op = ((form.get("op", ["save"])[0] or "save").strip().lower())
        if op == "delete":
            if not is_admin(role):
                raise PermissionError("Forbidden")
            if rid and str(rid).isdigit():
                hard_delete_master("Items", int(rid), username=user, role=role, ip=ip, force_cascade=False)
            return ("تم الحذف" if (lang or "en").lower().startswith("ar") else "Deleted")

        item_code = normalize_code((form.get("item_code", [""])[0] or ""))
        item_name = (form.get("item_name", [""])[0] or "").strip()
        if not item_code:
            raise ValueError("item_code required")
        if not item_name:
            raise ValueError("item_name required")

        rid_int = int(rid) if (rid and str(rid).isdigit()) else None
        item_name_norm = re.sub(r"\s+", " ", str(item_name).strip()).upper()
        con = db_connect()
        try:
            dup_code = con.execute(
                "SELECT id FROM Items WHERE UPPER(TRIM(COALESCE(item_code,'')))=? AND (? IS NULL OR id<>?) LIMIT 1",
                (item_code, rid_int, rid_int),
            ).fetchone()
            if dup_code:
                raise ValueError("كود الصنف مكرر" if (lang or "en").lower().startswith("ar") else "Duplicate item code")

            dup_name = con.execute(
                "SELECT id FROM Items WHERE UPPER(TRIM(COALESCE(item_name,'')))=? AND (? IS NULL OR id<>?) LIMIT 1",
                (item_name_norm, rid_int, rid_int),
            ).fetchone()
            if dup_name:
                raise ValueError("اسم الصنف مكرر" if (lang or "en").lower().startswith("ar") else "Duplicate item name")
        finally:
            try:
                con.close()
            except Exception:
                pass

        default_unit_price_raw = (form.get("default_unit_price", [""])[0] or "").strip()
        try:
            default_unit_price = float(default_unit_price_raw) if default_unit_price_raw != "" else None
        except Exception:
            raise ValueError("السعر الافتراضي غير صحيح" if (lang or "en").lower().startswith("ar") else "Invalid default unit price")
        if default_unit_price is not None and default_unit_price < 0:
            raise ValueError("السعر الافتراضي يجب ألا يكون سالبًا" if (lang or "en").lower().startswith("ar") else "Default unit price cannot be negative")

        with atomic_db():
            upsert_row("Items", rid_int, dict(
                item_code=item_code,
                item_name=item_name,
                unit=normalize_code((form.get("unit", ["PIECE"])[0] or "PIECE")) or "PIECE",
                min_qty=float((form.get("min_qty", ["0"])[0] or "0") or 0),
                default_unit_price=default_unit_price,
                active=1
            ))
        if rid and str(rid).isdigit():
            return ("تم التعديل" if (lang or "en").lower().startswith("ar") else "Updated")
        return ("تمت الإضافة" if (lang or "en").lower().startswith("ar") else "Added")

    def image_upload(self, *, fields: dict, files: dict, user: str, role: str, ip: str, lang: str) -> str:
        if not can_edit(user):
            raise PermissionError("Forbidden")
        code = (fields.get("item_code") or "")
        if isinstance(code, list):
            code = code[0] if code else ""
        code = str(code).strip()
        if not code:
            raise ValueError("item_code required")

        it = self.item_repo.get_by_code(code) if self.item_repo else None
        if not it:
            raise ValueError("Item not found")

        up = (files or {}).get("image")
        if not up:
            raise ValueError("No file")

        filename, data = up
        ext = _safe_ext(filename)
        if ext not in (".jpg",".jpeg",".png",".webp",".gif"):
            raise ValueError("Invalid image type")
        if len(data) > MAX_ITEM_IMAGE_BYTES:
            raise ValueError("Image too large")
        if not _looks_like_image(ext, data):
            raise ValueError("Invalid image content")

        _ensure_upload_dirs()

        old = ""
        try:
            old = it["image_path"] or ""
        except Exception:
            try:
                old = (it.get("image_path") or "")
            except Exception:
                old = ""

        fname = _rand_name(f"item_{code}", ext)
        fs_path = os.path.join(ITEM_IMG_DIR, fname)
        _safe_write_file_atomic(fs_path, data)

        # persist
        item_id = None
        try:
            item_id = int(it["id"])
        except Exception:
            try:
                item_id = int(it.get("id"))
            except Exception:
                item_id = None
        try:
            if self.item_repo and item_id is not None:
                self.item_repo.set_image_path(item_id, fs_path)
        except Exception:
            try:
                if fs_path and os.path.exists(fs_path):
                    _safe_unlink_file(fs_path, allowed_roots=[ITEM_IMG_DIR, TXN_PDF_DIR])
            except Exception as e:
                safe_log_exception("ITEM_IMAGE_UPLOAD_ROLLBACK", e, username=user, role=role, ip=ip)
            raise
        if old and old != fs_path and os.path.exists(old):
            try:
                _safe_unlink_file(old, allowed_roots=[ITEM_IMG_DIR, TXN_PDF_DIR])
            except Exception as e:
                safe_log_exception("ITEM_IMAGE_UPLOAD_REMOVE_OLD", e, username=user, role=role, ip=ip)

        return ("تم رفع الصورة" if (lang or "en").lower().startswith("ar") else "Image uploaded")

    def image_delete(self, *, fields: dict, user: str, role: str, ip: str, lang: str) -> str:
        if not can_edit(user):
            raise PermissionError("Forbidden")
        code = (fields.get("item_code") or "")
        if isinstance(code, list):
            code = code[0] if code else ""
        code = str(code).strip()
        if not code:
            raise ValueError("item_code required")

        it = self.item_repo.get_by_code(code) if self.item_repo else None
        if not it:
            raise ValueError("Item not found")

        old = ""
        try:
            old = it["image_path"] or ""
        except Exception:
            try:
                old = (it.get("image_path") or "")
            except Exception:
                old = ""

        item_id = None
        try:
            item_id = int(it["id"])
        except Exception:
            try:
                item_id = int(it.get("id"))
            except Exception:
                item_id = None
        if self.item_repo and item_id is not None:
            self.item_repo.clear_image_path(item_id)
        if old and os.path.exists(old):
            try:
                _safe_unlink_file(old, allowed_roots=[ITEM_IMG_DIR, TXN_PDF_DIR])
            except Exception as e:
                safe_log_exception("ITEM_IMAGE_DELETE_REMOVE_OLD", e, username=user, role=role, ip=ip)

        return ("تم حذف الصورة" if (lang or "en").lower().startswith("ar") else "Image deleted")

class TxnService:
    def __init__(self, txn_repo: "TxnRepo"):
        self.txn_repo = txn_repo

    def _msg(self, lang: str, en: str, ar: str) -> str:
        return ar if (lang or "en").lower().startswith("ar") else en

    def _after_txn_change(self, *, username: str, role: str, ip: str, tag: str):
        try:
            mark_stockcache_dirty(reason=tag, username=username)
            ensure_stockcache_async(username=username)
        except Exception as e:
            safe_log_exception(tag, e, username=username, role=role, ip=ip)

    def _run_write(self, *, db_work, audit_work=None, username: str, role: str, ip: str, stock_tag: str):
        """Run one transactional write path without opening a second writer connection.

        Root cause fixed here:
        - old code opened a write transaction via DBEngine.tx()
        - audit_work() then called audit_log(), which opened another sqlite connection
        - under write load this could block on the first uncommitted transaction and make
          /txn/save appear to hang for a long time.

        We now execute inside atomic_db(lock=False) while holding _TXN_WRITE_LOCK.
        Because atomic_db() publishes the current connection in thread-local storage,
        any nested db_connect() call (including audit_log) reuses the same connection.
        """
        with _TXN_WRITE_LOCK:
            with atomic_db(lock=False) as conn:
                result = db_work(conn)
                if audit_work:
                    audit_work(result)
        self._after_txn_change(username=username, role=role, ip=ip, tag=stock_tag)
        return result

    def delete_txn(self, *, txn_id: int, user: str, role: str, ip: str, lang: str, audit_action: str = "HARD_DELETE_TXN") -> str:
        if not is_admin(role):
            raise PermissionError("Forbidden")
        tx = self._load_txn_or_fail(int(txn_id), lang)
        self._ensure_not_locked(tx)
        old_attach = tx.get("attachment_path") or ""

        def _db_work(conn):
            self.txn_repo._hard_delete_txn_conn(conn, int(txn_id))
            _cost_state_recompute_pairs(conn, _cost_state_pairs_for_txn(tx))
            return {"tx": tx, "old_attach": old_attach}

        def _audit(ctx):
            audit_log(user, audit_action, entity="Transactions", entity_id=int(txn_id), details={"ts": str(tx.get("ts") or "")[:10], "txn_type": tx.get("txn_type"), "item_id": tx.get("item_id"), "qty": tx.get("qty"), "wh_from_id": tx.get("wh_from_id"), "wh_to_id": tx.get("wh_to_id"), "attachment_path": old_attach or None}, ip=ip, role=role)

        self._run_write(db_work=_db_work, audit_work=_audit, username=user, role=role, ip=ip, stock_tag="TXN_DELETE_STOCKCACHE_REFRESH")
        attachment_deleted = False
        if old_attach and os.path.exists(old_attach):
            try:
                with self.txn_repo.db.tx() as conn:
                    _txn_attachment_cleanup_if_unreferenced(conn, old_attach, exclude_txn_id=int(txn_id))
                attachment_deleted = not os.path.exists(old_attach)
            except Exception as e:
                safe_log_exception("txn_delete_attachment", e, username=user, role=role, ip=ip)
        if attachment_deleted:
            try:
                audit_log(user, audit_action + "_ATTACHMENT", entity="Transactions", entity_id=int(txn_id), details={"attachment_deleted": True, "attachment_path": old_attach}, ip=ip, role=role)
            except Exception:
                pass
        return self._msg(lang, "Deleted", "تم الحذف")

    def _parse_unit_price(self, unit_price):
        s = (unit_price or "").strip()
        return float(s) if s else None

    def _resolve_latest_item_price(self, conn, *, item_id: int, exclude_txn_id: int | None = None):
        """Return latest positive stored unit_price for the item from any non-voided txn."""
        sql = """
            SELECT unit_price
            FROM Transactions
            WHERE voided=0
              AND item_id=?
              AND unit_price IS NOT NULL
              AND CAST(unit_price AS REAL) > 0
        """
        params = [int(item_id)]
        if exclude_txn_id is not None:
            sql += " AND id<>?"
            params.append(int(exclude_txn_id))
        sql += " ORDER BY ts DESC, id DESC LIMIT 1"
        row = conn.execute(sql, tuple(params)).fetchone()
        if not row:
            return None
        try:
            return float(row[0] if not isinstance(row, sqlite3.Row) else row["unit_price"])
        except Exception:
            return None

    def _resolve_item_default_price(self, conn, *, item_id: int):
        try:
            row = conn.execute("SELECT default_unit_price FROM Items WHERE id=? LIMIT 1", (int(item_id),)).fetchone()
        except Exception:
            return None
        if not row:
            return None
        try:
            val = row[0] if not isinstance(row, sqlite3.Row) else row["default_unit_price"]
            val = float(val) if val is not None else None
            return val if (val is not None and val > 0) else None
        except Exception:
            return None

    def _resolve_wh_avg_cost(self, conn, *, wh_id: int | None, item_id: int, exclude_txn_id: int | None = None):
        """Resolve warehouse moving-average cost.

        Fast path:
        - Prefer the incremental WarehouseCostState table for normal add-flow.
        - Fall back to pair-level replay only when exclusion is required or cache/state is missing.
        """
        if not wh_id:
            return None
        wh_id = int(wh_id)
        item_id = int(item_id)
        if exclude_txn_id is None:
            cached = _avg_cost_cache_get(wh_id, item_id)
            if cached is not None:
                return cached
            state_avg = _cost_state_get_avg_cost(conn, wh_id, item_id, allow_recompute=True)
            if state_avg is not None:
                _avg_cost_cache_set(wh_id, item_id, state_avg)
                return state_avg
            return None
        avg = _cost_state_recompute_pair(conn, wh_id, item_id, exclude_txn_id=exclude_txn_id)
        return avg if avg > 0 else None

    def _resolve_effective_unit_price(self, conn, *, txn_type: str, item_id: int, explicit_price, wh_from_id: int | None = None, exclude_txn_id: int | None = None):
        """Resolve a stored unit_price without breaking existing stock valuation rules.

        - Explicit positive price always wins.
        - RECEIVE with blank/zero price falls back to latest known item price.
        - ISSUE / TRANSFER with blank/zero price tries source warehouse moving average,
          then latest known item price.
        - If no historical cost exists, keep None.
        """
        try:
            p = float(explicit_price) if explicit_price is not None else None
        except Exception:
            p = None
        if p is not None and p > 0:
            return p

        txn_type = str(txn_type or "").upper()
        if txn_type in ("ISSUE", "TRANSFER") and wh_from_id:
            avg = self._resolve_wh_avg_cost(
                conn,
                wh_id=int(wh_from_id),
                item_id=int(item_id),
                exclude_txn_id=exclude_txn_id,
            )
            if avg is not None and avg > 0:
                return float(avg)

        latest = self._resolve_latest_item_price(
            conn,
            item_id=int(item_id),
            exclude_txn_id=exclude_txn_id,
        )
        if latest is not None and latest > 0:
            return float(latest)

        default_price = self._resolve_item_default_price(conn, item_id=int(item_id))
        if default_price is not None and default_price > 0:
            return float(default_price)
        return p

    def _parse_scrap_qty(self, txn_type, scrap_qty, lang: str = "en"):
        s = (scrap_qty or "").strip()
        if not s:
            return 0.0
        try:
            v = float(s)
        except Exception:
            raise ValueError(self._msg(lang, "Invalid scrap quantity", "قيمة السكراب غير صحيحة"))
        if v < 0:
            raise ValueError(self._msg(lang, "scrap_qty must be >= 0", "قيمة السكراب يجب أن تكون أكبر من أو تساوي صفر"))
        if str(txn_type or "").strip().upper() != "ISSUE" and abs(v) > 1e-9:
            raise ValueError(self._msg(lang, "scrap_qty is only allowed for ISSUE", "السكراب مسموح فقط في حركات الصرف"))
        return v

    def _build_txn_ts(self, txn_date: str) -> str:
        ts = _now().isoformat(timespec="seconds")
        if (txn_date or "").strip():
            try:
                d = date.fromisoformat((txn_date or "").strip())
                now_t = _now().time().strftime("%H:%M:%S")
                ts = f"{d.isoformat()}T{now_t}"
            except Exception:
                pass
        return ts

    def _ensure_not_locked(self, tx: dict):
        ts = str((tx or {}).get("ts") or "")[:10]
        if not ts:
            return
        try:
            d = datetime.strptime(ts, "%Y-%m-%d").date()
        except Exception:
            return
        if d and is_locked_date(d):
            raise ValueError(f"Period locked: cannot modify transactions before {get_setting('period_lock_before','')}")

    def _load_txn_or_fail(self, txn_id: int, lang: str) -> dict:
        tx = self.txn_repo.get_by_id(int(txn_id))
        if not tx:
            raise ValueError(self._msg(lang, "Txn not found", "الحركة غير موجودة"))
        return tx

    def _validate_form(self, *, form: dict, lang: str) -> tuple[dict, dict]:
        nc = normalize_code
        payload = {
            "txn_type": (form.get("txn_type", ["RECEIVE"])[0] or "RECEIVE"),
            "txn_date": (form.get("txn_date", [""])[0] or ""),
            "item_code": nc((form.get("item_code", [""])[0] or "")),
            "qty": (form.get("qty", ["1"])[0] or "1"),
            "scrap_qty": (form.get("scrap_qty", [""])[0] or ""),
            "unit_price": (form.get("unit_price", [""])[0] or ""),
            "wh_from": nc((form.get("wh_from", [""])[0] or "")),
            "wh_to": nc((form.get("wh_to", [""])[0] or "")),
            "eq_code": nc((form.get("eq_code", [""])[0] or "")),
            "supplier_code": nc((form.get("supplier_code", [""])[0] or "")),
            "project_code": nc((form.get("project_code", [""])[0] or "")),
            "issue_type": (form.get("issue_type", [""])[0] or ""),
            "cost_allocation": (form.get("cost_allocation", [""])[0] or ""),
            "req_no": (form.get("req_no", [""])[0] or ""),
            "po_no": (form.get("po_no", [""])[0] or ""),
            "doc_no": (form.get("doc_no", [""])[0] or ""),
            "notes": (form.get("notes", [""])[0] or ""),
        }
        base = validate_txn(
            lang,
            payload["txn_type"],
            payload["item_code"],
            payload["qty"],
            payload["wh_from"],
            payload["wh_to"],
            payload["eq_code"],
            payload["supplier_code"],
            payload["project_code"],
            payload["cost_allocation"],
            payload["issue_type"],
        )
        return payload, base

    def _validate_attachment(self, *, tx: dict, files: dict, lang: str):
        if (tx.get("txn_type") or "").upper() not in ("RECEIVE", "ISSUE", "TRANSFER"):
            raise ValueError(self._msg(lang, "PDF not allowed", "لا يمكن إرفاق PDF لهذه الحركة"))
        up = (files or {}).get("pdf")
        if not up:
            raise ValueError(self._msg(lang, "No file", "لا يوجد ملف"))
        filename, data = up
        ext = _safe_ext(filename)
        if ext != ".pdf":
            raise ValueError(self._msg(lang, "PDF only", "PDF فقط"))
        if len(data) > MAX_TXN_PDF_BYTES:
            raise ValueError(self._msg(lang, "PDF too large", "الملف كبير"))
        if not _looks_like_pdf(data):
            raise ValueError(self._msg(lang, "Invalid PDF", "PDF غير صالح"))
        return filename, data

    def _replace_attachment(self, *, txn_id: int, tx: dict, files: dict, user: str, role: str, ip: str, lang: str):
        filename, data = self._validate_attachment(tx=tx, files=files, lang=lang)
        _ensure_upload_dirs()
        old = tx.get("attachment_path") or ""
        fname = _rand_name(f"txn_{int(txn_id)}", ".pdf")
        fs_path = os.path.join(TXN_PDF_DIR, fname)
        _safe_write_file_atomic(fs_path, data)
        try:
            with self.txn_repo.db.tx() as conn:
                self.txn_repo._set_attachment_path_conn(conn, int(txn_id), fs_path)
        except Exception:
            try:
                _safe_unlink_file(fs_path, allowed_roots=[ITEM_IMG_DIR, TXN_PDF_DIR])
            except Exception:
                pass
            raise
        if old and old != fs_path and os.path.exists(old):
            try:
                with self.txn_repo.db.tx() as conn:
                    _txn_attachment_cleanup_if_unreferenced(conn, old, exclude_txn_id=int(txn_id))
            except Exception as e:
                safe_log_exception("txn_attachment_remove_old", e, username=user, role=role, ip=ip)
        return fs_path

    def save(self, *, rid: str, form: dict, files: dict, user: str, role: str, ip: str, lang: str) -> str:
        op = ((form.get("op", ["save"])[0] or "save").strip().lower())

        if op == "delete":
            if rid and str(rid).isdigit():
                return self.delete_txn(txn_id=int(rid), user=user, role=role, ip=ip, lang=lang, audit_action="HARD_DELETE_TXN")
            return self._msg(lang, "Deleted", "تم الحذف")

        payload, base = self._validate_form(form=form, lang=lang)
        scrap_qty_val = self._parse_scrap_qty(payload["txn_type"], payload["scrap_qty"], lang)
        if scrap_qty_val - float(base["qty"]) > 1e-9:
            raise ValueError("scrap_qty cannot exceed qty")
        unit_price_val = self._parse_unit_price(payload["unit_price"])

        if rid and str(rid).isdigit():
            if not is_admin(role):
                raise PermissionError("Forbidden")
            tx_id = int(rid)
            old = self._load_txn_or_fail(tx_id, lang)
            self._ensure_not_locked(old)
            if int(old.get("voided", 0) or 0) == 1:
                raise ValueError("Cannot edit voided txn")
            def _db_work(conn):
                ok, available = ensure_stock_available_for_change(old_txn=old, new_txn={"voided": 0, **base}, con=conn)
                if not ok:
                    raise ValueError(t(lang, "insufficient", wh=payload["wh_from"], bal=available))
                effective_unit_price = self._resolve_effective_unit_price(
                    conn,
                    txn_type=base["txn_type"],
                    item_id=base["item_id"],
                    explicit_price=unit_price_val,
                    wh_from_id=base.get("wh_from_id"),
                    exclude_txn_id=tx_id,
                )
                self.txn_repo._update_txn_conn(
                    conn,
                    txn_id=tx_id,
                    base=base,
                    scrap_qty_val=scrap_qty_val,
                    unit_price_val=effective_unit_price,
                    req_no=payload["req_no"],
                    po_no=payload["po_no"],
                    doc_no=payload["doc_no"],
                    notes=payload["notes"],
                    username=user,
                )
                _cost_state_recompute_pairs(conn, _cost_state_pairs_for_txn(old) | _cost_state_pairs_for_txn({**base, 'id': tx_id}))
                return tx_id

            def _audit(_):
                audit_log(user, "UPDATE_TXN", entity="Transactions", entity_id=tx_id, details={
                    "txn_type": base["txn_type"],
                    "item_id": base["item_id"],
                    "qty": base["qty"],
                    "wh_from_id": base["wh_from_id"],
                    "wh_to_id": base["wh_to_id"],
                    "eq_id": base["eq_id"],
                    "supplier_id": base["supplier_id"],
                    "req_no": (payload["req_no"] or "").strip() or None,
                    "po_no": (payload["po_no"] or "").strip() or None,
                    "doc_no": (payload["doc_no"] or "").strip() or None,
                }, ip=ip, role=role)

            self._run_write(db_work=_db_work, audit_work=_audit, username=user, role=role, ip=ip, stock_tag="TXN_UPDATE_STOCKCACHE_REFRESH")
            try:
                up = (files or {}).get("pdf")
                if up:
                    tx = self._load_txn_or_fail(tx_id, lang)
                    self._replace_attachment(txn_id=tx_id, tx=tx, files=files, user=user, role=role, ip=ip, lang=lang)
            except Exception as e:
                safe_log_exception("txn_update_attachment", e, username=user, role=role, ip=ip)
                return self._msg(lang, "Updated (attachment failed)", "تم التعديل (فشل إرفاق الملف)") + ": " + str(e)
            return self._msg(lang, "Updated", "تم التعديل")

        ts = self._build_txn_ts(payload["txn_date"])
        def _db_work(conn):
            if base["txn_type"] in ("ISSUE", "TRANSFER"):
                ok, available = ensure_stock_available_for_change(
                    old_txn={"voided": 1, "txn_type": "ISSUE", "item_id": base["item_id"], "wh_from_id": base["wh_from_id"], "qty": 0},
                    new_txn={"voided": 0, **base},
                    con=conn,
                )
                if not ok:
                    raise ValueError(t(lang, "insufficient", wh=payload["wh_from"], bal=available))
            effective_unit_price = self._resolve_effective_unit_price(
                conn,
                txn_type=base["txn_type"],
                item_id=base["item_id"],
                explicit_price=unit_price_val,
                wh_from_id=base.get("wh_from_id"),
            )
            txn_id = self.txn_repo._insert_txn_conn(
                conn,
                ts=ts,
                base=base,
                scrap_qty_val=scrap_qty_val,
                unit_price_val=effective_unit_price,
                req_no=payload["req_no"],
                po_no=payload["po_no"],
                doc_no=payload["doc_no"],
                notes=payload["notes"],
                username=user,
            )
            txn_ctx = dict(base)
            txn_ctx.update({'id': txn_id, 'ts': ts, 'unit_price': effective_unit_price, 'qty': base['qty']})
            if not _cost_state_apply_add_txn(conn, txn_ctx):
                _cost_state_recompute_pairs(conn, _cost_state_pairs_for_txn(txn_ctx))
            return txn_id

        def _audit(txn_id):
            audit_log(user, "ADD_TXN", entity="Transactions", entity_id=txn_id, details={
                "txn_type": base["txn_type"],
                "item_id": base["item_id"],
                "qty": base["qty"],
                "wh_from_id": base["wh_from_id"],
                "wh_to_id": base["wh_to_id"],
                "eq_id": base["eq_id"],
                "supplier_id": base["supplier_id"],
                "req_no": (payload["req_no"] or "").strip() or None,
                "po_no": (payload["po_no"] or "").strip() or None,
                "doc_no": (payload["doc_no"] or "").strip() or None,
            }, ip=ip, role=role)

        txn_id = self._run_write(db_work=_db_work, audit_work=_audit, username=user, role=role, ip=ip, stock_tag="TXN_ADD_STOCKCACHE_REFRESH")
        try:
            up = (files or {}).get("pdf")
            if up:
                tx = self._load_txn_or_fail(txn_id, lang)
                self._replace_attachment(txn_id=txn_id, tx=tx, files=files, user=user, role=role, ip=ip, lang=lang)
        except Exception as e:
            safe_log_exception("txn_add_attachment", e, username=user, role=role, ip=ip)
            return self._msg(lang, "Added (attachment failed)", "تمت الإضافة (فشل إرفاق الملف)") + ": " + str(e)
        return self._msg(lang, "Added", "تمت الإضافة")

    def attach_upload(self, *, txn_id: int, files: dict, user: str, role: str, ip: str, lang: str) -> str:
        if not is_admin(role) and not can_edit(user):
            raise PermissionError("Forbidden")
        tx = self._load_txn_or_fail(int(txn_id), lang)
        self._replace_attachment(txn_id=int(txn_id), tx=tx, files=files, user=user, role=role, ip=ip, lang=lang)
        return self._msg(lang, "PDF uploaded", "تم رفع PDF")

    def attach_delete(self, *, txn_id: int, user: str, role: str, ip: str, lang: str) -> str:
        if not is_admin(role) and not can_edit(user):
            raise PermissionError("Forbidden")
        tx = self._load_txn_or_fail(int(txn_id), lang)
        old = tx.get("attachment_path") or ""
        with self.txn_repo.db.tx() as conn:
            self.txn_repo._clear_attachment_path_conn(conn, int(txn_id))
        if old and os.path.exists(old):
            try:
                with self.txn_repo.db.tx() as conn:
                    _txn_attachment_cleanup_if_unreferenced(conn, old, exclude_txn_id=int(txn_id))
            except Exception as e:
                safe_log_exception("txn_attachment_delete_file", e, username=user, role=role, ip=ip)
        return self._msg(lang, "PDF deleted", "تم حذف PDF")

    def void(self, *, txn_id: int, reason: str, user: str, role: str, ip: str, lang: str) -> str:
        if not can_edit(user):
            raise PermissionError("Forbidden")
        tx = self._load_txn_or_fail(int(txn_id), lang)
        self._ensure_not_locked(tx)
        if int(tx.get("voided", 0) or 0) == 1:
            return self._msg(lang, "Already voided", "الحركة ملغاة بالفعل")
        def _db_work(conn):
            changed = self.txn_repo._void_txn_conn(conn, int(txn_id), reason or "")
            if changed:
                _cost_state_recompute_pairs(conn, _cost_state_pairs_for_txn(tx))
            return changed

        def _audit(changed):
            if changed:
                audit_log(user, "VOID_TXN", entity="Transactions", entity_id=int(txn_id), details={"reason": (reason or "").strip() or None}, ip=ip, role=role)

        changed = self._run_write(db_work=_db_work, audit_work=_audit, username=user, role=role, ip=ip, stock_tag="TXN_VOID_STOCKCACHE_REFRESH")
        if not changed:
            return self._msg(lang, "Already voided", "الحركة ملغاة بالفعل")
        return self._msg(lang, "Voided", "تم الإلغاء")

    def clear_all(self, *, user: str, role: str, ip: str, lang: str) -> str:
        if str(role).strip().upper() != "ADMIN":
            raise PermissionError("Forbidden")
        self.txn_repo.clear_all()
        try:
            with self.txn_repo.db.tx() as conn:
                _cost_state_clear(conn)
        except Exception:
            pass
        audit_log(user, "CLEAR_ALL_TXN", entity="Transactions", entity_id=None, details={"all": True}, ip=ip, role=role)
        self._after_txn_change(username=user, role=role, ip=ip, tag="TXN_CLEAR_ALL_STOCKCACHE_REFRESH")
        return self._msg(lang, "All transactions cleared", "تم حذف كل الحركات")

class Router:
    def __init__(self):
        self._get = {}
        self._post = {}

    def get(self, path: str):
        def deco(fn):
            self._get[path] = fn
            return fn
        return deco

    def post(self, path: str):
        def deco(fn):
            self._post[path] = fn
            return fn
        return deco

    def dispatch(self, handler, method: str, path: str) -> bool:
        table = self._get if method == "GET" else self._post
        fn = table.get(path)
        if not fn:
            return False
        fn(handler)
        return True

ROUTER = Router()

# Centralized router-first POST paths to keep do_POST consistent and avoid
# falling through to legacy branches for already-migrated handlers.
_ROUTER_FIRST_POST_PATHS = (
    "/txn/save", "/txn/clear-all", "/txn/void", "/txn/delete_fast",
    "/txn/attach_upload", "/txn/attach_upload/",
    "/txn/attach_delete", "/txn/attach_delete/",
    "/txn/attach_bulk",
    "/items/image_upload", "/items/image_delete",
)

