@ROUTER.get("/__smoke")
def _smoke(h):
    user, role, lang = _router_need_login(h)
    if not user:
        return
    if not is_admin(role):
        return h._send_html(page(lang, "403", "<div class='card'>🚫 Forbidden</div>", user, role=role), 403)

    report = {"ok": True, "ts": _now().isoformat(timespec="seconds"), "checks": []}
    def add_check(name, ok, details=None):
        report["checks"].append({"name": name, "ok": bool(ok), "details": details})
        if not ok:
            report["ok"] = False

    # 1) Schema probe
    try:
        sch = schema_probe()
        add_check("schema_probe", True, {"tables": len(sch.get("tables", {}))})
    except Exception as e:
        add_check("schema_probe", False, str(e))

    # 2) Normalize code
    try:
        add_check("normalize_code", normalize_code("  ab- 12 ") == "AB- 12")
    except Exception as e:
        add_check("normalize_code", False, str(e))

    # 3) DB core tables accessible
    try:
        con = db_connect()
        try:
            for t in ("Items","Warehouses","Suppliers","Transactions","BalancesSnapshot"):
                try:
                    con.execute(f"SELECT 1 FROM {t} LIMIT 1;").fetchone()
                    add_check(f"select_{t}", True)
                except Exception as e:
                    add_check(f"select_{t}", False, str(e))
        finally:
            try: con.close()
            except Exception: pass
    except Exception as e:
        add_check("db_connect", False, str(e))

    # 4) Stockcache kick (non-blocking)
    try:
        mark_stockcache_dirty()
        ensure_stockcache_async(username=user)
        add_check("stockcache_kick", True)
    except Exception as e:
        add_check("stockcache_kick", False, str(e))

    # 5) High-volume indexes check (important for LAN / 200k+)
    try:
        con = db_connect()
        try:
            idx_rows = con.execute("PRAGMA index_list(Transactions);").fetchall()
            idx_names = {r[1] if not isinstance(r, sqlite3.Row) else r['name'] for r in idx_rows}
            needed = {"idx_txn_item_ts", "idx_txn_type_voided_ts", "idx_txn_eq_ts", "idx_txn_supplier_ts", "idx_txn_ts_id", "idx_txn_voided_ts_id", "idx_txn_req_no", "idx_txn_doc_no"}
            missing = sorted(list(needed - idx_names))
            add_check("txn_indexes", len(missing) == 0, {"missing": missing})
        finally:
            try: con.close()
            except Exception: pass
    except Exception as e:
        add_check("txn_indexes", False, str(e))

    h.send_response(200 if report["ok"] else 500)
    h.send_header("Content-Type", "application/json; charset=utf-8")
    h.send_header("Cache-Control", "no-store")
    h.end_headers()
    h.wfile.write(json.dumps(report, ensure_ascii=False, indent=2).encode("utf-8","replace"))

@ROUTER.get("/__stockcache")
def _stockcache_status(h):
    """Diagnostics: stockcache state + last snapshot info."""
    try:
        info = get_balances_snapshot_info()
    except Exception:
        info = None
    with _STOCKCACHE_LOCK:
        _dirty = bool(_STOCKCACHE_STATE.get("dirty"))
        _running = bool(_STOCKCACHE_STATE.get("running"))
        _last_try = _STOCKCACHE_STATE.get("last_try")
    with _STOCKCACHE_LOCK:
        _generation = int(_STOCKCACHE_STATE.get("generation", 0) or 0)
        _built_generation = int(_STOCKCACHE_STATE.get("built_generation", -1) or -1)
        _last_success = float(_STOCKCACHE_STATE.get("last_success", 0.0) or 0.0)
        _last_duration = float(_STOCKCACHE_STATE.get("last_duration", 0.0) or 0.0)
        _last_error = _STOCKCACHE_STATE.get("last_error") or ""
        _requested_by = _STOCKCACHE_STATE.get("requested_by") or "system"
    payload = {
        "dirty": _dirty,
        "running": _running,
        "last_try": _last_try,
        "last_success": _last_success,
        "last_duration": _last_duration,
        "last_error": _last_error,
        "generation": _generation,
        "built_generation": _built_generation,
        "requested_by": _requested_by,
        "snapshot": info,
    }
    h.send_response(200)
    h.send_header("Content-Type", "application/json; charset=utf-8")
    h.send_header("Cache-Control", "no-store")
    h.end_headers()
    h.wfile.write(json.dumps(payload, ensure_ascii=False).encode("utf-8"))
