# ============================================================
# V6 Enterprise Internal Structure (Single File)
# This file remains single-file, but is organized into CORE and MODULES sections.
# ============================================================

# =========================
# Migrated Routes (Items + Transactions) — Modular Internal (Single File)
# - No direct SQL in HTTP layer: handlers call domain functions (upsert_row/add_txn/update_txn/...)
# - Keeps legacy HTML renderers (render_txn, render_master, ...) unchanged
# =========================

def _router_need_login(handler):
    # returns (username, role, lang) or (None,None,None) after redirect
    if not hasattr(handler, "_need_login"):
        return None, None, None
    return handler._need_login()

def _router_redir_msg(handler, next_url, msg):
    # Always replace any stale flash message in the target URL instead of appending.
    # This prevents old errors/success messages from sticking around across operations.
    nxt = _url_with_message((next_url or "/").strip() or "/", str(msg) if msg else None)
    try:
        return handler._redirect(nxt)
    except Exception:
        return None


def _url_with_message(url, msg):
    nxt = (url or "/").strip() or "/"
    if msg is None or msg == "":
        return nxt
    try:
        parsed = urlparse(nxt)
        qs = parse_qs(parsed.query, keep_blank_values=True)
        qs["m"] = [str(msg)]
        flat = []
        for key, vals in qs.items():
            if not isinstance(vals, list):
                vals = [vals]
            for val in vals:
                flat.append((key, "" if val is None else str(val)))
        query = urlencode(flat, doseq=True)
        rebuilt = parsed._replace(query=query)
        return rebuilt.geturl()
    except Exception:
        sep = "&" if "?" in nxt else "?"
        return nxt + sep + "m=" + quote_plus(str(msg))

def _render_delete_confirm(handler, *, lang: str, user: str, role: str, action_url: str, rid: str, next_url: str):
    is_ar = (lang or "en").lower().startswith("ar")
    title = ("تأكيد الحذف" if is_ar else "Confirm delete")
    msg = (
        "سيتم حذف السجل نهائيًا بعد الضغط على زر الحذف. هل أنت متأكد؟"
        if is_ar else
        "This record will be permanently deleted after you press Delete. Are you sure?"
    )
    wait_txt = ("جارٍ تنفيذ الحذف..." if is_ar else "Deleting...")
    body = f"""
    <div class='card'>
      <h2 style='margin:0 0 10px 0'>{html_escape(title)}</h2>
      <div style='margin:0 0 14px 0'>{html_escape(msg)}</div>
      <form method='post' action='{html_escape(action_url)}' onsubmit="var b=this.querySelector('button[type=submit]'); if(b){{b.disabled=true; b.dataset.oldText=b.innerHTML; b.innerHTML='⏳ {html_escape(wait_txt)}';}}">
        {csrf_field_html(user)}
        <input type='hidden' name='op' value='delete'>
        <input type='hidden' name='id' value='{html_escape(rid)}'>
        <input type='hidden' name='next' value='{html_escape(next_url)}'>
        <div style='display:flex; gap:10px; flex-wrap:wrap'>
          <button class='btn bad' type='submit'>🗑️ {('تأكيد الحذف' if is_ar else 'Confirm delete')}</button>
          <a class='btn' href='{html_escape(next_url)}'>↩️ {('إلغاء' if is_ar else 'Cancel')}</a>
        </div>
      </form>
    </div>
    """
    return handler._send_html(page(lang, title, body, user, role=role))

def _render_action_done(handler, *, lang: str, user: str, role: str, title: str, message: str, next_url: str):
    is_ar = (lang or "en").lower().startswith("ar")
    body = f"""
    <div class='card'>
      <h2 style='margin:0 0 10px 0'>{html_escape(title)}</h2>
      <div style='margin:0 0 14px 0'>{html_escape(message)}</div>
      <div style='display:flex; gap:10px; flex-wrap:wrap'>
        <a class='btn' href='{html_escape(next_url or '/')}'>{('⬅️ رجوع' if is_ar else '⬅️ Back')}</a>
      </div>
    </div>
    """
    return handler._send_html(page(lang, title, body, user, role=role))


def _json_response(handler, payload: dict, status: int = 200):
    return handler._send_bytes(json.dumps(payload, ensure_ascii=False).encode("utf-8","replace"), "application/json", status=status)

def _read_post_any(handler):
    """Read POST body from either multipart/form-data or application/x-www-form-urlencoded.
    Returns (fields, files) where fields is a flat dict[str,str].
    """
    ctype = (handler.headers.get('Content-Type', '') or '').lower()
    if 'multipart/form-data' in ctype:
        fields, files = parse_multipart(handler)
        flat = {}
        for k, v in (fields or {}).items():
            if isinstance(v, list):
                flat[k] = v[0] if v else ''
            else:
                flat[k] = '' if v is None else str(v)
        return flat, (files or {})
    form = handler._read_post_urlencoded()
    flat = {}
    for k, vals in (form or {}).items():
        if isinstance(vals, list):
            flat[k] = vals[0] if vals else ''
        else:
            flat[k] = '' if vals is None else str(vals)
    return flat, {}


def _master_delete_fast(handler, *, entity: str, table_name: str, audit_action: str, force_cascade: bool = False):
    user, role, lang = _router_need_login(handler)
    if not user:
        return
    if not is_admin(role):
        payload = {"ok": False, "error": ("Forbidden" if (lang or "en").lower().startswith("en") else "غير مسموح")}
        return _json_response(handler, payload, 403)
    try:
        form = handler._read_post_urlencoded()
        rid = (form.get("id", [""])[0] or "").strip()
        if not rid.isdigit():
            raise ValueError("Invalid id")
        hard_delete_master(table_name, int(rid), username=user, role=role, ip=handler._client_ip(), force_cascade=force_cascade)
        audit_log(user, audit_action, entity=entity, entity_id=int(rid), details={"mode": "async_fast"}, ip=handler._client_ip(), role=role)
        payload = {"ok": True, "id": int(rid), "message": ("تم الحذف" if (lang or "en").lower().startswith("ar") else "Deleted")}
        return _json_response(handler, payload, 200)
    except Exception as e:
        safe_log_exception(audit_action + "_ERROR", e, username=user, role=role, ip=handler._client_ip())
        payload = {"ok": False, "error": str(e)}
        return _json_response(handler, payload, 400)


@ROUTER.get("/items")
def _rt_items_get(handler):
    user, role, lang = _router_need_login(handler)
    if not user:
        return
    parsed = urlparse(handler.path)
    qs = parse_qs(parsed.query)
    flash = (qs.get('m', [''])[0] or '').strip() or None

    q = (qs.get("q", [""])[0] or "")
    op = (qs.get("op", [""])[0] or "").strip().lower()
    rid = (qs.get("id", [""])[0] or "").strip()
    nxt = (qs.get("next", ["/items"])[0] or "/items").strip() or "/items"

    # direct GET delete is disabled; show a safe POST confirmation instead
    if op == "delete" and rid.isdigit():
        if not is_admin(role):
            return handler._redirect(_url_with_message(nxt, "🚫 Forbidden"))
        return _render_delete_confirm(handler, lang=lang, user=user, role=role, action_url="/items/save", rid=rid, next_url=nxt)

    # list / edit UI
    return handler._send_html(render_simple_crud(
        lang, user, role, "items", "Items",
        fields=[("item_code","item_code","text"),("item_name","item_name","text"),("unit","unit","text"),("min_qty","min_qty","number"),("default_unit_price","default_unit_price","number")],
        code_field="item_code",
        search_q=q,
        base_path="items",
        qs=qs,
        active_only_default=(False if (qs.get("show_all",[""])[0] or "") in ("1","true","yes") else True),
        flash=flash
    ))

