@ROUTER.post("/projects/save")
def _rt_projects_save(handler):
    user, role, lang = _router_need_login(handler)
    if not user:
        return
    if not can_edit(user):
        return handler._send_html(page(lang, '403', "<div class='card'>🚫 Forbidden</div>", user, role=role), 403)
    form = handler._read_post_urlencoded()
    op = ((form.get("op", ["save"])[0] or "save").strip().lower())
    rid = (form.get("id", [""])[0] or "").strip()
    next_url = (form.get("next", ["/projects"])[0] or "/projects").strip() or "/projects"
    try:
        if op == 'delete':
            if not is_admin(role):
                return handler._send_html(page(lang, '403', "<div class='card'>🚫 Forbidden</div>", user, role=role), 403)
            if rid.isdigit():
                hard_delete_master('Projects', int(rid), username=user, role=role, ip=handler._client_ip())
            return _router_redir_msg(handler, next_url, 'تم الحذف' if (lang or 'en').startswith('ar') else 'Deleted')
        payload = dict(
            project_code=normalize_code((form.get('project_code',[''])[0] or '')),
            project_name=(form.get('project_name',[''])[0] or '').strip(),
            active=1
        )
        if not payload['project_code'] or not payload['project_name']:
            raise ValueError('Project code/name required')
        upsert_row('Projects', int(rid) if rid.isdigit() else None, payload)
        return _router_redir_msg(handler, next_url, 'تم الحفظ' if (lang or 'en').startswith('ar') else 'Saved')
    except Exception as e:
        safe_log_exception('projects_save', e, username=user, role=role, ip=handler._client_ip())
        return _router_redir_msg(handler, next_url, '❌ ' + str(e))


