def _rt_users_delete_fast(handler):
    user, role, lang = _router_need_login(handler)
    if not user:
        return
    if not is_admin(role):
        payload = {"ok": False, "error": ("Forbidden" if (lang or "en").lower().startswith("en") else "غير مسموح")}
        return _json_response(handler, payload, 403)
    try:
        form = handler._read_post_urlencoded()
        target = (form.get("username", [""])[0] or "").strip()
        if not target:
            raise ValueError("Invalid username")
        if target == "admin" or normalize_code(target) == normalize_code(user):
            raise ValueError("Cannot delete this user")
        delete_user(target)
        audit_log(user, "HARD_DELETE_USER_FAST", entity="Users", entity_id=None, details={"mode": "async_fast", "username": target}, ip=handler._client_ip(), role=role)
        payload = {"ok": True, "id": target, "message": ("تم الحذف" if (lang or "en").lower().startswith("ar") else "Deleted")}
        return _json_response(handler, payload, 200)
    except Exception as e:
        safe_log_exception("router_users_delete_fast", e, username=user, role=role, ip=handler._client_ip())
        payload = {"ok": False, "error": str(e)}
        return _json_response(handler, payload, 400)



