@ROUTER.post("/scrap/sell/save")
def _rt_scrap_sell_save(handler):
    user, role, lang = _router_need_login(handler)
    if not user:
        return
    if not can_edit(user):
        return handler._send_html(page(lang, "403", "<div class='card'>🚫 Forbidden</div>", user, role=role), 403)
    try:
        form = handler._read_post_urlencoded()
        item_id = (form.get("item_id", [""])[0] or "").strip()
        wh_id = (form.get("wh_id", [""])[0] or "").strip()
        qty_sold = (form.get("qty_sold", [""])[0] or "").strip()
        unit_sale_price = (form.get("unit_sale_price", [""])[0] or "").strip()
        sold_at = (form.get("sold_at", [""])[0] or "").strip() or _today_iso()
        notes = (form.get("notes", [""])[0] or "").strip()
        if not item_id.isdigit():
            raise ValueError("Invalid item_id")
        if not qty_sold:
            raise ValueError("الكمية مطلوبة")
        if not unit_sale_price:
            raise ValueError("سعر البيع مطلوب")
        qty_val = float(qty_sold)
        price_val = float(unit_sale_price)
        if qty_val <= 0:
            raise ValueError("الكمية يجب أن تكون أكبر من صفر")
        if price_val <= 0:
            raise ValueError("سعر البيع يجب أن يكون أكبر من صفر")
        scrap_mark_sold(int(item_id), qty_val, unit_sale_price=price_val, sold_at=sold_at, notes=notes, username=user, wh_id=(int(wh_id) if wh_id.isdigit() else None))
        try:
            audit_log(user, "SCRAP_SELL", entity="ScrapSales", entity_id=None, details={"item_id": int(item_id), "wh_id": (int(wh_id) if wh_id.isdigit() else None), "qty_sold": qty_val, "unit_sale_price": price_val, "sold_at": sold_at, "notes": notes or None}, ip=handler._client_ip(), role=role)
        except Exception:
            pass
        return _router_redir_msg(handler, "/scrap", "✅ تم تسجيل بيع السكراب")
    except Exception as e:
        safe_log_exception("scrap_sell_save", e, username=user, role=role, ip=handler._client_ip())
        return _router_redir_msg(handler, "/scrap", "❌ " + str(e))




