    next_url = (form.get("next", [""])[0] or "").strip() or "/items"

    if op == "delete":
        msg = t(lang, "deleted") if "deleted" in I18N.get(lang, {}) else ("تم الحذف" if lang=="ar" else "Deleted")
    elif rid and rid.isdigit():
        msg = t(lang, "updated") if "updated" in I18N.get(lang, {}) else ("تم التعديل" if lang=="ar" else "Updated")
    else:
        msg = t(lang, "added") if "added" in I18N.get(lang, {}) else ("تمت الإضافة" if lang=="ar" else "Added")

    c = get_container()
    try:
        msg2 = c.item_service.save(rid=rid, form=form, user=user, role=role, ip=handler._client_ip(), lang=lang)
        if op == "delete":
            return _render_action_done(handler, lang=lang, user=user, role=role, title=("تم الحذف" if (lang or "en").lower().startswith("ar") else "Deleted"), message=msg2, next_url=next_url)
        return _router_redir_msg(handler, next_url, msg2)
    except PermissionError:
        return handler._send_html(page(lang, "403", "<div class='card'>🚫 Forbidden</div>", user, role=role), 403)
    except Exception as e:
        safe_log_exception("router_items_save", e, username=user, role=role, ip=handler._client_ip())
        return _router_redir_msg(handler, next_url, "❌ " + str(e))


