def _canonical_txn_entry_url(handler, default_txn_type="RECEIVE"):
    """Return a stable /txn URL while preserving query-string filters and normalizing txn_type.
    This keeps legacy entry points working (e.g. /txn/new?txn_type=ISSUE).
    """
    parsed = urlparse(handler.path)
    qs = parse_qs(parsed.query, keep_blank_values=True)
    raw_txn_type = (
        (qs.get("txn_type", [""])[0] or "")
        or (qs.get("type", [""])[0] or "")
        or (qs.get("mode", [""])[0] or "")
        or default_txn_type
    )
    txn_type = _canonical_txn_type(raw_txn_type, default_txn_type=default_txn_type)
    qs["txn_type"] = [txn_type]
    qs.pop("type", None)
    qs.pop("mode", None)
    flat = []
    for key, vals in qs.items():
        if not isinstance(vals, list):
            vals = [vals]
        for val in vals:
            flat.append((key, "" if val is None else str(val)))
    return "/txn" + (("?" + urlencode(flat, doseq=True)) if flat else "")


def _canonical_txn_type(raw_txn_type, default_txn_type="RECEIVE"):
    txn_type = str(raw_txn_type or default_txn_type).strip().upper()
    txn_aliases = {
        "RECEIVE": "RECEIVE", "RCV": "RECEIVE", "RECEIPT": "RECEIVE", "RECEIVED": "RECEIVE",
        "استلام": "RECEIVE",
        "ISSUE": "ISSUE", "صرف": "ISSUE", "صرف جديد": "ISSUE", "NEW ISSUE": "ISSUE",
        "TRANSFER": "TRANSFER", "تحويل": "TRANSFER",
    }
    txn_type = txn_aliases.get(txn_type, txn_type)
    return txn_type if txn_type in ("RECEIVE", "ISSUE", "TRANSFER") else default_txn_type


def _txn_type_from_handler_path(path: str, default_txn_type="RECEIVE"):
    p = str(path or "").strip().lower().rstrip("/")
    if p in ("/txn/issue", "/txn/issue/new"):
        return "ISSUE"
    if p in ("/txn/transfer", "/txn/transfer/new"):
        return "TRANSFER"
    if p in ("/txn/receive", "/txn/receive/new", "/txn/receipt", "/txn/receipt/new"):
        return "RECEIVE"
    return default_txn_type


def _default_txn_next_url(handler, form: dict | None = None, default_txn_type="RECEIVE"):
    form = form or {}
    parsed = urlparse(getattr(handler, 'path', '') or '')
    raw = (
        (form.get('txn_type', [''])[0] if isinstance(form.get('txn_type'), list) else form.get('txn_type', ''))
        or (form.get('type', [''])[0] if isinstance(form.get('type'), list) else form.get('type', ''))
        or (form.get('mode', [''])[0] if isinstance(form.get('mode'), list) else form.get('mode', ''))
        or _txn_type_from_handler_path(parsed.path, default_txn_type=default_txn_type)
    )
    txn_type = _canonical_txn_type(raw, default_txn_type=default_txn_type)
    return f"/txn?txn_type={quote_plus(txn_type)}"


