def _router_txn_id_from_fields(fields: dict, *, required: bool = True) -> int | None:
    raw = ""
    v = (fields or {}).get("txn_id")
    if isinstance(v, list):
        raw = v[0] if v else ""
    else:
        raw = v or ""
    raw_s = str(raw).strip()
    if not raw_s:
        if required:
            raise ValueError("txn_id required")
        return None
    if not raw_s.isdigit() or int(raw_s) <= 0:
        raise ValueError("Invalid txn_id")
    return int(raw_s)

