@ROUTER.post("/txn/attach_bulk")
def _rt_txn_attach_bulk(handler):
    """Bulk upload ONE PDF and attach it to multiple transactions."""
    user, role, lang = _router_need_login(handler)
    if not user:
        return
    # Permissions: same as single attachment
    if not is_admin(role) and not can_edit(user):
        return handler._send_html(page(lang, "403", "<div class='card'>🚫 Forbidden</div>", user, role=role), 403)

    fields = {}
    files = {}
    try:
        fields, files = parse_multipart(handler)
        # txn ids may come as:
        # - repeated fields: txn_ids=1&txn_ids=2...
        # - a single field (some multipart parsers keep only the last)
        # - comma/space separated string
        raw_parts = []
        for k in ("txn_ids", "txn_id", "ids", "txn_ids_csv", "txn_ids_json", "txn_ids_count", "selected_txn_ids", "selected_ids"):
            v = (fields or {}).get(k)
            if v is None:
                continue
            if isinstance(v, list):
                raw_parts.extend([str(x) for x in v])
            else:
                raw_parts.append(str(v))
        txn_ids = []
        raw_json = (fields or {}).get("txn_ids_json")
        if isinstance(raw_json, list):
            raw_json = raw_json[0] if raw_json else ""
        if raw_json:
            try:
                parsed_json = json.loads(str(raw_json))
                if isinstance(parsed_json, list):
                    for x in parsed_json:
                        try:
                            n = int(str(x).strip())
                            if n > 0:
                                txn_ids.append(n)
                        except Exception:
                            pass
            except Exception:
                pass
        blob = " ".join(raw_parts)
        for s in re.findall(r"\d+", blob):
            try:
                n = int(s)
                if n > 0:
                    txn_ids.append(n)
            except Exception:
                pass
        txn_ids = sorted(set(txn_ids))

        if not txn_ids:
            return _router_redir_msg(handler, "/txn", "❌ لم يتم اختيار حركات")

        up = (files or {}).get("pdf") or (files or {}).get("file")
        if not up:
            return _router_redir_msg(handler, "/txn", "❌ اختر ملف PDF")

        filename, data = up
        ext = _safe_ext(filename)
        if ext != ".pdf":
            return _router_redir_msg(handler, "/txn", "❌ PDF فقط")
        if len(data) > 20 * 1024 * 1024:
            return _router_redir_msg(handler, "/txn", "❌ الملف كبير (أقصى 20MB)")
        if not _looks_like_pdf(data):
            return _router_redir_msg(handler, "/txn", "❌ PDF غير صالح")

        c = get_container()
        ok_count = 0
        fail = []
        # Reuse the existing safe single-attach logic per txn (creates separate file per txn => safest).
        for tid in txn_ids:
            try:
                msg = c.txn_service.attach_upload(txn_id=int(tid), files={"pdf": (filename, data)}, user=user, role=role, ip=handler._client_ip(), lang=lang)
                ok_count += 1
            except Exception as e:
                if len(fail) < 7:
                    fail.append(f"#{tid}: {str(e)}")

        if ok_count <= 0:
            return _router_redir_msg(handler, "/txn", "❌ فشل رفع PDF للحركات المحددة" + (" — " + " | ".join(fail) if fail else ""))

        extra = ""
        if fail:
            extra = " — بعض الحركات فشلت: " + " | ".join(fail)
        return _router_redir_msg(handler, "/txn", f"✅ تم رفع PDF لعدد {ok_count} حركة{extra}")

    except Exception as e:
        safe_log_exception("ATTACH_BULK_ERROR", e)
        return _router_redir_msg(handler, "/txn", "❌ " + str(e))
@ROUTER.post("/txn/void")
def _rt_txn_void(handler):
    user, role, lang = _router_need_login(handler)
    if not user:
        return
    if not can_edit(user):
        return handler._send_html(page(lang, "403", "<div class='card'>🚫 Forbidden</div>", user, role=role), 403)
    form = handler._read_post_urlencoded()
    tid = (form.get("id",[""])[0] or "").strip()
    reason = (form.get("reason",[""])[0] or "")
    if tid.isdigit():
        try:
            c = get_container()
            c.txn_service.void(txn_id=int(tid), reason=reason, user=user, role=role, ip=handler._client_ip(), lang=lang)
        except Exception as e:
            return handler._redirect("/txn?m=" + quote_plus("❌ " + str(e)))
    return handler._redirect("/txn?voided=1")

# ===== CORE =====
# 1) DB Engine
# 2) Security Layer (CSRF, sessions, hardening)
