def is_admin(role):
    return str(role).strip().upper() == "ADMIN"


def has_any_users() -> bool:
    """True when at least one user exists in the database."""
    try:
        con = db_connect()
        try:
            r = con.execute("SELECT COUNT(*) c FROM Users;").fetchone()
            return int((r["c"] if isinstance(r, sqlite3.Row) else r[0]) or 0) > 0
        finally:
            try:
                con.close()
            except Exception:
                pass
    except Exception:
        return False

def is_bootstrap_mode() -> bool:
    """Bootstrap mode is active only on the very first run before any user is created."""
    return not has_any_users()



