# ===== LAN hardening: maintenance gate (blocks mutating requests during restore/maintenance) =====
_MAINTENANCE_MODE = False
_MAINTENANCE_LOCK = threading.Lock()

def set_maintenance_mode(on: bool):
    global _MAINTENANCE_MODE
    with _MAINTENANCE_LOCK:
        _MAINTENANCE_MODE = bool(on)

def is_maintenance_mode() -> bool:
    with _MAINTENANCE_LOCK:
        return bool(_MAINTENANCE_MODE)




# =========================
# CORE / IMPORT REPORTS ENGINE
# =========================
# ===== Import reports (store failed rows with reasons) =====
_IMPORT_REPORTS = {}  # token -> {"created": float, "view": str, "summary": dict, "errors": list[str], "failed_rows": list[dict], "failed_xlsx": bytes|None}
_IMPORT_REPORTS_LOCK = threading.Lock()
_IMPORT_REPORTS_TTL_SEC = 60 * 60  # 1 hour

def _cleanup_import_reports():
    now = time.time()
    with _IMPORT_REPORTS_LOCK:
        dead = [k for k,v in _IMPORT_REPORTS.items() if (now - float(v.get("created",0) or 0)) > _IMPORT_REPORTS_TTL_SEC]
        for k in dead:
            _IMPORT_REPORTS.pop(k, None)

def _store_import_report(view: str, res: dict) -> str:
    _cleanup_import_reports()
    token = secrets.token_urlsafe(16)
    summary = {
        "ok": int(res.get("ok",0) or 0),
        "add": int(res.get("add",0) or 0),
        "update": int(res.get("update",0) or 0),
        "skipped": int(res.get("skipped",0) or 0),
    }
    errors = list(res.get("errors") or [])
    failed_rows = list(res.get("failed") or [])
    failed_xlsx = res.get("failed_xlsx")  # optional
    with _IMPORT_REPORTS_LOCK:
        _IMPORT_REPORTS[token] = {"created": time.time(), "view": (view or ""), "summary": summary, "errors": errors, "failed_rows": failed_rows, "failed_xlsx": failed_xlsx}
    return token

def _get_import_report(token: str):
    if not token:
        return None
    _cleanup_import_reports()
    with _IMPORT_REPORTS_LOCK:
        return _IMPORT_REPORTS.get(token)
