# ===== Formatting helpers (stable core utils) =====
def fmt_num(x, dec: int = 2) -> str:
    """Format a number with thousands separators.
    Accepts None/empty and returns '0'. Never raises.
    """
    try:
        if x is None:
            return "0"
        if isinstance(x, str) and x.strip() == "":
            return "0"
        v = float(x)
        # Avoid "-0.00"
        if abs(v) < 0.0000001:
            v = 0.0
        return f"{v:,.{dec}f}"
    except Exception:
        return str(x)

def fmt_int(x) -> str:
    """Format an integer with thousands separators. Never raises."""
    try:
        if x is None or (isinstance(x, str) and x.strip() == ""):
            return "0"
        return f"{int(float(x)):,}"
    except Exception:
        return "0"

def fmt_date(x) -> str:
    """Best-effort date formatting (YYYY-MM-DD). Never raises."""
    try:
        if not x:
            return ""
        s = str(x)
        return s[:10]
    except Exception:
        return ""

def fmt_dt(x) -> str:
    """Best-effort datetime formatting. Never raises."""
    try:
        if not x:
            return ""
        s = str(x)
        return s.replace("T", " ")[:19]
    except Exception:
        return ""

def fmt_money(x) -> str:
    """Money formatting helper (2 decimals)."""
    return fmt_num(x, 2)

def fmt_money0(x) -> str:
    """Money formatting helper (0 decimals) for compact KPI/table display."""
    try:
        return f"{float(x or 0):,.0f}"
    except Exception:
        try:
            return str(int(float(x)))
        except Exception:
            return "0"

def fmt_qty(x) -> str:
    """Quantity formatting helper: integers without decimals, fractions up to 3 decimals."""
    try:
        v = float(x or 0)
        if abs(v - round(v)) < 1e-9:
            return f"{int(round(v)):,}"
        s = f"{v:,.3f}"
        s = s.rstrip("0").rstrip(".")
        return s
    except Exception:
        return "0"
