# ===================== V6 Enterprise Logging (files + rotation) =====================
LOG_DIR = os.path.join(BASE_DIR, "logs")
os.makedirs(LOG_DIR, exist_ok=True)

def _rotating_write(logfile: str, line: str, max_bytes: int = 5_000_000, backups: int = 10):
    """Append a line to logfile with simple size-based rotation.
    - max_bytes: rotate when file exceeds this size.
    - backups: keep .1 .. .N
    Best-effort, never raises.
    """
    try:
        fp = os.path.join(LOG_DIR, logfile)
        os.makedirs(os.path.dirname(fp), exist_ok=True)
        # rotate if needed
        try:
            if os.path.exists(fp) and os.path.getsize(fp) >= int(max_bytes):
                # shift backups
                for i in range(int(backups), 0, -1):
                    src = fp if i == 1 else f"{fp}.{i-1}"
                    dst = f"{fp}.{i}"
                    if os.path.exists(src):
                        try:
                            if os.path.exists(dst):
                                os.remove(dst)
                        except Exception:
                            pass
                        try:
                            os.replace(src, dst)
                        except Exception:
                            pass
        except Exception:
            pass
        with open(fp, "a", encoding="utf-8", errors="replace") as f:
            f.write(line.rstrip("\n") + "\n")
    except Exception:
        pass

def log_error(msg: str):
    ts = _now().strftime("%Y-%m-%d %H:%M:%S")
    _rotating_write("error.log", f"[{ts}] {msg}")

def log_security(msg: str):
    ts = _now().strftime("%Y-%m-%d %H:%M:%S")
    _rotating_write("security.log", f"[{ts}] {msg}")


