# ---------------- V6 Enterprise Rate Limiter (Token Bucket) ----------------
# Lightweight in-memory limiter: per-IP + per-path group, best-effort.
_RATE = {}
_RATE_LOCK = threading.Lock()

# defaults (can be tuned)
RL_GLOBAL_RPS = 25          # sustained requests/sec
RL_GLOBAL_BURST = 80        # burst tokens
RL_HEAVY_RPS = 6            # for heavy pages (balances/history/export)
RL_HEAVY_BURST = 18

_HEAVY_PATH_PREFIXES = (
    "/balances", "/history", "/excel", "/reports", "/backup",
    "/item_card", "/equipment_card", "/stale_items", "/diagnostics", "/health"
)

def _rl_bucket(ip: str, key: str, rps: float, burst: int) -> bool:
    now = time.time()
    k = (ip or "?", key)
    with _RATE_LOCK:
        b = _RATE.get(k)
        if not b:
            b = {"tokens": float(burst), "ts": now}
            _RATE[k] = b
        # refill
        dt = max(0.0, now - float(b.get("ts", now)))
        b["ts"] = now
        b["tokens"] = min(float(burst), float(b.get("tokens", 0.0)) + dt * float(rps))
        if b["tokens"] < 1.0:
            return False
        b["tokens"] -= 1.0
        # occasional cleanup
        if len(_RATE) > 5000:
            try:
                cutoff = now - 3600
                for kk in list(_RATE.keys())[:1000]:
                    if float(_RATE[kk].get("ts", 0)) < cutoff:
                        _RATE.pop(kk, None)
            except Exception:
                pass
        return True


# =========================
# CORE / RATE LIMITER
# =========================
def rate_limit_allow(ip: str, path: str) -> bool:
    p = (path or "/").split("?", 1)[0]
    # global limiter
    if not _rl_bucket(ip, "GLOBAL", RL_GLOBAL_RPS, RL_GLOBAL_BURST):
        return False
    # heavier pages limiter
    if p.startswith(_HEAVY_PATH_PREFIXES):
        if not _rl_bucket(ip, "HEAVY", RL_HEAVY_RPS, RL_HEAVY_BURST):
            return False
    return True
