def t(lang, k, **kw):
    s = TR.get(lang, TR["en"]).get(k, TR["en"].get(k, k))
    try:
        return s.format(**kw)
    except Exception:
        return s

def _now():
    return datetime.now()

def _today_iso():
    return date.today().isoformat()

def _coerce_date_yyyy_mm_dd(value):
    """Coerce many date representations to 'YYYY-MM-DD' (or None).

    Accepts:
      - datetime/date objects
      - Excel serial numbers (int/float) (Windows/Excel epoch)
      - strings like '2026-02-17', '17/02/2026', '2026/02/17', '2026-02-17 10:30'
    """
    if value is None:
        return None
    import datetime as _dt

    # date/datetime
    if isinstance(value, (_dt.datetime, _dt.date)):
        return value.strftime("%Y-%m-%d")

    # Excel serial (best-effort)
    if isinstance(value, (int, float)):
        try:
            base = _dt.datetime(1899, 12, 30)  # Excel serial base
            d = base + _dt.timedelta(days=float(value))
            return d.strftime("%Y-%m-%d")
        except Exception:
            return None

    s = str(value).strip()
    if not s:
        return None

    # Keep only date-ish prefix
    s10 = s[:10]

    # Try ISO first
    for fmt in ("%Y-%m-%d", "%Y/%m/%d", "%d/%m/%Y", "%d-%m-%Y", "%m/%d/%Y"):
        try:
            return _dt.datetime.strptime(s10, fmt).strftime("%Y-%m-%d")
        except Exception:
            pass

    # Try fromisoformat on full string (handles 'YYYY-MM-DDTHH:MM:SS')
    try:
        return _dt.datetime.fromisoformat(s.replace("Z","") ).date().strftime("%Y-%m-%d")
    except Exception:
        return None


def html_escape(s):
    if s is None:
        return ""
    return (str(s).replace("&","&amp;").replace("<","&lt;").replace(">","&gt;")
            .replace('"',"&quot;").replace("'","&#39;"))

