def csrf_field_html(user=None) -> str:
    """Hidden CSRF field for POST forms.
    JS also backfills this from the CSRF cookie, but we render a real field and
    include a tiny inline fallback so multipart forms stay reliable on strict browsers.
    """
    return (
        "<input type='hidden' name='csrf_token' value=''>"
        "<script>(function(){try{var e=document.currentScript&&document.currentScript.previousElementSibling;if(!e||e.value)return;var m=document.cookie.match(/(?:^|; )" + CSRF_COOKIE_NAME + "=([^;]+)/);if(m)e.value=decodeURIComponent(m[1]);}catch(_){}})();</script>"
    )

_IMPORT_WIZARD_STORE = {}
_IMPORT_WIZARD_MAX_AGE_SEC = 30 * 60

def _import_wizard_gc():
    try:
        now_ts = time.time()
        stale = [k for k, v in list(_IMPORT_WIZARD_STORE.items()) if now_ts - float(v.get("created_at", 0) or 0) > _IMPORT_WIZARD_MAX_AGE_SEC]
        for k in stale:
            _IMPORT_WIZARD_STORE.pop(k, None)
    except Exception:
        pass

def _import_wizard_put(view: str, filename: str, file_bytes: bytes, headers=None):
    _import_wizard_gc()
    token = secrets.token_urlsafe(18)
    _IMPORT_WIZARD_STORE[token] = {
        "view": (view or "").strip().lower(),
        "filename": filename or "upload.xlsx",
        "file_bytes": bytes(file_bytes or b""),
        "headers": [str(h) for h in (headers or [])],
        "created_at": time.time(),
    }
    return token

def _import_wizard_get(token: str):
    _import_wizard_gc()
    rec = _IMPORT_WIZARD_STORE.get(str(token or "").strip())
    if not rec:
        return None
    rec["created_at"] = time.time()
    return rec

