    # create index safely after ensuring column exists
    try:
        cur.execute("CREATE INDEX IF NOT EXISTS idx_audit_ts ON AuditLog(ts);")
        con.commit()
    except Exception as _e:
        print("[DB][MIGRATION] init_db step failed:", _e)
        traceback.print_exc()

    # default settings
    try:
        cur.execute("INSERT OR IGNORE INTO Settings(key,value) VALUES('period_lock_before','')")
    except Exception as _e:
        print("[DB][MIGRATION] init_db step failed:", _e)
        traceback.print_exc()

    # lightweight migrations + seed (runs on startup)
    # migrate DailyRequests -> WorkflowRequests (one-time, safe)
    try:
        c_wf = cur.execute("SELECT COUNT(*) c FROM WorkflowRequests;").fetchone()["c"]
        try:
            c_dr = cur.execute("SELECT COUNT(*) c FROM DailyRequests;").fetchone()["c"]
        except Exception:
            c_dr = 0
        if c_wf == 0 and c_dr > 0:
            drs = cur.execute("SELECT * FROM DailyRequests ORDER BY id;").fetchall()
            for r in drs:
                rid = r["id"]
                d = (r["req_date"] or _today_iso())
                wf_no = f"WR-{d.replace('-','')}-{rid:06d}"
                st = (r["status"] or "NOT_RECEIVED").upper()
                if st in ("FULL","RECEIVED","DONE","CLOSED","CLOSE"):
                    stage = "FULFILLED"
                elif st in ("PARTIAL","PART","SOME"):
                    stage = "PARTIAL"
                else:
                    stage = "SUBMITTED"
                cur.execute(
                    """INSERT OR IGNORE INTO WorkflowRequests
                    (wf_no, req_type, title, eq_id, maint_req_no, wh_req_no, po_no, priority, stage, status, owner, due_date, notes, username, created_at, updated_at)
                    VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
                    (wf_no, "MIX", (r["description"] or ""), r["eq_id"],
                     (r["maint_req_no"] or ""), (r["wh_req_no"] or ""), (r["po_no"] or ""),
                     "NORMAL", stage, "OPEN", None, None, (r["notes"] or ""), (r["username"] or ""),
                     (r["created_at"] or _now().isoformat(timespec="seconds")), _now().isoformat(timespec="seconds"))
                )
            cur.execute(
                "INSERT INTO WorkflowAudit(wf_id, ts, username, action, details) "
                "SELECT id, ?, 'system', 'MIGRATE', 'Imported from DailyRequests' FROM WorkflowRequests;",
                (_now().isoformat(timespec="seconds"),)
            )
    except Exception as _e:
        print("[DB][MIGRATION] init_db step failed:", _e)
        traceback.print_exc()

    # first-run bootstrap: do NOT create any default login automatically.
    # The first admin user must be created explicitly from /setup.
    if cur.execute("SELECT COUNT(*) c FROM Warehouses;").fetchone()["c"] == 0:
        cur.executemany("INSERT INTO Warehouses(wh_code, wh_name, active) VALUES (?,?,1)",
                        [("MAIN","Main Warehouse"), ("YARD","Yard / Site")])
    if cur.execute("SELECT COUNT(*) c FROM Items;").fetchone()["c"] == 0:
        cur.executemany("INSERT INTO Items(item_code,item_name,unit,min_qty,active) VALUES (?,?,?,?,1)", [
            ("SP-DEMO-001","فلتر زيت - شيول 966","PIECE",1),
            ("SP-DEMO-002","فلتر ديزل - Isuzu","PIECE",2),
            ("SP-DEMO-003","زيت هيدروليك 20L","PIECE",1),
            ("SP-DEMO-004","لمبة لوحة - تريلا","PIECE",5),
            ("SP-DEMO-005","وجه راس - دينا","PIECE",1),
        ])
    if cur.execute("SELECT COUNT(*) c FROM Equipment;").fetchone()["c"] == 0:
        cur.executemany("INSERT INTO Equipment(eq_code,eq_name,model,year,serial_no,driver_name,active) VALUES (?,?,?,?,?,?,1)", [
            ("FL-966F","شيول 966F","CAT 966F",2001,"",""),
            ("IS-TRK","دينا اسوزو","Isuzu",2017,"",""),
            ("TR-001","تريلا 1","Trailer",2020,"",""),
        ])
    if cur.execute("SELECT COUNT(*) c FROM Suppliers;").fetchone()["c"] == 0:
        cur.executemany("INSERT INTO Suppliers(supplier_code,supplier_name,active) VALUES (?,?,1)", [
            ("SUP-001","مورد جدة 1"),
            ("SUP-002","مورد جدة 2"),
        ])
    con.commit()
    try:
        ensure_critical_indexes(con)
    except Exception as _e:
        print("[DB][MIGRATION] ensure_critical_indexes failed:", _e)
        traceback.print_exc()
    con.close()

