# =========================
# CORE / DB CONSTRAINTS (SAFE, TRIGGER-BASED)
# =========================
# NOTE:
# - SQLite cannot reliably add CHECK/UNIQUE constraints to existing tables via ALTER TABLE.
# - To avoid breaking existing production DBs, we enforce strict rules for NEW/UPDATED rows using triggers.
# - This improves data quality without touching existing rows.
#
# Enforced (where tables/columns exist):
#   - Code columns must be non-empty after trim
#   - Prevent duplicate codes on INSERT/UPDATE (soft-unique; doesn't fail on legacy duplicates unless updated)
#   - Transactions: qty > 0, unit_price >= 0 (if provided), valid txn_type, basic date sanity

def _table_exists(cur, table: str) -> bool:
    r = cur.execute("SELECT name FROM sqlite_master WHERE type='table' AND name=?;", (table,)).fetchone()
    return bool(r)

def _trigger_exists(cur, name: str) -> bool:
    r = cur.execute("SELECT name FROM sqlite_master WHERE type='trigger' AND name=?;", (name,)).fetchone()
    return bool(r)

def _col_exists(cur, table: str, col: str) -> bool:
    try:
        cols = [r["name"] for r in cur.execute(f"PRAGMA table_info({table});").fetchall()]
        return col in cols
    except Exception:
        return False

def _create_trigger_if_not_exists(cur, name: str, sql: str):
    if _trigger_exists(cur, name):
        return
    cur.execute(sql)

def _ensure_soft_unique_code(cur, table: str, code_col: str, id_col: str = "id"):
    if not _table_exists(cur, table):
        return
    if not _col_exists(cur, table, code_col) or not _col_exists(cur, table, id_col):
        return

    # INSERT duplicate guard
    trig1 = f"trg_{table}_{code_col}_softuniq_ins"
    sql1 = f"""CREATE TRIGGER IF NOT EXISTS {trig1}
    BEFORE INSERT ON {table}
    WHEN NEW.{code_col} IS NOT NULL AND TRIM(NEW.{code_col}) <> ''
    BEGIN
      SELECT
        CASE
          WHEN EXISTS(SELECT 1 FROM {table} WHERE TRIM({code_col}) = TRIM(NEW.{code_col}) LIMIT 1)
          THEN RAISE(ABORT, '{table}.{code_col} already exists')
        END;
    END;"""
    _create_trigger_if_not_exists(cur, trig1, sql1)

    # UPDATE duplicate guard (exclude same id)
    trig2 = f"trg_{table}_{code_col}_softuniq_upd"
    sql2 = f"""CREATE TRIGGER IF NOT EXISTS {trig2}
    BEFORE UPDATE ON {table}
    WHEN NEW.{code_col} IS NOT NULL AND TRIM(NEW.{code_col}) <> ''
    BEGIN
      SELECT
        CASE
          WHEN EXISTS(
              SELECT 1 FROM {table}
              WHERE TRIM({code_col}) = TRIM(NEW.{code_col})
                AND {id_col} <> OLD.{id_col}
              LIMIT 1
          )
          THEN RAISE(ABORT, '{table}.{code_col} already exists')
        END;
    END;"""
    _create_trigger_if_not_exists(cur, trig2, sql2)

def _ensure_not_empty_trim(cur, table: str, col: str):
    if not _table_exists(cur, table):
        return
    if not _col_exists(cur, table, col):
        return

    trig = f"trg_{table}_{col}_notempty"
    sql = f"""CREATE TRIGGER IF NOT EXISTS {trig}
    BEFORE INSERT ON {table}
    WHEN NEW.{col} IS NULL OR TRIM(NEW.{col}) = ''
    BEGIN
      SELECT RAISE(ABORT, '{table}.{col} required');
    END;"""
    _create_trigger_if_not_exists(cur, trig, sql)

    trig2 = f"trg_{table}_{col}_notempty_upd"
    sql2 = f"""CREATE TRIGGER IF NOT EXISTS {trig2}
    BEFORE UPDATE ON {table}
    WHEN NEW.{col} IS NULL OR TRIM(NEW.{col}) = ''
    BEGIN
      SELECT RAISE(ABORT, '{table}.{col} required');
    END;"""
    _create_trigger_if_not_exists(cur, trig2, sql2)

def _ensure_txn_rules(cur):
    if not _table_exists(cur, "Transactions"):
        return

    # qty > 0 (some legacy DBs might be missing CHECK)
    if _col_exists(cur, "Transactions", "qty"):
        trig = "trg_Transactions_qty_positive"
        sql = """CREATE TRIGGER IF NOT EXISTS trg_Transactions_qty_positive
        BEFORE INSERT ON Transactions
        WHEN NEW.qty IS NULL OR NEW.qty <= 0
        BEGIN
          SELECT RAISE(ABORT, 'Transactions.qty must be > 0');
        END;"""
        _create_trigger_if_not_exists(cur, trig, sql)

        trig2 = "trg_Transactions_qty_positive_upd"
        sql2 = """CREATE TRIGGER IF NOT EXISTS trg_Transactions_qty_positive_upd
        BEFORE UPDATE ON Transactions
        WHEN NEW.qty IS NULL OR NEW.qty <= 0
        BEGIN
          SELECT RAISE(ABORT, 'Transactions.qty must be > 0');
        END;"""
        _create_trigger_if_not_exists(cur, trig2, sql2)

    # unit_price >= 0 if provided
    if _col_exists(cur, "Transactions", "unit_price"):
        trig3 = "trg_Transactions_unit_price_nonneg"
        sql3 = """CREATE TRIGGER IF NOT EXISTS trg_Transactions_unit_price_nonneg
        BEFORE INSERT ON Transactions
        WHEN NEW.unit_price IS NOT NULL AND NEW.unit_price < 0
        BEGIN
          SELECT RAISE(ABORT, 'Transactions.unit_price must be >= 0');
        END;"""
        _create_trigger_if_not_exists(cur, trig3, sql3)

        trig4 = "trg_Transactions_unit_price_nonneg_upd"
        sql4 = """CREATE TRIGGER IF NOT EXISTS trg_Transactions_unit_price_nonneg_upd
        BEFORE UPDATE ON Transactions
        WHEN NEW.unit_price IS NOT NULL AND NEW.unit_price < 0
        BEGIN
          SELECT RAISE(ABORT, 'Transactions.unit_price must be >= 0');
        END;"""
        _create_trigger_if_not_exists(cur, trig4, sql4)

    # txn_type whitelist
    if _col_exists(cur, "Transactions", "txn_type"):
        trig5 = "trg_Transactions_txn_type_whitelist"
        sql5 = """CREATE TRIGGER IF NOT EXISTS trg_Transactions_txn_type_whitelist
        BEFORE INSERT ON Transactions
        WHEN NEW.txn_type IS NULL OR UPPER(TRIM(NEW.txn_type)) NOT IN ('RECEIVE','ISSUE','TRANSFER')
        BEGIN
          SELECT RAISE(ABORT, 'Transactions.txn_type invalid');
        END;"""
        _create_trigger_if_not_exists(cur, trig5, sql5)

        trig6 = "trg_Transactions_txn_type_whitelist_upd"
        sql6 = """CREATE TRIGGER IF NOT EXISTS trg_Transactions_txn_type_whitelist_upd
        BEFORE UPDATE ON Transactions
        WHEN NEW.txn_type IS NULL OR UPPER(TRIM(NEW.txn_type)) NOT IN ('RECEIVE','ISSUE','TRANSFER')
        BEGIN
          SELECT RAISE(ABORT, 'Transactions.txn_type invalid');
        END;"""
        _create_trigger_if_not_exists(cur, trig6, sql6)

    # ts basic sanity (YYYY-MM-DD or ISO)
    if _col_exists(cur, "Transactions", "ts"):
        trig7 = "trg_Transactions_ts_sanity"
        sql7 = """CREATE TRIGGER IF NOT EXISTS trg_Transactions_ts_sanity
        BEFORE INSERT ON Transactions
        WHEN NEW.ts IS NULL OR LENGTH(TRIM(NEW.ts)) < 8
        BEGIN
          SELECT RAISE(ABORT, 'Transactions.ts required');
        END;"""
        _create_trigger_if_not_exists(cur, trig7, sql7)

def ensure_db_constraints(con):
    """Idempotent. Adds safe triggers to enforce strict validations on new/updated rows."""
    cur = con.cursor()
    try:
        # Codes not empty
        _ensure_not_empty_trim(cur, "Items", "item_code")
        _ensure_not_empty_trim(cur, "Items", "item_name")
        _ensure_not_empty_trim(cur, "Warehouses", "wh_code")
        _ensure_not_empty_trim(cur, "Warehouses", "wh_name")
        _ensure_not_empty_trim(cur, "Equipment", "eq_code")
        _ensure_not_empty_trim(cur, "Equipment", "eq_name")
        _ensure_not_empty_trim(cur, "Suppliers", "supplier_code")
        _ensure_not_empty_trim(cur, "Suppliers", "supplier_name")
        _ensure_not_empty_trim(cur, "Tools", "tool_code")
        _ensure_not_empty_trim(cur, "Tools", "tool_name")
        _ensure_not_empty_trim(cur, "Assets", "asset_code")
        _ensure_not_empty_trim(cur, "Assets", "asset_name")

        # Soft-unique codes (safe for legacy DBs)
        _ensure_soft_unique_code(cur, "Items", "item_code", "id")
        _ensure_soft_unique_code(cur, "Warehouses", "wh_code", "id")
        _ensure_soft_unique_code(cur, "Equipment", "eq_code", "id")
        _ensure_soft_unique_code(cur, "Suppliers", "supplier_code", "id")
        _ensure_soft_unique_code(cur, "Tools", "tool_code", "id")
        _ensure_soft_unique_code(cur, "Assets", "asset_code", "id")

        # Transactions strict rules
        _ensure_txn_rules(cur)

        try:
            # Best-effort audit entry (won't break if AuditLog schema differs)
            audit_log("MIGRATION", "DB_CONSTRAINTS", "Installed trigger-based constraints", username="system", role="SYSTEM", ip="127.0.0.1")
        except Exception:
            pass
    finally:
        try:
            con.commit()
        except Exception:
            pass


def _one(con, sql, params=()):
    return con.execute(sql, params).fetchone()


