def get_user(username):
    con = db_connect()
    r = con.execute("SELECT username, role, active FROM Users WHERE username=?", (username,)).fetchone()
    con.close()
    return dict(r) if r else None

def user_role(username):
    u = get_user(username)
    return (u or {}).get("role") if u and u.get("active",1)==1 else None

def get_user_profile(username):
    username = (username or "").strip()
    if not username:
        return None
    con = db_connect()
    try:
        cols = {r["name"] if isinstance(r, sqlite3.Row) else r[1] for r in con.execute("PRAGMA table_info(Users);").fetchall()}
        select_cols = ["username", "role", "active", "created_at"]
        select_cols.append("last_login" if "last_login" in cols else "NULL AS last_login")
        select_cols.append("avatar_path" if "avatar_path" in cols else "NULL AS avatar_path")
        r = con.execute(f"SELECT {', '.join(select_cols)} FROM Users WHERE username=?", (username,)).fetchone()
        return dict(r) if r else None
    finally:
        con.close()

def set_user_last_login(username, ts=None):
    username = (username or "").strip()
    if not username:
        return
    ts = ts or _now().isoformat(timespec="seconds")
    con = db_connect()
    try:
        cols = {r["name"] if isinstance(r, sqlite3.Row) else r[1] for r in con.execute("PRAGMA table_info(Users);").fetchall()}
        if "last_login" in cols:
            con.execute("UPDATE Users SET last_login=? WHERE username=?", (ts, username))
            if not _in_atomic_db():
                con.commit()
    finally:
        con.close()

def _fmt_user_last_login(ts, lang="ar"):
    s = str(ts or "").strip()
    if not s:
        return ("لم يسجل دخول بعد" if (lang or "en").lower().startswith("ar") else "No login yet")
    try:
        return datetime.fromisoformat(s.replace("Z", "")).strftime("%Y-%m-%d %H:%M")
    except Exception:
        return s[:16].replace("T", " ")

def _avatar_data_uri(username: str, role: str = "") -> str:
    initials = (normalize_code(username)[:2] or "U")
    role_txt = (role or "USER").strip().upper()[:10]
    svg = f"""<svg xmlns='http://www.w3.org/2000/svg' width='96' height='96' viewBox='0 0 96 96'>
    <defs>
      <linearGradient id='g' x1='0' y1='0' x2='1' y2='1'>
        <stop offset='0%' stop-color='#1d4ed8'/>
        <stop offset='100%' stop-color='#0f172a'/>
      </linearGradient>
    </defs>
    <rect width='96' height='96' rx='24' fill='url(#g)'/>
    <circle cx='48' cy='36' r='18' fill='rgba(255,255,255,.18)'/>
    <path d='M22 82c4-14 18-22 26-22s22 8 26 22' fill='rgba(255,255,255,.18)'/>
    <text x='48' y='42' text-anchor='middle' font-family='Arial, sans-serif' font-size='20' font-weight='700' fill='#fff'>{html_escape(initials)}</text>
    <text x='48' y='91' text-anchor='middle' font-family='Arial, sans-serif' font-size='9' font-weight='700' fill='#dbeafe'>{html_escape(role_txt)}</text>
    </svg>"""
    return "data:image/svg+xml;base64," + base64.b64encode(svg.encode("utf-8")).decode("ascii")

def get_user_avatar_src(profile: dict | None) -> str:
    if not profile:
        return _avatar_data_uri("U", "")
    fs_path = str((profile or {}).get("avatar_path") or "").strip()
    if fs_path and os.path.exists(fs_path):
        try:
            mime = mimetypes.guess_type(fs_path)[0] or "image/png"
            with open(fs_path, "rb") as f:
                return f"data:{mime};base64," + base64.b64encode(f.read()).decode("ascii")
        except Exception:
            pass
    return _avatar_data_uri(str((profile or {}).get("username") or "U"), str((profile or {}).get("role") or ""))

def require_role(username, allowed=("VIEWER","EDITOR","ADMIN")):
    role = user_role(username)
    if role is None:
        return False
    current = str(role).strip().upper()
    allowed_set = {str(r).strip().upper() for r in (allowed or ())}
    return current in allowed_set

# Whitelist for dynamic lookups to avoid SQL injection via table/column names
_ALLOWED_CODE_LOOKUPS = {
    "Items": {"item_code"},
    "Warehouses": {"wh_code"},
    "Equipment": {"eq_code"},
    "Suppliers": {"supplier_code"},
}

def _norm_code(code: str) -> str:
    """Back-compat alias. Prefer normalize_code()."""
    return normalize_code(code)


def _get_id_by_code(table, code_col, code, active_only=True):
    if not code:
        return None
    # SECURITY: prevent injection by allowing only known table/column pairs
    if table not in _ALLOWED_CODE_LOOKUPS or code_col not in _ALLOWED_CODE_LOOKUPS.get(table, set()):
        raise ValueError("Invalid lookup")

    norm = _norm_code(code)
    if not norm:
        return None

    con = db_connect()
    try:
        # Case-insensitive + trims stored codes
        if active_only:
            r = _one(con, f"SELECT id FROM {table} WHERE UPPER(TRIM({code_col}))=? AND active=1", (norm,))
        else:
            r = _one(con, f"SELECT id FROM {table} WHERE UPPER(TRIM({code_col}))=?", (norm,))

        # Fallback: exact match (in case codes contain non-ASCII / special casing)
        if not r:
            if active_only:
                r = _one(con, f"SELECT id FROM {table} WHERE {code_col}=? AND active=1", (str(code).strip(),))
            else:
                r = _one(con, f"SELECT id FROM {table} WHERE {code_col}=?", (str(code).strip(),))
        return r["id"] if r else None
    finally:
        con.close()


def get_item_id(code, active_only=True): return _get_id_by_code("Items","item_code",code,active_only)
def get_wh_id(code, active_only=True): return _get_id_by_code("Warehouses","wh_code",code,active_only)
def get_eq_id(code, active_only=True): return _get_id_by_code("Equipment","eq_code",code,active_only)
def get_supplier_id(code, active_only=True): return _get_id_by_code("Suppliers","supplier_code",code,active_only)

