# ---------------- Audit Log ----------------

# -------------- CRUD generic (safe upserts) ----------------
# ===== LAN hardening: DB lock stats (for Diagnostics) =====
_DB_LOCK_STATS = {
    "count": 0,
    "last_ts": 0.0,
    "last_msg": "",
    "events": []  # list of dicts: {ts, msg, attempt}
}
_DB_LOCK_STATS_MAX_EVENTS = 200


# ===== V6: Controlled writes (Atomic Write Gate) =====
# Goal: prevent random "database is locked" under multi-user LAN by serializing writes.
_DB_WRITE_LOCK = threading.RLock()

_WRITE_PREFIXES = {
    "insert", "update", "delete", "replace", "create", "drop", "alter",
    "vacuum", "reindex", "analyze", "attach", "detach"
}
def _sql_is_write(sql: str) -> bool:
    try:
        s = (sql or "").lstrip().lower()
        # ignore leading WITH ... (can still be write, but rare here; detect INSERT/UPDATE after WITH)
        if s.startswith("with "):
            # cheap scan for first keyword after CTEs (best-effort)
            # If it contains " insert " / " update " etc, treat as write.
            for kw in (" insert", " update", " delete", " replace", " create", " drop", " alter"):
                if kw in s[:600].replace("\n"," "):
                    return True
            return False
        kw = s.split(None, 1)[0] if s else ""
        return kw in _WRITE_PREFIXES
    except Exception:
        return False
def _retry_db(fn, retries: int = 7, base_sleep: float = 0.12):
    """Retry transient SQLite errors (database is locked/busy) to avoid random crashes under concurrency."""
    last = None
    for i in range(max(1, int(retries))):
        try:
            return fn()
        except sqlite3.OperationalError as e:
            msg = str(e).lower()
            if ("locked" in msg) or ("busy" in msg) or ("database is locked" in msg):
                last = e
                # record lock/busy events for /diagnostics (best-effort, never raises)
                try:
                    _DB_LOCK_STATS["count"] = int(_DB_LOCK_STATS.get("count",0) or 0) + 1
                    _DB_LOCK_STATS["last_ts"] = time.time()
                    _DB_LOCK_STATS["last_msg"] = str(e)
                    ev = {"ts": _DB_LOCK_STATS["last_ts"], "msg": _DB_LOCK_STATS["last_msg"], "attempt": int(i+1)}
                    _DB_LOCK_STATS.setdefault("events", [])
                    _DB_LOCK_STATS["events"].append(ev)
                    if len(_DB_LOCK_STATS["events"]) > _DB_LOCK_STATS_MAX_EVENTS:
                        _DB_LOCK_STATS["events"] = _DB_LOCK_STATS["events"][-_DB_LOCK_STATS_MAX_EVENTS:]
                except Exception:
                    pass
                time.sleep((base_sleep * (i + 1)) + (random.random() * 0.05))
                continue
            raise
    if last:
        raise last


def upsert_row(table, id_value, fields: dict, id_col="id", audit=None):
    """Insert/update a row with crash-safe handling for UNIQUE constraints and transient locks.
    audit: optional dict {username, action, entity, entity_id, details, ip, role}
    """
    def _do():
        con = db_connect()
        try:
            cols = list(fields.keys())
            vals = [fields[c] for c in cols]
            if id_value:
                sets = ", ".join([f"{c}=?" for c in cols])
                con.execute(f"UPDATE {table} SET {sets} WHERE {id_col}=?", (*vals, int(id_value)))
                _eid = id_value
                _action = "UPDATE"
            else:
                qcols = ", ".join(cols)
                qs = ", ".join(["?"]*len(cols))
                cur = con.execute(f"INSERT INTO {table}({qcols}) VALUES ({qs})", vals)
                _eid = cur.lastrowid
                _action = "INSERT"
            con.commit()
        except sqlite3.IntegrityError as e:
            # Friendly error message (prevents raw traceback to user)
            raise ValueError(f"Integrity error: {e}")
        finally:
            try:
                if not _in_atomic_db():
                    con.close()
            except Exception:
                pass

        if isinstance(audit, dict):
            audit_log(
                audit.get("username"),
                audit.get("action") or _action,
                entity=audit.get("entity") or table,
                entity_id=audit.get("entity_id") or _eid,
                details=audit.get("details"),
                ip=audit.get("ip"),
                role=audit.get("role"),
            )

    return _retry_db(_do)


def soft_delete(table, id_value, id_col="id", audit=None):
    def _do():
        con = db_connect()
        try:
            con.execute(f"UPDATE {table} SET active=0 WHERE {id_col}=?", (int(id_value),))
            con.commit()
        finally:
            try:
                if not _in_atomic_db():
                    con.close()
            except Exception:
                pass

        if isinstance(audit, dict):
            audit_log(
                audit.get("username"),
                audit.get("action") or "SOFT_DELETE",
                entity=audit.get("entity") or table,
                entity_id=audit.get("entity_id") or id_value,
                details=audit.get("details"),
                ip=audit.get("ip"),
                role=audit.get("role"),
            )

    return _retry_db(_do)

# ---------------- Lists ----------------
def hard_delete_master(entity, rid, username=None, role=None, ip=None, force_cascade=False):
    """Hard delete records (DELETE) with best-effort cascade cleanup for this app's schema.
    WARNING: This will permanently remove data and related history. Use with care.
    """
    rid_int = int(rid)

    def _do():
        con = db_connect()
        try:
            con.execute("BEGIN IMMEDIATE;")

            # Normalize entity name
            ent = (entity or "").strip().lower()

            # Safe delete checks (deny delete when referenced) unless force_cascade=True
            def _has(sql, params):
                r = con.execute(sql, params).fetchone()
                return bool(r and r[0] and int(r[0]) > 0)

            def _deny(msg):
                raise ValueError(msg)


            if ent in ("items", "item"):
                if _has("SELECT COUNT(*) FROM Transactions WHERE item_id=?", (rid_int,)) and not force_cascade:
                    _deny("Cannot delete item: it is referenced by transactions.")
                if _has("SELECT COUNT(*) FROM WorkflowItems WHERE item_id=?", (rid_int,)) and not force_cascade:
                    _deny("Cannot delete item: it is referenced by workflow items.")
                if force_cascade:
                    con.execute("DELETE FROM WorkflowItems WHERE item_id=?", (rid_int,))
                    con.execute("DELETE FROM Transactions WHERE item_id=?", (rid_int,))
                con.execute("DELETE FROM Items WHERE id=?", (rid_int,))

            elif ent in ("warehouses", "warehouse", "wh"):
                if _has("SELECT COUNT(*) FROM Transactions WHERE wh_from_id=? OR wh_to_id=?", (rid_int, rid_int)) and not force_cascade:
                    _deny("Cannot delete warehouse: it is referenced by transactions.")
                if _has("SELECT COUNT(*) FROM WorkflowItems WHERE wh_id=?", (rid_int,)) and not force_cascade:
                    _deny("Cannot delete warehouse: it is referenced by workflow items.")
                if force_cascade:
                    con.execute("DELETE FROM WorkflowItems WHERE wh_id=?", (rid_int,))
                    con.execute("DELETE FROM Transactions WHERE wh_from_id=? OR wh_to_id=?", (rid_int, rid_int))
                con.execute("DELETE FROM Warehouses WHERE id=?", (rid_int,))


            elif ent in ("suppliers", "supplier"):
                if _has("SELECT COUNT(*) FROM Transactions WHERE supplier_id=?", (rid_int,)) and not force_cascade:
                    _deny("Cannot delete supplier: it is referenced by transactions.")
                if force_cascade:
                    con.execute("DELETE FROM Transactions WHERE supplier_id=?", (rid_int,))
                con.execute("DELETE FROM Suppliers WHERE id=?", (rid_int,))


            elif ent in ("equipment", "equip", "eq"):
                if _has("SELECT COUNT(*) FROM Transactions WHERE eq_id=?", (rid_int,)) and not force_cascade:
                    _deny("Cannot delete equipment: it is referenced by transactions.")
                if _has("SELECT COUNT(*) FROM DailyRequests WHERE eq_id=?", (rid_int,)) and not force_cascade:
                    _deny("Cannot delete equipment: it is referenced by daily requests.")
                if _has("SELECT COUNT(*) FROM WorkflowRequests WHERE eq_id=?", (rid_int,)) and not force_cascade:
                    _deny("Cannot delete equipment: it is referenced by workflow requests.")
                if force_cascade:
                    wf_ids = [r[0] for r in con.execute("SELECT id FROM WorkflowRequests WHERE eq_id=?", (rid_int,)).fetchall()]
                    if wf_ids:
                        con.execute(f"DELETE FROM WorkflowItems WHERE wf_id IN ({','.join(['?']*len(wf_ids))})", wf_ids)
                        con.execute(f"DELETE FROM WorkflowAudit WHERE wf_id IN ({','.join(['?']*len(wf_ids))})", wf_ids)
                    con.execute("DELETE FROM WorkflowRequests WHERE eq_id=?", (rid_int,))
                    con.execute("DELETE FROM Transactions WHERE eq_id=?", (rid_int,))
                    con.execute("DELETE FROM Equipment WHERE id=?", (rid_int,))
                else:
                    con.execute("DELETE FROM Equipment WHERE id=?", (rid_int,))


            elif ent in ("workflowrequests", "workflow_request", "workflow"):
                con.execute("DELETE FROM WorkflowItems WHERE wf_id=?", (rid_int,))
                con.execute("DELETE FROM WorkflowAudit WHERE wf_id=?", (rid_int,))
                con.execute("DELETE FROM WorkflowRequests WHERE id=?", (rid_int,))

            elif ent in ("standalonerequests", "standalone", "requests", "request"):
                con.execute("DELETE FROM StandaloneRequests WHERE id=?", (rid_int,))

            elif ent in ("tools", "tool"):
                con.execute("DELETE FROM Tools WHERE id=?", (rid_int,))

            elif ent in ("assets", "asset"):
                con.execute("DELETE FROM Assets WHERE id=?", (rid_int,))

            elif ent in ("projects", "project"):
                if _has("SELECT COUNT(*) FROM Transactions WHERE project_id=?", (rid_int,)) and not force_cascade:
                    _deny("Cannot delete project: it is referenced by transactions.")
                if force_cascade:
                    con.execute("DELETE FROM Transactions WHERE project_id=?", (rid_int,))
                con.execute("DELETE FROM Projects WHERE id=?", (rid_int,))

            elif ent in ("users", "user"):
                # Don't allow deleting the last ADMIN account (safety)
                try:
                    admins = con.execute("SELECT COUNT(*) FROM Users WHERE role='ADMIN' AND active=1;").fetchone()[0]
                    urole = con.execute("SELECT role FROM Users WHERE id=?;", (rid_int,)).fetchone()
                    if urole and urole[0] == "ADMIN" and admins <= 1:
                        raise ValueError("Cannot delete last ADMIN user.")
                except Exception as e:
                        safe_log_exception("hard_delete_user_guard", e, username=username or "system", role=role, ip=ip)
                con.execute("DELETE FROM Users WHERE id=?", (rid_int,))

            else:
                # Fallback: attempt raw table delete if entity matches a known table name
                allowed = {'Items','Equipment','Tools','Assets','Projects','Warehouses','Suppliers','Transactions','Users','WorkflowRequests','WorkflowItems','WorkflowAudit','StandaloneRequests','AuditLog','DailyRequests','LoginSecurity','Settings','BalancesSnapshot','BalancesSnapshotInfo','WorkflowItems','WorkflowAudit'}
                # Entity may be provided as a table name with correct case
                table = entity if entity in allowed else None
                if not table:
                    raise ValueError("Unknown entity/table for hard delete")
                con.execute(f"DELETE FROM {table} WHERE id=?", (rid_int,))

            con.commit()
        finally:
            try:
                if not _in_atomic_db():
                    con.close()
            except Exception:
                pass

        # Audit
        try:
            audit_log(username, "HARD_DELETE", entity=entity, entity_id=rid_int,
                      details={"force_cascade": bool(force_cascade), "entity": str(entity), "record_id": rid_int},
                      ip=ip, role=role)
        except Exception as e:
                safe_log_exception("hard_delete_audit", e, username=username or "system", role=role, ip=ip)

        # Rebuild snapshot after destructive deletes that can affect balances
        try:
            if str(entity).strip().lower() in ("items","item","warehouses","warehouse","wh","suppliers","supplier","equipment","equip","eq","transactions","txn"):
                rebuild_balances_snapshot(username or "system", role=role, ip=ip)
        except Exception as e:
                safe_log_exception("hard_delete_rebuild_snapshot", e, username=username or "system", role=role, ip=ip)

    return _retry_db(_do)


def hard_delete_transaction(  # LEGACY_TXN_HELPER_UNUSED_BY_ROUTER
txn_id, username=None, role=None, ip=None):
    """
    HARD delete a single transaction row (DELETE FROM Transactions).
    - Enforces period lock (same rule as void)
    - Deletes attached PDF (best-effort)
    - Marks stockcache dirty + triggers async rebuild so balances stop "hearing" the deleted txn
    """
    tid = int(txn_id)

    def _do():
        con = db_connect()
        attach_path = None
        ts_date = None
        try:
            con.execute("BEGIN IMMEDIATE;")
            r = con.execute("SELECT ts, attachment_path FROM Transactions WHERE id=?", (tid,)).fetchone()
            if not r:
                raise ValueError("Transaction not found")

            # Period lock enforcement (same as void_txn)
            ts = (r["ts"] or "")[:10]
            try:
                d = datetime.strptime(ts, "%Y-%m-%d").date()
            except Exception:
                d = None
            if d and is_locked_date(d):
                raise ValueError(f"Period locked: cannot delete transactions before {get_setting('period_lock_before','')}")
            ts_date = ts
            attach_path = r["attachment_path"] if "attachment_path" in r.keys() else None

            con.execute("DELETE FROM Transactions WHERE id=?", (tid,))
            con.commit()
        except Exception:
            try:
                con.rollback()
            except Exception:
                pass
            raise
        finally:
            try:
                if not _in_atomic_db():
                    con.close()
            except Exception:
                pass

        # delete attachment file after commit (best-effort)
        if attach_path and isinstance(attach_path, str) and attach_path.strip():
            try:
                if os.path.exists(attach_path):
                    os.remove(attach_path)
            except Exception as e:
                safe_log_exception("hard_delete_txn_attachment", e, username=username or "system", role=role, ip=ip)

        # audit (best-effort)
        try:
            audit_log(username, "HARD_DELETE_TXN", entity="Transactions", entity_id=tid,
                      details={"ts": ts_date, "attachment_deleted": bool(attach_path)}, ip=ip, role=role)
        except Exception as e:
            safe_log_exception("hard_delete_txn_audit", e, username=username or "system", role=role, ip=ip)

        # balances cache refresh (best-effort)
        try:
            mark_stockcache_dirty()
            ensure_stockcache_async(username=username or "system")
        except Exception as e:
            safe_log_exception("hard_delete_txn_stockcache", e, username=username or "system", role=role, ip=ip)

    return _retry_db(_do)

def list_rows(table, search="", cols=None, order_by=None, active_only=True, limit=None, offset=0, col_filters=None):
    """Generic listing with optional pagination.
    If the table has an `active` column, hide inactive rows by default.
    """
    search = (search or "").strip()
    con = db_connect()
    if cols is None:
        cols = [r["name"] for r in con.execute(f"PRAGMA table_info({table})").fetchall()]
    order_by = order_by or cols[0]

    has_active = "active" in cols
    where_parts = []
    params = []

    if active_only and has_active:
        where_parts.append("active=1")

    if search:
        like = f"%{search}%"
        search_cols = [c for c in cols if c not in ("id", "active", "min_qty", "year")]
        if search_cols:
            wh = " OR ".join([f"{c} LIKE ?" for c in search_cols])
            where_parts.append(f"({wh})")
            params.extend([like] * len(search_cols))

    
    # column filters (server-side) - works with pagination across all pages
    # Expected query params: f_<col>=value (LIKE %value%)
    if col_filters:
        for k, v in (col_filters or {}).items():
            if not k:
                continue
            if k not in cols:
                continue
            vv = (v or "").strip()
            if vv == "":
                continue
            negate = False
            if vv.startswith("!"):
                negate = True
                vv = vv[1:].strip()
            if vv == "":
                continue
            # basic wildcard support: * -> %
            vv = vv.replace("*", "%")
            if "%" not in vv:
                vv = f"%{vv}%"
            op = "NOT LIKE" if negate else "LIKE"
            where_parts.append(f"{k} {op} ?")
            params.append(vv)

    where_sql = ("WHERE " + " AND ".join(where_parts)) if where_parts else ""

    sql = f"SELECT * FROM {table} {where_sql} ORDER BY {order_by}"
    if limit is not None:
        # SQLite requires LIMIT before OFFSET
        sql += " LIMIT ? OFFSET ?"
        params.extend([int(limit), int(max(0, offset or 0))])

    rows = con.execute(sql, params).fetchall()
    con.close()
    return [dict(r) for r in rows]


def _master_toggle_meta(base_path: str):
    base = (base_path or '').strip('/').lower()
    mapping = {
        'items': ('Items', 'item_code', 'item_name'),
        'warehouses': ('Warehouses', 'wh_code', 'wh_name'),
        'suppliers': ('Suppliers', 'supplier_code', 'supplier_name'),
        'equipment': ('Equipment', 'eq_code', 'eq_name'),
    }
    return mapping.get(base)


_ITEM_DUP_REPAIR_LOCK = threading.Lock()
_ITEM_DUP_REPAIR_STATE = {"last_full_scan": 0.0, "last_error": "", "runs": 0}

def repair_duplicate_items(force: bool = False, target_code: str | None = None, username: str = "system"):
    """Merge duplicate Items rows that share the same normalized item_code."""
    now_ts = time.time()
    norm_target = normalize_code(target_code or "")
    with _ITEM_DUP_REPAIR_LOCK:
        if not force and not norm_target:
            last = float(_ITEM_DUP_REPAIR_STATE.get("last_full_scan", 0.0) or 0.0)
            if (now_ts - last) < 20.0:
                return {"checked": 0, "groups": 0, "merged": 0, "skipped": True}

        con = db_connect()
        merged_rows = 0
        groups_fixed = 0
        groups_checked = 0
        try:
            con.execute("BEGIN IMMEDIATE;")

            where_extra = ""
            params = []
            if norm_target:
                where_extra = " AND UPPER(TRIM(COALESCE(item_code,'')))=? "
                params.append(norm_target)

            dup_rows = con.execute(
                f"""
                SELECT UPPER(TRIM(COALESCE(item_code,''))) AS norm_code, COUNT(*) AS cnt
                FROM Items
                WHERE TRIM(COALESCE(item_code,'')) <> ''
                {where_extra}
                GROUP BY UPPER(TRIM(COALESCE(item_code,'')))
                HAVING COUNT(*) > 1
                ORDER BY norm_code
                """,
                tuple(params),
            ).fetchall()

            def _has_table(name: str) -> bool:
                try:
                    rr = con.execute("SELECT 1 FROM sqlite_master WHERE type='table' AND name=? LIMIT 1", (name,)).fetchone()
                    return bool(rr)
                except Exception:
                    return False

            def _count_refs(table_name: str, item_id: int) -> int:
                if not _has_table(table_name):
                    return 0
                try:
                    rr = con.execute(f"SELECT COUNT(*) FROM {table_name} WHERE item_id=?", (int(item_id),)).fetchone()
                    if not rr:
                        return 0
                    if isinstance(rr, sqlite3.Row):
                        return int(rr[0] or 0)
                    return int(rr[0] or 0)
                except Exception:
                    return 0

            ref_tables = ["Transactions", "WorkflowItems", "ScrapSales", "ScrapTransfers"]
            has_scrapsettings = _has_table("ScrapSettings")

            for dup in dup_rows:
                norm_code = (dup["norm_code"] if isinstance(dup, sqlite3.Row) else dup[0]) or ""
                groups_checked += 1
                rows = [dict(r) for r in con.execute(
                    """
                    SELECT id, item_code, item_name, unit, min_qty, default_unit_price, active
                    FROM Items
                    WHERE UPPER(TRIM(COALESCE(item_code,'')))=?
                    ORDER BY id ASC
                    """,
                    (norm_code,),
                ).fetchall()]
                if len(rows) <= 1:
                    continue

                scored = []
                for row in rows:
                    iid = int(row.get("id") or 0)
                    refs = sum(_count_refs(tn, iid) for tn in ref_tables)
                    if has_scrapsettings:
                        refs += _count_refs("ScrapSettings", iid)
                    scored.append((
                        -refs,
                        -(1 if int(row.get("active", 1) or 0) == 1 else 0),
                        iid,
                        row,
                    ))
                scored.sort()
                keeper = scored[0][3]
                keeper_id = int(keeper.get("id") or 0)

                changed_this_group = 0
                for _, _, _, row in scored[1:]:
                    dup_id = int(row.get("id") or 0)
                    if dup_id == keeper_id:
                        continue

                    for table_name in ref_tables:
                        if _has_table(table_name):
                            con.execute(f"UPDATE {table_name} SET item_id=? WHERE item_id=?", (keeper_id, dup_id))

                    if has_scrapsettings:
                        keeper_ss = con.execute("SELECT sale_threshold_qty, updated_at, updated_by FROM ScrapSettings WHERE item_id=?", (keeper_id,)).fetchone()
                        dup_ss = con.execute("SELECT sale_threshold_qty, updated_at, updated_by FROM ScrapSettings WHERE item_id=?", (dup_id,)).fetchone()
                        if dup_ss and keeper_ss:
                            try:
                                keep_qty = float((keeper_ss["sale_threshold_qty"] if isinstance(keeper_ss, sqlite3.Row) else keeper_ss[0]) or 0.0)
                            except Exception:
                                keep_qty = 0.0
                            try:
                                dup_qty = float((dup_ss["sale_threshold_qty"] if isinstance(dup_ss, sqlite3.Row) else dup_ss[0]) or 0.0)
                            except Exception:
                                dup_qty = 0.0
                            merged_qty = max(keep_qty, dup_qty)
                            updated_at = (keeper_ss["updated_at"] if isinstance(keeper_ss, sqlite3.Row) else keeper_ss[1]) or (dup_ss["updated_at"] if isinstance(dup_ss, sqlite3.Row) else dup_ss[1])
                            updated_by = (keeper_ss["updated_by"] if isinstance(keeper_ss, sqlite3.Row) else keeper_ss[2]) or (dup_ss["updated_by"] if isinstance(dup_ss, sqlite3.Row) else dup_ss[2]) or username
                            con.execute(
                                "UPDATE ScrapSettings SET sale_threshold_qty=?, updated_at=?, updated_by=? WHERE item_id=?",
                                (merged_qty, updated_at, updated_by, keeper_id),
                            )
                            con.execute("DELETE FROM ScrapSettings WHERE item_id=?", (dup_id,))
                        elif dup_ss and not keeper_ss:
                            con.execute("UPDATE ScrapSettings SET item_id=? WHERE item_id=?", (keeper_id, dup_id))

                    try:
                        if int(row.get("active", 1) or 0) == 1 and int(keeper.get("active", 1) or 0) != 1:
                            con.execute("UPDATE Items SET active=1 WHERE id=?", (keeper_id,))
                            keeper["active"] = 1
                    except Exception:
                        pass

                    for col in ("item_name", "unit", "default_unit_price", "min_qty"):
                        keep_val = keeper.get(col)
                        dup_val = row.get(col)
                        empty_keep = keep_val in (None, "", 0, 0.0, "0", "0.0")
                        useful_dup = dup_val not in (None, "")
                        if empty_keep and useful_dup:
                            con.execute(f"UPDATE Items SET {col}=? WHERE id=?", (dup_val, keeper_id))
                            keeper[col] = dup_val

                    con.execute("DELETE FROM Items WHERE id=?", (dup_id,))
                    changed_this_group += 1
                    merged_rows += 1

                    try:
                        audit_log(
                            username,
                            "MERGE_DUP_ITEM",
                            entity="Items",
                            entity_id=keeper_id,
                            details={
                                "duplicate_id": dup_id,
                                "keeper_id": keeper_id,
                                "item_code": norm_code,
                                "keeper_name": keeper.get("item_name"),
                                "duplicate_name": row.get("item_name"),
                            },
                        )
                    except Exception:
                        pass

                if changed_this_group:
                    groups_fixed += 1

            if not _in_atomic_db():
                con.commit()
            _ITEM_DUP_REPAIR_STATE["last_full_scan"] = now_ts
            _ITEM_DUP_REPAIR_STATE["last_error"] = ""
            _ITEM_DUP_REPAIR_STATE["runs"] = int(_ITEM_DUP_REPAIR_STATE.get("runs", 0) or 0) + 1
        except Exception as e:
            try:
                con.rollback()
            except Exception:
                pass
            _ITEM_DUP_REPAIR_STATE["last_error"] = str(e)
            raise
        finally:
            try:
                con.close()
            except Exception:
                pass

    if merged_rows:
        try:
            mark_stockcache_dirty(reason="ITEM_DUP_REPAIR", username=username)
            ensure_stockcache_async(username=username)
        except Exception:
            pass
    return {"checked": groups_checked, "groups": groups_fixed, "merged": merged_rows, "skipped": False}


def toggle_master_active(base_path: str, rid, active: int):
    meta = _master_toggle_meta(base_path)
    if not meta:
        raise ValueError('Unsupported master toggle path')
    table_name, code_col, name_col = meta
    rid_i = int(rid)
    active_i = 1 if int(active or 0) == 1 else 0
    con = db_connect()
    try:
        row = con.execute(f"SELECT id, {code_col} AS code, {name_col} AS name FROM {table_name} WHERE id=?", (rid_i,)).fetchone()
        if not row:
            raise ValueError('Row not found')
        con.execute(f"UPDATE {table_name} SET active=? WHERE id=?", (active_i, rid_i))
        if not _in_atomic_db():
            con.commit()
        return {'table': table_name, 'id': rid_i, 'code': row['code'], 'name': row['name'], 'active': active_i}
    finally:
        try:
            con.close()
        except Exception:
            pass

def lookup_active_for_datalists():
    con = db_connect()
    items = con.execute("SELECT item_code,item_name FROM Items WHERE active=1 ORDER BY item_code").fetchall()
    whs = con.execute("SELECT wh_code,wh_name FROM Warehouses WHERE active=1 ORDER BY wh_code").fetchall()
    eqs = con.execute("SELECT eq_code,eq_name FROM Equipment WHERE active=1 ORDER BY eq_code").fetchall()
    sups = con.execute("SELECT supplier_code,supplier_name FROM Suppliers WHERE active=1 ORDER BY supplier_code").fetchall()
    con.close()
    return [dict(x) for x in items], [dict(x) for x in whs], [dict(x) for x in eqs], [dict(x) for x in sups]

def get_project_id(project_code, active_only=True):
    code = normalize_code(project_code)
    if not code:
        return None
    con = db_connect()
    try:
        sql = "SELECT id FROM Projects WHERE UPPER(TRIM(project_code))=?"
        params = [code]
        if active_only and has_col('Projects', 'active'):
            sql += " AND active=1"
        row = con.execute(sql + " LIMIT 1", tuple(params)).fetchone()
        return int(row[0]) if row else None
    finally:
        con.close()

def list_active_projects_for_datalist():
    con = db_connect()
    try:
        if has_col('Projects', 'active'):
            rows = con.execute("SELECT project_code, project_name FROM Projects WHERE active=1 ORDER BY project_code").fetchall()
        else:
            rows = con.execute("SELECT project_code, project_name FROM Projects ORDER BY project_code").fetchall()
        return [dict(x) for x in rows]
    finally:
        con.close()

# ---------------- Stock logic ----------------
def balance_rows_live(item_code=None, wh_code=None, limit=500, offset=0):
    """Exact live balances using warehouse moving-average cost."""
    con = db_connect()
    try:
        rows, _neg = _build_balances_snapshot_rows_exact(con)
    finally:
        try:
            con.close()
        except Exception:
            pass
    ic = normalize_code(item_code or "")
    wc = normalize_code(wh_code or "")
    if ic:
        rows = [r for r in rows if normalize_code(r.get("item_code") or "") == ic]
    if wc:
        rows = [r for r in rows if normalize_code(r.get("wh_code") or "") == wc]
    off = int(offset or 0)
    lim = int(limit or 500)
    return rows[off:off+lim]

def balance_rows(item_code=None, wh_code=None, limit=500, offset=0):
    """Hybrid balances policy (recommended):
    - Transactions remain the source of truth for writes.
    - BalancesSnapshot is the preferred source for reads (fast + stable).
    - If the snapshot is marked dirty, we still serve the LAST verified snapshot
      while triggering an async rebuild in the background.
    - Live aggregation is used only as a bootstrap fallback when no snapshot exists yet.
    This avoids expensive live reads during normal operation and keeps the UI fast.
    """
    limit = int(limit or 500)
    offset = int(offset or 0)

    info = None
    try:
        info = get_balances_snapshot_info()
    except Exception:
        info = None

    dirty = False
    try:
        dirty = stockcache_is_dirty()
    except Exception:
        dirty = False

    if info:
        if dirty:
            try:
                ensure_stockcache_async(username='system')
            except Exception:
                pass
        con = db_connect()
        try:
            where = "WHERE 1=1 "
            params = []
            if item_code:
                where += "AND item_code LIKE ? "
                params.append(str(item_code).strip() + "%")
            if wh_code:
                where += "AND wh_code LIKE ? "
                params.append(str(wh_code).strip() + "%")
            q = f"""SELECT item_code,item_name,unit,min_qty,wh_code,wh_name,balance,avg_cost,value,last_supplier,last_date
                    FROM BalancesSnapshot
                    {where}
                    ORDER BY item_code, wh_code
                    LIMIT ? OFFSET ?"""
            params.extend([limit, offset])
            rows = con.execute(q, params).fetchall()
            return [dict(r) for r in rows]
        finally:
            try:
                if not _in_atomic_db():
                    con.close()
            except Exception:
                pass

    try:
        _bootstrap_balances_snapshot_on_startup()
    except Exception:
        pass
    return balance_rows_live(item_code=item_code, wh_code=wh_code, limit=limit, offset=offset)



def _aggregate_balance_row_dicts(rows, limit=500, offset=0):
    grouped = {}
    for raw in rows or []:
        r = dict(raw)
        code = normalize_code(r.get('item_code') or '')
        if not code:
            continue
        g = grouped.get(code)
        if not g:
            g = {
                'item_code': r.get('item_code') or code,
                'item_name': r.get('item_name') or '',
                'unit': r.get('unit') or '',
                'min_qty': float(r.get('min_qty') or 0.0),
                'balance': 0.0,
                'value': 0.0,
                'avg_cost': 0.0,
                'last_supplier': r.get('last_supplier') or '',
                'last_date': r.get('last_date') or '',
            }
            grouped[code] = g
        try:
            g['balance'] += float(r.get('balance') or 0.0)
        except Exception:
            pass
        try:
            g['value'] += float(r.get('value') or 0.0)
        except Exception:
            pass
        try:
            g['min_qty'] = max(float(g.get('min_qty') or 0.0), float(r.get('min_qty') or 0.0))
        except Exception:
            pass
        row_date = str(r.get('last_date') or '')
        if row_date and row_date >= str(g.get('last_date') or ''):
            g['last_date'] = row_date
            g['last_supplier'] = r.get('last_supplier') or g.get('last_supplier') or ''
        if (not g.get('item_name')) and r.get('item_name'):
            g['item_name'] = r.get('item_name')
        if (not g.get('unit')) and r.get('unit'):
            g['unit'] = r.get('unit')
    rows2 = []
    for g in grouped.values():
        bal = float(g.get('balance') or 0.0)
        val = float(g.get('value') or 0.0)
        g['balance'] = round(bal, 3)
        g['value'] = round(val, 2)
        g['avg_cost'] = round((val / bal), 6) if abs(bal) > 1e-12 else 0.0
        g['min_qty'] = round(float(g.get('min_qty') or 0.0), 3)
        rows2.append(g)
    rows2.sort(key=lambda x: (normalize_code(x.get('item_code') or ''), normalize_code(x.get('item_name') or '')))
    off = int(offset or 0)
    lim = int(limit or 500)
    return rows2[off:off+lim]


def balance_rows_global_live(item_code=None, limit=500, offset=0):
    rows = balance_rows_live(item_code=item_code, wh_code=None, limit=2000000, offset=0)
    return _aggregate_balance_row_dicts(rows, limit=limit, offset=offset)


def balance_rows_global(item_code=None, limit=500, offset=0):
    limit = int(limit or 500)
    offset = int(offset or 0)
    info = None
    try:
        info = get_balances_snapshot_info()
    except Exception:
        info = None
    dirty = False
    try:
        dirty = stockcache_is_dirty()
    except Exception:
        dirty = False
    if info:
        if dirty:
            try:
                ensure_stockcache_async(username='system')
            except Exception:
                pass
        con = db_connect()
        try:
            where = "WHERE 1=1 "
            params = []
            if item_code:
                where += "AND item_code LIKE ? "
                params.append(str(item_code).strip() + "%")
            q = f"""
                SELECT
                  item_code,
                  MAX(item_name) AS item_name,
                  MAX(unit) AS unit,
                  MAX(min_qty) AS min_qty,
                  ROUND(SUM(COALESCE(balance,0)),3) AS balance,
                  ROUND(SUM(COALESCE(value,0)),2) AS value,
                  CASE WHEN ABS(SUM(COALESCE(balance,0))) > 1e-12
                       THEN ROUND(SUM(COALESCE(value,0))/SUM(COALESCE(balance,0)), 6)
                       ELSE 0 END AS avg_cost,
                  MAX(COALESCE(last_supplier,'')) AS last_supplier,
                  MAX(COALESCE(last_date,'')) AS last_date
                FROM BalancesSnapshot
                {where}
                GROUP BY item_code
                ORDER BY item_code
                LIMIT ? OFFSET ?
            """
            params.extend([limit, offset])
            return [dict(r) for r in con.execute(q, tuple(params)).fetchall()]
        finally:
            try:
                if not _in_atomic_db():
                    con.close()
            except Exception:
                pass
    try:
        _bootstrap_balances_snapshot_on_startup()
    except Exception:
        pass
    return balance_rows_global_live(item_code=item_code, limit=limit, offset=offset)


def low_stock_rows_global(item_code=None, limit=500, offset=0):
    """Global low-stock rows based on item total across all warehouses.

    Important behavior:
    - Uses the same governed source as global balances (snapshot when available,
      last verified snapshot while dirty, live fallback when no snapshot exists).
    - Includes active items that have a positive min_qty even when they have no
      transactions yet, treating their global balance as zero. This keeps Low
      Stock and Dashboard alerts correct for newly created items.
    """
    limit = int(limit or 500)
    offset = int(offset or 0)

    rows = balance_rows_global(item_code=item_code, limit=2000000, offset=0)
    grouped = {normalize_code((r.get('item_code') or '')): dict(r) for r in rows if normalize_code((r.get('item_code') or ''))}

    ic = normalize_code(item_code or "")
    con = db_connect()
    try:
        params = []
        where = "WHERE COALESCE(active,1)=1 AND COALESCE(min_qty,0) > 0 "
        if ic:
            where += "AND UPPER(TRIM(COALESCE(item_code,''))) = ? "
            params.append(ic)
        item_rows = con.execute(
            f"""
            SELECT item_code, item_name, unit, COALESCE(min_qty,0) AS min_qty
            FROM Items
            {where}
            ORDER BY item_code
            """,
            tuple(params)
        ).fetchall()
    finally:
        try:
            con.close()
        except Exception:
            pass

    for rr in item_rows:
        r = dict(rr)
        code = normalize_code(r.get('item_code') or '')
        if not code:
            continue
        base = grouped.get(code)
        if not base:
            grouped[code] = {
                'item_code': r.get('item_code') or code,
                'item_name': r.get('item_name') or '',
                'unit': r.get('unit') or '',
                'min_qty': float(r.get('min_qty') or 0.0),
                'balance': 0.0,
                'value': 0.0,
                'avg_cost': 0.0,
                'last_supplier': '',
                'last_date': '',
            }
        else:
            if not base.get('item_name') and r.get('item_name'):
                base['item_name'] = r.get('item_name')
            if not base.get('unit') and r.get('unit'):
                base['unit'] = r.get('unit')
            try:
                base['min_qty'] = max(float(base.get('min_qty') or 0.0), float(r.get('min_qty') or 0.0))
            except Exception:
                pass

    out = []
    for r in grouped.values():
        try:
            min_qty = float(r.get('min_qty') or 0.0)
        except Exception:
            min_qty = 0.0
        try:
            balance = float(r.get('balance') or 0.0)
        except Exception:
            balance = 0.0
        if min_qty > 0 and balance < min_qty:
            d = dict(r)
            d['balance'] = round(balance, 3)
            d['min_qty'] = round(min_qty, 3)
            d['shortage'] = round(min_qty - balance, 3)
            out.append(d)
    out.sort(key=lambda x: (-float(x.get('shortage') or 0.0), normalize_code(x.get('item_code') or '')))
    return out[offset:offset+limit]


def _cost_state_pairs_for_txn(txn: dict):
    pairs = set()
    try:
        item_id = int(txn.get('item_id') or 0)
    except Exception:
        item_id = 0
    if item_id <= 0:
        return pairs
    for key in ('wh_from_id', 'wh_to_id'):
        try:
            wh_id = int(txn.get(key) or 0)
        except Exception:
            wh_id = 0
        if wh_id > 0:
            pairs.add((wh_id, item_id))
    return pairs


def _cost_state_clear(conn):
    try:
        conn.execute('DELETE FROM WarehouseCostState')
    except Exception:
        pass


def _cost_state_get_row(conn, wh_id: int, item_id: int):
    row = conn.execute(
        'SELECT qty, val, avg_cost, last_txn_ts, last_txn_id FROM WarehouseCostState WHERE wh_id=? AND item_id=? LIMIT 1',
        (int(wh_id), int(item_id))
    ).fetchone()
    if not row:
        return {'qty': 0.0, 'val': 0.0, 'avg_cost': 0.0, 'last_txn_ts': '', 'last_txn_id': 0}
    return {
        'qty': float((row[0] if not isinstance(row, sqlite3.Row) else row['qty']) or 0.0),
        'val': float((row[1] if not isinstance(row, sqlite3.Row) else row['val']) or 0.0),
        'avg_cost': float((row[2] if not isinstance(row, sqlite3.Row) else row['avg_cost']) or 0.0),
        'last_txn_ts': str((row[3] if not isinstance(row, sqlite3.Row) else row['last_txn_ts']) or ''),
        'last_txn_id': int((row[4] if not isinstance(row, sqlite3.Row) else row['last_txn_id']) or 0),
    }


def _cost_state_upsert(conn, wh_id: int, item_id: int, qty: float, val: float, last_txn_ts: str = '', last_txn_id: int | None = None):
    qty = float(qty or 0.0)
    val = float(val or 0.0)
    avg = (val / qty) if abs(qty) > 1e-12 else 0.0
    conn.execute(
        '''
        INSERT INTO WarehouseCostState(wh_id,item_id,qty,val,avg_cost,last_txn_ts,last_txn_id,rebuilt_at)
        VALUES (?,?,?,?,?,?,?,?)
        ON CONFLICT(wh_id,item_id) DO UPDATE SET
          qty=excluded.qty,
          val=excluded.val,
          avg_cost=excluded.avg_cost,
          last_txn_ts=excluded.last_txn_ts,
          last_txn_id=excluded.last_txn_id,
          rebuilt_at=excluded.rebuilt_at
        ''',
        (int(wh_id), int(item_id), qty, val, avg, (last_txn_ts or ''), int(last_txn_id or 0), _now().isoformat(timespec='seconds'))
    )


def _cost_state_last_order_ok(conn, wh_id: int, item_id: int, ts: str, txn_id: int | None = None) -> bool:
    st = _cost_state_get_row(conn, wh_id, item_id)
    last_ts = st.get('last_txn_ts') or ''
    last_id = int(st.get('last_txn_id') or 0)
    cur_id = int(txn_id or 0)
    cur_ts = str(ts or '')
    if not last_ts:
        return True
    return (cur_ts, cur_id) >= (last_ts, last_id)


def _cost_state_apply_add_txn(conn, txn: dict) -> bool:
    try:
        txn_type = str(txn.get('txn_type') or '').upper().strip()
        item_id = int(txn.get('item_id') or 0)
        qty = float(txn.get('qty') or 0.0)
        ts = str(txn.get('ts') or '')
        txn_id = int(txn.get('id') or 0)
        unit_price = float(txn.get('unit_price') or 0.0)
    except Exception:
        return False
    if item_id <= 0 or qty <= 0 or txn_type not in ('RECEIVE', 'ISSUE', 'TRANSFER'):
        return False
    pairs = _cost_state_pairs_for_txn(txn)
    if not pairs:
        return False
    for wh_id, _ in pairs:
        if not _cost_state_last_order_ok(conn, wh_id, item_id, ts, txn_id):
            return False

    def _load(wh_id):
        return _cost_state_get_row(conn, wh_id, item_id)

    if txn_type == 'RECEIVE':
        wh_to = int(txn.get('wh_to_id') or 0)
        if wh_to <= 0:
            return False
        st = _load(wh_to)
        new_qty = st['qty'] + qty
        new_val = st['val'] + (qty * max(0.0, unit_price))
        _cost_state_upsert(conn, wh_to, item_id, new_qty, new_val, ts, txn_id)
        return True

    if txn_type == 'ISSUE':
        wh_from = int(txn.get('wh_from_id') or 0)
        if wh_from <= 0:
            return False
        st = _load(wh_from)
        avg = (st['val'] / st['qty']) if abs(st['qty']) > 1e-12 else 0.0
        new_qty = st['qty'] - qty
        new_val = st['val'] - (qty * avg)
        _cost_state_upsert(conn, wh_from, item_id, new_qty, new_val, ts, txn_id)
        return True

    if txn_type == 'TRANSFER':
        wh_from = int(txn.get('wh_from_id') or 0)
        wh_to = int(txn.get('wh_to_id') or 0)
        if wh_from <= 0 or wh_to <= 0:
            return False
        st_from = _load(wh_from)
        avg = (st_from['val'] / st_from['qty']) if abs(st_from['qty']) > 1e-12 else 0.0
        new_from_qty = st_from['qty'] - qty
        new_from_val = st_from['val'] - (qty * avg)
        _cost_state_upsert(conn, wh_from, item_id, new_from_qty, new_from_val, ts, txn_id)
        st_to = _load(wh_to)
        in_cost = unit_price if unit_price > 0 else avg
        new_to_qty = st_to['qty'] + qty
        new_to_val = st_to['val'] + (qty * in_cost)
        _cost_state_upsert(conn, wh_to, item_id, new_to_qty, new_to_val, ts, txn_id)
        return True
    return False


def _cost_state_recompute_pair(conn, wh_id: int, item_id: int, *, exclude_txn_id: int | None = None):
    wh_id = int(wh_id)
    item_id = int(item_id)
    qty_state = 0.0
    val_state = 0.0
    last_ts = ''
    last_txn_id = 0
    rows = conn.execute(
        '''
        SELECT id, ts, txn_type, qty, unit_price, wh_from_id, wh_to_id
        FROM Transactions
        WHERE voided=0 AND item_id=? AND (wh_from_id=? OR wh_to_id=?)
        ORDER BY ts ASC, id ASC
        ''',
        (item_id, wh_id, wh_id)
    ).fetchall()
    for row in rows:
        rid = int(row[0] if not isinstance(row, sqlite3.Row) else row['id'])
        if exclude_txn_id is not None and rid == int(exclude_txn_id):
            continue
        ts = str(row[1] if not isinstance(row, sqlite3.Row) else row['ts'] or '')
        txn_type = str(row[2] if not isinstance(row, sqlite3.Row) else row['txn_type'] or '').upper()
        qty = float(row[3] if not isinstance(row, sqlite3.Row) else row['qty'] or 0.0)
        unit_price = float((row[4] if not isinstance(row, sqlite3.Row) else row['unit_price']) or 0.0)
        wh_from_id = int((row[5] if not isinstance(row, sqlite3.Row) else row['wh_from_id']) or 0)
        wh_to_id = int((row[6] if not isinstance(row, sqlite3.Row) else row['wh_to_id']) or 0)
        if qty <= 0:
            continue
        if txn_type == 'RECEIVE' and wh_to_id == wh_id:
            qty_state += qty
            val_state += qty * max(0.0, unit_price)
        elif txn_type == 'ISSUE' and wh_from_id == wh_id:
            avg = (val_state / qty_state) if abs(qty_state) > 1e-12 else 0.0
            qty_state -= qty
            val_state -= qty * avg
        elif txn_type == 'TRANSFER':
            if wh_from_id == wh_id:
                avg = (val_state / qty_state) if abs(qty_state) > 1e-12 else 0.0
                qty_state -= qty
                val_state -= qty * avg
            if wh_to_id == wh_id:
                qty_state += qty
                val_state += qty * max(0.0, unit_price)
        last_ts = ts
        last_txn_id = rid
    _cost_state_upsert(conn, wh_id, item_id, qty_state, val_state, last_ts, last_txn_id)
    return (val_state / qty_state) if abs(qty_state) > 1e-12 else 0.0


def _cost_state_recompute_pairs(conn, pairs, *, exclude_txn_id: int | None = None):
    seen = set()
    for wh_id, item_id in (pairs or set()):
        try:
            key = (int(wh_id), int(item_id))
        except Exception:
            continue
        if key in seen or key[0] <= 0 or key[1] <= 0:
            continue
        seen.add(key)
        _cost_state_recompute_pair(conn, key[0], key[1], exclude_txn_id=exclude_txn_id)


def _cost_state_get_avg_cost(conn, wh_id: int | None, item_id: int, *, allow_recompute: bool = True):
    if not wh_id:
        return None
    wh_id = int(wh_id)
    item_id = int(item_id)
    try:
        row = conn.execute('SELECT avg_cost FROM WarehouseCostState WHERE wh_id=? AND item_id=? LIMIT 1', (wh_id, item_id)).fetchone()
    except Exception:
        row = None
    if row is None and allow_recompute:
        avg = _cost_state_recompute_pair(conn, wh_id, item_id)
        return float(avg or 0.0) if float(avg or 0.0) > 0 else None
    if row is None:
        return None
    try:
        avg = float((row[0] if not isinstance(row, sqlite3.Row) else row['avg_cost']) or 0.0)
    except Exception:
        avg = 0.0
    if avg <= 0 and allow_recompute:
        avg = float(_cost_state_recompute_pair(conn, wh_id, item_id) or 0.0)
    return avg if avg > 0 else None


def _rebuild_cost_state_from_snapshot(conn, rebuilt_at: str = ''):
    _cost_state_clear(conn)
    item_map = {str(r['item_code'] or ''): int(r['id']) for r in conn.execute('SELECT id, item_code FROM Items').fetchall()}
    wh_map = {str(r['wh_code'] or ''): int(r['id']) for r in conn.execute('SELECT id, wh_code FROM Warehouses').fetchall()}
    rows = conn.execute('SELECT item_code, wh_code, balance, value, avg_cost FROM BalancesSnapshot').fetchall()
    for r in rows:
        item_id = item_map.get(str(r['item_code'] or ''))
        wh_id = wh_map.get(str(r['wh_code'] or ''))
        if not item_id or not wh_id:
            continue
        qty = float(r['balance'] or 0.0)
        val = float(r['value'] or 0.0)
        avg = float(r['avg_cost'] or 0.0)
        conn.execute(
            'INSERT OR REPLACE INTO WarehouseCostState(wh_id,item_id,qty,val,avg_cost,last_txn_ts,last_txn_id,rebuilt_at) VALUES (?,?,?,?,?,?,?,?)',
            (int(wh_id), int(item_id), qty, val, avg, '', 0, rebuilt_at or _now().isoformat(timespec='seconds'))
        )


def get_sync_status_payload(username='system', auto_kick: bool = False):
    info = None
    try:
        info = get_balances_snapshot_info()
    except Exception:
        info = None
    try:
        dirty = stockcache_is_dirty()
    except Exception:
        dirty = False
    try:
        running = bool(_STOCKCACHE_STATE.get('running'))
    except Exception:
        running = False
    try:
        generation = stockcache_generation()
    except Exception:
        generation = 0
    try:
        built_generation = stockcache_built_generation()
    except Exception:
        built_generation = -1
    if auto_kick and dirty:
        try:
            ensure_stockcache_async(username=username or 'system')
        except Exception:
            pass
    mode = 'synced'
    if dirty and running:
        mode = 'rebuilding'
    elif dirty:
        mode = 'pending'
    snapshot_rows = 0
    rebuilt_at = ''
    rebuilt_by = ''
    if info:
        snapshot_rows = int(info.get('rows_count') or 0)
        rebuilt_at = str(info.get('rebuilt_at') or '')
        rebuilt_by = str(info.get('rebuilt_by') or '')
    return {
        'mode': mode,
        'dirty': bool(dirty),
        'running': bool(running),
        'generation': int(generation),
        'built_generation': int(built_generation),
        'snapshot_rows': int(snapshot_rows),
        'rebuilt_at': rebuilt_at,
        'rebuilt_by': rebuilt_by,
    }


def render_sync_status_card(lang, username='system', *, auto_kick: bool = False, compact: bool = False):
    st = get_sync_status_payload(username=username or 'system', auto_kick=auto_kick)
    is_ar = (lang or 'en').lower().startswith('ar')
    if st['mode'] == 'synced':
        title = '✅ حالة مزامنة الأرصدة: مستقرة' if is_ar else '✅ Balance sync status: stable'
        msg = 'الأرصدة المعروضة حالياً متزامنة مع آخر كاش معتمد.' if is_ar else 'Displayed balances are synchronized with the latest verified cache.'
        color = '#16a34a'
    elif st['mode'] == 'rebuilding':
        title = '⏳ حالة مزامنة الأرصدة: جارٍ التحديث' if is_ar else '⏳ Balance sync status: rebuilding'
        msg = 'تم حفظ الحركات، ويجري الآن تحديث كاش الأرصدة في الخلفية. قد يظهر آخر كاش معتمد مؤقتاً.' if is_ar else 'Transactions were saved and the balance cache is rebuilding in the background. The last verified cache may be shown temporarily.'
        color = '#f59e0b'
    else:
        title = '⚠️ حالة مزامنة الأرصدة: بانتظار التحديث' if is_ar else '⚠️ Balance sync status: pending refresh'
        msg = 'تم حفظ الحركات لكن كاش الأرصدة ما زال بانتظار إعادة البناء. سيتم تشغيل التحديث تلقائياً.' if is_ar else 'Transactions were saved but the balance cache is still pending rebuild. Refresh will be triggered automatically.'
        color = '#dc2626'
    meta = []
    if st.get('rebuilt_at'):
        meta.append(('آخر إعادة بناء' if is_ar else 'Last rebuild') + ': ' + html_escape(st['rebuilt_at']))
    if st.get('snapshot_rows'):
        meta.append(('صفوف الكاش' if is_ar else 'Snapshot rows') + f": {int(st['snapshot_rows'])}")
    meta.append(('Generation' if not is_ar else 'الجيل') + f": {int(st['built_generation'])}/{int(st['generation'])}")
    meta_html = '' if compact else '<div class="small muted" style="margin-top:6px">' + ' &nbsp; | &nbsp; '.join(meta) + '</div>'
    return f'<div class="card no-print" style="border-right:4px solid {color};margin-bottom:12px"><div style="font-weight:700">{html_escape(title)}</div><div class="small" style="margin-top:6px">{html_escape(msg)}</div>{meta_html}</div>'


def save_balances_snapshot_xlsx(rebuilt_at_iso, username, role=None, ip=None):
    """Save balances snapshot to server-side backups folder as an Excel file.
    This is in addition to browser download (for governance / audit).
    Returns full path of saved file or None if saving failed (best-effort).
    """
    try:
        os.makedirs(os.path.join(BASE_DIR, "backups"), exist_ok=True)
        ts = (rebuilt_at_iso or _now().isoformat(timespec="seconds")).replace(":", "").replace("-", "").replace("T", "_")
        fname = f"balances_snapshot_{ts}.xlsx"
        fpath = os.path.join(BASE_DIR, "backups", fname)
        # build xlsx bytes from snapshot table
        xbytes = export_view_as_xlsx("balances_snapshot", {})
        _safe_write_file_atomic(fpath, xbytes)
        # audit (best effort)
        audit_log(username, action="SAVE_SNAPSHOT_XLSX", entity="BalancesSnapshot", entity_id=fname,
                  details=f"saved_to={fpath}", ip=ip, role=(role if 'role' in locals() else '') )
        return fpath
    except Exception:
        return None

def _build_balances_snapshot_rows_exact(con):
    """Accounting-first balances snapshot.

    Computes ending balance and warehouse-level moving-average cost exactly by replaying
    non-voided RECEIVE / ISSUE / TRANSFER transactions in chronological order.
    TRANSFER carries source warehouse cost into destination warehouse.
    """
    item_rows = con.execute(
        "SELECT id, item_code, item_name, unit, COALESCE(min_qty,0) AS min_qty, COALESCE(default_unit_price,0) AS default_unit_price, COALESCE(active,1) AS active FROM Items"
    ).fetchall()
    wh_rows = con.execute(
        "SELECT id, wh_code, wh_name, COALESCE(active,1) AS active FROM Warehouses"
    ).fetchall()
    supplier_rows = con.execute(
        "SELECT id, supplier_name FROM Suppliers"
    ).fetchall()

    items = {int(r["id"]): dict(r) for r in item_rows}
    warehouses = {int(r["id"]): dict(r) for r in wh_rows}
    suppliers = {int(r["id"]): (r["supplier_name"] or "") for r in supplier_rows}

    state = {}  # (wh_id, item_id) -> {"qty": float, "val": float}
    last_recv = {}  # (wh_id, item_id) -> {"supplier_name": str, "last_date": str}

    rows = con.execute(
        """
        SELECT id, ts, txn_type, item_id, qty, unit_price, wh_from_id, wh_to_id, supplier_id
        FROM Transactions
        WHERE voided=0 AND txn_type IN ('RECEIVE','ISSUE','TRANSFER')
        ORDER BY ts ASC, id ASC
        """
    ).fetchall()

    def _get_state(wh_id, item_id):
        key = (int(wh_id), int(item_id))
        st = state.get(key)
        if not st:
            st = {"qty": 0.0, "val": 0.0}
            state[key] = st
        return st

    def _add_stock(wh_id, item_id, qty, unit_cost):
        if not wh_id or not item_id:
            return
        st = _get_state(wh_id, item_id)
        q = float(qty or 0.0)
        uc = float(unit_cost or 0.0)
        if q <= 0:
            return
        st["qty"] += q
        st["val"] += (q * uc)

    def _remove_stock(wh_id, item_id, qty):
        if not wh_id or not item_id:
            return 0.0
        st = _get_state(wh_id, item_id)
        q_req = float(qty or 0.0)
        if q_req <= 0:
            return 0.0
        q_have = float(st.get("qty") or 0.0)
        v_have = float(st.get("val") or 0.0)
        unit_cost = (v_have / q_have) if q_have > 1e-12 else 0.0
        st["qty"] = q_have - q_req
        st["val"] = v_have - (q_req * unit_cost)
        return unit_cost

    for r in rows:
        txn_type = str(r["txn_type"] or "").upper().strip()
        item_id = int(r["item_id"]) if r["item_id"] is not None else 0
        qty = float(r["qty"] or 0.0)
        if item_id <= 0 or qty <= 0:
            continue

        if txn_type == "RECEIVE":
            wh_to = r["wh_to_id"]
            if not wh_to:
                continue
            price = float(r["unit_price"] or 0.0)
            if price <= 0:
                item_meta = items.get(item_id) or {}
                price = float(item_meta.get("default_unit_price") or 0.0)
            _add_stock(wh_to, item_id, qty, price)
            last_recv[(int(wh_to), item_id)] = {
                "supplier_name": suppliers.get(int(r["supplier_id"])) if r["supplier_id"] is not None else "",
                "last_date": str(r["ts"] or "")[:10],
            }

        elif txn_type == "ISSUE":
            wh_from = r["wh_from_id"]
            if not wh_from:
                continue
            _remove_stock(wh_from, item_id, qty)

        elif txn_type == "TRANSFER":
            wh_from = r["wh_from_id"]
            wh_to = r["wh_to_id"]
            if not wh_from or not wh_to:
                continue
            unit_cost = _remove_stock(wh_from, item_id, qty)
            _add_stock(wh_to, item_id, qty, unit_cost)

    out = []
    negatives = []
    for (wh_id, item_id), st in state.items():
        item = items.get(int(item_id))
        wh = warehouses.get(int(wh_id))
        if not item or not wh:
            continue
        if int(item.get("active") or 0) != 1 or int(wh.get("active") or 0) != 1:
            continue
        qty = round(float(st.get("qty") or 0.0), 3)
        val = round(float(st.get("val") or 0.0), 2)
        avg_cost = round((val / qty), 4) if qty > 1e-12 else 0.0
        if qty < -1e-9:
            negatives.append({
                "item_code": item.get("item_code") or "",
                "wh_code": wh.get("wh_code") or "",
                "balance": qty,
            })
        meta = last_recv.get((int(wh_id), int(item_id)), {})
        out.append({
            "item_code": item.get("item_code") or "",
            "item_name": item.get("item_name") or "",
            "unit": item.get("unit") or "",
            "min_qty": float(item.get("min_qty") or 0.0),
            "wh_code": wh.get("wh_code") or "",
            "wh_name": wh.get("wh_name") or "",
            "balance": qty,
            "avg_cost": avg_cost,
            "value": val,
            "last_supplier": meta.get("supplier_name") or "",
            "last_date": meta.get("last_date") or "",
        })

    out.sort(key=lambda x: ((x.get("item_code") or ""), (x.get("wh_code") or "")))
    return out, negatives

def rebuild_balances_snapshot(username, role=None, ip=None):
    """Rebuild balances snapshot table from Transactions using exact warehouse moving average."""
    con = db_connect()
    try:
        integrity = ""
        fk_issues = 0
        try:
            integrity = con.execute("PRAGMA integrity_check;").fetchone()[0]
        except Exception:
            integrity = ""
        try:
            fk_issues = len(con.execute("PRAGMA foreign_key_check;").fetchall())
        except Exception:
            fk_issues = 0

        rebuilt_at = _now().isoformat(timespec="seconds")
        rows_data, neg_list = _build_balances_snapshot_rows_exact(con)

        con.execute("BEGIN IMMEDIATE;")
        con.execute("DELETE FROM BalancesSnapshot;")
        if rows_data:
            con.executemany(
                """
                INSERT INTO BalancesSnapshot(
                    item_code,item_name,unit,min_qty,wh_code,wh_name,balance,avg_cost,value,last_supplier,last_date,rebuilt_at,rebuilt_by
                ) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?)
                """,
                [
                    (
                        r["item_code"], r["item_name"], r["unit"], r["min_qty"], r["wh_code"], r["wh_name"],
                        r["balance"], r["avg_cost"], r["value"], r["last_supplier"], r["last_date"],
                        rebuilt_at, username
                    )
                    for r in rows_data
                ]
            )

        rows_count = len(rows_data)
        con.execute(
            "INSERT INTO BalancesSnapshotInfo(id,rebuilt_at,rebuilt_by,rows_count) VALUES (1,?,?,?) "
            "ON CONFLICT(id) DO UPDATE SET rebuilt_at=excluded.rebuilt_at, rebuilt_by=excluded.rebuilt_by, rows_count=excluded.rows_count",
            (rebuilt_at, username, rows_count),
        )
        _rebuild_cost_state_from_snapshot(con, rebuilt_at=rebuilt_at)
        con.commit()

        audit_log(username, action="REBUILD_BALANCES", entity="BalancesSnapshot", entity_id=str(rows_count),
                  details=f"rebuilt_at={rebuilt_at} integrity={integrity} fk_issues={fk_issues} neg={len(neg_list)} method=exact_wh_mavg",
                  ip=ip, role=role)

        saved_xlsx = save_balances_snapshot_xlsx(rebuilt_at, username, role=role, ip=ip)

        return {
            "rebuilt_at": rebuilt_at,
            "rows_count": rows_count,
            "integrity": integrity,
            "fk_issues": fk_issues,
            "negative_balances": neg_list[:50],
            "saved_xlsx": saved_xlsx,
            "method": "exact_wh_mavg",
        }
    finally:
        try:
            con.close()
        except Exception:
            pass

# BalancesSnapshot acts as materialized cache for balances (fast open even with 300k txns).
# Phase 5 hardening:
# - serialize mutating writes so the snapshot always represents a stable commit boundary
# - track generations to prevent a stale worker from clearing the dirty flag after a newer write
# - expose wait/sync helpers for tests and admin diagnostics
_STOCKCACHE_STATE = {
    "dirty": True,
    "running": False,
    "last_try": 0.0,
    "last_success": 0.0,
    "last_duration": 0.0,
    "last_error": "",
    "generation": 0,
    "built_generation": -1,
    "requested_by": "system",
}
_STOCKCACHE_LOCK = threading.Lock()
_STOCKCACHE_COND = threading.Condition(_STOCKCACHE_LOCK)
_TXN_WRITE_LOCK = threading.RLock()

# Warehouse moving-average cache (safe acceleration)
# - keyed by stockcache generation so any write/rebuild invalidates old entries
# - only caches the common add-flow (exclude_txn_id is None)
# - keeps behavior identical while removing repeated full-history scans for the same item/warehouse
_AVG_COST_CACHE = {}
_AVG_COST_CACHE_META = {"generation": -1}
_AVG_COST_CACHE_LOCK = threading.Lock()

def _avg_cost_cache_get(wh_id: int, item_id: int):
    gen = stockcache_generation()
    key = (int(wh_id), int(item_id))
    with _AVG_COST_CACHE_LOCK:
        if int(_AVG_COST_CACHE_META.get("generation", -1) or -1) != gen:
            _AVG_COST_CACHE.clear()
            _AVG_COST_CACHE_META["generation"] = gen
            return None
        return _AVG_COST_CACHE.get(key)

def _avg_cost_cache_set(wh_id: int, item_id: int, value):
    gen = stockcache_generation()
    key = (int(wh_id), int(item_id))
    with _AVG_COST_CACHE_LOCK:
        if int(_AVG_COST_CACHE_META.get("generation", -1) or -1) != gen:
            _AVG_COST_CACHE.clear()
            _AVG_COST_CACHE_META["generation"] = gen
        _AVG_COST_CACHE[key] = value
        # soft cap to avoid unbounded growth on very large data sets
        if len(_AVG_COST_CACHE) > 20000:
            for i, k in enumerate(list(_AVG_COST_CACHE.keys())):
                del _AVG_COST_CACHE[k]
                if i >= 4999:
                    break


def mark_stockcache_dirty(reason: str = "txn_write", username: str = "system"):
    with _STOCKCACHE_COND:
        _STOCKCACHE_STATE["dirty"] = True
        _STOCKCACHE_STATE["generation"] = int(_STOCKCACHE_STATE.get("generation", 0) or 0) + 1
        _STOCKCACHE_STATE["requested_by"] = username or "system"
        _STOCKCACHE_COND.notify_all()
        return int(_STOCKCACHE_STATE["generation"])

def stockcache_is_dirty() -> bool:
    with _STOCKCACHE_LOCK:
        return bool(_STOCKCACHE_STATE.get("dirty"))

def stockcache_generation() -> int:
    with _STOCKCACHE_LOCK:
        return int(_STOCKCACHE_STATE.get("generation", 0) or 0)

def stockcache_built_generation() -> int:
    with _STOCKCACHE_LOCK:
        return int(_STOCKCACHE_STATE.get("built_generation", -1) or -1)

def wait_for_stockcache(timeout: float = 30.0) -> bool:
    deadline = time.time() + max(0.1, float(timeout or 0.0))
    with _STOCKCACHE_COND:
        while bool(_STOCKCACHE_STATE.get("dirty")) or bool(_STOCKCACHE_STATE.get("running")):
            remaining = deadline - time.time()
            if remaining <= 0:
                return False
            _STOCKCACHE_COND.wait(min(0.5, remaining))
        return True

def rebuild_stockcache_sync(username="system"):
    target_generation = stockcache_generation()
    with _TXN_WRITE_LOCK:
        started = time.time()
        report = rebuild_balances_snapshot(username=username, role="SYSTEM", ip="127.0.0.1")
    with _STOCKCACHE_COND:
        current_generation = int(_STOCKCACHE_STATE.get("generation", 0) or 0)
        _STOCKCACHE_STATE["running"] = False
        _STOCKCACHE_STATE["last_try"] = started
        _STOCKCACHE_STATE["last_success"] = time.time()
        _STOCKCACHE_STATE["last_duration"] = round(_STOCKCACHE_STATE["last_success"] - started, 4)
        _STOCKCACHE_STATE["last_error"] = ""
        _STOCKCACHE_STATE["built_generation"] = max(target_generation, int(_STOCKCACHE_STATE.get("built_generation", -1) or -1))
        _STOCKCACHE_STATE["dirty"] = current_generation > int(_STOCKCACHE_STATE.get("built_generation", -1) or -1)
        _STOCKCACHE_COND.notify_all()
    return report

def _stockcache_worker(username="system"):
    # best-effort background rebuild; never raises
    try:
        with _STOCKCACHE_COND:
            _STOCKCACHE_STATE["running"] = True
            _STOCKCACHE_STATE["last_try"] = time.time()
            target_generation = int(_STOCKCACHE_STATE.get("generation", 0) or 0)
            _STOCKCACHE_STATE["requested_by"] = username or "system"
            _STOCKCACHE_COND.notify_all()
        started = time.time()
        with _TXN_WRITE_LOCK:
            rebuild_balances_snapshot(username=username, role="SYSTEM", ip="127.0.0.1")
        with _STOCKCACHE_COND:
            _STOCKCACHE_STATE["last_success"] = time.time()
            _STOCKCACHE_STATE["last_duration"] = round(_STOCKCACHE_STATE["last_success"] - started, 4)
            _STOCKCACHE_STATE["last_error"] = ""
            _STOCKCACHE_STATE["built_generation"] = max(target_generation, int(_STOCKCACHE_STATE.get("built_generation", -1) or -1))
            current_generation = int(_STOCKCACHE_STATE.get("generation", 0) or 0)
            _STOCKCACHE_STATE["dirty"] = current_generation > int(_STOCKCACHE_STATE.get("built_generation", -1) or -1)
    except Exception as e:
        with _STOCKCACHE_COND:
            _STOCKCACHE_STATE["last_error"] = str(e)
        safe_log_exception("stockcache_worker", e, username=username, role="SYSTEM", ip="127.0.0.1")
    finally:
        with _STOCKCACHE_COND:
            _STOCKCACHE_STATE["running"] = False
            _STOCKCACHE_COND.notify_all()

def ensure_stockcache_async(username="system", force: bool = False):
    """Kick background rebuild if snapshot missing/dirty.
    This does NOT block page loads.
    """
    try:
        with _STOCKCACHE_COND:
            running = bool(_STOCKCACHE_STATE.get("running"))
            dirty = bool(_STOCKCACHE_STATE.get("dirty"))
            last_try = float(_STOCKCACHE_STATE.get("last_try", 0.0) or 0.0)
            if running or ((not dirty) and (not force)):
                return False
            # avoid tight loop unless forced
            if (not force) and (time.time() - last_try < 5):
                return False
            th = threading.Thread(target=_stockcache_worker, kwargs={"username": username}, daemon=True)
            th.start()
            return True
    except Exception:
        return False


def run_stock_engine_stress_test(username="system", loops: int = 25, timeout: float = 30.0):
    """Lightweight internal stress helper for phase 5 validation.
    It repeatedly dirties the cache, requests async rebuilds, then waits for consistency.
    Returns a compact dict for diagnostics/tests.
    """
    loops = max(1, min(int(loops or 1), 250))
    started = time.time()
    kicked = 0
    for i in range(loops):
        mark_stockcache_dirty(reason=f"stress_{i+1}", username=username)
        kicked += 1 if ensure_stockcache_async(username=username, force=True) else 0
        if not wait_for_stockcache(timeout=timeout):
            return {
                "ok": False,
                "loops": loops,
                "kicked": kicked,
                "generation": stockcache_generation(),
                "built_generation": stockcache_built_generation(),
                "elapsed": round(time.time() - started, 4),
            }
    return {
        "ok": not stockcache_is_dirty(),
        "loops": loops,
        "kicked": kicked,
        "generation": stockcache_generation(),
        "built_generation": stockcache_built_generation(),
        "elapsed": round(time.time() - started, 4),
    }

def get_balances_snapshot_info():
    con = db_connect()
    try:
        r = con.execute("SELECT rebuilt_at, rebuilt_by, rows_count FROM BalancesSnapshotInfo WHERE id=1;").fetchone()
        return dict(r) if r else None
    finally:
        con.close()


