def _bal(con, item_id, wh_id):
    # Controlled balance source:
    # - fresh snapshot for stable read paths
    # - live aggregation whenever cache is dirty or we are inside an active mutation
    try:
        if (not _in_atomic_db()) and (not stockcache_is_dirty()):
            r = con.execute("""
                SELECT balance
                FROM BalancesSnapshot bs
                JOIN Items i ON i.item_code = bs.item_code
                JOIN Warehouses w ON w.wh_code = bs.wh_code
                WHERE i.id=? AND w.id=?
                LIMIT 1;
            """, (item_id, wh_id)).fetchone()
            if r is not None:
                return float((r[0] if not isinstance(r, sqlite3.Row) else r["balance"]) or 0.0)
    except Exception:
        pass
    q = """
    WITH base AS (
      SELECT t.item_id,
        CASE WHEN t.txn_type IN ('RECEIVE','TRANSFER') THEN t.wh_to_id END AS wh_in,
        CASE WHEN t.txn_type IN ('ISSUE','TRANSFER') THEN t.wh_from_id END AS wh_out,
        t.qty
      FROM Transactions t
      WHERE t.voided=0
    ),
    moved AS (
      SELECT item_id, wh_in AS wh_id, qty AS qty_in, 0.0 AS qty_out FROM base WHERE wh_in IS NOT NULL
      UNION ALL
      SELECT item_id, wh_out AS wh_id, 0.0 AS qty_in, qty AS qty_out FROM base WHERE wh_out IS NOT NULL
    )
    SELECT COALESCE(ROUND(SUM(qty_in-qty_out),3),0.0) AS balance
    FROM moved WHERE item_id=? AND wh_id=?;
    """
    r = con.execute(q, (item_id, wh_id)).fetchone()
    return float(r["balance"] or 0.0)

def _out_effect(txn, wh_id):
    if int(txn.get("voided",0))==1:
        return 0.0
    if txn["txn_type"]=="ISSUE" and txn.get("wh_from_id")==wh_id:
        return float(txn["qty"])
    if txn["txn_type"]=="TRANSFER" and txn.get("wh_from_id")==wh_id:
        return float(txn["qty"])
    return 0.0

def ensure_stock_available_for_change(old_txn: dict, new_txn: dict, *, con=None):
    own = con is None
    con = con or db_connect()
    try:
        checks=[]
        if new_txn["txn_type"] in ("ISSUE","TRANSFER") and new_txn.get("wh_from_id"):
            checks.append((new_txn["item_id"], new_txn["wh_from_id"]))
        for item_id, wh_id in checks:
            current = _bal(con, item_id, wh_id)
            refund = 0.0
            if old_txn and old_txn.get("item_id")==item_id:
                refund = _out_effect(old_txn, wh_id)
            need = _out_effect(new_txn, wh_id)
            available = current + refund
            if available + 1e-9 < need:
                return False, available
        return True, None
    finally:
        if own:
            con.close()

# ---------------- Transactions ----------------
def validate_txn(lang, txn_type, item_code, qty, wh_from_code, wh_to_code, eq_code, supplier_code, project_code="", cost_allocation="", issue_type=""):
    txn_type = (txn_type or "").strip().upper()
    item_id = get_item_id(item_code, active_only=False)
    if not item_id:
        raise ValueError(t(lang, "not_found_item"))
    if not get_item_id(item_code, active_only=True):
        raise ValueError("❌ الصنف غير نشط ولا يمكن استخدامه في الحركات")
    qty = float(qty or 0)
    if qty <= 0:
        raise ValueError(t(lang, "qty_gt0"))

    wh_from_id = get_wh_id(wh_from_code, active_only=False) if (wh_from_code or "").strip() else None
    wh_to_id = get_wh_id(wh_to_code, active_only=False) if (wh_to_code or "").strip() else None
    eq_id = get_eq_id(eq_code, active_only=False) if (eq_code or "").strip() else None
    supplier_id = get_supplier_id(supplier_code, active_only=False) if (supplier_code or "").strip() else None
    project_id = get_project_id(project_code, active_only=False) if (project_code or "").strip() else None

    if (wh_from_code or "").strip() and not wh_from_id:
        raise ValueError(t(lang, "not_found_wh"))
    if (wh_to_code or "").strip() and not wh_to_id:
        raise ValueError(t(lang, "not_found_wh"))
    if (eq_code or "").strip() and not eq_id:
        raise ValueError(t(lang, "not_found_eq"))
    if (supplier_code or "").strip() and not supplier_id:
        raise ValueError(t(lang, "not_found_supplier"))
    if (project_code or "").strip() and not project_id:
        raise ValueError("❌ كود المشروع غير موجود")

    if (wh_from_code or "").strip() and not get_wh_id(wh_from_code, active_only=True):
        raise ValueError("❌ المستودع غير نشط ولا يمكن استخدامه")
    if (wh_to_code or "").strip() and not get_wh_id(wh_to_code, active_only=True):
        raise ValueError("❌ المستودع غير نشط ولا يمكن استخدامه")
    if (eq_code or "").strip() and not get_eq_id(eq_code, active_only=True):
        raise ValueError("❌ المعدة غير نشطة ولا يمكن استخدامها")
    if (supplier_code or "").strip() and not get_supplier_id(supplier_code, active_only=True):
        raise ValueError("❌ المورد غير نشط ولا يمكن استخدامه")
    if (project_code or "").strip() and not get_project_id(project_code, active_only=True):
        raise ValueError("❌ المشروع غير نشط ولا يمكن استخدامه")

    if txn_type == "RECEIVE":
        if not wh_to_id:
            raise ValueError(t(lang, "need_to"))
        wh_from_id = None
    elif txn_type == "ISSUE":
        if not wh_from_id:
            raise ValueError(t(lang, "need_from"))
        if not eq_id:
            raise ValueError("❌ كود المعدة مطلوب في الصرف")
        alloc = (cost_allocation or "").strip().upper()
        if alloc == "PROJECT" and not project_id:
            raise ValueError("❌ يجب تحديد مشروع عند تحميل التكلفة على مشروع")
        wh_to_id = None
    elif txn_type == "TRANSFER":
        if not wh_from_id or not wh_to_id:
            raise ValueError(t(lang, "need_both"))
        if wh_from_id == wh_to_id:
            raise ValueError(t(lang, "same_wh"))
    else:
        raise ValueError(t(lang, "invalid_type"))

    return dict(
        txn_type=txn_type, item_id=item_id, qty=qty,
        wh_from_id=wh_from_id, wh_to_id=wh_to_id,
        eq_id=eq_id, supplier_id=supplier_id, project_id=project_id,
        issue_type=(issue_type or "").strip().upper() or None,
        cost_allocation=(cost_allocation or "").strip().upper() or None
    )

def get_txn(txn_id):
    con = db_connect()
    r = con.execute("SELECT * FROM Transactions WHERE id=?", (int(txn_id),)).fetchone()
    con.close()
    return dict(r) if r else None

def add_txn(  # LEGACY_TXN_HELPER_COMPAT
lang, username, txn_type, txn_date, item_code, qty, scrap_qty, unit_price, wh_from, wh_to, eq_code, supplier_code, req_no, po_no, doc_no, notes):
    """Compatibility shim: route old callers through the unified TxnService engine."""
    svc = get_container().txn_service
    payload, base = svc._validate_form(form={
        "txn_type": [txn_type],
        "txn_date": [txn_date],
        "item_code": [item_code],
        "qty": [qty],
        "scrap_qty": [scrap_qty],
        "unit_price": [unit_price],
        "wh_from": [wh_from],
        "wh_to": [wh_to],
        "eq_code": [eq_code],
        "supplier_code": [supplier_code],
        "project_code": [""],
        "issue_type": [""],
        "cost_allocation": [""],
        "req_no": [req_no],
        "po_no": [po_no],
        "doc_no": [doc_no],
        "notes": [notes],
    }, lang=lang)
    scrap_qty_val = svc._parse_scrap_qty(payload["txn_type"], payload["scrap_qty"])
    if scrap_qty_val - float(base["qty"]) > 1e-9:
        raise ValueError("scrap_qty cannot exceed qty")
    unit_price_val = svc._parse_unit_price(payload["unit_price"])
    ts = svc._build_txn_ts(payload["txn_date"])
    if base["txn_type"] in ("ISSUE", "TRANSFER"):
        ok, available = ensure_stock_available_for_change(
            old_txn={"voided": 1, "txn_type": "ISSUE", "item_id": base["item_id"], "wh_from_id": base["wh_from_id"], "qty": 0},
            new_txn={"voided": 0, **base},
        )
        if not ok:
            raise ValueError(t(lang, "insufficient", wh=payload["wh_from"], bal=available))
    def _db_work(conn):
        effective_unit_price = svc._resolve_effective_unit_price(
            conn,
            txn_type=base["txn_type"],
            item_id=base["item_id"],
            explicit_price=unit_price_val,
            wh_from_id=base.get("wh_from_id"),
        )
        return svc.txn_repo._insert_txn_conn(
            conn,
            ts=ts,
            base=base,
            scrap_qty_val=scrap_qty_val,
            unit_price_val=effective_unit_price,
            req_no=payload["req_no"],
            po_no=payload["po_no"],
            doc_no=payload["doc_no"],
            notes=payload["notes"],
            username=username,
        )
    def _audit(txn_id):
        audit_log(username, "ADD_TXN", entity="Transactions", entity_id=txn_id, details={
            "txn_type": base["txn_type"],
            "item_id": base["item_id"],
            "qty": base["qty"],
            "wh_from_id": base["wh_from_id"],
            "wh_to_id": base["wh_to_id"],
            "eq_id": base["eq_id"],
            "supplier_id": base["supplier_id"],
            "req_no": (payload["req_no"] or "").strip() or None,
            "po_no": (payload["po_no"] or "").strip() or None,
            "doc_no": (payload["doc_no"] or "").strip() or None,
        }, ip=None, role=None)
    return svc._run_write(db_work=_db_work, audit_work=_audit, username=username, role=None, ip=None, stock_tag="LEGACY_ADD_TXN_STOCKCACHE_REFRESH")

def update_txn(lang, txn_id, username, txn_type, item_code, qty, unit_price, wh_from, wh_to, eq_code, supplier_code, req_no, po_no, doc_no, notes, txn_date=None, scrap_qty=""):
    """Compatibility shim: route old callers through the unified TxnService engine."""
    svc = get_container().txn_service
    old = svc._load_txn_or_fail(int(txn_id), lang)
    svc._ensure_not_locked(old)
    if int(old.get("voided", 0) or 0) == 1:
        raise ValueError("Cannot edit voided txn")
    payload, base = svc._validate_form(form={
        "txn_type": [txn_type],
        "txn_date": [txn_date],
        "item_code": [item_code],
        "qty": [qty],
        "scrap_qty": [scrap_qty],
        "unit_price": [unit_price],
        "wh_from": [wh_from],
        "wh_to": [wh_to],
        "eq_code": [eq_code],
        "supplier_code": [supplier_code],
        "project_code": [""],
        "issue_type": [""],
        "cost_allocation": [""],
        "req_no": [req_no],
        "po_no": [po_no],
        "doc_no": [doc_no],
        "notes": [notes],
    }, lang=lang)
    scrap_qty_val = svc._parse_scrap_qty(payload["txn_type"], payload["scrap_qty"])
    if scrap_qty_val - float(base["qty"]) > 1e-9:
        raise ValueError("scrap_qty cannot exceed qty")
    unit_price_val = svc._parse_unit_price(payload["unit_price"])
    ok, available = ensure_stock_available_for_change(old_txn=old, new_txn={"voided": 0, **base})
    if not ok:
        raise ValueError(t(lang, "insufficient", wh=payload["wh_from"], bal=available))
    def _db_work(conn):
        effective_unit_price = svc._resolve_effective_unit_price(
            conn,
            txn_type=base["txn_type"],
            item_id=base["item_id"],
            explicit_price=unit_price_val,
            wh_from_id=base.get("wh_from_id"),
            exclude_txn_id=int(txn_id),
        )
        svc.txn_repo._update_txn_conn(
            conn,
            txn_id=int(txn_id),
            base=base,
            scrap_qty_val=scrap_qty_val,
            unit_price_val=effective_unit_price,
            req_no=payload["req_no"],
            po_no=payload["po_no"],
            doc_no=payload["doc_no"],
            notes=payload["notes"],
            username=username,
        )
        return int(txn_id)
    def _audit(_):
        audit_log(username, "UPDATE_TXN", entity="Transactions", entity_id=int(txn_id), details={
            "txn_type": base["txn_type"],
            "item_id": base["item_id"],
            "qty": base["qty"],
            "wh_from_id": base["wh_from_id"],
            "wh_to_id": base["wh_to_id"],
            "eq_id": base["eq_id"],
            "supplier_id": base["supplier_id"],
            "req_no": (payload["req_no"] or "").strip() or None,
            "po_no": (payload["po_no"] or "").strip() or None,
            "doc_no": (payload["doc_no"] or "").strip() or None,
        }, ip=None, role=None)
    return svc._run_write(db_work=_db_work, audit_work=_audit, username=username, role=None, ip=None, stock_tag="LEGACY_UPDATE_TXN_STOCKCACHE_REFRESH")


def void_txn(txn_id, reason="", username=None, ip=None, role=None):
    """Compatibility shim: route old callers through the unified TxnService engine.

    Also tolerates an older positional calling style:
        void_txn(txn_id, username, reason)
    by auto-detecting whether the 2nd arg looks like an existing username and
    the 3rd arg does not. If the resolved username does not exist, it falls
    back to the trusted system user for legacy/internal callers.
    """
    resolved_user = (username or "system")
    resolved_reason = (reason or "")
    try:
        con = db_connect()
        try:
            reason_is_user = bool(con.execute("SELECT 1 FROM Users WHERE username=? LIMIT 1", ((reason or "").strip(),)).fetchone())
            username_is_user = bool(con.execute("SELECT 1 FROM Users WHERE username=? LIMIT 1", ((username or "").strip(),)).fetchone())
            fallback_row = con.execute("SELECT username FROM Users WHERE active=1 AND UPPER(role) IN ('ADMIN','EDITOR') ORDER BY CASE WHEN UPPER(role)='ADMIN' THEN 0 ELSE 1 END, username LIMIT 1").fetchone()
        finally:
            con.close()
        if username is not None and role is None and ip is None and reason_is_user and not username_is_user:
            resolved_user = (reason or "")
            resolved_reason = (username or "")
        elif username and username_is_user:
            resolved_user = username
        elif reason and reason_is_user and not username:
            resolved_user = reason
        else:
            resolved_user = (fallback_row[0] if fallback_row and fallback_row[0] else "system")
    except Exception:
        pass
    svc = get_container().txn_service
    return svc.void(txn_id=int(txn_id), reason=resolved_reason, user=resolved_user, role=(role or "ADMIN"), ip=ip, lang="en")



def clear_all_transactions(  # LEGACY_TXN_HELPER_UNUSED_BY_ROUTER
username, role=None, ip=None):
    """Hard delete ALL transactions (dangerous). Admin only should call this."""
    con = db_connect()
    try:
        con.execute("BEGIN")
        con.execute("DELETE FROM Transactions")
        # reset autoincrement so IDs start from 1 again (optional)
        try:
            con.execute("DELETE FROM sqlite_sequence WHERE name='Transactions'")
        except Exception:
            pass
        # clear balances snapshot too
        try:
            con.execute("DELETE FROM BalancesSnapshot")
        except Exception:
            pass
        con.commit()
        try:
            mark_stockcache_dirty()
            ensure_stockcache_async(username=username)
        except Exception:
            pass

    except Exception:
        con.rollback()
        raise
    finally:
        con.close()

    try:
        audit_log("TXN_CLEAR_ALL", username, None, details=f"All transactions cleared by admin. ip={ip}")
    except Exception:
        pass

    # rebuild snapshot to be consistent (will be empty)
    try:
        rebuild_balances_snapshot(username=username, role=role, ip=ip)
    except Exception:
        pass




def _txn_filters(q_item="", q_eq="", q_supplier="", q_project="", q_req="", q_doc="", txn_type="", from_date="", to_date="", include_voided=False):
    q_item=(q_item or "").strip()
    q_eq=(q_eq or "").strip()
    q_supplier=(q_supplier or "").strip()
    q_project=(q_project or "").strip()
    txn_type=(txn_type or "").strip().upper()
    from_date=(from_date or "").strip()
    to_date=(to_date or "").strip()
    where=[]
    params=[]
    if not include_voided:
        where.append("t.voided=0")
    if txn_type in ("RECEIVE","ISSUE","TRANSFER"):
        where.append("t.txn_type=?")
        params.append(txn_type)
    ts_where, ts_params = _sqlite_ts_range(from_date, to_date, field="t.ts")
    if ts_where:
        where.append(ts_where)
        params.extend(ts_params)

    def _smart_code_or_name_filter(code_sql: str, name_sql: str, raw_value: str):
        raw_value = (raw_value or "").strip()
        if not raw_value:
            return None, []
        norm_value = normalize_code(raw_value)
        looks_like_code = bool(re.fullmatch(r"[A-Z0-9][A-Z0-9_./\- ]{1,}", norm_value or ""))
        if looks_like_code:
            return f"({code_sql} = ? OR {code_sql} LIKE ? OR {name_sql} LIKE ?)", [norm_value, f"{norm_value}%", f"%{raw_value}%"]
        like = f"%{raw_value}%"
        return f"({code_sql} LIKE ? OR {name_sql} LIKE ?)", [like, like]

    if q_item:
        sql, sql_params = _smart_code_or_name_filter("i.item_code", "i.item_name", q_item)
        where.append(sql)
        params.extend(sql_params)
    if q_eq:
        sql, sql_params = _smart_code_or_name_filter("e.eq_code", "e.eq_name", q_eq)
        where.append(sql)
        params.extend(sql_params)
    if q_supplier:
        sql, sql_params = _smart_code_or_name_filter("s.supplier_code", "s.supplier_name", q_supplier)
        where.append(sql)
        params.extend(sql_params)
    if q_project:
        sql, sql_params = _smart_code_or_name_filter("p.project_code", "p.project_name", q_project)
        where.append(sql)
        params.extend(sql_params)
    q_req = (q_req or "").strip()
    q_doc = (q_doc or "").strip()
    if q_req:
        where.append("COALESCE(t.req_no,\'\') LIKE ?")
        params.append(f"%{q_req}%")
    if q_doc:
        where.append("COALESCE(t.doc_no,\'\') LIKE ?")
        params.append(f"%{q_doc}%")

    where_sql=("WHERE "+" AND ".join(where)) if where else ""
    return where_sql, params


def list_txn(q_item="", q_eq="", q_supplier="", q_project="", q_req="", q_doc="", txn_type="", from_date="", to_date="", include_voided=False, limit=500, offset=0):
    where_sql, params = _txn_filters(
        q_item=q_item, q_eq=q_eq, q_supplier=q_supplier, q_project=q_project, q_req=q_req, q_doc=q_doc, txn_type=txn_type,
        from_date=from_date, to_date=to_date, include_voided=include_voided
    )
    con=db_connect()
    rows=con.execute(f"""
      SELECT
        t.id, t.ts, t.txn_type, t.qty, COALESCE(t.scrap_qty,0) AS scrap_qty, t.unit_price, t.req_no, t.po_no, t.doc_no, t.notes, t.username, t.attachment_path,
        t.voided, t.void_reason, t.issue_type, t.cost_allocation,
        i.item_code, i.item_name, i.unit,
        wf.wh_code AS wh_from_code, wt.wh_code AS wh_to_code,
        e.eq_code, e.eq_name,
        s.supplier_code, s.supplier_name,
        p.project_code, p.project_name
      FROM Transactions t
      JOIN Items i ON i.id=t.item_id
      LEFT JOIN Warehouses wf ON wf.id=t.wh_from_id
      LEFT JOIN Warehouses wt ON wt.id=t.wh_to_id
      LEFT JOIN Equipment e ON e.id=t.eq_id
      LEFT JOIN Suppliers s ON s.id=t.supplier_id
      LEFT JOIN Projects p ON p.id=t.project_id
      {where_sql}
      ORDER BY t.ts DESC, t.id DESC
      LIMIT ? OFFSET ?;
    """, (*params, int(limit), int(offset or 0))).fetchall()
    con.close()
    return [dict(r) for r in rows]


def count_txn(q_item="", q_eq="", q_supplier="", q_project="", q_req="", q_doc="", txn_type="", from_date="", to_date="", include_voided=False):
    where_sql, params = _txn_filters(
        q_item=q_item, q_eq=q_eq, q_supplier=q_supplier, q_project=q_project, q_req=q_req, q_doc=q_doc, txn_type=txn_type,
        from_date=from_date, to_date=to_date, include_voided=include_voided
    )
    con = db_connect()
    try:
        row = con.execute(f"""
          SELECT COUNT(*) AS n
          FROM Transactions t
          JOIN Items i ON i.id=t.item_id
          LEFT JOIN Equipment e ON e.id=t.eq_id
          LEFT JOIN Suppliers s ON s.id=t.supplier_id
          LEFT JOIN Projects p ON p.id=t.project_id
          {where_sql}
        """, tuple(params)).fetchone()
        return int((row[0] if row is not None else 0) or 0)
    finally:
        con.close()



def _txn_has_heavy_filters(q_item="", q_eq="", q_supplier="", q_req="", q_doc="", txn_type="", from_date="", to_date="") -> bool:
    return any(bool((v or "").strip()) for v in (q_item, q_eq, q_supplier, q_req, q_doc, txn_type, from_date, to_date))

def _txn_recommended_page_size(q_item="", q_eq="", q_supplier="", q_req="", q_doc="", txn_type="", from_date="", to_date="") -> int:
    """Safe default page size for /txn.
    - no filters: keep first page light
    - with filters: allow more rows because result set is usually narrower
    """
    if _txn_has_heavy_filters(q_item=q_item, q_eq=q_eq, q_supplier=q_supplier, q_req=q_req, q_doc=q_doc, txn_type=txn_type, from_date=from_date, to_date=to_date):
        return 1000
    return 300

def _txn_safe_page_size(requested: int | None, *, q_item="", q_eq="", q_supplier="", q_req="", q_doc="", txn_type="", from_date="", to_date="") -> int:
    base = _txn_recommended_page_size(q_item=q_item, q_eq=q_eq, q_supplier=q_supplier, q_req=q_req, q_doc=q_doc, txn_type=txn_type, from_date=from_date, to_date=to_date)
    try:
        val = int(requested or base)
    except Exception:
        val = base
    hard_max = 3000 if _txn_has_heavy_filters(q_item=q_item, q_eq=q_eq, q_supplier=q_supplier, q_req=q_req, q_doc=q_doc, txn_type=txn_type, from_date=from_date, to_date=to_date) else 1000
    return max(100, min(val, hard_max))

def _txn_safe_export_limit(q_item="", q_eq="", q_supplier="", q_req="", q_doc="", txn_type="", from_date="", to_date="") -> int:
    """Cap exports more aggressively when the user exports an unfiltered transaction history."""
    if _txn_has_heavy_filters(q_item=q_item, q_eq=q_eq, q_supplier=q_supplier, q_req=q_req, q_doc=q_doc, txn_type=txn_type, from_date=from_date, to_date=to_date):
        return 20000
    return 5000


# --------- Transaction Value (Moving Avg Cost) ---------
def _num(v, default=0.0):
    """Best-effort float coercion (handles commas and Arabic separators)."""
    try:
        if v is None:
            return float(default)
        if isinstance(v, (int, float)):
            return float(v)
        sv = str(v).strip()
        if not sv:
            return float(default)
        # normalize Arabic separators and thousands separators
        sv = sv.replace("٬", "").replace(",", "")
        sv = sv.replace("٫", ".")
        # keep only first valid number token
        m = re.search(r"[-+]?(?:\d+\.?\d*|\d*\.?\d+)", sv)
        if not m:
            return float(default)
        return float(m.group(0))
    except Exception:
        return float(default)

def compute_txn_value_map(txn_ids, from_date, to_date, txn_type_filter=""):
    """Return map: txn_id -> {'txn_value':..., 'unit_cost':...} using moving-average cost per (wh,item).
    - RECEIVE: value = qty * unit_price
    - ISSUE: value computed from moving avg of wh_from
    - TRANSFER: value computed from moving avg of wh_from (moves to wh_to at same unit cost)
    Notes:
      - Needs full history up to to_date to get correct avg cost.
    """
    try:
        ids_set = set(int(x) for x in (txn_ids or []) if str(x).isdigit())
    except Exception:
        ids_set = set()

    if not ids_set:
        return {}

    from_date = _parse_date_ymd(from_date, default="")
    to_date = _parse_date_ymd(to_date, default=_today_iso())
    tfilter = (txn_type_filter or "").strip().upper()

    con = db_connect()
    try:
        all_tx = [dict(r) for r in con.execute("""
            SELECT id, ts, txn_type, item_id, qty, unit_price, wh_from_id, wh_to_id, voided
            FROM Transactions
            WHERE voided=0 AND ts < ?
            ORDER BY ts ASC, id ASC
        """, (((datetime.strptime(to_date, "%Y-%m-%d") + timedelta(days=1)).strftime("%Y-%m-%d") + " 00:00:00"),)).fetchall()]
    finally:
        con.close()

    state = {}  # (wh_id,item_id) -> {'qty':float,'val':float}
    out = {}

    def _add_stock(wh_id, item_id, qty, unit_cost):
        if not wh_id or not item_id:
            return
        key = (int(wh_id), int(item_id))
        st = state.get(key) or {"qty": 0.0, "val": 0.0}
        q = float(qty or 0.0)
        uc = float(unit_cost or 0.0)
        st["qty"] += q
        st["val"] += q * uc
        state[key] = st

    def _avg_cost(wh_id, item_id):
        key = (int(wh_id), int(item_id))
        st = state.get(key) or {"qty": 0.0, "val": 0.0}
        q = float(st.get("qty") or 0.0)
        v = float(st.get("val") or 0.0)
        return (v / q) if q > 0 else 0.0

    def _remove_stock(wh_id, item_id, qty):
        if not wh_id or not item_id:
            return 0.0, 0.0
        key = (int(wh_id), int(item_id))
        st = state.get(key) or {"qty": 0.0, "val": 0.0}
        q_req = float(qty or 0.0)
        if q_req <= 0:
            return 0.0, 0.0
        q_have = float(st.get("qty") or 0.0)
        v_have = float(st.get("val") or 0.0)
        unit_cost = (v_have / q_have) if q_have > 0 else 0.0
        q_take = min(q_req, q_have) if q_have > 0 else 0.0
        total_cost = q_req * unit_cost  # even if negative stock, keep unit_cost
        # update state (allow negative if issued more than available)
        st["qty"] = q_have - q_req
        st["val"] = v_have - (q_req * unit_cost)
        state[key] = st
        return unit_cost, total_cost

    for r in all_tx:
        ttype = (r.get("txn_type") or "").upper()
        if ttype not in ("RECEIVE", "ISSUE", "TRANSFER"):
            continue
        ts = (r.get("ts") or "")
        ts_date = ts[:10] if ts else ""
        qty = _num(r.get("qty"), 0.0)
        if qty == 0:
            continue

        # update state in chronological order
        if ttype == "RECEIVE":
            wh_to = r.get("wh_to_id")
            unit_price = _num(r.get("unit_price"), 0.0)
            _add_stock(wh_to, r.get("item_id"), qty, unit_price)
            txn_value = qty * unit_price
            unit_cost = unit_price

        elif ttype == "ISSUE":
            wh_from = r.get("wh_from_id")
            unit_cost, txn_value = _remove_stock(wh_from, r.get("item_id"), qty)

        else:  # TRANSFER
            wh_from = r.get("wh_from_id")
            wh_to = r.get("wh_to_id")
            unit_cost, txn_value = _remove_stock(wh_from, r.get("item_id"), qty)
            _add_stock(wh_to, r.get("item_id"), qty, unit_cost)

        # record only if in requested ids + in date window + matches filter
        rid = int(r.get("id") or 0)
        if rid in ids_set:
            in_window = True
            if from_date and ts_date and ts_date < from_date:
                in_window = False
            if to_date and ts_date and ts_date > to_date:
                in_window = False
            if tfilter and ttype != tfilter:
                in_window = False
            if in_window:
                out[rid] = {"txn_value": float(txn_value or 0.0), "unit_cost": float(unit_cost or 0.0)}

    return out

# ---------------- Requests ----------------
def _req_status_norm(s: str) -> str:
    """Normalize request status for filtering only.

    - Keeps user-entered free text (uppercased).
    - Special case: 'ALL' -> ALL (no filter).
    - Empty -> '' (no filter).
    """
    s = (s or "").strip()
    if not s:
        return ""
    su = s.upper()
    if su == "ALL":
        return "ALL"
    return su



def list_requests(req_date="", status="ALL", q_wh="", q_maint="", q_whreq="", q_po="", q_eq="", limit=500, offset=0):
    """Standalone requests list (NOT linked to inventory/transactions)."""
    req_date=(req_date or "").strip()
    status=(status or "").strip()
    q_wh=(q_wh or "").strip()
    q_maint=(q_maint or "").strip()
    q_whreq=(q_whreq or "").strip()
    q_po=(q_po or "").strip()
    q_eq=(q_eq or "").strip()

    where=[]
    params=[]
    if req_date:
        where.append("r.req_date=?"); params.append(req_date)
    if status and status.upper()!="ALL":
        where.append("UPPER(COALESCE(r.status,'')) LIKE ?"); params.append(f"%{status.upper()}%")
    if q_wh:
        where.append("COALESCE(r.warehouse_name,'') LIKE ?"); params.append(f"%{q_wh}%")
    if q_maint:
        where.append("COALESCE(r.maint_req_no,'') LIKE ?"); params.append(f"%{q_maint}%")
    if q_whreq:
        where.append("COALESCE(r.wh_req_no,'') LIKE ?"); params.append(f"%{q_whreq}%")
    if q_po:
        where.append("COALESCE(r.po_no,'') LIKE ?"); params.append(f"%{q_po}%")
    if q_eq:
        where.append("COALESCE(r.eq_code,'') LIKE ?"); params.append(f"%{q_eq}%")

    wsql=("WHERE "+" AND ".join(where)) if where else ""
    con=db_connect()
    rows=con.execute(f"""
      SELECT r.id, r.req_date,
             COALESCE(r.warehouse_name,'') AS warehouse_name,
             COALESCE(r.maint_req_no,'') AS maint_req_no,
             COALESCE(r.wh_req_no,'') AS wh_req_no,
             COALESCE(r.po_no,'') AS po_no,
             COALESCE(r.eq_code,'') AS eq_code,
             COALESCE(r.status,'') AS status,
             COALESCE(r.notes,'') AS notes
      FROM StandaloneRequests r
      {wsql}
      ORDER BY r.req_date DESC, r.id DESC
      LIMIT ? OFFSET ?;
    """, (*params, int(limit), int(offset or 0))).fetchall()
    con.close()
    return [dict(r) for r in rows]

def get_request(req_id):
    con=db_connect()
    r=con.execute("""SELECT * FROM StandaloneRequests WHERE id=?""", (int(req_id),)).fetchone()
    con.close()
    return dict(r) if r else None

def upsert_request(req_id, username, req_date, warehouse_name, maint_req_no, wh_req_no, po_no, eq_code, status, notes):
    req_date=(req_date or "").strip() or _today_iso()
    now=_now().strftime("%Y-%m-%d %H:%M:%S")
    con=db_connect()
    if req_id:
        con.execute("""
          UPDATE StandaloneRequests
          SET req_date=?, warehouse_name=?, maint_req_no=?, wh_req_no=?, po_no=?, eq_code=?, status=?, notes=?
          WHERE id=?
        """, (req_date,
              (warehouse_name or "").strip() or None,
              (maint_req_no or "").strip() or None,
              (wh_req_no or "").strip() or None,
              (po_no or "").strip() or None,
              (eq_code or "").strip() or None,
              (status or "").strip() or None,
              (notes or "").strip() or None,
              int(req_id)))
    else:
        con.execute("""
          INSERT INTO StandaloneRequests(req_date,warehouse_name,maint_req_no,wh_req_no,po_no,eq_code,status,notes,username,created_at)
          VALUES (?,?,?,?,?,?,?,?,?,?)
        """, (req_date,
              (warehouse_name or "").strip() or None,
              (maint_req_no or "").strip() or None,
              (wh_req_no or "").strip() or None,
              (po_no or "").strip() or None,
              (eq_code or "").strip() or None,
              (status or "").strip() or None,
              (notes or "").strip() or None,
              username, now))
    con.commit(); con.close()

def delete_request(req_id):
    con=db_connect()
    con.execute("DELETE FROM StandaloneRequests WHERE id=?", (int(req_id),))
    con.commit(); con.close()

# ---------------- Workflow (Smart Requests) ----------------
WF_STAGES = ["DRAFT","SUBMITTED","APPROVED","PURCHASING","READY","PARTIAL","FULFILLED","CLOSED","CANCELLED"]
WF_PRIORITIES = ["LOW","NORMAL","HIGH","URGENT"]
WF_TYPES = ["MAINT","WH","PO","MIX"]

def wf_audit(wf_id, username, action, details=""):
    try:
        con=db_connect()
        con.execute("INSERT INTO WorkflowAudit(wf_id, ts, username, action, details) VALUES (?,?,?,?,?)",
                    (int(wf_id), _now().isoformat(timespec="seconds"), username, action, details))
        con.commit(); con.close()
    except Exception:
        pass

def wf_next_no(d=None):
    d = (d or _today_iso()).replace("-","")
    con=db_connect()
    row=con.execute("SELECT COUNT(*) c FROM WorkflowRequests WHERE wf_no LIKE ?", (f"WR-{d}-%",)).fetchone()
    n = int(row["c"] or 0) + 1
    con.close()
    return f"WR-{d}-{n:06d}"

def wf_recalc_fulfillment(wf_id):
    """Recalculate stage/status from WorkflowItems ONLY (no link to Transactions).
    This keeps the Workflow module independent and prevents any automatic coupling to stock movements.
    """
    con=db_connect()
    wf=con.execute("SELECT * FROM WorkflowRequests WHERE id=?", (int(wf_id),)).fetchone()
    if not wf:
        con.close(); return
    items=con.execute("SELECT qty_requested, qty_fulfilled FROM WorkflowItems WHERE wf_id=?", (int(wf_id),)).fetchall()

    total_req=sum([float(x["qty_requested"] or 0) for x in items]) if items else 0.0
    total_ful=sum([float(x["qty_fulfilled"] or 0) for x in items]) if items else 0.0

    stage=(wf["stage"] or "DRAFT").strip().upper() or "DRAFT"
    stage_new=stage

    if stage not in ("CLOSED","CANCELLED"):
        if total_req > 0:
            if total_ful >= total_req - 1e-9:
                stage_new="FULFILLED"
            elif total_ful > 0:
                stage_new="PARTIAL"
            else:
                stage_new=stage if stage in ("DRAFT","SUBMITTED","APPROVED","PURCHASING","READY") else "SUBMITTED"
        else:
            stage_new=stage

    # Overdue status (based on due_date only)
    status="OPEN"
    due=(wf["due_date"] or "").strip()
    if due:
        try:
            if date.fromisoformat(due) < date.today() and stage_new not in ("FULFILLED","CLOSED","CANCELLED"):
                status="OVERDUE"
        except Exception:
            pass

    con.execute("UPDATE WorkflowRequests SET stage=?, status=?, updated_at=? WHERE id=?",
                (stage_new, status, _now().isoformat(timespec="seconds"), int(wf_id)))
    con.commit(); con.close()

def wf_delete(wf_id, username):
    # delete children first to avoid orphan rows even if FK cascade is off
    try:
        wf_audit(wf_id, username, "DELETE", "")
    except Exception:
        pass
    con=db_connect()
    con.execute("DELETE FROM WorkflowItems WHERE wf_id=?", (int(wf_id),))
    con.execute("DELETE FROM WorkflowAudit WHERE wf_id=?", (int(wf_id),))
    con.execute("DELETE FROM WorkflowRequests WHERE id=?", (int(wf_id),))
    con.commit(); con.close()

def wf_transition(wf_id, username, stage):
    stage=(stage or "").strip().upper()
    if stage not in WF_STAGES: return
    con=db_connect()
    con.execute("UPDATE WorkflowRequests SET stage=?, updated_at=? WHERE id=?",
                (stage, _now().isoformat(timespec="seconds"), int(wf_id)))
    con.commit(); con.close()
    wf_audit(wf_id, username, "TRANSITION", stage)
    wf_recalc_fulfillment(wf_id)

def wf_item_upsert(item_line_id, wf_id, item_code, wh_code, qty_requested, notes, username):
    item_code=(item_code or "").strip()
    wh_code=(wh_code or "").strip()
    notes=(notes or "").strip()
    try:
        qty=float(qty_requested)
    except Exception:
        qty=0
    if qty<=0:
        raise ValueError(t("en","qty_gt0"))
    con=db_connect()
    it=con.execute("SELECT id FROM Items WHERE item_code=? AND active=1", (item_code,)).fetchone()
    if not it:
        con.close(); raise ValueError(t("en","not_found_item"))
    item_id=int(it["id"])
    wh_id=None
    if wh_code:
        w=con.execute("SELECT id FROM Warehouses WHERE wh_code=? AND active=1", (wh_code,)).fetchone()
        if w: wh_id=int(w["id"])
    if item_line_id is None:
        con.execute("""INSERT INTO WorkflowItems(wf_id, item_id, wh_id, qty_requested, qty_fulfilled, notes)
                       VALUES (?,?,?,?,0,?)""",
                    (int(wf_id), item_id, wh_id, qty, notes))
        con.commit(); con.close()
        wf_audit(wf_id, username, "ADD_LINE", f"{item_code} qty={qty}")
    else:
        con.execute("""UPDATE WorkflowItems SET item_id=?, wh_id=?, qty_requested=?, notes=? WHERE id=? AND wf_id=?""",
                    (item_id, wh_id, qty, notes, int(item_line_id), int(wf_id)))
        con.commit(); con.close()
        wf_audit(wf_id, username, "EDIT_LINE", f"{item_code} qty={qty}")
    wf_recalc_fulfillment(wf_id)

def wf_item_delete(item_line_id, wf_id, username):
    con=db_connect()
    con.execute("DELETE FROM WorkflowItems WHERE id=? AND wf_id=?", (int(item_line_id), int(wf_id)))
    con.commit(); con.close()
    wf_audit(wf_id, username, "DEL_LINE", f"id={item_line_id}")
    wf_recalc_fulfillment(wf_id)

