def _parse_cols_from_qs(qs):
    qs = qs or {}
    try:
        raw = (qs.get("cols", [""])[0] or "").strip()
    except Exception:
        raw = ""
    if not raw:
        return []
    parts = []
    for p in raw.replace(";", ",").split(","):
        p = (p or "").strip()
        if p:
            parts.append(p)
    seen=set(); out=[]
    for c in parts:
        if c not in seen:
            seen.add(c); out.append(c)
    return out

def _apply_cols(headers, cols):
    hs = list(headers or [])
    if not cols:
        return hs
    hset = set(hs)
    chosen = [c for c in cols if c in hset]
    return chosen if chosen else hs

def _xlsx_write(rows, headers, sheet_name="Data"):
    """
    Write XLSX bytes with:
    - AutoFit columns (bounded)
    - Freeze header row
    - AutoFilter
    - Print-Ready setup (A4, Landscape, Fit to 1 page wide)
    """
    try:
        from openpyxl import Workbook
        from openpyxl.utils import get_column_letter
    except Exception as e:
        raise RuntimeError("Missing dependency: openpyxl. Install: pip install openpyxl") from e

    wb = Workbook()
    ws = wb.active
    ws.title = (sheet_name or "Data")[:31]

    headers = list(headers or [])
    ws.append(headers)

    for r in (rows or []):
        try:
            d = dict(r)
        except Exception:
            d = r if isinstance(r, dict) else {}
        ws.append([d.get(h, "") for h in headers])

    # Freeze header row
    ws.freeze_panes = "A2"

    # AutoFilter on header row
    if headers:
        ws.auto_filter.ref = f"A1:{get_column_letter(len(headers))}1"

    # AutoFit columns (bounded so it stays printable)
    # Use a sample of rows for performance on huge exports
    max_scan = min(ws.max_row, 1200)
    for col_idx in range(1, len(headers) + 1):
        letter = get_column_letter(col_idx)
        max_len = 0
        for row_idx in range(1, max_scan + 1):
            v = ws.cell(row=row_idx, column=col_idx).value
            if v is None:
                continue
            s = str(v)
            if len(s) > max_len:
                max_len = len(s)
        # width tuning
        width = max(10, min(40, max_len + 3))
        ws.column_dimensions[letter].width = width

    # Print setup: A4 Landscape, fit to 1 page wide
    try:
        ws.page_setup.orientation = ws.ORIENTATION_LANDSCAPE
        ws.page_setup.paperSize = ws.PAPERSIZE_A4
        ws.page_setup.fitToWidth = 1
        ws.page_setup.fitToHeight = 0
        ws.sheet_properties.pageSetUpPr.fitToPage = True
        ws.print_title_rows = "1:1"   # repeat header row
        ws.page_margins.left = 0.25
        ws.page_margins.right = 0.25
        ws.page_margins.top = 0.4
        ws.page_margins.bottom = 0.4
    except Exception:
        pass

    bio = io.BytesIO()
    wb.save(bio)
    return bio.getvalue()

def _template_headers_for_view(view: str):
    """Return the real import-template headers for a given view.
    This is the single source of truth for template generation and the
    template columns wizard, so the user never sees columns that will be
    silently dropped from the downloaded template.
    """
    view = (view or "").strip().lower()

    readonly = {"balances", "stale-items", "stale_items", "history", "scrap", "low-stock", "no-price-items", "item_card", "equipment_card"}
    if view in readonly:
        raise ValueError("Template is not available for this page.")

    templates = {
        # Master data
        "assets_master": ["asset_code","asset_name","category","model","serial_no","purchase_date","purchase_cost","quantity","current_condition","location_label","current_wh_code","current_wh_name","custodian_name","notes"],
        "asset_movements": ["movement_date","movement_type_label","qty","asset_code","asset_name","category","model","serial_no","from_wh_code","from_wh_name","to_wh_code","to_wh_name","person_name","return_condition","notes"],
        "tools_master": ["tool_code","tool_name","category","unit","min_qty","current_condition","location_label","current_wh_code","current_wh_name","custodian_name","notes"],
        "tool_movements": ["movement_date","movement_type_label","tool_code","tool_name","category","unit","from_wh_code","from_wh_name","to_wh_code","to_wh_name","person_name","return_condition","notes"],
        "items": ["item_code", "item_name", "unit", "min_qty", "default_unit_price", "active"],
        "equipment": ["eq_code", "eq_name", "model", "year", "serial_no", "driver_name", "active"],
        "warehouses": ["wh_code", "wh_name", "active"],
        "suppliers": ["supplier_code", "supplier_name", "active"],
        "users": ["username", "password", "role", "full_name", "is_active"],
        "projects": ["project_code", "project_name", "active"],

        # Operational
        # NOTE: txn_date will be preserved on import (not replaced with today's date)
        # Keep this list aligned with the transaction import parser and the visible txn form.
        "txn": [
            "txn_date", "txn_type", "item_code", "qty", "scrap_qty", "unit_price",
            "wh_from", "wh_to", "eq_code", "supplier_code",
            "project_code", "issue_type", "cost_allocation",
            "req_no", "po_no", "doc_no", "notes"
        ],

        # Requests / workflow
        "requests": ["wf_no", "req_type", "title", "eq_code", "priority", "stage", "status",
                    "owner", "due_date", "maint_req_no", "wh_req_no", "po_no"],
        "workflow": ["wf_no", "req_type", "title", "eq_code", "priority", "stage", "status",
                    "owner", "due_date", "maint_req_no", "wh_req_no", "po_no"],
    }
    headers = templates.get(view)
    if not headers:
        raise ValueError(f"Unknown view for template: {view}")
    return list(headers)


def _available_template_cols_for_view(view: str):
    try:
        return _template_headers_for_view(view)
    except Exception:
        return []


def template_view_xlsx_with_cols(view: str, cols=None):
    """Return an XLSX template (headers only) for the given view/page."""
    view = (view or "").strip().lower()
    headers = _template_headers_for_view(view)
    headers = _apply_cols(headers, cols or [])
    return _xlsx_write([], headers, sheet_name=f"Template-{view}")


def template_view_xlsx(view: str):
    return template_view_xlsx_with_cols(view, cols=None)


def _xlsx_read(file_bytes):
    try:
        from openpyxl import load_workbook
    except Exception as e:
        raise RuntimeError("Missing dependency: openpyxl. Install: pip install openpyxl") from e
    wb=load_workbook(io.BytesIO(file_bytes), data_only=True)
    ws=wb.active
    rows=list(ws.iter_rows(values_only=True))
    if not rows:
        return [], []
    headers=[str(x).strip() if x is not None else "" for x in rows[0]]
    data=[]
    for row in rows[1:]:
        if row is None:
            continue
        rec={}
        empty=True
        for i,h in enumerate(headers):
            v=row[i] if i < len(row) else None
            if v is None: v=""
            if str(v).strip()!="": empty=False
            rec[h]=v
        if not empty:
            data.append(rec)
    return headers, data



