def export_view_as_xlsx(view, qs):
    view=(view or "").strip().lower()

    cols=_parse_cols_from_qs(qs)

    if view=="cost_centers":
        rows, meta = compute_cost_centers(qs or {})
        headers=["wh_code","wh_name","in_value","out_value","net","missing_price_in","missing_cost_out"]
        return _xlsx_write(rows, _apply_cols(headers, cols), "CostCenters")

    if view=="items":
        q=(qs.get("q",[""])[0] or "").strip()
        rows=[dict(r) for r in list_rows("Items", q, order_by="item_code")]
        item_ids=[int(r.get("id") or 0) for r in rows if str(r.get("id") or "").isdigit()]
        latest_price_map={}
        if item_ids:
            con_lp=db_connect()
            try:
                ph=",".join(["?"]*len(item_ids))
                sql_lp=f"""
                    SELECT item_id, unit_price
                    FROM (
                        SELECT item_id, unit_price,
                               ROW_NUMBER() OVER (PARTITION BY item_id ORDER BY ts DESC, id DESC) AS rn
                        FROM Transactions
                        WHERE voided=0
                          AND unit_price IS NOT NULL
                          AND CAST(unit_price AS REAL) > 0
                          AND item_id IN ({ph})
                    ) z
                    WHERE rn=1
                """
                for rr in con_lp.execute(sql_lp, tuple(item_ids)).fetchall():
                    iid = rr[0] if not isinstance(rr, sqlite3.Row) else rr["item_id"]
                    up = rr[1] if not isinstance(rr, sqlite3.Row) else rr["unit_price"]
                    try:
                        latest_price_map[int(iid)] = float(up)
                    except Exception:
                        pass
            finally:
                try:
                    con_lp.close()
                except Exception:
                    pass
        for r in rows:
            iid = int(r.get("id") or 0) if str(r.get("id") or "").isdigit() else 0
            v = latest_price_map.get(iid)
            r["last_txn_price"] = ("" if v is None else (f"{v:.3f}".rstrip("0").rstrip(".")))
        headers=["item_code","item_name","unit","min_qty","default_unit_price","last_txn_price","active"]
        return _xlsx_write(rows, _apply_cols(headers, cols), "Items")


    if view=="assets_master":
        rows = list_assets_filtered(qs, limit=50000)
        for r in rows:
            r["location_label"] = ('مع شخص' if str(r.get('current_location_type') or '').strip() == 'person' else ('موزع' if str(r.get('current_location_type') or '').strip() == 'mixed' else 'داخل مستودع'))
        headers=["asset_code","asset_name","category","model","serial_no","purchase_date","purchase_cost","quantity","current_condition","location_label","current_wh_code","current_wh_name","custodian_name","notes"]
        return _xlsx_write(rows, _apply_cols(headers, cols), "Assets")

    if view=="asset_movements":
        rows = list_asset_movements_filtered(qs, limit=50000)
        headers=["movement_date","movement_type_label","qty","asset_code","asset_name","category","model","serial_no","from_wh_code","from_wh_name","to_wh_code","to_wh_name","person_name","return_condition","notes"]
        return _xlsx_write(rows, _apply_cols(headers, cols), "AssetMovements")

    if view=="tools_master":
        rows = list_tools_filtered(qs, limit=50000)
        for r in rows:
            r["location_label"] = ('مع شخص' if str(r.get('current_location_type') or '').strip() == 'person' else ('موزع' if str(r.get('current_location_type') or '').strip() == 'mixed' else 'داخل مستودع'))
        headers=["tool_code","tool_name","category","unit","min_qty","current_condition","location_label","current_wh_code","current_wh_name","custodian_name","notes"]
        return _xlsx_write(rows, _apply_cols(headers, cols), "Tools")

    if view=="tool_movements":
        rows = list_tool_movements_filtered(qs, limit=50000)
        headers=["movement_date","movement_type_label","tool_code","tool_name","category","unit","from_wh_code","from_wh_name","to_wh_code","to_wh_name","person_name","return_condition","notes"]
        return _xlsx_write(rows, _apply_cols(headers, cols), "ToolMovements")

    if view=="equipment":
        q=(qs.get("q",[""])[0] or "").strip()
        rows=[dict(r) for r in list_rows("Equipment", q, order_by="eq_code")]
        headers=["eq_code","eq_name","model","year","serial_no","driver_name","active"]
        return _xlsx_write(rows, _apply_cols(headers, cols), "Equipment")


    if view=="equipment_consumption":
        rows = compute_equipment_consumption(qs or {})
        headers=["eq_code","eq_name","issue_qty","issue_value","lines","distinct_items","last_issue_date"]
        return _xlsx_write(rows, _apply_cols(headers, cols), "EquipConsumption")

    if view=="warehouses":
        q=(qs.get("q",[""])[0] or "").strip()
        rows=[dict(r) for r in list_rows("Warehouses", q, order_by="wh_code")]
        headers=["wh_code","wh_name","active"]
        return _xlsx_write(rows, _apply_cols(headers, cols), "Warehouses")

    if view=="suppliers":
        q=(qs.get("q",[""])[0] or "").strip()
        rows=[dict(r) for r in list_rows("Suppliers", q, order_by="supplier_code")]
        headers=["supplier_code","supplier_name","active"]
        return _xlsx_write(rows, _apply_cols(headers, cols), "Suppliers")

    if view=="requests":
        req_date=(qs.get("req_date",[""])[0] or "").strip()
        status=(qs.get("status",["ALL"])[0] or "ALL").strip()
        q_wh=(qs.get("q_wh",[""])[0] or "").strip()
        q_maint=(qs.get("q_maint",[""])[0] or "").strip()
        q_whreq=(qs.get("q_whreq",[""])[0] or "").strip()
        q_po=(qs.get("q_po",[""])[0] or "").strip()
        q_eq=(qs.get("q_eq",[""])[0] or "").strip()
        rows=list_requests(req_date=req_date, status=status, q_wh=q_wh, q_maint=q_maint, q_whreq=q_whreq, q_po=q_po, q_eq=q_eq, limit=50000)
        headers=["req_date","warehouse_name","maint_req_no","wh_req_no","po_no","eq_code","status","notes"]
        return _xlsx_write(rows, _apply_cols(headers, cols), "Requests")


    if view in ("daily_reports","daily-report","dailyreports"):
        # Accept multiple possible parameter names from UI/export links
        d = (qs.get("date",[""])[0] or qs.get("from_date",[""])[0] or qs.get("req_date",[""])[0] or _today_iso()).strip()
        d2 = (qs.get("to_date",[""])[0] or "").strip()
        if not d2:
            d2 = d
        typ = (qs.get("txn_type",[""])[0] or qs.get("type",[""])[0] or "").strip().upper()
        rows = list_txn(txn_type=typ, from_date=d, to_date=d2, include_voided=False, limit=50000, offset=0)

        # Add per-transaction value for Excel too (same logic as PDF)
        try:
            _ids = [int(r.get("id") or 0) for r in (rows or []) if str(r.get("id") or "").isdigit()]
        except Exception:
            _ids = []
        try:
            _vmap = compute_txn_value_map(_ids, d, d2, txn_type_filter=typ)
        except Exception:
            _vmap = {}
        for _r in (rows or []):
            try:
                _rid = int(_r.get("id") or 0)
            except Exception:
                _rid = 0
            _r["txn_value"] = float((_vmap.get(_rid) or {}).get("txn_value") or 0.0)

        headers=["id","ts","txn_type","item_code","item_name","qty","unit_price","txn_value","wh_from_code","wh_to_code","eq_code","supplier_code","req_no","po_no","doc_no","notes"]
        return _xlsx_write(rows, _apply_cols(headers, cols), "DailyReports")

    if view=="txn":
        _q_item=(qs.get("q_item",[""])[0] or "")
        _q_eq=(qs.get("q_eq",[""])[0] or "")
        _q_supplier=(qs.get("q_supplier",[""])[0] or "")
        _q_req=(qs.get("q_req",[""])[0] or "")
        _q_doc=(qs.get("q_doc",[""])[0] or "")
        _txn_type=(qs.get("txn_type",[""])[0] or "")
        _from_date=(qs.get("from_date",[""])[0] or "")
        _to_date=(qs.get("to_date",[""])[0] or "")
        rows=list_txn(q_item=_q_item,
                      q_eq=_q_eq,
                      q_supplier=_q_supplier,
                      q_req=_q_req,
                      q_doc=_q_doc,
                      txn_type=_txn_type,
                      from_date=_from_date,
                      to_date=_to_date,
                      include_voided=(qs.get("voided",["0"])[0] or "0") in ("1","true","on","yes","y"),
                      limit=_txn_safe_export_limit(q_item=_q_item, q_eq=_q_eq, q_supplier=_q_supplier, q_req=_q_req, q_doc=_q_doc, txn_type=_txn_type, from_date=_from_date, to_date=_to_date),
                      offset=0)
        headers=["id","ts","txn_type","item_code","item_name","qty","unit_price","wh_from","wh_to","eq_code","supplier_code","req_no","po_no","doc_no","notes","username","voided"]
        return _xlsx_write([dict(r) for r in rows], headers, "Transactions")

    if view=="item_card":
        item_code=(qs.get("item_code",[""])[0] or "").strip()
        from_date=(qs.get("from_date",[""])[0] or "").strip()
        to_date=(qs.get("to_date",[""])[0] or "").strip()
        rows=list_txn(q_item=item_code,
                      q_eq="",
                      q_supplier="",
                      txn_type="",
                      from_date=from_date,
                      to_date=to_date,
                      include_voided=(qs.get("voided",["0"])[0] or "0") in ("1","true","yes"),
                      limit=50000)
        headers=["id","ts","txn_type","item_code","item_name","unit","qty","unit_price","wh_from_code","wh_to_code","eq_code","eq_name","supplier_code","supplier_name","req_no","po_no","doc_no","notes","voided"]
        sheet="ItemCard" + (("_"+item_code) if item_code else "")
        return _xlsx_write(rows, _apply_cols(headers, cols), sheet)

    if view=="equipment_card":
        eq_code=(qs.get("eq_code",[""])[0] or "").strip()
        from_date=(qs.get("from_date",[""])[0] or "").strip()
        to_date=(qs.get("to_date",[""])[0] or "").strip()
        rows=list_txn(q_item="",
                      q_eq=eq_code,
                      q_supplier="",
                      txn_type="",
                      from_date=from_date,
                      to_date=to_date,
                      include_voided=(qs.get("voided",["0"])[0] or "0") in ("1","true","yes"),
                      limit=50000)
        headers=["id","ts","txn_type","item_code","item_name","unit","qty","unit_price","wh_from_code","wh_to_code","eq_code","eq_name","supplier_code","supplier_name","req_no","po_no","doc_no","notes","voided"]
        sheet="EquipCard" + (("_"+eq_code) if eq_code else "")
        return _xlsx_write(rows, _apply_cols(headers, cols), sheet)



    if view=="no-price-items":
        q_item=(qs.get("q_item",[""])[0] or "").strip()
        con=db_connect()
        try:
            params=[]
            item_filter=""
            if q_item:
                iid = get_item_id(q_item, active_only=False)
                item_filter="AND i.id=? "
                params.append(iid if iid else -1)
            q=f"""
            SELECT
              i.item_code, i.item_name, i.unit, COALESCE(i.min_qty,0) AS min_qty,
              COUNT(t.id) AS txn_count,
              COALESCE(MAX(substr(t.ts,1,10)),'') AS last_txn_date
            FROM Items i
            LEFT JOIN Transactions t
              ON t.item_id=i.id AND t.voided=0
            WHERE i.active=1
              {item_filter}
            GROUP BY i.id
            HAVING COALESCE(SUM(CASE WHEN t.unit_price IS NOT NULL AND t.unit_price>0 THEN 1 ELSE 0 END),0)=0
            ORDER BY i.item_code;
            """
            rows=[dict(r) for r in con.execute(q, params).fetchall()]
        finally:
            try:
                if not _in_atomic_db():
                    con.close()
            except Exception:
                pass
        headers=["item_code","item_name","unit","min_qty","txn_count","last_txn_date"]
        return _xlsx_write(rows, _apply_cols(headers, cols), "Items Without Price")

    if view=="balances":
        q_item=(qs.get("q_item",[""])[0] or "").strip()
        q_wh=(qs.get("q_wh",[""])[0] or "").strip()
        rows=balance_rows(item_code=q_item or None, wh_code=q_wh or None, limit=50000, offset=0)
        # Export MUST include quantity (on-hand). balance_rows() typically returns key 'balance'.
        headers=["item_code","item_name","wh_code","wh_name","qty_on_hand","min_qty","status"]
        out=[]
        for r in rows:
            d=dict(r)
            # normalize common keys so qty_on_hand always has a value
            d.setdefault("qty_on_hand", d.get("balance", d.get("qty", d.get("on_hand", ""))))
            # also keep a friendly alias 'qty' for any downstream templates (doesn't affect headers)
            d.setdefault("qty", d.get("qty_on_hand",""))
            out.append(d)
        return _xlsx_write(out, headers, "Balances")


    if view=="scrap":
        rows=scrap_rows(q_item=(qs.get("q_item",[""])[0] or ""),
                    q_wh=(qs.get("q_wh",[""])[0] or ""),
                    q_eq=(qs.get("q_eq",[""])[0] or ""),
                    from_date=(qs.get("from_date",[""])[0] or ""),
                    to_date=(qs.get("to_date",[""])[0] or ""),
                    limit=50000, offset=0)
        headers=["item_code","item_name","unit","wh_code","wh_name","scrap_qty","sale_threshold_qty","status","issue_count","last_issue"]
        return _xlsx_write(rows, _apply_cols(headers, cols), "Scrap")

    raise ValueError("Unknown view export")


def import_view_from_xlsx(view, lang, username, file_bytes, dry_run=True, import_mode="add_update"):
    """Generic XLSX import that ACCEPTS ANY COLUMNS + ANY CONTENT (best-effort).

    - Unknown columns are ignored.
    - Values are coerced safely; bad values never crash the import.
    - For each supported view, we upsert into the related table using its natural key.
    - Returns dict: {ok, add, update, skipped, errors:[...]}  (ALWAYS).
    """
    view = (view or "").strip().lower()
    import_mode = (import_mode or "add_update").strip().lower()
    if import_mode not in ("add_update", "add_only", "update_only"):
        import_mode = "add_update"

    # Read workbook
    headers, data = _xlsx_read(file_bytes)

    counts = {"ok": 0, "add": 0, "update": 0, "skipped": 0}
    errors = []
    # ===== LAN hardening: DB write batching for imports =====
    _IMPORT_BATCH_SIZE = 500
    _import_batch_cons = []   # keep refs so we can flush at end
    _import_batch_pending = {}  # id(con) -> pending writes
    
    def _import_batch_mark(con):
        """Mark a successful write; commit every 500 writes (best-effort)."""
        if dry_run or (con is None):
            return
        cid = id(con)
        if cid not in _import_batch_pending:
            _import_batch_pending[cid] = 0
            _import_batch_cons.append(con)
        _import_batch_pending[cid] = int(_import_batch_pending.get(cid, 0) or 0) + 1
        if _import_batch_pending[cid] >= _IMPORT_BATCH_SIZE:
            try:
                if not _in_atomic_db():
                    con.commit()
            finally:
                _import_batch_pending[cid] = 0
    
    def _import_batch_flush():
        """Commit any remaining pending writes and close connections opened during import."""
        if dry_run:
            return
        for con in list(_import_batch_cons):
            try:
                cid = id(con)
                pend = int(_import_batch_pending.get(cid, 0) or 0)
                if pend > 0:
                    if not _in_atomic_db():
                        con.commit()
                    _import_batch_pending[cid] = 0
            except Exception:
                pass
            try:
                con.close()
            except Exception:
                pass
        _import_batch_cons.clear()
        _import_batch_pending.clear()
    # =======================================================

    failed = []
    def _is_empty(v):
        try:
            return v is None or str(v).strip() == "" or str(v).strip().lower() in ("none", "null", "nan")
        except Exception:
            return True

    # ---------- normalize header keys ----------
    import re as _re

    def _norm_key(k):
        k = "" if k is None else str(k)
        k = k.replace("\u00A0", " ").strip().lower()
        k = _re.sub(r"[\s\-\/]+", "_", k)
        k = _re.sub(r"[^0-9a-zA-Z_\u0600-\u06FF]+", "", k)
        return k.strip("_")

    def _to_text(v):
        try:
            return "" if v is None else str(v).replace("\u00A0", " ").strip()
        except Exception:
            return ""

    def _first(rec_norm: dict, keys: list[str]):
        for k in keys:
            v = rec_norm.get(_norm_key(k))
            if not _is_empty(v):
                return v
        return None

    def _as_str(rec_norm: dict, keys: list[str]) -> str:
        return _to_text(_first(rec_norm, keys))

    def _as_num(rec_norm: dict, keys: list[str]) -> float | None:
        v = _first(rec_norm, keys)
        if _is_empty(v):
            return None
        try:
            return float(str(v).replace(",", "").strip())
        except Exception:
            return None

    def _as_int(rec_norm: dict, keys: list[str]) -> int | None:
        v = _first(rec_norm, keys)
        if _is_empty(v):
            return None
        try:
            return int(float(str(v).replace(",", "").strip()))
        except Exception:
            return None

    def _as_date(rec_norm: dict, keys: list[str]) -> str:
        v = _first(rec_norm, keys)
        if _is_empty(v):
            return ""
        try:
            return _coerce_date_yyyy_mm_dd(v) or ""
        except Exception:
            return ""

    def _as_code(rec_norm: dict, keys: list[str]) -> str:
        v = _first(rec_norm, keys)
        if _is_empty(v):
            return ""
        if isinstance(v, float):
            try:
                if float(v).is_integer():
                    v = str(int(v))
            except Exception:
                pass
        s = _to_text(v)
        if _re.fullmatch(r"\d+\.0+", s or ""):
            s = s.split(".", 1)[0]
        try:
            return normalize_code(s)
        except Exception:
            return s

    # ---------- SPECIAL VIEWS (need extra logic) ----------
    # role-based safety for admin-only operations
    try:
        _role = user_role(username) or ""
    except Exception:
        _role = ""

    # ---- USERS import ----
    if view in ("users", "user", "accounts"):
        if not is_admin(_role):
            # keep it safe: user management import is ADMIN only
            counts["skipped"] = len(data or [])
            errors.append("Users import is ADMIN only.")
            return {"ok": 0, "add": 0, "update": 0, "skipped": counts["skipped"], "errors": errors, "failed": failed}

        for row_no, rec in enumerate(data or [], start=2):
            try:
                if not isinstance(rec, dict):
                    counts["skipped"] += 1
                    errors.append(f"Row {row_no}: skipped (row is not a dict)")
                    try:
                        failed.append({"row_number": row_no, "error": "row is not a dict"})
                    except Exception:
                        pass
                    continue
                rec_norm = {_norm_key(k): rec.get(k) for k in rec.keys()}

                uname = _as_str(rec_norm, ["username", "user", "login", "اسم_المستخدم", "يوزر"]).strip()
                if not uname:
                    counts["skipped"] += 1
                    continue

                role_in = (_as_str(rec_norm, ["role", "صلاحية", "الصلاحية"]) or "").strip().upper() or "VIEWER"
                if role_in not in ("VIEWER", "EDITOR", "ADMIN"):
                    role_in = "VIEWER"

                active_in = _as_int(rec_norm, ["active", "is_active", "enabled", "فعال"])
                active_in = 1 if (active_in is None) else (1 if int(active_in) != 0 else 0)

                pw = _as_str(rec_norm, ["password", "pass", "pw", "كلمة_المرور", "باسورد"]).strip()

                con = db_connect()
                try:
                    row = con.execute("SELECT username, pass_hash FROM Users WHERE username=?", (uname,)).fetchone()
                    exists = bool(row)
                    if (not exists) and (not pw):
                        counts["skipped"] += 1
                        errors.append(f"Row {row_no}: new user '{uname}' missing password")
                        continue

                    if dry_run:
                        counts["ok"] += 1
                        counts["update"] += 1 if exists else 0
                        counts["add"] += 0 if exists else 1
                        continue

                    if exists:
                        # keep old password unless a new one is supplied
                        if pw:
                            ph = pbkdf2_hash(pw)
                            con.execute("UPDATE Users SET pass_hash=?, role=?, active=? WHERE username=?",
                                        (ph, role_in, active_in, uname))
                        else:
                            con.execute("UPDATE Users SET role=?, active=? WHERE username=?",
                                        (role_in, active_in, uname))
                        _import_batch_mark(con)
                        counts["update"] += 1
                    else:
                        ph = pbkdf2_hash(pw)
                        con.execute("INSERT INTO Users(username, pass_hash, role, active, created_at, last_login) VALUES (?,?,?,?,?,?)",
                                    (uname, ph, role_in, active_in, _now().isoformat(timespec="seconds")))
                        _import_batch_mark(con)
                        counts["add"] += 1

                    counts["ok"] += 1
                finally:
                    con.close()
            except Exception as e:
                counts["skipped"] += 1
                errors.append(f"Row {row_no}: {e}")
                try:
                    failed.append({"row_number": row_no, "view": view, "error": str(e)})
                except Exception:
                    pass
        return {"ok": counts["ok"], "add": counts["add"], "update": counts["update"], "skipped": counts["skipped"], "errors": errors, "failed": failed}

    # ---- TRANSACTIONS import ----
    if view in ("txn", "txns", "transactions", "movement", "حركة", "الحركة"):
        allow_update = is_admin(_role)
        for row_no, rec in enumerate(data or [], start=2):
            try:
                if not isinstance(rec, dict):
                    counts["skipped"] += 1
                    continue
                rec_norm = {_norm_key(k): rec.get(k) for k in rec.keys()}

                tid = _as_int(rec_norm, ["id", "txn_id", "معرف", "رقم"])
                txn_type = (_as_str(rec_norm, ["txn_type", "type", "movement_type", "نوع", "نوع_الحركة"]) or "").strip().upper()
                txn_date = _as_date(rec_norm, ["txn_date", "date", "ts", "التاريخ", "تاريخ"])
                item_code = _as_code(rec_norm, ["item_code", "item", "code", "كود", "كود_الصنف"])
                qty = _as_str(rec_norm, ["qty", "quantity", "الكمية", "كمية"])
                unit_price = _as_str(rec_norm, ["unit_price", "price", "سعر", "السعر"])
                scrap_qty = _as_str(rec_norm, ["scrap_qty", "scrap", "scrap_quantity", "كمية_السكراب", "سكراب"])
                wh_from = _as_code(rec_norm, ["wh_from", "wh_from_code", "from", "من", "مستودع_من"])
                wh_to = _as_code(rec_norm, ["wh_to", "wh_to_code", "to", "الى", "إلى", "مستودع_الى"])
                eq_code = _as_code(rec_norm, ["eq_code", "equipment", "equipment_code", "كود_المعدة", "المعدة"])
                supplier_code = _as_code(rec_norm, ["supplier_code", "vendor", "supplier", "المورد", "كود_المورد"])
                project_code = _as_code(rec_norm, ["project_code", "project", "projectcode", "المشروع", "كود_المشروع"])
                issue_type = _as_str(rec_norm, ["issue_type", "issue kind", "issue_kind", "نوع_الصرف"])
                cost_allocation = _as_str(rec_norm, ["cost_allocation", "allocation", "allocation_type", "تحميل_التكلفة"])
                req_no = _as_str(rec_norm, ["req_no", "request_no", "mr_no", "رقم_طلب", "طلب"])
                po_no = _as_str(rec_norm, ["po_no", "po", "purchase_order", "رقم_امر_شراء", "امر_شراء"])
                doc_no = _as_str(rec_norm, ["doc_no", "document_no", "مستند", "رقم_مستند"])
                notes = _as_str(rec_norm, ["notes", "note", "ملاحظات", "ملاحظة"])

                # Require minimum fields
                if not txn_type or not item_code or _is_empty(qty):
                    counts["skipped"] += 1
                    reason = []
                    if not txn_type: reason.append("missing txn_type")
                    if not item_code: reason.append("missing item_code")
                    if _is_empty(qty): reason.append("missing qty")
                    errors.append(f"Row {row_no}: skipped ({', '.join(reason) or 'missing required fields'})")
                    try:
                        failed.append({
                            "row_number": row_no,
                            "txn_type": txn_type,
                            "txn_date": txn_date,
                            "item_code": item_code,
                            "qty": qty,
                            "unit_price": unit_price,
                            "scrap_qty": scrap_qty,
                            "wh_from": wh_from,
                            "wh_to": wh_to,
                            "eq_code": eq_code,
                            "supplier_code": supplier_code,
                            "project_code": project_code,
                            "issue_type": issue_type,
                            "cost_allocation": cost_allocation,
                            "req_no": req_no,
                            "po_no": po_no,
                            "doc_no": doc_no,
                            "notes": notes,
                            "error": "missing required fields: " + (", ".join(reason) or "unknown")
                        })
                    except Exception:
                        pass
                    continue

                # Decide add/update
                is_upd = bool(tid and allow_update and (import_mode in ("add_update", "update_only")))
                is_add = (not is_upd) and (import_mode in ("add_update", "add_only"))

                if not is_add and not is_upd:
                    counts["skipped"] += 1
                    errors.append(f"Row {row_no}: skipped (import_mode prevents add/update for this row)")
                    try:
                        failed.append({
                            "row_number": row_no,
                            "txn_type": txn_type,
                            "txn_date": txn_date,
                            "item_code": item_code,
                            "qty": qty,
                            "unit_price": unit_price,
                            "scrap_qty": scrap_qty,
                            "wh_from": wh_from,
                            "wh_to": wh_to,
                            "eq_code": eq_code,
                            "supplier_code": supplier_code,
                            "req_no": req_no,
                            "po_no": po_no,
                            "doc_no": doc_no,
                            "notes": notes,
                            "error": f"import_mode={import_mode} prevents add/update"
                        })
                    except Exception:
                        pass
                    continue

                form_payload = {
                    "txn_type": [txn_type],
                    "txn_date": [txn_date],
                    "item_code": [item_code],
                    "qty": [qty],
                    "scrap_qty": [scrap_qty],
                    "unit_price": [unit_price],
                    "wh_from": [wh_from],
                    "wh_to": [wh_to],
                    "eq_code": [eq_code],
                    "supplier_code": [supplier_code],
                    "project_code": [project_code],
                    "issue_type": [issue_type],
                    "cost_allocation": [cost_allocation],
                    "req_no": [req_no],
                    "po_no": [po_no],
                    "doc_no": [doc_no],
                    "notes": [notes],
                }

                svc = get_container().txn_service
                if dry_run:
                    # Make dry-run validate the same master-code and field logic used by real import.
                    svc._validate_form(form=form_payload, lang=lang)
                    svc._parse_scrap_qty(txn_type, scrap_qty)
                    svc._parse_unit_price(unit_price)
                    counts["ok"] += 1
                    if is_upd:
                        counts["update"] += 1
                    else:
                        counts["add"] += 1
                    continue

                if is_upd:
                    svc.save(rid=str(int(tid)), form=form_payload, files={}, user=username, role=_role, ip="import", lang=lang)
                    counts["update"] += 1
                else:
                    svc.save(rid="", form=form_payload, files={}, user=username, role=_role, ip="import", lang=lang)
                    counts["add"] += 1

                counts["ok"] += 1
            except Exception as e:
                counts["skipped"] += 1
                errors.append(f"Row {row_no}: {e}")
                try:
                    failed.append({"row_number": row_no, "view": view, "error": str(e)})
                except Exception:
                    pass
        return {"ok": counts["ok"], "add": counts["add"], "update": counts["update"], "skipped": counts["skipped"], "errors": errors, "failed": failed}

    # ---- STANDALONE REQUESTS import ----
    if view in ("requests", "standalone_requests", "all_requests", "طلبات", "طلبات_شراء", "طلبات_الصيانة"):
        for row_no, rec in enumerate(data or [], start=2):
            try:
                if not isinstance(rec, dict):
                    counts["skipped"] += 1
                    continue
                rec_norm = {_norm_key(k): rec.get(k) for k in rec.keys()}

                rid = _as_str(rec_norm, ["id", "request_id", "rid", "رقم"]).strip()
                req_date = _as_date(rec_norm, ["req_date", "date", "التاريخ", "تاريخ"]) or _today_iso()
                warehouse_name = _as_str(rec_norm, ["warehouse_name", "warehouse", "المستودع"])
                maint_req_no = _as_str(rec_norm, ["maint_req_no", "maint", "رقم_طلب_صيانة"])
                wh_req_no = _as_str(rec_norm, ["wh_req_no", "warehouse_req_no", "رقم_طلب_مستودع"])
                po_no = _as_str(rec_norm, ["po_no", "purchase_order", "رقم_امر_شراء"])
                eq_code = _as_str(rec_norm, ["eq_code", "equipment", "كود_المعدة"])
                status = _as_str(rec_norm, ["status", "حالة", "الحالة"])
                notes = _as_str(rec_norm, ["notes", "ملاحظات", "ملاحظة"])

                # If row is completely empty -> skip
                if all(_is_empty(x) for x in [warehouse_name, maint_req_no, wh_req_no, po_no, eq_code, status, notes]) and not rid:
                    counts["skipped"] += 1
                    continue

                if dry_run:
                    counts["ok"] += 1
                    # best-effort counters
                    counts["update"] += 1 if rid else 0
                    counts["add"] += 0 if rid else 1
                    continue

                upsert_request(rid or None, username, req_date, warehouse_name, maint_req_no, wh_req_no, po_no, eq_code, status, notes)
                counts["ok"] += 1
                counts["update"] += 1 if rid else 0
                counts["add"] += 0 if rid else 1
            except Exception as e:
                counts["skipped"] += 1
                errors.append(f"Row {row_no}: {e}")
                try:
                    failed.append({"row_number": row_no, "view": view, "error": str(e)})
                except Exception:
                    pass
        return {"ok": counts["ok"], "add": counts["add"], "update": counts["update"], "skipped": counts["skipped"], "errors": errors, "failed": failed}

    # ---------- GENERIC TABLE IMPORTS ----------
    # extendable map for pages that use the standard CRUD tables
    VIEW_MAP = {
        "items": ("Items", "item_code"),
        "equipment": ("Equipment", "eq_code"),
        "equipments": ("Equipment", "eq_code"),
        "warehouses": ("Warehouses", "wh_code"),
        "suppliers": ("Suppliers", "supplier_code"),
        "vendors": ("Suppliers", "supplier_code"),
        "settings": ("Settings", "key"),
        "workflowrequests": ("WorkflowRequests", "wf_no"),
        "workflow_requests": ("WorkflowRequests", "wf_no"),
    }

    if view not in VIEW_MAP:
        counts["skipped"] = len(data or [])
        errors.append(f"View '{view}' import is not configured. File read OK; nothing imported.")
        return {"ok": counts["ok"], "add": counts["add"], "update": counts["update"], "skipped": counts["skipped"], "errors": errors, "failed": failed}

    table, unique_col = VIEW_MAP[view]

    # ---------- get table columns ----------
    try:
        con = db_connect()
        cols = con.execute(f"PRAGMA table_info({table})").fetchall()
        con.close()
    except Exception as e:
        return {"ok": 0, "add": 0, "update": 0, "skipped": len(data or []), "errors": [f"Cannot read table schema for {table}: {e}"], "failed": failed}

    col_names = [c["name"] if isinstance(c, dict) else c[1] for c in cols]
    col_types = { (c["name"] if isinstance(c, dict) else c[1]) : ((c["type"] if isinstance(c, dict) else c[2]) or "") for c in cols }

    writable_cols = [c for c in col_names if c.lower() not in ("id",)]
    writable_norm = {_norm_key(c): c for c in writable_cols}

    def _to_num(v, as_int=False):
        if _is_empty(v):
            return None
        try:
            fv = float(str(v).replace(",", "").strip())
            return int(fv) if as_int else fv
        except Exception:
            return None

    def _coerce_by_type(col, v):
        t = (col_types.get(col) or "").upper()
        if "INT" in t:
            return _to_num(v, as_int=True)
        if any(x in t for x in ("REAL", "FLOA", "DOUB", "NUM", "DEC")):
            return _to_num(v, as_int=False)
        if "date" in col.lower():
            try:
                return _coerce_date_yyyy_mm_dd(v)
            except Exception:
                return None
        return _to_text(v)

    def _find_id_by_unique(uval):
        if _is_empty(uval):
            return None
        con = db_connect()
        try:
            row = con.execute(f"SELECT id FROM {table} WHERE {unique_col}=?", (_to_text(uval),)).fetchone()
            return int(row["id"]) if row else None
        finally:
            try:
                if not _in_atomic_db():
                    con.close()
            except Exception:
                pass

    def _apply_import_defaults(fields, existing_id):
        out = dict(fields or {})

        # Default all standard CRUD masters to active=1 on insert when the Excel file
        # does not explicitly include the column. This fixes NOT NULL failures such as
        # Items.active during real imports from the provided template.
        if existing_id is None and "active" in writable_cols and _is_empty(out.get("active")):
            out["active"] = 1

        # Table-specific safe defaults for required columns commonly omitted by templates.
        if table == "Items":
            if _is_empty(out.get("unit")):
                out["unit"] = "PIECE"
            if _is_empty(out.get("min_qty")):
                out["min_qty"] = 0
        elif table == "Equipment":
            if _is_empty(out.get("eq_name")) and not _is_empty(out.get("eq_code")):
                out["eq_name"] = out.get("eq_code")
        elif table == "Warehouses":
            if _is_empty(out.get("wh_name")) and not _is_empty(out.get("wh_code")):
                out["wh_name"] = out.get("wh_code")
        elif table == "Suppliers":
            if _is_empty(out.get("supplier_name")) and not _is_empty(out.get("supplier_code")):
                out["supplier_name"] = out.get("supplier_code")

        # Normalization for common master-code fields.
        for code_col in ("item_code", "eq_code", "wh_code", "supplier_code"):
            if code_col in out and not _is_empty(out.get(code_col)):
                out[code_col] = normalize_code(out.get(code_col))

        return out

    def _do_upsert(fields, existing_id):
        fields = _apply_import_defaults(fields, existing_id)
        if "upsert_row" in globals():
            return upsert_row(table, existing_id, fields, id_col="id")
        con = db_connect()
        try:
            if existing_id is None:
                ks = list(fields.keys())
                vs = [fields[k] for k in ks]
                q = ",".join(["?"] * len(ks))
                con.execute(f"INSERT INTO {table} ({','.join(ks)}) VALUES ({q})", vs)
                _import_batch_mark(con)
                row = con.execute("SELECT last_insert_rowid() id").fetchone()
                return int(row["id"])
            else:
                ks = [k for k in fields.keys() if k.lower() != "id"]
                vs = [fields[k] for k in ks]
                sets = ",".join([f"{k}=?" for k in ks])
                con.execute(f"UPDATE {table} SET {sets} WHERE id=?", vs + [int(existing_id)])
                _import_batch_mark(con)
                return int(existing_id)
        finally:
            try:
                if not _in_atomic_db():
                    con.close()
            except Exception:
                pass

    for row_no, rec in enumerate(data or [], start=2):
        try:
            if not isinstance(rec, dict):
                counts["skipped"] += 1
                continue

            rec_norm = {_norm_key(k): rec.get(k) for k in rec.keys()}

            u_in = rec_norm.get(_norm_key(unique_col))
            if _is_empty(u_in):
                counts["skipped"] += 1
                continue

            uval = _to_text(u_in)
            existing_id = _find_id_by_unique(uval)

            want_add = existing_id is None
            want_upd = existing_id is not None

            if import_mode == "add_only" and want_upd:
                counts["skipped"] += 1
                continue
            if import_mode == "update_only" and want_add:
                counts["skipped"] += 1
                continue

            fields = {}
            for k_norm, raw_val in rec_norm.items():
                col = writable_norm.get(k_norm)
                if not col:
                    continue
                fields[col] = _coerce_by_type(col, raw_val)

            if not fields:
                counts["skipped"] += 1
                continue

            if dry_run:
                counts["ok"] += 1
                if want_add:
                    counts["add"] += 1
                else:
                    counts["update"] += 1
                continue

            _do_upsert(fields, existing_id)
            counts["ok"] += 1
            if want_add:
                counts["add"] += 1
            else:
                counts["update"] += 1
        except Exception as e:
            counts["skipped"] += 1
            errors.append(f"Row {row_no}: {e}")
            try:
                failed.append({"row_number": row_no, "view": view, "error": str(e)})
            except Exception:
                pass

    _import_batch_flush()

    return {"ok": counts["ok"], "add": counts["add"], "update": counts["update"], "skipped": counts["skipped"], "errors": errors, "failed": failed}

def norm_text(v):
    """Return safe trimmed text (keeps anything as text)."""
    if v is None:
        return ""
    s = str(v).replace("\u00A0", " ").strip()
    return s

def norm_num(v):
    """Normalize numbers coming from Excel (e.g., 123.0 -> '123', 1.2e3 -> '1200')."""
    if v is None:
        return ""
    if isinstance(v, bool):
        return "1" if v else "0"
    if isinstance(v, int):
        return str(v)
    if isinstance(v, float):
        try:
            d = Decimal(str(v))
            if d == d.to_integral_value():
                return str(int(d))
            return format(d.normalize(), "f")
        except InvalidOperation:
            return str(v).strip()
    # strings: keep as-is, just trim
    return str(v).replace("\u00A0", " ").strip()

def norm_code(v):
    """Normalize codes/IDs/doc numbers: stable text; fixes Excel numeric coercion."""
    return norm_num(v)
