def _ensure_pdf_font():
    """Register a Unicode-capable TTF for ReportLab PDF exports (Arabic supported if font has glyphs).
    Falls back to Helvetica if no TTF is found or registration fails.
    """
    try:
        from reportlab.pdfbase import pdfmetrics
        from reportlab.pdfbase.ttfonts import TTFont
    except Exception:
        return "Helvetica"

    font_name = "SWERPFont"
    try:
        _ = pdfmetrics.getFont(font_name)
        return font_name
    except Exception:
        pass

    candidates = []
    # 1) Local folder next to script (user can drop a font file there)
    try:
        base_dir = os.path.dirname(os.path.abspath(__file__))
        candidates += [
            os.path.join(base_dir, "DejaVuSans.ttf"),
            os.path.join(base_dir, "NotoNaskhArabic-Regular.ttf"),
            os.path.join(base_dir, "NotoSansArabic-Regular.ttf"),
        ]
    except Exception:
        pass

    # 2) Common Linux paths
    candidates += [
        "/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf",
        "/usr/share/fonts/truetype/dejavu/DejaVuSansCondensed.ttf",
        "/usr/share/fonts/truetype/noto/NotoNaskhArabic-Regular.ttf",
        "/usr/share/fonts/truetype/noto/NotoSansArabic-Regular.ttf",
    ]

    # 3) Common Windows paths
    candidates += [
        "C:/Windows/Fonts/arial.ttf",
        "C:/Windows/Fonts/tahoma.ttf",
        "C:/Windows/Fonts/segoeui.ttf",
        "C:/Windows/Fonts/Arialuni.ttf",
    ]

    font_path = None
    for p in candidates:
        try:
            if p and os.path.exists(p):
                font_path = p
                break
        except Exception:
            continue

    if not font_path:
        return "Helvetica"

    try:
        pdfmetrics.registerFont(TTFont(font_name, font_path))
        return font_name
    except Exception:
        return "Helvetica"


def _has_arabic(s: str) -> bool:
    try:
        return any("\u0600" <= ch <= "\u06FF" or "\u0750" <= ch <= "\u077F" or "\u08A0" <= ch <= "\u08FF" for ch in s)
    except Exception:
        return False

# --- Basic Arabic shaping + bidi fallback (no extra deps) ---
# If arabic_reshaper + python-bidi are installed, we prefer them.
# Otherwise we use a lightweight internal shaper so Arabic prints connected and RTL in ReportLab.
_ARABIC_FORMS = {
    # letter: (isolated, final, initial, medial)
    "\u0627": ("\uFE8D","\uFE8E",None,None),  # ALEF
    "\u0628": ("\uFE8F","\uFE90","\uFE91","\uFE92"),  # BEH
    "\u062A": ("\uFE95","\uFE96","\uFE97","\uFE98"),  # TEH
    "\u062B": ("\uFE99","\uFE9A","\uFE9B","\uFE9C"),  # THEH
    "\u062C": ("\uFE9D","\uFE9E","\uFE9F","\uFEA0"),  # JEEM
    "\u062D": ("\uFEA1","\uFEA2","\uFEA3","\uFEA4"),  # HAH
    "\u062E": ("\uFEA5","\uFEA6","\uFEA7","\uFEA8"),  # KHAH
    "\u062F": ("\uFEA9","\uFEAA",None,None),  # DAL
    "\u0630": ("\uFEAB","\uFEAC",None,None),  # THAL
    "\u0631": ("\uFEAD","\uFEAE",None,None),  # REH
    "\u0632": ("\uFEAF","\uFEB0",None,None),  # ZAIN
    "\u0633": ("\uFEB1","\uFEB2","\uFEB3","\uFEB4"),  # SEEN
    "\u0634": ("\uFEB5","\uFEB6","\uFEB7","\uFEB8"),  # SHEEN
    "\u0635": ("\uFEB9","\uFEBA","\uFEBB","\uFEBC"),  # SAD
    "\u0636": ("\uFEBD","\uFEBE","\uFEBF","\uFEC0"),  # DAD
    "\u0637": ("\uFEC1","\uFEC2","\uFEC3","\uFEC4"),  # TAH
    "\u0638": ("\uFEC5","\uFEC6","\uFEC7","\uFEC8"),  # ZAH
    "\u0639": ("\uFEC9","\uFECA","\uFECB","\uFECC"),  # AIN
    "\u063A": ("\uFECD","\uFECE","\uFECF","\uFED0"),  # GHAIN
    "\u0641": ("\uFED1","\uFED2","\uFED3","\uFED4"),  # FEH
    "\u0642": ("\uFED5","\uFED6","\uFED7","\uFED8"),  # QAF
    "\u0643": ("\uFED9","\uFEDA","\uFEDB","\uFEDC"),  # KAF
    "\u0644": ("\uFEDD","\uFEDE","\uFEDF","\uFEE0"),  # LAM
    "\u0645": ("\uFEE1","\uFEE2","\uFEE3","\uFEE4"),  # MEEM
    "\u0646": ("\uFEE5","\uFEE6","\uFEE7","\uFEE8"),  # NOON
    "\u0647": ("\uFEE9","\uFEEA","\uFEEB","\uFEEC"),  # HEH
    "\u0648": ("\uFEED","\uFEEE",None,None),  # WAW
    "\u064A": ("\uFEF1","\uFEF2","\uFEF3","\uFEF4"),  # YEH
    "\u0629": ("\uFE93","\uFE94",None,None),  # TEH MARBUTA
    "\u0621": ("\uFE80","\uFE80",None,None),  # HAMZA
    "\u0623": ("\uFE83","\uFE84",None,None),  # ALEF WITH HAMZA ABOVE
    "\u0625": ("\uFE87","\uFE88",None,None),  # ALEF WITH HAMZA BELOW
    "\u0622": ("\uFE81","\uFE82",None,None),  # ALEF WITH MADDA
    "\u0649": ("\uFEEF","\uFEF0",None,None),  # ALEF MAKSURA (right-joining)
}
# Characters that do not connect to the next character on the left (i.e., they are right-joining only)
_RIGHT_JOINING_ONLY = set([
    "\u0627","\u0622","\u0623","\u0625","\u0621","\u0629","\u0648","\u0649","\u062F","\u0630","\u0631","\u0632"
])

_TATWEEL = "\u0640"
_DIACRITICS = set(chr(c) for c in range(0x064B, 0x065F+1))  # harakat etc.

def _is_arabic_letter(ch: str) -> bool:
    return ch in _ARABIC_FORMS

def _can_connect_right(ch: str) -> bool:
    # can connect to previous (on the right side in logical order)
    return _is_arabic_letter(ch) and ch not in _DIACRITICS

def _can_connect_left(ch: str) -> bool:
    # can connect to next (on the left side in logical order)
    return _is_arabic_letter(ch) and ch not in _RIGHT_JOINING_ONLY and ch not in _DIACRITICS

def _arabic_shape_basic(s: str) -> str:
    # Keep diacritics and tatweel as-is; shape letters into presentation forms.
    chars = list(s)
    out = []
    n = len(chars)
    for i, ch in enumerate(chars):
        if not _is_arabic_letter(ch):
            out.append(ch)
            continue

        prev_ch = chars[i-1] if i-1 >= 0 else ""
        next_ch = chars[i+1] if i+1 < n else ""

        # Skip over diacritics when checking neighbors
        j = i-1
        while j >= 0 and chars[j] in _DIACRITICS:
            j -= 1
        prev_ch = chars[j] if j >= 0 else ""

        k = i+1
        while k < n and chars[k] in _DIACRITICS:
            k += 1
        next_ch = chars[k] if k < n else ""

        connect_prev = _can_connect_left(prev_ch) and _can_connect_right(ch)
        connect_next = _can_connect_left(ch) and _can_connect_right(next_ch)

        iso, fin, ini, med = _ARABIC_FORMS.get(ch, (ch, ch, ch, ch))
        if connect_prev and connect_next and med:
            out.append(med)
        elif connect_prev and fin:
            out.append(fin)
        elif connect_next and ini:
            out.append(ini)
        else:
            out.append(iso if iso else ch)

    return "".join(out)

def _bidi_basic(s: str) -> str:
    # Very lightweight RTL: reverse overall string, but keep latin/digits sequences LTR.
    # This is a heuristic; python-bidi is preferred when available.
    import re as _re
    # Mark segments: arabic vs non-arabic
    parts = []
    buf = ""
    buf_is_ar = None
    for ch in s:
        is_ar = _has_arabic(ch)
        if buf_is_ar is None:
            buf_is_ar = is_ar
            buf = ch
        elif is_ar == buf_is_ar:
            buf += ch
        else:
            parts.append((buf_is_ar, buf))
            buf_is_ar = is_ar
            buf = ch
    if buf:
        parts.append((buf_is_ar, buf))

    # Reverse arabic parts and reverse order of parts (RTL), then fix LTR runs of digits/latin by re-reversing them
    parts = list(reversed(parts))
    out = []
    for is_ar, seg in parts:
        if is_ar:
            out.append(seg[::-1])
        else:
            # keep as-is, but reverse digit/latin sequences inside because overall order flipped
            out.append(seg)
    out_s = "".join(out)
    # Fix common number runs: reverse them back
    out_s = _re.sub(r"([0-9A-Za-z\-/\.]+)", lambda m: m.group(1)[::-1], out_s)
    return out_s


# ---- Arabic PDF shaping support ----
def _pdf_arabic_libs_ok() -> bool:
    try:
        import arabic_reshaper  # type: ignore
        from bidi.algorithm import get_display  # type: ignore
        return True
    except Exception:
        return False

def _ensure_pdf_arabic_deps() -> None:
    """Ensure Arabic shaping dependencies are available for PDF printing.

    Final V8 policy:
    - never auto-install at runtime
    - fail clearly with packaging guidance
    - stay compatible with PyInstaller/Nuitka builds
    """
    try:
        import arabic_reshaper  # type: ignore
        from bidi.algorithm import get_display  # type: ignore
        return
    except Exception as e:
        runtime_hint = []
        try:
            if getattr(sys, "frozen", False):
                runtime_hint.append("frozen build detected")
        except Exception:
            pass
        hint = ("; " + ", ".join(runtime_hint)) if runtime_hint else ""
        raise RuntimeError(
            "Arabic PDF printing requires bundled dependencies: arabic-reshaper and python-bidi. "
            "Install them before packaging, and include them in the EXE build if you are using PyInstaller/Nuitka"
            f"{hint}. Current interpreter: {sys.executable}"
        ) from e

def _pdf_text(s: str, lang: str) -> str:
    """Prepare text for ReportLab PDF.

    - Non-Arabic: returns as-is
    - Arabic: uses arabic_reshaper + python-bidi (auto-installed if missing)
    """
    try:
        s = "" if s is None else str(s)
    except Exception:
        return ""
    if not s:
        return ""
    if lang != "ar" or not _has_arabic(s):
        return s

    _ensure_pdf_arabic_deps()
    import arabic_reshaper  # type: ignore
    from bidi.algorithm import get_display  # type: ignore
    return get_display(arabic_reshaper.reshape(s))



    # Prefer external libs if available
    try:
        import arabic_reshaper  # type: ignore
        from bidi.algorithm import get_display  # type: ignore
        return get_display(arabic_reshaper.reshape(s))
    except Exception:
        # Internal fallback: basic shaping + bidi heuristic
        try:
            shaped = _arabic_shape_basic(s)
            return _bidi_basic(shaped)
        except Exception:
            return s


def export_view_as_pdf(view, qs, lang="ar"):
    try:
        from reportlab.lib.pagesizes import A4, landscape
        from reportlab.platypus import SimpleDocTemplate, Table, TableStyle, Paragraph, Spacer
        from reportlab.lib import colors
        from reportlab.lib.styles import getSampleStyleSheet
    except Exception as e:
        raise RuntimeError("Missing dependency: reportlab. Install: pip install reportlab") from e

    view=(view or "").strip().lower()
    title=view
    if view=="items":
        rows=[dict(r) for r in list_rows("Items", (qs.get("q",[""])[0] or ""), order_by="item_code")]
        item_ids=[int(r.get("id") or 0) for r in rows if str(r.get("id") or "").isdigit()]
        latest_price_map={}
        if item_ids:
            con_lp=db_connect()
            try:
                ph=",".join(["?"]*len(item_ids))
                sql_lp=f"""
                    SELECT item_id, unit_price
                    FROM (
                        SELECT item_id, unit_price,
                               ROW_NUMBER() OVER (PARTITION BY item_id ORDER BY ts DESC, id DESC) AS rn
                        FROM Transactions
                        WHERE voided=0
                          AND unit_price IS NOT NULL
                          AND CAST(unit_price AS REAL) > 0
                          AND item_id IN ({ph})
                    ) z
                    WHERE rn=1
                """
                for rr in con_lp.execute(sql_lp, tuple(item_ids)).fetchall():
                    iid = rr[0] if not isinstance(rr, sqlite3.Row) else rr["item_id"]
                    up = rr[1] if not isinstance(rr, sqlite3.Row) else rr["unit_price"]
                    try:
                        latest_price_map[int(iid)] = float(up)
                    except Exception:
                        pass
            finally:
                try:
                    con_lp.close()
                except Exception:
                    pass
