def _safe_ext(filename: str) -> str:
    fn = (filename or "").lower()
    if "." not in fn:
        return ""
    return "." + fn.rsplit(".", 1)[1]

def _looks_like_pdf(data: bytes) -> bool:
    """Best-effort PDF signature check (server-side)."""
    try:
        if not data:
            return False
        head = data.lstrip()[:8]
        return head.startswith(b"%PDF-")
    except Exception:
        return False

def _looks_like_image(ext: str, data: bytes) -> bool:
    ext = (ext or "").lower()
    if not data:
        return False
    if ext in (".jpg", ".jpeg"):
        return data[:3] == b"\xff\xd8\xff"
    if ext == ".png":
        return data[:8] == b"\x89PNG\r\n\x1a\n"
    if ext == ".gif":
        return data[:6] in (b"GIF87a", b"GIF89a")
    if ext == ".webp":
        return len(data) >= 12 and data[:4] == b"RIFF" and data[8:12] == b"WEBP"
    return False

def _looks_like_excel_upload(ext: str, data: bytes) -> bool:
    ext = (ext or "").lower()
    if ext in (".xlsx", ".xlsm", ".xltx", ".xltm"):
        return bool(data) and data[:2] == b"PK"
    return False

def _friendly_upload_error(lang: str, kind: str, err) -> str:
    is_ar = (lang or "en").lower().startswith("ar")
    def _msg(en, ar):
        return ar if is_ar else en
    raw = str(err or "").strip()
    kind_title = {
        "attachment": _msg("Attachment upload failed", "فشل رفع المرفق"),
        "image": _msg("Image upload failed", "فشل رفع الصورة"),
        "excel": _msg("Excel import failed", "فشل استيراد الإكسيل"),
    }.get(kind, _msg("Upload failed", "فشل الرفع"))
    lower = raw.lower()
    if "csrf validation failed" in lower:
        detail = _msg("Session protection check failed; reopen the page and try again", "فشل تحقق الحماية للجلسة؛ افتح الصفحة مرة أخرى ثم أعد المحاولة")
    elif "upload too large" in lower or "too large" in lower:
        detail = _msg("The file is larger than the allowed size", "حجم الملف أكبر من الحد المسموح")
        m = re.search(r"max\s*(\d+)\s*mb", raw, re.I)
        if m:
            detail += f" ({m.group(1)} MB)"
    elif "invalid image type" in lower:
        detail = _msg("Allowed image types: JPG, PNG, WEBP, GIF", "أنواع الصور المسموحة: JPG و PNG و WEBP و GIF")
    elif "invalid image content" in lower:
        detail = _msg("The uploaded image file appears invalid or damaged", "ملف الصورة المرفوع غير صالح أو تالف")
    elif "image too large" in lower:
        detail = _msg("The image is larger than the allowed size", "حجم الصورة أكبر من الحد المسموح")
    elif "pdf only" in lower:
        detail = _msg("Only PDF files are allowed", "يسمح بملفات PDF فقط")
    elif "invalid pdf" in lower:
        detail = _msg("The PDF file appears invalid or damaged", "ملف الـ PDF غير صالح أو تالف")
    elif "pdf too large" in lower:
        detail = _msg("The PDF is larger than the allowed size", "حجم ملف الـ PDF أكبر من الحد المسموح")
    elif "excel only" in lower:
        detail = _msg("Allowed Excel types: XLSX, XLSM, XLTX, XLTM", "أنواع الإكسيل المسموحة: XLSX و XLSM و XLTX و XLTM")
    elif "invalid excel" in lower:
        detail = _msg("The Excel file appears invalid or damaged", "ملف الإكسيل غير صالح أو تالف")
    elif "excel file too large" in lower:
        detail = _msg("The Excel file is larger than the allowed size", "حجم ملف الإكسيل أكبر من الحد المسموح")
    elif raw:
        detail = raw
    else:
        detail = _msg("Unknown error", "خطأ غير معروف")
    return f"❌ {kind_title}: {detail}"


def _rand_name(prefix: str, ext: str) -> str:
    return f"{prefix}_{secrets.token_hex(8)}{ext}"

def _abs_norm(path: str) -> str:
    try:
        return os.path.abspath(str(path or "")).replace(chr(92), "/")
    except Exception:
        return ""

def _is_path_within(base_dir: str, path: str) -> bool:
    base = _abs_norm(base_dir).rstrip("/")
    target = _abs_norm(path)
    return bool(base and target and (target == base or target.startswith(base + "/")))

def _safe_unlink_file(path: str, *, allowed_roots=None) -> bool:
    target = _abs_norm(path)
    if not target or not os.path.exists(target):
        return False
    roots = [r for r in (allowed_roots or [UPLOAD_ROOT]) if r]
    if roots and not any(_is_path_within(r, target) for r in roots):
        raise ValueError(f"Refusing to delete file outside allowed roots: {target}")
    os.remove(target)
    return True

def cleanup_stale_upload_temps(max_age_hours: int = 24) -> dict:
    """Best-effort cleanup for interrupted atomic upload temp files."""
    now_ts = time.time()
    removed = 0
    scanned = 0
    cutoff = float(max_age_hours or 24) * 3600.0
    for root in (ITEM_IMG_DIR, TXN_PDF_DIR):
        try:
            os.makedirs(root, exist_ok=True)
            for name in os.listdir(root):
                if not name.startswith('.upload_') or not name.endswith('.tmp'):
                    continue
                scanned += 1
                fp = os.path.join(root, name)
                try:
                    age = now_ts - os.path.getmtime(fp)
                except Exception:
                    age = cutoff + 1
                if age >= cutoff:
                    try:
                        _safe_unlink_file(fp, allowed_roots=[ITEM_IMG_DIR, TXN_PDF_DIR])
                        removed += 1
                    except Exception:
                        pass
        except Exception:
            continue
    return {"scanned": scanned, "removed": removed, "max_age_hours": int(max_age_hours or 24)}

def _safe_write_file_atomic(final_path: str, data: bytes):
    """Write file atomically to reduce orphan/partial uploads on crashes."""
    final_path = os.path.abspath(final_path)
    parent = os.path.dirname(final_path) or BASE_DIR
    os.makedirs(parent, exist_ok=True)
    fd, tmp_path = tempfile.mkstemp(prefix='.upload_', suffix='.tmp', dir=parent)
    try:
        with os.fdopen(fd, 'wb') as f:
            f.write(data or b'')
            try:
                f.flush()
                os.fsync(f.fileno())
            except Exception:
                pass
        os.replace(tmp_path, final_path)
    except Exception:
        try:
            os.remove(tmp_path)
        except Exception:
            pass
        raise

def _db_get_item_by_code(code: str):
    if not code:
        return None
    norm = _norm_code(code)
    if not norm:
        return None
    con = db_connect()
    try:
        r = con.execute(
            "SELECT id, item_code, item_name, image_path FROM Items WHERE UPPER(TRIM(item_code))=?",
            (norm,)
        ).fetchone()
        if not r:
            r = con.execute(
                "SELECT id, item_code, item_name, image_path FROM Items WHERE item_code=?",
                (str(code).strip(),)
            ).fetchone()
        return dict(r) if r else None
    finally:
        con.close()


def _db_get_txn(txn_id: int):
    """Compatibility helper for old UI/read-only paths.
    Delegates to the modern repo when available so views read the same source of truth
    as the Transaction Engine.
    """
    try:
        c = get_container()
        tx = c.txn_repo.get_by_id(int(txn_id))
        if tx:
            return tx
    except Exception:
        pass
    con = db_connect()
    try:
        r = con.execute("SELECT id, txn_type, attachment_path FROM Transactions WHERE id=?", (txn_id,)).fetchone()
        return dict(r) if r else None
    finally:
        con.close()


