TOOL_MOVE_PDF_DIR = os.path.join(UPLOAD_ROOT, "tool_move_pdfs")
os.makedirs(TOOL_MOVE_PDF_DIR, exist_ok=True)


def ensure_tool_tracking_schema():
    con = db_connect()
    try:
        cur = con.cursor()
        cur.execute("""
            CREATE TABLE IF NOT EXISTS ToolMovements(
              id INTEGER PRIMARY KEY AUTOINCREMENT,
              tool_id INTEGER NOT NULL,
              movement_date TEXT NOT NULL,
              movement_type TEXT NOT NULL,
              from_wh_id INTEGER,
              to_wh_id INTEGER,
              person_name TEXT,
              condition_text TEXT,
              return_good INTEGER NOT NULL DEFAULT 0,
              return_damaged INTEGER NOT NULL DEFAULT 0,
              return_maintenance INTEGER NOT NULL DEFAULT 0,
              notes TEXT,
              attachment_path TEXT,
              created_at TEXT,
              created_by TEXT,
              updated_at TEXT,
              updated_by TEXT,
              FOREIGN KEY(tool_id) REFERENCES Tools(id)
            );
        """)
        cur.execute("CREATE INDEX IF NOT EXISTS idx_toolmoves_tool_date ON ToolMovements(tool_id, movement_date DESC, id DESC);")
        cur.execute("CREATE INDEX IF NOT EXISTS idx_toolmoves_type ON ToolMovements(movement_type);")
        _ensure_column(cur, "Tools", "current_location_type", "current_location_type TEXT")
        _ensure_column(cur, "Tools", "current_wh_id", "current_wh_id INTEGER")
        _ensure_column(cur, "Tools", "custodian_name", "custodian_name TEXT")
        _ensure_column(cur, "Tools", "current_condition", "current_condition TEXT")
        _ensure_column(cur, "Tools", "status", "status TEXT")
        _ensure_column(cur, "Tools", "updated_at", "updated_at TEXT")
        try:
            cur.execute("UPDATE Tools SET current_location_type='warehouse' WHERE current_location_type IS NULL OR TRIM(current_location_type)='';")
        except Exception:
            pass
        if not _in_atomic_db():
            con.commit()
    finally:
        try: con.close()
        except Exception: pass


def _tool_validate_pdf_upload(filename: str, data: bytes):
    ext = _safe_ext(filename or '')
    if ext != '.pdf':
        raise ValueError('PDF only')
    if not _looks_like_pdf(data):
        raise ValueError('Invalid PDF')
    if len(data or b'') > MAX_TXN_PDF_BYTES:
        raise ValueError('PDF too large')


def _tool_save_pdf(filename: str, data: bytes) -> str:
    _tool_validate_pdf_upload(filename, data)
    os.makedirs(TOOL_MOVE_PDF_DIR, exist_ok=True)
    fs_path = os.path.join(TOOL_MOVE_PDF_DIR, _rand_name('tool_move', '.pdf'))
    _safe_write_file_atomic(fs_path, data)
    return fs_path


def _tool_clean_file(fs_path: str):
    try:
        if fs_path and os.path.exists(fs_path):
            os.remove(fs_path)
    except Exception:
        pass


def _tool_condition_from_flags(good=False, damaged=False, maintenance=False, fallback=''):
    if good:
        return 'سليم'
    vals = []
    if damaged:
        vals.append('به عطل')
    if maintenance:
        vals.append('يحتاج صيانة')
    if vals:
        return ' + '.join(vals)
    return (fallback or '').strip()


def _tool_last_person_for_return(conn, tool_id: int) -> str:
    r = conn.execute("""
        SELECT person_name FROM ToolMovements
        WHERE tool_id=? AND movement_type IN ('ISSUE_PERSON','RETURN_PERSON')
        ORDER BY movement_date DESC, id DESC LIMIT 1
    """, (int(tool_id),)).fetchone()
    return ((r['person_name'] if isinstance(r, sqlite3.Row) else (r[0] if r else '')) or '').strip() if r else ''


def _tool_sync_state_conn(conn, tool_id: int):
    row = conn.execute("SELECT current_wh_id, current_condition, status FROM Tools WHERE id=?", (int(tool_id),)).fetchone()
    if not row:
        return
    last = conn.execute("SELECT * FROM ToolMovements WHERE tool_id=? ORDER BY movement_date DESC, id DESC LIMIT 1", (int(tool_id),)).fetchone()
    location_type = 'warehouse'
    current_wh_id = row['current_wh_id'] if isinstance(row, sqlite3.Row) else row[0]
    custodian_name = ''
    current_condition = ((row['current_condition'] if isinstance(row, sqlite3.Row) else row[1]) or 'سليم').strip() or 'سليم'
    status_text = current_condition
    if last:
        mv = dict(last)
        mtype = (mv.get('movement_type') or '').upper()
        if mtype in ('RECEIVE','TRANSFER'):
            location_type = 'warehouse'
            current_wh_id = mv.get('to_wh_id') or mv.get('from_wh_id') or current_wh_id
            custodian_name = ''
            current_condition = (mv.get('condition_text') or current_condition or 'سليم').strip() or 'سليم'
            status_text = current_condition
        elif mtype == 'ISSUE_PERSON':
            location_type = 'person'
            current_wh_id = mv.get('from_wh_id') or current_wh_id
            custodian_name = (mv.get('person_name') or '').strip()
            current_condition = (mv.get('condition_text') or current_condition or 'بعهدة').strip() or 'بعهدة'
            status_text = 'بعهدة'
        elif mtype == 'RETURN_PERSON':
            location_type = 'warehouse'
            current_wh_id = mv.get('to_wh_id') or current_wh_id
            custodian_name = ''
            current_condition = _tool_condition_from_flags(bool(int(mv.get('return_good') or 0)), bool(int(mv.get('return_damaged') or 0)), bool(int(mv.get('return_maintenance') or 0)), mv.get('condition_text') or current_condition or 'سليم')
            status_text = current_condition
    conn.execute("UPDATE Tools SET current_location_type=?, current_wh_id=?, custodian_name=?, current_condition=?, status=?, updated_at=? WHERE id=?", (location_type, current_wh_id, custodian_name, current_condition, status_text, _now().isoformat(timespec='seconds'), int(tool_id)))


def _tool_save_master(form, user, role, ip):
    ensure_tool_tracking_schema()
    rid = (form.get('id', [''])[0] or '').strip()
    rid_i = int(rid) if rid.isdigit() else None
    tool_code = (form.get('tool_code', [''])[0] or '').strip()
    tool_name = (form.get('tool_name', [''])[0] or '').strip()
    if not tool_code or not tool_name:
        raise ValueError('كود الأداة واسم الأداة مطلوبان')
    current_wh_id_s = (form.get('current_wh_id', [''])[0] or '').strip()
    current_wh_id = int(current_wh_id_s) if current_wh_id_s.isdigit() else None
    current_condition = (form.get('status', [''])[0] or '').strip() or 'سليم'
    min_qty_raw = (form.get('min_qty', ['0'])[0] or '0').strip()
    try:
        min_qty = float(min_qty_raw) if min_qty_raw not in ('', '.', '-', '+') else 0.0
    except Exception:
        min_qty = 0.0
    payload = {
        'tool_code': tool_code,
        'tool_name': tool_name,
        'category': (form.get('category', [''])[0] or '').strip(),
        'unit': (form.get('unit', [''])[0] or '').strip(),
        'min_qty': min_qty,
        'notes': (form.get('notes', [''])[0] or '').strip(),
        'status': current_condition,
        'current_location_type': 'warehouse',
        'current_wh_id': current_wh_id,
        'custodian_name': '',
        'current_condition': current_condition,
        'updated_at': _now().isoformat(timespec='seconds'),
        'active': 1,
    }
    upsert_row('Tools', rid_i, payload, audit={
        'username': user,
        'action': 'UPDATE_TOOL' if rid_i else 'INSERT_TOOL',
        'entity': 'Tools',
        'entity_id': rid_i,
        'details': {'tool_code': tool_code},
        'ip': ip,
        'role': role,
    })


def _tool_save_movement(fields, files, user, role, ip):
    ensure_tool_tracking_schema()
    def _fv(mapping, key, default=''):
        try:
            val = (mapping or {}).get(key, default)
        except Exception:
            return default
        if isinstance(val, list):
            return val[0] if val else default
        return default if val is None else val
    move_id_s = str(_fv(fields, 'move_id', '') or '').strip()
    move_id = int(move_id_s) if move_id_s.isdigit() else None
    tool_id_s = str(_fv(fields, 'tool_id', '') or '').strip()
    if not tool_id_s.isdigit():
        raise ValueError('الأداة مطلوبة')
    tool_id = int(tool_id_s)
    movement_type = (str(_fv(fields, 'movement_type', '') or '').strip() or 'RECEIVE').upper()
    movement_date = (str(_fv(fields, 'movement_date', '') or '').strip() or datetime.now().strftime('%Y-%m-%d'))[:10]
    try:
        datetime.strptime(movement_date, '%Y-%m-%d')
    except Exception:
        raise ValueError('تاريخ الحركة غير صحيح')
    from_wh_id_s = str(_fv(fields, 'from_wh_id', '') or '').strip()
    to_wh_id_s = str(_fv(fields, 'to_wh_id', '') or '').strip()
    from_wh_id = int(from_wh_id_s) if from_wh_id_s.isdigit() else None
    to_wh_id = int(to_wh_id_s) if to_wh_id_s.isdigit() else None
    person_name = str(_fv(fields, 'person_name', '') or '').strip()
    notes = str(_fv(fields, 'notes', '') or '').strip()
    return_good = 1 if str(_fv(fields, 'return_good', '') or '').strip() in ('1','true','on','yes') else 0
    return_damaged = 1 if str(_fv(fields, 'return_damaged', '') or '').strip() in ('1','true','on','yes') else 0
    return_maintenance = 1 if str(_fv(fields, 'return_maintenance', '') or '').strip() in ('1','true','on','yes') else 0
    if movement_type == 'RECEIVE':
        if not to_wh_id:
            raise ValueError('مستودع الاستلام مطلوب')
        condition_text = 'سليم'
    elif movement_type == 'TRANSFER':
        if not from_wh_id or not to_wh_id:
            raise ValueError('من وإلى مستودع مطلوبان')
        if from_wh_id == to_wh_id:
            raise ValueError('لا يمكن التحويل إلى نفس المستودع')
        condition_text = 'سليم'
    elif movement_type == 'ISSUE_PERSON':
        if not from_wh_id:
            raise ValueError('المستودع الحالي مطلوب')
        if not person_name:
            raise ValueError('اسم الشخص مطلوب')
        condition_text = 'بعهدة'
    elif movement_type == 'RETURN_PERSON':
        if not to_wh_id:
            raise ValueError('المستودع الراجع إليه مطلوب')
        if not person_name:
            person_name = ''
        if not (return_good or return_damaged or return_maintenance):
            return_good = 1
        condition_text = _tool_condition_from_flags(return_good, return_damaged, return_maintenance, '') or 'سليم'
    else:
        raise ValueError('نوع الحركة غير مدعوم')
    conn = db_connect()
    try:
        snap = conn.execute("SELECT * FROM Tools WHERE id=?", (tool_id,)).fetchone()
        if not snap:
            raise ValueError('الأداة غير موجودة')
        snap = dict(snap)
        if movement_type == 'TRANSFER':
            expected = int(snap.get('current_wh_id') or 0) if str(snap.get('current_wh_id') or '').isdigit() else None
            if expected and from_wh_id and expected != from_wh_id and not move_id:
                raise ValueError('الأداة ليست في هذا المستودع حاليًا')
        if movement_type == 'ISSUE_PERSON':
            if str(snap.get('current_location_type') or 'warehouse') == 'person' and not move_id:
                raise ValueError('الأداة بعهدة شخص بالفعل')
        if movement_type == 'RETURN_PERSON':
            if str(snap.get('current_location_type') or 'warehouse') != 'person' and not move_id:
                raise ValueError('الأداة ليست بعهدة شخص حاليًا')
            if not person_name:
                person_name = _tool_last_person_for_return(conn, tool_id)
        old_attachment = ''
        if move_id:
            old = conn.execute('SELECT attachment_path, tool_id FROM ToolMovements WHERE id=?', (move_id,)).fetchone()
            if not old:
                raise ValueError('حركة الأداة غير موجودة')
            old_attachment = str(old['attachment_path'] or '')
        uploaded = _fv(files, 'pdf', None) if isinstance(files, dict) else None
        new_attachment = old_attachment
        if uploaded and ((isinstance(uploaded, dict) and uploaded.get('filename')) or (isinstance(uploaded, tuple) and len(uploaded) >= 1 and uploaded[0])):
            if isinstance(uploaded, tuple):
                up_filename = uploaded[0] if len(uploaded) > 0 else ''
                up_content = uploaded[1] if len(uploaded) > 1 else b''
            else:
                up_filename = uploaded.get('filename')
                up_content = uploaded.get('content') or b''
            new_attachment = _tool_save_pdf(up_filename, up_content)
        elif str(_fv(fields, 'remove_attachment', '') or '').strip() in ('1','true','on','yes'):
            new_attachment = ''
        payload = {
            'tool_id': tool_id,
            'movement_date': movement_date,
            'movement_type': movement_type,
            'from_wh_id': from_wh_id,
            'to_wh_id': to_wh_id,
            'person_name': person_name,
            'condition_text': condition_text,
            'return_good': int(return_good),
            'return_damaged': int(return_damaged),
            'return_maintenance': int(return_maintenance),
            'notes': notes,
            'attachment_path': new_attachment,
            'updated_at': _now().isoformat(timespec='seconds'),
            'updated_by': user,
        }
        if move_id:
            sets = ', '.join([f"{k}=?" for k in payload.keys()])
            conn.execute(f"UPDATE ToolMovements SET {sets} WHERE id=?", list(payload.values()) + [move_id])
            move_pk = move_id
        else:
            payload['created_at'] = payload['updated_at']
            payload['created_by'] = user
            cols = ','.join(payload.keys())
            ph = ','.join(['?']*len(payload))
            cur = conn.execute(f"INSERT INTO ToolMovements({cols}) VALUES ({ph})", list(payload.values()))
            move_pk = int(cur.lastrowid)
        _tool_sync_state_conn(conn, tool_id)
        conn.commit()
        if old_attachment and old_attachment != new_attachment:
            _tool_clean_file(old_attachment)
        audit_log(user, 'UPDATE_TOOL_MOVE' if move_id else 'INSERT_TOOL_MOVE', entity='ToolMovements', entity_id=move_pk, details={'tool_id': tool_id, 'movement_type': movement_type}, ip=ip, role=role)
    except Exception:
        conn.rollback()
        raise
    finally:
        conn.close()


def _tool_delete_movement(move_id: int, user, role, ip):
    ensure_tool_tracking_schema()
    con = db_connect()
    try:
        row = con.execute('SELECT tool_id, attachment_path FROM ToolMovements WHERE id=?', (int(move_id),)).fetchone()
        if not row:
            raise ValueError('حركة الأداة غير موجودة')
        tool_id = int(row['tool_id'])
        attachment = str(row['attachment_path'] or '')
        con.execute('DELETE FROM ToolMovements WHERE id=?', (int(move_id),))
        _tool_sync_state_conn(con, tool_id)
        con.commit()
        _tool_clean_file(attachment)
        audit_log(user, 'DELETE_TOOL_MOVE', entity='ToolMovements', entity_id=int(move_id), details={'tool_id': tool_id}, ip=ip, role=role)
    except Exception:
        con.rollback(); raise
    finally:
        con.close()


def _tool_delete_tool(tool_id: int, user, role, ip):
    ensure_tool_tracking_schema()
    con = db_connect()
    try:
        r = con.execute('SELECT id FROM Tools WHERE id=?', (int(tool_id),)).fetchone()
        if not r:
            raise ValueError('أداة غير صحيحة')
        paths = [str(rr['attachment_path'] or '') for rr in con.execute('SELECT attachment_path FROM ToolMovements WHERE tool_id=?', (int(tool_id),)).fetchall()]
        con.execute('DELETE FROM ToolMovements WHERE tool_id=?', (int(tool_id),))
        con.execute('DELETE FROM Tools WHERE id=?', (int(tool_id),))
        con.commit()
        for fp in paths:
            _tool_clean_file(fp)
        audit_log(user, 'DELETE_TOOL', entity='Tools', entity_id=int(tool_id), details={}, ip=ip, role=role)
    except Exception:
        con.rollback(); raise
    finally:
        con.close()


def _tool_collect_filters(qs):
    qs = qs or {}
    def _pick(name, default=''):
        val = qs.get(name, default)
        if isinstance(val, (list, tuple)):
            val = val[0] if val else default
        if val is None:
            val = default
        return str(val).strip()
    return {
        'q': _pick('q'),
        'tool_id': _pick('tool_id'),
        'wh_id': _pick('wh_id'),
        'loc': _pick('loc').lower(),
        'tool_status': _pick('tool_status'),
        'person': _pick('person'),
        'move_type': _pick('move_type').upper(),
        'move_wh_id': _pick('move_wh_id'),
        'from_date': _pick('from_date'),
        'to_date': _pick('to_date'),
    }


def list_tools_filtered(qs, con=None, limit=None):
    ensure_tool_tracking_schema()
    flt = _tool_collect_filters(qs)
    close_after = False
    if con is None:
        con = db_connect(); close_after = True
    try:
        params=[]; where=[]
        if flt['q']:
            like=f"%{flt['q'].upper()}%"
            where.append("(UPPER(COALESCE(t.tool_code,'')) LIKE ? OR UPPER(COALESCE(t.tool_name,'')) LIKE ? OR UPPER(COALESCE(t.category,'')) LIKE ? OR UPPER(COALESCE(t.unit,'')) LIKE ? OR UPPER(COALESCE(t.notes,'')) LIKE ?)")
            params.extend([like]*5)
        if flt['tool_id'].isdigit():
            where.append('t.id=?'); params.append(int(flt['tool_id']))
        if flt['wh_id'].isdigit():
            where.append('t.current_wh_id=?'); params.append(int(flt['wh_id']))
        if flt['loc'] in ('warehouse','person'):
            where.append("COALESCE(t.current_location_type,'warehouse')=?"); params.append(flt['loc'])
        if flt['tool_status']:
            where.append('UPPER(COALESCE(t.current_condition, t.status, "")) LIKE ?'); params.append(f"%{flt['tool_status'].upper()}%")
        if flt['person']:
            where.append("UPPER(COALESCE(t.custodian_name,'')) LIKE ?"); params.append(f"%{flt['person'].upper()}%")
        sql="""
            SELECT t.*, w.wh_code AS current_wh_code, w.wh_name AS current_wh_name
            FROM Tools t LEFT JOIN Warehouses w ON w.id=t.current_wh_id
        """
        if where: sql += ' WHERE ' + ' AND '.join(where)
        sql += ' ORDER BY t.tool_code, t.tool_name'
        if limit: sql += f' LIMIT {int(limit)}'
        return [dict(r) for r in con.execute(sql, tuple(params)).fetchall()]
    finally:
        if close_after:
            try: con.close()
            except Exception: pass


def list_tool_movements_filtered(qs, con=None, limit=250):
    ensure_tool_tracking_schema()
    flt = _tool_collect_filters(qs)
    close_after = False
    if con is None:
        con = db_connect(); close_after = True
    try:
        params=[]; where=[]
        if flt['tool_id'].isdigit():
            where.append('m.tool_id=?'); params.append(int(flt['tool_id']))
        if flt['q']:
            like=f"%{flt['q'].upper()}%"
            where.append("(UPPER(COALESCE(t.tool_code,'')) LIKE ? OR UPPER(COALESCE(t.tool_name,'')) LIKE ? OR UPPER(COALESCE(m.person_name,'')) LIKE ? OR UPPER(COALESCE(m.notes,'')) LIKE ?)")
            params.extend([like]*4)
        if flt['move_type']:
            where.append("UPPER(COALESCE(m.movement_type,''))=?"); params.append(flt['move_type'])
        if flt['move_wh_id'].isdigit():
            where.append('(m.from_wh_id=? OR m.to_wh_id=?)'); params.extend([int(flt['move_wh_id']), int(flt['move_wh_id'])])
        if flt['wh_id'].isdigit() and not flt['move_wh_id'].isdigit():
            where.append('(m.from_wh_id=? OR m.to_wh_id=?)'); params.extend([int(flt['wh_id']), int(flt['wh_id'])])
        if flt['person']:
            where.append("UPPER(COALESCE(m.person_name,'')) LIKE ?"); params.append(f"%{flt['person'].upper()}%")
        if flt['from_date']:
            where.append("COALESCE(m.movement_date,'') >= ?"); params.append(flt['from_date'])
        if flt['to_date']:
            where.append("COALESCE(m.movement_date,'') <= ?"); params.append(flt['to_date'])
        sql="""
            SELECT m.*, t.tool_code, t.tool_name, t.category, t.unit,
                   wf.wh_code AS from_wh_code, wf.wh_name AS from_wh_name,
                   wt.wh_code AS to_wh_code, wt.wh_name AS to_wh_name
            FROM ToolMovements m
            JOIN Tools t ON t.id = m.tool_id
            LEFT JOIN Warehouses wf ON wf.id = m.from_wh_id
            LEFT JOIN Warehouses wt ON wt.id = m.to_wh_id
        """
        if where: sql += ' WHERE ' + ' AND '.join(where)
        sql += ' ORDER BY m.movement_date DESC, m.id DESC'
        if limit: sql += f' LIMIT {int(limit)}'
        rows=[dict(r) for r in con.execute(sql, tuple(params)).fetchall()]
        for r in rows:
            r['movement_type_label'] = _asset_move_type_label(str(r.get('movement_type') or ''))
            r['return_condition'] = _tool_condition_from_flags(bool(int(r.get('return_good') or 0)), bool(int(r.get('return_damaged') or 0)), bool(int(r.get('return_maintenance') or 0)), str(r.get('condition_text') or ''))
            r['tool_display'] = ((str(r.get('tool_code') or '') + ' — ' + str(r.get('tool_name') or '')).strip(' —'))
        return rows
    finally:
        if close_after:
            try: con.close()
            except Exception: pass


