            if not selected_tool_obj:
                rr = con.execute("SELECT t.*, w.wh_name AS current_wh_name, w.wh_code AS current_wh_code FROM Tools t LEFT JOIN Warehouses w ON w.id=t.current_wh_id WHERE t.id=?", (selected_tool_id_i,)).fetchone()
                selected_tool_obj = dict(rr) if rr else None
