def _serve_file(handler, fs_path: str, download_name: str, download: bool):
    if not fs_path or not os.path.exists(fs_path):
        return handler._send_html("<h3>Not found</h3>", status=404)
    ctype = mimetypes.guess_type(fs_path)[0] or "application/octet-stream"
    try:
        with open(fs_path, "rb") as f:
            data = f.read()
    except Exception:
        return handler._send_html("<h3>Cannot read file</h3>", status=500)
    handler.send_response(200)
    handler.send_header("Content-Type", ctype)
    disp = "attachment" if download else "inline"
    handler.send_header("Content-Disposition", f"{disp}; filename=\"{download_name}\"")
    handler.send_header("Content-Length", str(len(data)))
    handler.end_headers()
    handler.wfile.write(data)


