def render_admin_tools(lang, user, role, qs):
    if role != "ADMIN":
        return page(lang, t(lang,"unauth"), "<div class='card'>Unauthorized</div>", user, role=role)
    con = db_connect()
    integrity = ""
    fk_issues = 0
    try:
        integrity = con.execute("PRAGMA integrity_check;").fetchone()[0]
    except Exception:
        integrity = ""
