def render_dashboard(lang, username, role):
    con = db_connect()
    try:
        kpi = {}
        kpi["items"] = con.execute("SELECT COUNT(*) c FROM Items WHERE active=1").fetchone()["c"]
        kpi["items_inactive"] = con.execute("SELECT COUNT(*) c FROM Items WHERE COALESCE(active,1)=0").fetchone()["c"]
        kpi["eq"] = con.execute("SELECT COUNT(*) c FROM Equipment WHERE active=1").fetchone()["c"]
        kpi["eq_inactive"] = con.execute("SELECT COUNT(*) c FROM Equipment WHERE COALESCE(active,1)=0").fetchone()["c"]
        kpi["wh"] = con.execute("SELECT COUNT(*) c FROM Warehouses WHERE active=1").fetchone()["c"]
        kpi["wh_inactive"] = con.execute("SELECT COUNT(*) c FROM Warehouses WHERE COALESCE(active,1)=0").fetchone()["c"]
        kpi["txn_total"] = con.execute("SELECT COUNT(*) c FROM Transactions WHERE voided=0").fetchone()["c"]
        kpi["txn_today"] = con.execute("SELECT COUNT(*) c FROM Transactions WHERE voided=0 AND date(ts)=date('now','localtime')").fetchone()["c"]
        kpi["req_total"] = (
            con.execute("SELECT COUNT(*) c FROM DailyRequests").fetchone()["c"]
            + con.execute("SELECT COUNT(*) c FROM StandaloneRequests").fetchone()["c"]
            + con.execute("SELECT COUNT(*) c FROM WorkflowRequests").fetchone()["c"]
        )

        last_txn = con.execute("SELECT MAX(substr(ts,1,19)) d FROM Transactions WHERE voided=0").fetchone()["d"] or ""
        last_req = con.execute(r"""
            SELECT MAX(d) AS d FROM (
                SELECT MAX(req_date) AS d FROM DailyRequests
                UNION ALL
                SELECT MAX(req_date) AS d FROM StandaloneRequests
                UNION ALL
                SELECT MAX(substr(created_at,1,10)) AS d FROM WorkflowRequests
            )
        """).fetchone()["d"] or ""

        inv_total, inv_warn = inventory_value_mavg_per_wh(con)
        inv_total = float(inv_total or 0.0)

        top_items = con.execute(r"""
          SELECT
            i.item_code, i.item_name,
            ROUND(COALESCE(SUM(CASE WHEN t.txn_type='ISSUE' THEN t.qty ELSE 0 END),0),3) AS issued_qty,
            COUNT(CASE WHEN t.txn_type='ISSUE' THEN 1 END) AS issue_count,
            COALESCE(MAX(CASE WHEN t.txn_type='ISSUE' THEN substr(t.ts,1,10) END),'') AS last_issue
          FROM Items i
          LEFT JOIN Transactions t ON t.item_id=i.id AND t.voided=0
          WHERE i.active=1
          GROUP BY i.id
          HAVING COALESCE(SUM(CASE WHEN t.txn_type='ISSUE' THEN t.qty ELSE 0 END),0) > 0
          ORDER BY issued_qty DESC, issue_count DESC
          LIMIT 10;
        """).fetchall()

        low = [dict(r) for r in low_stock_rows_global(limit=15, offset=0)]
        low_count = len(low_stock_rows_global(limit=2000000, offset=0))

        recent_txn = con.execute(r"""
          SELECT
            substr(T.ts,1,19) AS ts,
            COALESCE(T.txn_type,'') AS txn_type,
            COALESCE(I.item_code,'') AS item_code,
            COALESCE(I.item_name,'') AS item_name,
            ROUND(COALESCE(T.qty,0),3) AS qty,
            COALESCE(U.username, T.username, '') AS username
          FROM Transactions T
          LEFT JOIN Items I ON I.id=T.item_id
          LEFT JOIN Users U ON LOWER(COALESCE(U.username,'')) = LOWER(COALESCE(T.username,''))
          WHERE T.voided=0
          ORDER BY T.id DESC
          LIMIT 8;
        """).fetchall()

        recent_audit = []
        if role == "ADMIN":
            recent_audit = con.execute(r"""
              SELECT substr(created_at,1,19) AS created_at,
                     COALESCE(username,'') AS username,
                     COALESCE(action,'') AS action,
                     COALESCE(entity,'') AS entity,
                     COALESCE(details,'') AS details
              FROM AuditLog
              ORDER BY id DESC
              LIMIT 8;
            """).fetchall()
    finally:
        con.close()

    low_tbl = table(low,
                    ["item_code","item_name","balance","min_qty","shortage"],
                    {"item_code":t(lang,"item_code"),"item_name":t(lang,"item_name"),
                     "balance":t(lang,"balance"),"min_qty":t(lang,"min_qty"),"shortage":"Shortage"})

    top_tbl = table([dict(r) for r in top_items],
                    ["item_code","item_name","issued_qty","issue_count","last_issue"],
                    {"item_code":t(lang,"item_code"),"item_name":t(lang,"item_name"),
                     "issued_qty":t(lang,"qty") if "qty" in TR.get(lang,{}) else "Issued Qty",
                     "issue_count":t(lang,"count") if "count" in TR.get(lang,{}) else "Count",
                     "last_issue":t(lang,"date") if "date" in TR.get(lang,{}) else "Last Issue"})

    txn_tbl = table([dict(r) for r in recent_txn],
                    ["ts","txn_type","item_code","item_name","qty","username"],
                    {"ts":"Time","txn_type":"Type","item_code":t(lang,"item_code"),"item_name":t(lang,"item_name"),"qty":t(lang,"qty"),"username":"User"})

    audit_tbl = ""
    if role == "ADMIN":
        audit_tbl = table([dict(r) for r in recent_audit],
                          ["created_at","username","action","entity","details"],
                          {"created_at":"Time","username":"User","action":"Action","entity":"Entity","details":"Details"})

    inactive_total = int(kpi.get("items_inactive", 0) or 0) + int(kpi.get("eq_inactive", 0) or 0) + int(kpi.get("wh_inactive", 0) or 0)
    warnings_html = ""
    if low_count or inactive_total or inv_warn:
        warn_bits = []
        if low_count:
            warn_bits.append(f"<a class='warnchip' href='/balances?low=1'>⚠️ {low_count} أصناف تحت الحد الأدنى</a>")
        if inactive_total:
            warn_bits.append(f"<span class='warnchip soft'>🗂️ {inactive_total} سجلات غير نشطة تحتاج مراجعة</span>")
        if inv_warn:
            warn_bits.append("<span class='warnchip soft'>ℹ️ راجع تسعير الاستلام لبعض الأصناف</span>")
        warnings_html = "<div class='card' style='margin-top:12px'><div class='cardtitle'>مركز التنبيهات</div><div class='warnwrap'>" + "".join(warn_bits) + "</div></div>"

    audit_block = ""
    if role == "ADMIN":
        audit_block = f"""
        <div class="card" style="grid-column:span 6;align-self:start">
          <div class="cardtitle" style="display:flex;justify-content:space-between;gap:12px;align-items:center">
            <span>🧾 آخر سجل تدقيق</span>
            <a class="pill" href="/audit">فتح السجل الكامل</a>
          </div>
          {audit_tbl}
        </div>
        """

    body = f"""
    <div class="dashhead">
      <div>
        <div class="title">{html_escape(t(lang,'dashboard'))}</div>
        <div class="subtitle">{html_escape(COMPANY_NAME)}</div>
      </div>
      <div class="dashmeta">
        <a class="pill" href="/items">📦 {html_escape(t(lang,'items'))}</a>
        <a class="pill" href="/equipment">🚜 {html_escape(t(lang,'equipment'))}</a>
        <a class="pill" href="/warehouses">🏭 {html_escape(t(lang,'warehouses'))}</a>
        <a class="pill" href="/txn">🔁 {html_escape(t(lang,'txn'))}</a>
        <a class="pill" href="/scrap">♻️ {html_escape(t(lang,'scrap'))}</a>
        <a class="pill" href="/balances">📊 {html_escape(t(lang,'balances'))}</a>
        <a class="pill" href="/requests">🧾 {html_escape(t(lang,'requests'))}</a>
      </div>
    </div>

    <div class="ops-grid" style="margin-top:10px">
      <div class="card ops-hero">
        <div class="eyebrow">نظرة تشغيلية سريعة</div>
        <div class="hero-grid">
          <div><b>آخر حركة</b><span>{html_escape(last_txn or '-')}</span></div>
          <div><b>آخر طلب</b><span>{html_escape(last_req or '-')}</span></div>
          <div><b>حركات اليوم</b><span>{int(kpi['txn_today'] or 0)}</span></div>
          <div><b>قيمة المخزون</b><span>{inv_total:,.2f}</span></div>
        </div>
      </div>
      <div class="card quick-actions">
        <div class="cardtitle">إجراءات سريعة</div>
        <div class="quick-links">
          <a class="quick-link" href="/txn?txn_type=RECEIVE">⬇️ استلام جديد</a>
          <a class="quick-link" href="/txn?txn_type=ISSUE">⬆️ صرف جديد</a>
          <a class="quick-link" href="/txn?txn_type=TRANSFER">🔄 تحويل جديد</a>
          <a class="quick-link" href="/excel/wizard?view=txn">📥 استيراد حركات</a>
          <a class="quick-link" href="/daily_reports">🖨️ تقرير يومي</a>
          <a class="quick-link" href="/audit">🧾 السجل</a>
        </div>
      </div>
    </div>

    {warnings_html}

    <div class="kpi-grid">
      <a class="card kpi-card kpi-link" href="/items"><div class="kpi"><div class="v">{kpi['items']}</div><div class="k">{html_escape(t(lang,'items'))}</div><div class="muted">غير نشط: {int(kpi['items_inactive'] or 0)}</div></div></a>
      <a class="card kpi-card kpi-link" href="/equipment"><div class="kpi"><div class="v">{kpi['eq']}</div><div class="k">{html_escape(t(lang,'equipment'))}</div><div class="muted">غير نشط: {int(kpi['eq_inactive'] or 0)}</div></div></a>
      <a class="card kpi-card kpi-link" href="/warehouses"><div class="kpi"><div class="v">{kpi['wh']}</div><div class="k">{html_escape(t(lang,'warehouses'))}</div><div class="muted">غير نشط: {int(kpi['wh_inactive'] or 0)}</div></div></a>
      <a class="card kpi-card kpi-link" href="/txn"><div class="kpi"><div class="v">{kpi['txn_total']}</div><div class="k">{html_escape(t(lang,'txn'))}</div><div class="muted">اليوم: {int(kpi['txn_today'] or 0)}</div></div></a>
      <a class="card kpi-card kpi-link" href="/requests"><div class="kpi"><div class="v">{kpi['req_total']}</div><div class="k">{html_escape(t(lang,'requests'))}</div><div class="muted">جاهز للمتابعة</div></div></a>
      <a class="card kpi-card accent kpi-link" href="/balances"><div class="kpi"><div class="v">{inv_total:,.2f}</div><div class="k">💠 {html_escape(t(lang,'inventory_value'))}</div><div class="muted">تنبيهات الحد الأدنى: {low_count}</div></div></a>
    </div>

    <div class="grid" style="margin-top:12px">
      <div class="col12" style="display:grid;grid-template-columns:repeat(12,minmax(0,1fr));gap:12px;align-items:start">
        <div class="card" style="grid-column:span 6;align-self:start">
          <div class="cardtitle" style="display:flex;justify-content:space-between;gap:12px;align-items:center">
            <span>🕒 أحدث الحركات</span>
            <a class="pill" href="/txn">فتح سجل الحركات</a>
          </div>
          {txn_tbl}
        </div>
        {audit_block}
      </div>
      <div class="col12 card">
        <div class="cardtitle">🔥 أعلى الأصناف استهلاكًا</div>
        {top_tbl}
      </div>

      <div class="col12 card">
        <div class="cardtitle">⚠️ أصناف تحت الحد الأدنى</div>
        {low_tbl}
      </div>
    </div>
    """
    return page(lang, t(lang,"dashboard"), body, username=username, role=role)



def render_item_card(lang, username, role, qs):
    """Item Card: summary RECEIVE/ISSUE totals + balance, and all transactions for an item.
    Notes:
      - Totals: RECEIVE + ISSUE only (TRANSFER excluded from totals but shown in table)
      - Optional date range filter (from_date/to_date) applies to totals and table
    """
    con = db_connect()

    item_code = (qs.get("item_code", [""])[0] or "").strip()
    from_date = (qs.get("from_date", [""])[0] or "").strip()  # YYYY-MM-DD
    to_date = (qs.get("to_date", [""])[0] or "").strip()      # YYYY-MM-DD

    item = None
    if item_code:
        item = con.execute("SELECT id, item_code, item_name, unit FROM Items WHERE item_code=?", (item_code,)).fetchone()

    # Index-friendly date filter on raw timestamp column
    _ts_sql, date_params = _sqlite_ts_range(from_date, to_date, field="T.ts")
    date_where = (" AND " + _ts_sql) if _ts_sql else ""

    recv_total = iss_total = 0.0
    bal = 0.0
    tx_rows = []

    if item:
        item_id = item["id"]

        recv_total = con.execute(
            "SELECT COALESCE(SUM(T.qty),0) s FROM Transactions T WHERE T.voided=0 AND T.item_id=? AND T.txn_type='RECEIVE' " + date_where,
            (item_id, *date_params),
        ).fetchone()["s"] or 0.0

        iss_total = con.execute(
            "SELECT COALESCE(SUM(T.qty),0) s FROM Transactions T WHERE T.voided=0 AND T.item_id=? AND T.txn_type='ISSUE' " + date_where,
            (item_id, *date_params),
        ).fetchone()["s"] or 0.0

        bal = float(recv_total or 0) - float(iss_total or 0)

        tx_rows = con.execute(
            """
            SELECT
              T.ts, T.txn_type, T.qty, T.unit_price,
              WF.wh_code AS wh_from_code, WF.wh_name AS wh_from_name,
              WT.wh_code AS wh_to_code,   WT.wh_name AS wh_to_name,
              E.eq_code  AS eq_code, E.eq_name AS eq_name,
              S.supplier_code AS supplier_code, S.supplier_name AS supplier_name,
              T.req_no, T.po_no, T.doc_no, T.notes, T.username, T.voided, T.void_reason
            FROM Transactions T
            LEFT JOIN Warehouses WF ON WF.id=T.wh_from_id
            LEFT JOIN Warehouses WT ON WT.id=T.wh_to_id
            LEFT JOIN Equipment   E ON E.id=T.eq_id
            LEFT JOIN Suppliers   S ON S.id=T.supplier_id
            WHERE T.item_id=? """ + date_where + """
            ORDER BY T.ts DESC, T.id DESC
            LIMIT 2000
            """,
            (item_id, *date_params),
        ).fetchall()

    # Options list for quick selection
    # Keep it light: only active items (user can still type code manually)
    opts = con.execute("SELECT item_code, item_name FROM Items WHERE active=1 ORDER BY item_code LIMIT 3000").fetchall()
    dl = "".join([f"<option value='{html_escape(r['item_code'])}'>{html_escape(r['item_name'])}</option>" for r in opts])

    msg = ""
    if item_code and not item:
        msg = f"<div class='card'><b>{html_escape(t(lang,'item_code'))}:</b> {html_escape(item_code)} — <span class='muted'>غير موجود</span></div>"

    # Header + form
    title = t(lang, "item_card") if "item_card" in TR.get(lang, {}) else "Item Card"
    body = f"""
<div class="row">
  <div class="card" style="flex:1">
    <div class="toolbar">
      <div class="left">
        <div class="hint">{html_escape(title)}</div>
      </div>
    </div>

    {tools_bar("item_card", qs, lang) or ""}

    <form method="GET" action="/item_card" class="toolbar" style="gap:10px; flex-wrap:wrap">
      <div class="frow" style="min-width:260px">
        <label>{html_escape(t(lang,'item_code'))}</label>
        <input name="item_code" value="{html_escape(item_code)}" list="dl_items" placeholder="مثال: SP-0001"/>
        <datalist id="dl_items">{dl}</datalist>
      </div>
      <div class="frow">
        <label>{html_escape(t(lang,'from_date'))}</label>
        <input type="date" name="from_date" value="{html_escape(from_date)}"/>
      </div>
      <div class="frow">
        <label>{html_escape(t(lang,'to_date'))}</label>
        <input type="date" name="to_date" value="{html_escape(to_date)}"/>
      </div>
      <div class="frow" style="align-self:flex-end">
        <button class="btn" type="submit">بحث</button>
      </div>
      <div class="spacer"></div>
      <div class="frow" style="align-self:flex-end">
        <a class="btn" href="/item_card">تفريغ</a>
      </div>
    </form>
  </div>
</div>

{msg}
"""

    if item:
        body += f"""
<div class="grid" style="grid-template-columns:repeat(auto-fit,minmax(220px,1fr)); gap:12px; margin-top:10px">
  <div class="card">
    <div class="kpi">
      <div class="klabel">{html_escape(t(lang,'item_name'))}</div>
      <div class="kval">{html_escape(item['item_name'])}</div>
      <div class="muted">{html_escape(item['item_code'])}</div>
    </div>
  </div>

  <div class="card">
    <div class="kpi">
      <div class="klabel">إجمالي الاستلام (RECEIVE)</div>
      <div class="kval">{fmt_num(recv_total)}</div>
    </div>
  </div>

  <div class="card">
    <div class="kpi">
      <div class="klabel">إجمالي الصرف (ISSUE)</div>
      <div class="kval">{fmt_num(iss_total)}</div>
    </div>
  </div>

  <div class="card">
    <div class="kpi">
      <div class="klabel">الرصيد</div>
      <div class="kval">{fmt_num(bal)}</div>
    </div>
  </div>
</div>

<div class="card" style="margin-top:12px">
  <div class="toolbar">
    <div class="left"><b>حركات الصنف</b></div>
    <div class="spacer"></div>
    <div class="hint">* الاستلام/الصرف محسوبين بدون TRANSFER (لكن التحويلات تظهر هنا)</div>
  </div>
  <div class="table-wrap">
    <table class="v6tbl">
      <thead>
        <tr>
          <th>{html_escape(t(lang,'txn_date'))}</th>
          <th>{html_escape(t(lang,'txn'))}</th>
          <th>{html_escape(t(lang,'qty')) if 'qty' in TR.get(lang,{}) else 'Qty'}</th>
          <th>{html_escape(t(lang,'unit_price')) if 'unit_price' in TR.get(lang,{}) else 'Unit Price'}</th>
          <th>من مستودع</th>
          <th>إلى مستودع</th>
          <th>المعدة</th>
          <th>المورد</th>
          <th>Req#</th>
          <th>PO#</th>
          <th>Doc#</th>
          <th>{html_escape(t(lang,'notes')) if 'notes' in TR.get(lang,{}) else 'Notes'}</th>
          <th>User</th>
        </tr>
      </thead>
      <tbody>
"""
        for r in tx_rows:
            ts = r["ts"] or ""
            body += "<tr>"
            body += f"<td>{html_escape(ts)}</td>"
            body += f"<td>{html_escape(r['txn_type'] or '')}</td>"
            body += f"<td>{fmt_num(r['qty'])}</td>"
            body += f"<td>{fmt_num(r['unit_price']) if r['unit_price'] is not None else ''}</td>"

            wf = ""
            if r["wh_from_code"] or r["wh_from_name"]:
                wf = f"{html_escape(r['wh_from_code'] or '')} - {html_escape(r['wh_from_name'] or '')}"
            wt = ""
            if r["wh_to_code"] or r["wh_to_name"]:
                wt = f"{html_escape(r['wh_to_code'] or '')} - {html_escape(r['wh_to_name'] or '')}"

            body += f"<td>{wf}</td>"
            body += f"<td>{wt}</td>"

            eq = ""
            if r["eq_code"] or r["eq_name"]:
                eq = f"{html_escape(r['eq_code'] or '')} - {html_escape(r['eq_name'] or '')}"
            sup = ""
            if r["supplier_code"] or r["supplier_name"]:
                sup = f"{html_escape(r['supplier_code'] or '')} - {html_escape(r['supplier_name'] or '')}"

            body += f"<td>{eq}</td>"
            body += f"<td>{sup}</td>"

            body += f"<td>{html_escape(r['req_no'] or '')}</td>"
            body += f"<td>{html_escape(r['po_no'] or '')}</td>"
            body += f"<td>{html_escape(r['doc_no'] or '')}</td>"
            body += f"<td>{html_escape(r['notes'] or '')}</td>"
            body += f"<td>{html_escape(r['username'] or '')}</td>"
            body += "</tr>"

        body += """
      </tbody>
    </table>
  </div>
</div>
"""

    return page(lang, title, body, username, role=role)



def render_equipment_card(lang, username, role, qs):
    """Equipment Card: show equipment info + transactions linked to this equipment (eq_id).
    - Optional date range filter (from_date/to_date) applies to totals and table.
    - Totals are based on ISSUE/RECEIVE only for quick KPIs (TRANSFER shown in table).
    """
    con = db_connect()

    eq_code = (qs.get("eq_code", [""])[0] or "").strip()
    from_date = (qs.get("from_date", [""])[0] or "").strip()  # YYYY-MM-DD
    to_date = (qs.get("to_date", [""])[0] or "").strip()      # YYYY-MM-DD

    eq = None
    if eq_code:
        eq = con.execute(
            "SELECT id, eq_code, eq_name, model, year, serial_no, driver_name FROM Equipment WHERE eq_code=?",
            (eq_code,),
        ).fetchone()

    # Index-friendly date filter on raw timestamp column
    _ts_sql, date_params = _sqlite_ts_range(from_date, to_date, field="T.ts")
    date_where = (" AND " + _ts_sql) if _ts_sql else ""

    recv_total = iss_total = 0.0
    tx_rows = []
    top_items = []

    if eq:
        eq_id = eq["id"]

        recv_total = con.execute(
            "SELECT COALESCE(SUM(T.qty),0) s FROM Transactions T WHERE T.voided=0 AND T.eq_id=? AND T.txn_type='RECEIVE' " + date_where,
            (eq_id, *date_params),
        ).fetchone()["s"] or 0.0

        iss_total = con.execute(
            "SELECT COALESCE(SUM(T.qty),0) s FROM Transactions T WHERE T.voided=0 AND T.eq_id=? AND T.txn_type='ISSUE' " + date_where,
            (eq_id, *date_params),
        ).fetchone()["s"] or 0.0

        tx_rows = con.execute(
            """
            SELECT
              T.ts, T.txn_type, T.qty, T.unit_price,
              I.item_code AS item_code, I.item_name AS item_name, I.unit AS unit,
              WF.wh_code AS wh_from_code, WF.wh_name AS wh_from_name,
              WT.wh_code AS wh_to_code,   WT.wh_name AS wh_to_name,
              S.supplier_code AS supplier_code, S.supplier_name AS supplier_name,
              T.req_no, T.po_no, T.doc_no, T.notes, T.username, T.voided, T.void_reason
            FROM Transactions T
            LEFT JOIN Items I         ON I.id=T.item_id
            LEFT JOIN Warehouses WF   ON WF.id=T.wh_from_id
            LEFT JOIN Warehouses WT   ON WT.id=T.wh_to_id
            LEFT JOIN Suppliers S     ON S.id=T.supplier_id
            WHERE T.eq_id=? """ + date_where + """
            ORDER BY T.ts DESC, T.id DESC
            LIMIT 4000
            """,
            (eq_id, *date_params),
        ).fetchall()

        top_items = con.execute(
            """
            SELECT I.item_code, I.item_name, COALESCE(SUM(T.qty),0) s
            FROM Transactions T
            JOIN Items I ON I.id=T.item_id
            WHERE T.voided=0 AND T.eq_id=? AND T.txn_type='ISSUE' """ + date_where + """
            GROUP BY I.id
            ORDER BY s DESC
            LIMIT 10
            """,
            (eq_id, *date_params),
        ).fetchall()

    # Options list for quick selection (active equipment)
    opts = con.execute("SELECT eq_code, eq_name FROM Equipment WHERE active=1 ORDER BY eq_code LIMIT 3000").fetchall()
    dl = "".join([f"<option value='{html_escape(r['eq_code'])}'>{html_escape(r['eq_name'])}</option>" for r in opts])

    msg = ""
    if eq_code and not eq:
        msg = f"<div class='card'><b>{html_escape(t(lang,'eq_code'))}:</b> {html_escape(eq_code)} — <span class='muted'>غير موجود</span></div>"

    title = t(lang, "equipment_card") if "equipment_card" in TR.get(lang, {}) else "Equipment Card"
    body = f"""
<div class="row">
  <div class="card" style="flex:1">
    <div class="toolbar">
      <div class="left">
        <div class="hint">{html_escape(title)}</div>
      </div>
    </div>

    {tools_bar("equipment_card", qs, lang) or ""}

    <form method="GET" action="/equipment_card" class="toolbar" style="gap:10px; flex-wrap:wrap">
      <div class="frow" style="min-width:260px">
        <label>{html_escape(t(lang,'eq_code'))}</label>
        <input name="eq_code" value="{html_escape(eq_code)}" list="dl_eq" placeholder="مثال: EQ-0001"/>
        <datalist id="dl_eq">{dl}</datalist>
      </div>
      <div class="frow">
        <label>{html_escape(t(lang,'from_date'))}</label>
        <input type="date" name="from_date" value="{html_escape(from_date)}"/>
      </div>
      <div class="frow">
        <label>{html_escape(t(lang,'to_date'))}</label>
        <input type="date" name="to_date" value="{html_escape(to_date)}"/>
      </div>
      <div class="frow" style="align-self:flex-end">
        <button class="btn" type="submit">بحث</button>
      </div>
      <div class="spacer"></div>
      <div class="frow" style="align-self:flex-end">
        <a class="btn" href="/equipment_card">تفريغ</a>
      </div>
    </form>
  </div>
</div>

{msg}
"""

    if eq:
        body += f"""
<div class="grid" style="grid-template-columns:repeat(auto-fit,minmax(220px,1fr)); gap:12px; margin-top:10px">
  <div class="card">
    <div class="kpi">
      <div class="klabel">{html_escape(t(lang,'equipment'))}</div>
      <div class="kval">{html_escape(eq['eq_name'] or '')}</div>
      <div class="muted">{html_escape(eq['eq_code'] or '')}</div>
    </div>
  </div>

  <div class="card">
    <div class="kpi">
      <div class="klabel">Model / موديل</div>
      <div class="kval">{html_escape((eq['model'] or '') if 'model' in eq.keys() else '')}</div>
      <div class="muted">Year: {html_escape(str(eq['year'] or ''))}</div>
    </div>
  </div>

  <div class="card">
    <div class="kpi">
      <div class="klabel">Serial / سيريال</div>
      <div class="kval">{html_escape(str(eq['serial_no'] or ''))}</div>
      <div class="muted">Driver: {html_escape(str(eq['driver_name'] or ''))}</div>
    </div>
  </div>

  <div class="card">
    <div class="kpi">
      <div class="klabel">إجمالي الاستلام (RECEIVE)</div>
      <div class="kval">{fmt_num(recv_total)}</div>
    </div>
  </div>

  <div class="card">
    <div class="kpi">
      <div class="klabel">إجمالي الصرف للمعدة (ISSUE)</div>
      <div class="kval">{fmt_num(iss_total)}</div>
    </div>
  </div>
</div>
"""

        if top_items:
            rows = ""
            for r in top_items:
                rows += (
                    "<tr>"
                    f"<td>{html_escape(r['item_code'] or '')}</td>"
                    f"<td>{html_escape(r['item_name'] or '')}</td>"
                    f"<td>{fmt_num(r['s'] or 0)}</td>"
                    "</tr>"
                )
            body += f"""
<div class="card" style="margin-top:12px">
  <div class="toolbar">
    <div class="left"><b>🔥 أكثر الأصناف صرفًا للمعدة</b></div>
    <div class="spacer"></div>
    <div class="hint">* حسب ISSUE فقط</div>
  </div>
  <div class="table-wrap">
    <table class="v6tbl">
      <thead><tr><th>كود</th><th>اسم الصنف</th><th>Qty</th></tr></thead>
      <tbody>{rows}</tbody>
    </table>
  </div>
</div>
"""

        body += f"""
<div class="card" style="margin-top:12px">
  <div class="toolbar">
    <div class="left"><b>حركات المعدة</b></div>
    <div class="spacer"></div>
    <div class="hint">* تظهر RECEIVE/ISSUE/TRANSFER (والمحذوفة تظهر مع سبب الإلغاء)</div>
  </div>
  <div class="table-wrap">
    <table class="v6tbl">
      <thead>
        <tr>
          <th>{html_escape(t(lang,'txn_date'))}</th>
          <th>{html_escape(t(lang,'txn'))}</th>
          <th>الصنف</th>
          <th>{html_escape(t(lang,'qty')) if 'qty' in TR.get(lang,{}) else 'Qty'}</th>
          <th>{html_escape(t(lang,'unit_price')) if 'unit_price' in TR.get(lang,{}) else 'Unit Price'}</th>
          <th>من مستودع</th>
          <th>إلى مستودع</th>
          <th>المورد</th>
          <th>Req#</th>
          <th>PO#</th>
          <th>Doc#</th>
          <th>{html_escape(t(lang,'notes'))}</th>
          <th>{html_escape(t(lang,'user')) if 'user' in TR.get(lang,{}) else 'User'}</th>
          <th>Voided</th>
        </tr>
      </thead>
      <tbody>
"""

        for r in tx_rows:
            dt = (r["ts"] or "")[:19].replace("T", " ")
            item_txt = f"{html_escape(r['item_code'] or '')} — {html_escape(r['item_name'] or '')}"
            wh_from = f"{html_escape(r['wh_from_code'] or '')} {html_escape(r['wh_from_name'] or '')}".strip()
            wh_to = f"{html_escape(r['wh_to_code'] or '')} {html_escape(r['wh_to_name'] or '')}".strip()
            supplier_txt = f"{html_escape(r['supplier_code'] or '')} {html_escape(r['supplier_name'] or '')}".strip()
            voided = "YES" if (r["voided"] or 0) else ""
            if voided and r["void_reason"]:
                voided = "YES — " + html_escape(str(r["void_reason"]))
            body += (
                "<tr>"
                f"<td>{html_escape(dt)}</td>"
                f"<td>{html_escape(r['txn_type'] or '')}</td>"
                f"<td>{item_txt}</td>"
                f"<td>{fmt_num(r['qty'] or 0)}</td>"
                f"<td>{fmt_num(r['unit_price'] or 0)}</td>"
                f"<td>{wh_from}</td>"
                f"<td>{wh_to}</td>"
                f"<td>{supplier_txt}</td>"
                f"<td>{html_escape(r['req_no'] or '')}</td>"
                f"<td>{html_escape(r['po_no'] or '')}</td>"
                f"<td>{html_escape(r['doc_no'] or '')}</td>"
                f"<td>{html_escape(r['notes'] or '')}</td>"
                f"<td>{html_escape(r['username'] or '')}</td>"
                f"<td>{voided}</td>"
                "</tr>"
            )

        body += """
      </tbody>
    </table>
  </div>
</div>
"""

    return page(lang, title, body, username, role=role)


def render_equipment_consumption(lang, username, role, qs):
    qs = qs or {}
    from_date = (qs.get("from_date", [""])[0] or "").strip()
    to_date   = (qs.get("to_date",   [""])[0] or "").strip()
    metric    = (qs.get("metric",    ["value"])[0] or "value").strip().lower()
    limit     = (qs.get("limit",     ["30"])[0] or "30").strip()
    if metric not in ("qty","value"):
        metric="value"
    try:
        _ = int(limit)
    except Exception:
        limit="30"

    rows = compute_equipment_consumption(qs)

    title = "اكثر المعدات استهلاكا" if lang=="ar" else "Top Consuming Equipment"
    # export link goes through wizard for column selection
    from urllib.parse import urlencode
    base_qs = {"view":"equipment_consumption","from_date":from_date,"to_date":to_date,"metric":metric,"limit":limit}
    wiz_url = "/excel/wizard?" + urlencode({**base_qs, "mode":"export"})
    tpl_url = "/excel/wizard?" + urlencode({**base_qs, "mode":"template"})
    export_direct = "/excel/export?" + urlencode(base_qs)

    # filters form
    body = f"""
    <div class="card">
      <div class="toolbar">
        <div class="left">
          <div class="hint">🔥 {html_escape(title)}</div>
          <div class="muted small">ISSUE فقط المرتبطة بالمعدة (eq_id) • يمكن فلترة بالتاريخ</div>
        </div>
        <div class="right">
          <a class="btn" href="{html_escape(wiz_url)}">📤 Export (Columns)</a>
          <a class="btn" href="{html_escape(tpl_url)}">📄 Template (Columns)</a>
          <a class="btn" href="{html_escape(export_direct)}">⬇️ Export سريع</a>
        </div>
      </div>

      <form method="GET" action="/equipment_consumption" class="toolbar" style="gap:10px; flex-wrap:wrap">
        <div class="frow">
          <label>{html_escape(t(lang,'from_date'))}</label>
          <input type="date" name="from_date" value="{html_escape(from_date)}"/>
        </div>
        <div class="frow">
          <label>{html_escape(t(lang,'to_date'))}</label>
          <input type="date" name="to_date" value="{html_escape(to_date)}"/>
        </div>
        <div class="frow">
          <label>{'الترتيب حسب' if lang=='ar' else 'Sort by'}</label>
          <select name="metric">
            <option value="value" {'selected' if metric=='value' else ''}>{'القيمة' if lang=='ar' else 'Value'}</option>
            <option value="qty" {'selected' if metric=='qty' else ''}>{'الكمية' if lang=='ar' else 'Quantity'}</option>
          </select>
        </div>
        <div class="frow" style="width:120px">
          <label>{'عدد النتائج' if lang=='ar' else 'Top N'}</label>
          <input name="limit" value="{html_escape(limit)}" inputmode="numeric"/>
        </div>
        <div class="frow" style="align-self:flex-end">
          <button class="btn" type="submit">{'تحديث' if lang=='ar' else 'Refresh'}</button>
        </div>
        <div class="spacer"></div>
        <div class="frow" style="align-self:flex-end">
          <a class="btn" href="/equipment_consumption">{'تفريغ' if lang=='ar' else 'Clear'}</a>
        </div>
      </form>
    </div>
    """

    # table
    body += """<div class="card" style="margin-top:12px">
      <div class="tablewrap">
        <table class="tbl">
          <thead>
            <tr>
              <th>#</th>
              <th>{}</th>
              <th>{}</th>
              <th>{}</th>
              <th>{}</th>
              <th>{}</th>
            </tr>
          </thead>
          <tbody>
    """.format(
        "كود المعدة" if lang=="ar" else "Eq Code",
        "اسم المعدة" if lang=="ar" else "Equipment",
        "إجمالي الكمية" if lang=="ar" else "Total Qty",
        "إجمالي القيمة" if lang=="ar" else "Total Value",
        "آخر صرف" if lang=="ar" else "Last Issue",
    )

    if not rows:
        body += f"<tr><td colspan='6' class='muted' style='padding:14px'>{'لا توجد بيانات' if lang=='ar' else 'No data'}</td></tr>"
    else:
        for i,r in enumerate(rows, start=1):
            eq_code = r.get("eq_code","") or ""
            eq_name = r.get("eq_name","") or ""
            issue_qty = r.get("issue_qty",0) or 0
            issue_value = r.get("issue_value",0) or 0
            last_issue = r.get("last_issue_date","") or ""
            link = "/equipment_card?eq_code=" + quote(eq_code)
            body += """<tr>
              <td>{i}</td>
              <td><a href="{link}">{eq_code}</a></td>
              <td>{eq_name}</td>
              <td class="num">{qty}</td>
              <td class="num">{val}</td>
              <td>{last}</td>
            </tr>""".format(
                i=i,
                link=html_escape(link),
                eq_code=html_escape(eq_code),
                eq_name=html_escape(eq_name),
                qty=html_escape(fmt_num(issue_qty)),
                val=html_escape(fmt_money(issue_value)),
                last=html_escape(last_issue),
            )

    body += """</tbody></table></div></div>"""
    return page(lang, title, body, username, role=role)


def render_global_search(lang, username, role, qs):
    q = (qs.get("q", [""])[0] or "").strip()
    limit = qs_int(qs, "limit", 50, 10, 200)
    qlike = f"%{q}%"
    rows = []
    if q:
        try:
            con = db_connect()
            con.row_factory = sqlite3.Row

            def add_section(title, items, link_builder):
                for it in items:
                    rows.append({
                        "source": title,
                        "code": it.get("code",""),
                        "name": it.get("name",""),
                        "details": it.get("details",""),
                        "open": link_builder(it)
                    })

            # Items
            its = [dict(r) for r in con.execute(
                """SELECT item_code AS code, item_name AS name, unit AS details
                     FROM Items
                     WHERE active=1 AND (item_code LIKE ? OR item_name LIKE ?)
                     ORDER BY item_code
                     LIMIT ?""",
                (qlike, qlike, limit)
            ).fetchall()]
            add_section(t(lang,"items"), its, lambda it: f"<a class='btn sm' href='/items?q={quote_plus(q)}'>فتح</a>")

            # Warehouses
            whs = [dict(r) for r in con.execute(
                """SELECT wh_code AS code, wh_name AS name, '' AS details
                     FROM Warehouses
                     WHERE active=1 AND (wh_code LIKE ? OR wh_name LIKE ?)
                     ORDER BY wh_code
                     LIMIT ?""",
                (qlike, qlike, limit)
            ).fetchall()]
            add_section(t(lang,"warehouses"), whs, lambda it: f"<a class='btn sm' href='/warehouses?q={quote_plus(q)}'>فتح</a>")

            # Equipment
            eqs = [dict(r) for r in con.execute(
                """SELECT eq_code AS code, eq_name AS name, COALESCE(model,'') AS details
                     FROM Equipment
                     WHERE active=1 AND (eq_code LIKE ? OR eq_name LIKE ? OR COALESCE(model,'') LIKE ?)
                     ORDER BY eq_code
                     LIMIT ?""",
                (qlike, qlike, qlike, limit)
            ).fetchall()]
            add_section(t(lang,"equipment"), eqs, lambda it: f"<a class='btn sm' href='/equipment?q={quote_plus(q)}'>فتح</a>")

            # Suppliers
            sups = [dict(r) for r in con.execute(
                """SELECT supplier_code AS code, supplier_name AS name, '' AS details
                     FROM Suppliers
                     WHERE active=1 AND (supplier_code LIKE ? OR supplier_name LIKE ?)
                     ORDER BY supplier_code
                     LIMIT ?""",
                (qlike, qlike, limit)
            ).fetchall()]
            add_section(t(lang,"suppliers"), sups, lambda it: f"<a class='btn sm' href='/suppliers?q={quote_plus(q)}'>فتح</a>")

            # Requests (Standalone)
            srs = [dict(r) for r in con.execute(
                """SELECT COALESCE(wh_req_no,'') AS code,
                            COALESCE(warehouse_name,'') AS name,
                            (COALESCE(status,'') || ' • ' || COALESCE(eq_code,'')) AS details
                     FROM StandaloneRequests
                     WHERE (warehouse_name LIKE ? OR maint_req_no LIKE ? OR wh_req_no LIKE ? OR po_no LIKE ? OR eq_code LIKE ? OR status LIKE ? OR notes LIKE ?)
                     ORDER BY req_date DESC, id DESC
                     LIMIT ?""",
                (qlike, qlike, qlike, qlike, qlike, qlike, qlike, limit)
            ).fetchall()]
            add_section(t(lang,"requests"), srs, lambda it: f"<a class='btn sm' href='/requests?q_whreq={quote_plus(q)}'>فتح</a>")

            # Transactions
            txs = [dict(r) for r in con.execute(
                """SELECT CAST(t.id AS TEXT) AS code,
                            t.ts AS name,
                            (t.txn_type || ' • ' || COALESCE(i.item_code,'') || ' • ' || COALESCE(t.req_no,'') || ' • ' || COALESCE(t.po_no,'')) AS details
                     FROM Transactions t
                     LEFT JOIN Items i ON i.id=t.item_id
                     WHERE (t.ts LIKE ? OR t.req_no LIKE ? OR t.po_no LIKE ? OR t.doc_no LIKE ? OR COALESCE(t.notes,'') LIKE ? OR COALESCE(i.item_code,'') LIKE ? OR COALESCE(i.item_name,'') LIKE ?)
                     ORDER BY t.id DESC
                     LIMIT ?""",
                (qlike, qlike, qlike, qlike, qlike, qlike, qlike, limit)
            ).fetchall()]
            add_section(t(lang,"txn"), txs, lambda it: f"<a class='btn sm' href='/txn?q_item={quote_plus(q)}'>فتح</a>")

            con.close()
        except Exception:
            rows = []

    headers = ["source","code","name","details","open"]
    labels = {"source":"Source","code":"Code","name":"Name/Date","details":"Details","open":t(lang,"open")}
    # raw for open column
    tbl = table(rows, headers, labels, raw_cols={"open"}, table_id="global", view="search")

    body = f"""
    <div class="card no-print">
      <form method="get" action="/search">
        <div class="grid">
          <div class="col10">
            <label>{html_escape(t(lang,'search'))}</label>
            <input name="q" value="{html_escape(q)}" placeholder="{html_escape(t(lang,'search'))}"><div class="small" style="margin-top:6px">البيانات غير النشطة تظل ظاهرة هنا لكن لا تُستخدم في الحركات أو الاختيارات.</div>
          </div>
          <div class="col2" style="display:flex;align-items:end;gap:8px">
            <button class="btn" type="submit">🔎 {html_escape(t(lang,'search'))}</button>
            <a class="btn" href="/search">♻️ {html_escape(t(lang,'reset'))}</a>
          </div>
        </div>
      </form>
      <div class="small" style="margin-top:6px;opacity:.85">يبحث داخل: الأصناف • المخازن • المعدات • الموردين • الطلبات • الحركة</div>
    </div>

    <div class="card">
      {tbl}
    </div>
    """
    return page(lang, "🔎 Global Search", body, username=username, role=role)


def render_simple_crud(lang, username, role, title_key, table_name, fields, code_field, search_q, base_path, qs=None, active_only_default=True, flash=None):
    # fields: list of tuples (col_name, label_key, type)
    can_add = role in ("ADMIN","EDITOR")
    is_admin = role == "ADMIN"
    q = (search_q or "").strip()
    qs = qs or ({"q":[q]} if q else {})

    # Keep inactive rows visible in master pages; they remain blocked in lookups/transactions.
    show_all = (qs.get('show_all',[''])[0] or '').strip() in ('1','true','yes','on')
    active_only = False

    # pagination (same style as balances)
    page_no = qs_int(qs, "page", 1, 1, 100000)
    # Master-data pages are not transaction reports; keep pagination simple and self-contained.
    page_size = qs_int(qs, "page_size", 200, 50, 5000)
    offset = (page_no - 1) * page_size

    base = base_path.strip("/")

    if base == "items":
        try:
            repair_duplicate_items(username=username or "system")
        except Exception as _dup_e:
            try:
                safe_log_exception("repair_duplicate_items", _dup_e, username=username or "system", role=role)
            except Exception:
                pass

    # edit mode (ADMIN only)
    edit_id = (qs.get("edit", [""])[0] or "").strip()
    edit_row = None
    if edit_id.isdigit():
        con = db_connect()
        r = con.execute(f"SELECT * FROM {table_name} WHERE id=?", (int(edit_id),)).fetchone()
        con.close()
        edit_row = dict(r) if r else None

    # server-side column filters (for pagination across all pages)
    col_filters = {}
    for h in ([f[0] for f in fields] + ['active']):
        key = f"f_{h}"
        vv = (qs.get(key, [""])[0] or "").strip()
        if vv != "":
            col_filters[h] = vv

    rows = list_rows(table_name, q, order_by=code_field, limit=page_size+1, offset=offset, col_filters=col_filters, active_only=active_only)
    has_next = len(rows) > page_size
    rows = rows[:page_size]
    pager = ""

    headers = [f[0] for f in fields] + ["active"]
    labels = {f[0]: t(lang, f[1]) for f in fields}
    labels["active"] = "active"

    if base == "items":
        labels["last_txn_price"] = t(lang, "last_txn_price")
        insert_at = headers.index("default_unit_price") if "default_unit_price" in headers else len(headers) - 1
        headers.insert(insert_at, "last_txn_price")
        item_ids = [int(r.get("id") or 0) for r in rows if str(r.get("id") or "").isdigit()]
        latest_price_map = {}
        if item_ids:
            con_lp = db_connect()
            try:
                ph = ",".join(["?"] * len(item_ids))
                sql_lp = f"""
                    SELECT item_id, unit_price
                    FROM (
                        SELECT item_id, unit_price,
                               ROW_NUMBER() OVER (PARTITION BY item_id ORDER BY ts DESC, id DESC) AS rn
                        FROM Transactions
                        WHERE voided=0
                          AND unit_price IS NOT NULL
                          AND CAST(unit_price AS REAL) > 0
                          AND item_id IN ({ph})
                    ) z
                    WHERE rn=1
                """
                for rr in con_lp.execute(sql_lp, tuple(item_ids)).fetchall():
                    iid = rr[0] if not isinstance(rr, sqlite3.Row) else rr["item_id"]
                    up = rr[1] if not isinstance(rr, sqlite3.Row) else rr["unit_price"]
                    try:
                        latest_price_map[int(iid)] = float(up)
                    except Exception:
                        pass
            finally:
                try:
                    con_lp.close()
                except Exception:
                    pass
        for r in rows:
            iid = int(r.get("id") or 0) if str(r.get("id") or "").isdigit() else 0
            v = latest_price_map.get(iid)
            r["last_txn_price"] = ("" if v is None else (f"{v:.3f}".rstrip("0").rstrip(".")))

    if is_admin:
        headers.append("actions")
        labels["actions"] = t(lang, "actions")

    # decorate rows
    for r in rows:
        is_active_row = int(r.get("active", 1) or 0) == 1
        r["active"] = "1" if is_active_row else "0"
        if not is_active_row:
            r["_row_class"] = "inactive-row"
        if base == "items":
            ic = str(r.get("item_code","") or "")
            if ic:
                img_url = f"/items/image?item_code={quote_plus(ic)}"
                # prepend small icon link next to name
                nm = str(r.get("item_name","") or "")
                r["item_name"] = f"<a class='btn' style='padding:2px 6px' href='{img_url}'>🖼️</a> " + html_escape(nm)
            else:
                r["item_name"] = html_escape(str(r.get("item_name","") or ""))
        rid = str(r.get("id", ""))
        query_parts = []
        if q:
            query_parts.append(f"q={quote_plus(q)}")
        if show_all:
            query_parts.append("show_all=1")
        next_url = f"/{base}" + (("?" + "&".join(query_parts)) if query_parts else "")
        if rid and is_admin and base in ("items","warehouses","suppliers","equipment"):
            toggle_url = f"/{base}/toggle_active"
            next_active = '0' if is_active_row else '1'
            next_label = 'OFF' if is_active_row else 'ON'
            r["active"] = (
                f"<form method='post' action='{toggle_url}' style='display:flex;align-items:center;gap:8px;margin:0' "
                f"onsubmit=\"if(this.dataset.submitting==='1') return false; this.dataset.submitting='1'; var b=this.querySelector('button[type=submit]'); if(b) b.disabled=true;\">"
                f"{csrf_field_html(username)}"
                f"<input type='hidden' name='id' value='{html_escape(rid)}'>"
                f"<input type='hidden' name='next' value='{html_escape(next_url)}'>"
                f"<input type='hidden' name='active' value='{next_active}'>"
                f"<button type='submit' class='btn' style='padding:0;border:none;background:transparent;display:flex;align-items:center;gap:8px;cursor:pointer'>"
                f"<span class='switch'>"
                f"<input type='checkbox' {'checked' if is_active_row else ''} disabled style='pointer-events:none'>"
                f"<span class='slider'></span>"
                f"</span>"
                f"<span class='small'>{'ON' if is_active_row else 'OFF'} → {next_label}</span>"
                f"</button>"
                f"</form>"
            )
        else:
            badge_cls = 'ok' if is_active_row else 'bad'
            badge_txt = 'نشط' if is_active_row else 'غير نشط'
            r["active"] = f"<span class='badge {badge_cls}'>{badge_txt}</span>"
        if is_admin:
            qpart = f"&q={quote_plus(q)}" if q else ""
            show_all_part = "&show_all=1" if show_all else ""
            edit_url = f"/{base}?edit={quote_plus(rid)}{qpart}{show_all_part}"
            delete_url = f"/{base}?op=delete&id={quote_plus(rid)}{qpart}{show_all_part}"
            r["actions"] = (
                f"<div style='display:flex;gap:6px;flex-wrap:wrap'>"
                f"<a class='btn' href='{edit_url}'>✏️ {html_escape(t(lang,'edit'))}</a>"
                f"<a class='btn bad' href='{delete_url}'>🗑️ {html_escape(t(lang,'delete'))}</a>"
                f"</div>"
            )

    html_table = table(rows, headers, labels, table_id=base, view=f"/{base}", qs=qs)

    # form fields (add / edit)
    form_fields = []
    for name, lbl_key, typ in fields:
        inp_type = "text" if typ == "text" else ("number" if typ == "number" else "text")
        step = ' step="0.001"' if typ == "number" else ""
        val = ""
        if edit_row is not None:
            v = edit_row.get(name, "")
            val = "" if v is None else str(v)
        required_attr = "" if name == "default_unit_price" else " required"
        form_fields.append(
            f"<div class='col3'>"
            f"<label>{html_escape(t(lang,lbl_key))}</label>"
            f"<input name='{html_escape(name)}' type='{inp_type}'{step} value='{html_escape(val)}'{required_attr}>"
            f"</div>"
        )

    if base == "items":
        latest_edit_price = ""
        if edit_row is not None and str(edit_row.get("id") or "").isdigit():
            con_lp = db_connect()
            try:
                rr = con_lp.execute(
                    """
                    SELECT unit_price
                    FROM Transactions
                    WHERE voided=0 AND item_id=? AND unit_price IS NOT NULL AND CAST(unit_price AS REAL) > 0
                    ORDER BY ts DESC, id DESC
                    LIMIT 1
                    """,
                    (int(edit_row.get("id")),),
                ).fetchone()
                if rr:
                    up = rr[0] if not isinstance(rr, sqlite3.Row) else rr["unit_price"]
                    latest_edit_price = f"{float(up):.3f}".rstrip("0").rstrip(".")
            except Exception:
                latest_edit_price = ""
            finally:
                try:
                    con_lp.close()
                except Exception:
                    pass
        form_fields.append(
            f"<div class='col3'>"
            f"<label>{html_escape(t(lang,'last_txn_price'))}</label>"
            f"<input type='text' value='{html_escape(latest_edit_price)}' readonly tabindex='-1' style='background:#f8fafc'>"
            f"</div>"
        )

    next_url = f"/{base}" + (f"?q={quote_plus(q)}" if q else "")
    show_edit_form = bool(edit_row) and is_admin
    show_add_form = (edit_row is None) and can_add

    form_html = ""
    if show_add_form or show_edit_form:
        form_title = f"✏️ {html_escape(t(lang,'edit'))}" if show_edit_form else f"➕ {html_escape(t(lang,'add'))}"
        submit_label = html_escape(t(lang,'update')) if show_edit_form else html_escape(t(lang,'save'))
        hidden = ""
        if show_edit_form:
            hidden += f"<input type='hidden' name='id' value='{html_escape(edit_id)}'>"
        hidden += f"<input type='hidden' name='next' value='{html_escape(next_url)}'>"
        form_html = f"""
        <div class="card no-print">
          <h3 style="margin:0 0 10px">{form_title}</h3>
          <form method="post" action="/{base}/save">
            {hidden}
            <div class="grid">
              {''.join(form_fields)}
              <div class="col12" style="display:flex;gap:10px;flex-wrap:wrap;align-items:center">
                <button class="btn good" type="submit">💾 {submit_label}</button>
                {"<a class='btn' href='"+html_escape(next_url)+"'>↩️ "+html_escape(t(lang,'cancel'))+"</a>" if show_edit_form else ""}
              </div>
            </div>
          </form>
</div>
        """
    elif edit_row is not None and not is_admin:
        form_html = f"<div class='card no-print warn'>{html_escape(t(lang,'admin_only'))}</div>"

    body = f"""
    {tools_bar(base, {"q":[q]} if q else {}, lang)}
    <div class="card no-print">
      <form method="get" action="/{base}">
        <input type="hidden" name="page" value="1">
        <input type="hidden" name="page_size" value="{page_size}">
        <div class="grid">
          <div class="col10">
            <label>{html_escape(t(lang,'search'))}</label>
            <input name="q" value="{html_escape(q)}" placeholder="{html_escape(t(lang,'search'))}"><div class="small" style="margin-top:6px"><label style="display:flex;gap:8px;align-items:center"><input type="checkbox" name="show_all" value="1" {"checked" if show_all else ""}> Show inactive / المخفي</label></div>
          </div>
          <div class="col2" style="display:flex;align-items:end;gap:8px">
            <button class="btn" type="submit">🔎 {html_escape(t(lang,'search'))}</button>
            <a class="btn" href="/{base}">♻️ {html_escape(t(lang,'reset'))}</a>
          </div>
        </div>
      </form>
    </div>

    {form_html}

    <div class="card">
      <div class="small" style="margin-bottom:10px">{html_escape(t(lang,'type_hint'))}</div>
      {pager}
      {html_table}
    </div>
    """
    return page(lang, t(lang, title_key), body, username=username, role=role, flash=flash)



def render_users(lang, username, role, q="", edit_user="", show_all=False, flash=None):
    if role != "ADMIN":
        return page(lang, t(lang, "unauth"), "<div class='card'>Unauthorized</div>", username=username, role=role)

    q = (q or "").strip()
    edit_user = (edit_user or "").strip()
    show_all = bool(show_all)

    con = db_connect()

    # Users list (active only by default; include inactive if show_all=1)
    params = []
    where = []
    if not show_all:
        where.append("active=1")
    if q:
        where.append("username LIKE ?")
        params.append(f"%{q}%")
    wsql = (" WHERE " + " AND ".join(where)) if where else ""
    rows = con.execute(
        "SELECT username, role, active, created_at FROM Users" + wsql + " ORDER BY username",
        tuple(params),
    ).fetchall()

    edit_row = None
    if edit_user:
        r = con.execute("SELECT username, role, active FROM Users WHERE username=?", (edit_user,)).fetchone()
        if r:
            edit_row = dict(r)

    con.close()

    data = [dict(r) for r in rows]

    # Preserve current filters in next/edit links
    q_part = f"&q={quote_plus(q)}" if q else ""
    show_all_part = "&show_all=1" if show_all else ""
    next_url = "/users"
    if q or show_all:
        parts = []
        if q:
            parts.append(f"q={quote_plus(q)}")
        if show_all:
            parts.append("show_all=1")
        next_url += "?" + "&".join(parts)

    # Render an interactive ON/OFF toggle in the users list (admin-only page).
    for r in data:
        u = (r.get("username") or "").strip()
        on = int(r.get("active", 1) or 0) == 1
        disabled = (u == "admin") or (u == username)
        dis_attr = " disabled" if disabled else ""
        r["active"] = (
            f"<form method='post' action='/users/toggle_active' style='display:flex;align-items:center;gap:8px' onsubmit='return true'>"
            f"<input type='hidden' name='username' value='{html_escape(u)}'>"
            f"<input type='hidden' name='next' value='{html_escape(next_url)}'>"
            f"<input type='hidden' name='active' value='0'>"
            f"<label class='switch'>"
            f"<input type='checkbox' name='active' value='1' {'checked' if on else ''}{dis_attr} onchange='this.form.submit()'>"
            f"<span class='slider'></span>"
            f"</label>"
            f"<span class='small'>{'ON' if on else 'OFF'}</span>"
            f"</form>"
        )

    for r in data:
        u = r.get("username", "")
        edit_link = f"/users?edit={quote_plus(u)}{q_part}{show_all_part}"
        btns = [f"<a class='btn' href='{html_escape(edit_link)}'>✏️ {html_escape(t(lang,'edit'))}</a>"]
        if u != "admin":
            btns.append(
                f"<button class='btn bad async-delete-btn' type='button' onclick='return window.__fastDelete ? window.__fastDelete(this) : false' data-confirm='هل أنت متأكد من الحذف النهائي؟' data-endpoint='/users/delete_fast' data-id='{html_escape(u)}' data-name='username'>🗑️ {html_escape(t(lang,'delete'))}</button>"
            )
        r["action"] = "<div style='display:flex;gap:8px;flex-wrap:wrap'>" + "".join(btns) + "</div>"

    headers = ["username", "role", "active", "created_at", "action"]
    labels = {
        "username": t(lang, "username") if "username" in I18N.get(lang, {}) else "Username",
        "role": t(lang, "role") if "role" in I18N.get(lang, {}) else "Role",
        "active": t(lang, "active") if "active" in I18N.get(lang, {}) else "Active",
        "created_at": t(lang, "created_at") if "created_at" in I18N.get(lang, {}) else "Created",
        "action": t(lang, "actions") if "actions" in I18N.get(lang, {}) else "Actions",
    }

    tbl = table(data, headers, labels, table_id="users", view="/users", qs={"q":[q], "show_all":["1" if show_all else ""]})

    form_html = ""
    if edit_row:
        # Edit existing user
        u = edit_row.get("username", "")
        rrole = edit_row.get("role", "VIEWER")
        ractive = int(edit_row.get("active", 1) or 0)
        form_html = f"""
        <div class="card no-print">
          <h3 style="margin:0 0 10px">✏️ {html_escape(t(lang,'edit'))}: {html_escape(u)}</h3>
          <form method="post" action="/users/save">
            <input type="hidden" name="op" value="update">
            <input type="hidden" name="username" value="{html_escape(u)}">
            <input type="hidden" name="next" value="{html_escape(next_url)}">
            {csrf_field_html(username)}
            <div class="grid">
              <div class="col4">
                <label>{html_escape(t(lang,'role'))}</label>
                <select name="role">
                  <option value="VIEWER" {"selected" if rrole=="VIEWER" else ""}>VIEWER</option>
                  <option value="EDITOR" {"selected" if rrole=="EDITOR" else ""}>EDITOR</option>
                  <option value="ADMIN" {"selected" if rrole=="ADMIN" else ""}>ADMIN</option>
                </select>
              </div>
              <div class="col4">
                <label>{html_escape(t(lang,'active'))}</label>
                <select name="active">
                  <option value="1" {"selected" if ractive==1 else ""}>1</option>
                  <option value="0" {"selected" if ractive!=1 else ""}>0</option>
                </select>
              </div>
              <div class="col4" style="display:flex;align-items:end;gap:10px;flex-wrap:wrap">
                <button class="btn good" type="submit">💾 {html_escape(t(lang,'save'))}</button>
                <a class="btn" href="{html_escape(next_url)}">↩️ {html_escape(t(lang,'back')) if 'back' in I18N.get(lang,{}) else 'Back'}</a>
              </div>
            </div>
          </form>
        </div>
        """
    else:
        # Add new user
        form_html = f"""
        <div class="card no-print">
          <h3 style="margin:0 0 10px">➕ {html_escape(t(lang,'add')) if 'add' in I18N.get(lang,{}) else 'Add user'}</h3>
          <form method="post" action="/users/save">
            <input type="hidden" name="op" value="create">
            <input type="hidden" name="next" value="{html_escape(next_url)}">
            {csrf_field_html(username)}
            <div class="grid">
              <div class="col3">
                <label>{html_escape(t(lang,'username')) if 'username' in I18N.get(lang,{}) else 'Username'}</label>
                <input name="username" required autocomplete="username" style="text-transform:uppercase" oninput="this.value=this.value.toUpperCase()">
              </div>
              <div class="col3">
                <label>{html_escape(t(lang,'password')) if 'password' in I18N.get(lang,{}) else 'Password'}</label>
                <input name="password" type="password" required>
              </div>
              <div class="col3">
                <label>{html_escape(t(lang,'role')) if 'role' in I18N.get(lang,{}) else 'Role'}</label>
                <select name="role">
                  <option value="VIEWER">VIEWER</option>
                  <option value="EDITOR">EDITOR</option>
                  <option value="ADMIN">ADMIN</option>
                </select>
              </div>
              <div class="col3" style="display:flex;align-items:end;gap:10px;flex-wrap:wrap">
                <button class="btn good" type="submit">💾 {html_escape(t(lang,'save'))}</button>
              </div>
            </div>
          </form>
        </div>
        """

    body = f"""
    <div class="card no-print">
      <form method="get" action="/users">
        <div class="grid">
          <div class="col10">
            <label>{html_escape(t(lang,'search'))}</label>
            <input name="q" value="{html_escape(q)}" placeholder="{html_escape(t(lang,'search'))}">
            <div class="small" style="margin-top:6px">
              <label style="display:flex;gap:8px;align-items:center">
                <input type="checkbox" name="show_all" value="1" {"checked" if show_all else ""}> Show inactive / المخفي
              </label>
            </div>
          </div>
          <div class="col2" style="display:flex;align-items:end;gap:8px">
            <button class="btn" type="submit">🔎 {html_escape(t(lang,'search'))}</button>
            <a class="btn" href="/users">♻️ {html_escape(t(lang,'reset'))}</a>
          </div>
        </div>
      </form>
    </div>

    {form_html}

    <div class="card">
      {tbl}
    </div>
    """
    return page(lang, t(lang, "users"), body, username=username, role=role, flash=flash)

def render_txn(lang, username, role, qs, flash=None):
    can_add = role in ("ADMIN","EDITOR")
    is_admin = role == "ADMIN"
    sync_status_html = render_sync_status_card(lang, username=username, auto_kick=True, compact=False)

    q_item=(qs.get("q_item",[""])[0] or "")
    q_eq=(qs.get("q_eq",[""])[0] or "")
    q_supplier=(qs.get("q_supplier",[""])[0] or "")
    q_project=(qs.get("q_project",[""])[0] or "")
    q_req=(qs.get("q_req",[""])[0] or "")
    q_doc=(qs.get("q_doc",[""])[0] or "")
    txn_type=(qs.get("txn_type",[""])[0] or "")
    from_date=(qs.get("from_date",[""])[0] or "")
    to_date=(qs.get("to_date",[""])[0] or "")
    voided=(qs.get("voided",["0"])[0] or "0")
    today = _now().date().isoformat()
    tools = tools_bar('txn', qs, lang)


    clear_block = ""
    if is_admin:
        clear_block = f"""
        <div class='card no-print' style='border:1px solid #c33'>
          <h3 style='margin:0 0 10px'>🧹 مسح الحركة بالكامل</h3>
          <div style='margin-bottom:8px;color:#a00'>
            تحذير: هذا الإجراء يحذف كل حركات الاستلام/الصرف/التحويل نهائيًا ولا يمكن التراجع عنه.
          </div>
          <form method='post' action='/txn/clear-all' onsubmit="return confirm('تأكيد نهائي: هل تريد مسح الحركة بالكامل؟');">
            <div class='grid'>
              <div class='col4'>
                <label>Password</label>
                <input type='password' name='pw' placeholder='أدخل كلمة المرور'>
              </div>
              <div class='col4' style='display:flex;align-items:flex-end'>
                <button class='btn danger' type='submit'>🧨 مسح كل الحركة</button>
              </div>
            </div>
          </form>
        </div>
        """



    # Bulk PDF attach (attach same PDF to multiple selected transactions)
    bulk_block = ""
    if can_add:
        bulk_block = """
        <div class='card no-print'>
          <h3 style='margin:0 0 10px'>📎 رفع PDF للحركات المحددة</h3>
          <div class='small muted' style='margin-bottom:8px'>
            اختر الحركات من الجدول ثم ارفع PDF واحد سيتم إرفاقه لكل الحركات المحددة.
          </div>
          <form id='bulkAttachForm' method='post' action='/txn/attach_bulk' enctype='multipart/form-data' style='display:flex;gap:10px;flex-wrap:wrap;align-items:end' onsubmit="return bulkCollectTxnIds();">
            """ + csrf_field_html(username) + """
            <input type='hidden' name='txn_ids_csv' id='bulkTxnIdsCsv' value=''>
            <input type='hidden' name='txn_ids_json' id='bulkTxnIdsJson' value='[]'>
            <input type='hidden' name='txn_ids_count' id='bulkTxnIdsCount' value='0'>
            <div>
              <label style='display:block;margin-bottom:4px'>PDF</label>
              <input type='file' name='pdf' accept='application/pdf' required>
            </div>
            <div style='display:flex;gap:8px;flex-wrap:wrap;align-items:end'>
              <button class='btn' type='submit' onclick="return confirm('تأكيد: رفع نفس PDF لكل الحركات المحددة؟');">⬆️ رفع PDF</button>
              <button class='btn' type='button' onclick="bulkToggleTxnSelection();">☑️ تحديد/إلغاء الكل</button>
              <span class='small muted'>* الحركات الـ voided لن تُحدد.</span>
            </div>
          </form>
          <script>
          function bulkSelectedTxnIds(){
            var a=document.querySelectorAll('.txnSel');
            var ids=[];
            var seen={};
            for(var i=0;i<a.length;i++){
              var el=a[i];
              if(!el || !el.checked || el.disabled) continue;
              var v=(el.getAttribute('data-txn-id') || el.value || el.getAttribute('data-id') || '').trim();
              if(!v) continue;
              if(!/^[0-9]+$/.test(v)) continue;
              if(seen[v]) continue;
              seen[v]=1;
              ids.push(v);
            }
            return ids;
          }
          function bulkSyncTxnIds(){
            try{
              var ids=bulkSelectedTxnIds();
              var csv=document.getElementById('bulkTxnIdsCsv');
              var jsn=document.getElementById('bulkTxnIdsJson');
              var cnt=document.getElementById('bulkTxnIdsCount');
              if(csv) csv.value=ids.join(',');
              if(jsn) jsn.value=JSON.stringify(ids);
              if(cnt) cnt.value=String(ids.length);
              return ids;
            }catch(e){
              return [];
            }
          }
          function bulkToggleTxnSelection(){
            try{
              var a=document.querySelectorAll('.txnSel');
              var any=false;
              for(var i=0;i<a.length;i++){ if(a[i] && !a[i].disabled && a[i].checked){ any=true; break; } }
              for(var j=0;j<a.length;j++){ if(a[j] && !a[j].disabled){ a[j].checked=!any; } }
              bulkSyncTxnIds();
            }catch(e){}
          }
          function bulkCollectTxnIds(){
            var ids=bulkSyncTxnIds();
            if(!ids || ids.length===0){
              alert('❌ لم يتم اختيار حركات');
              return false;
            }
            return true;
          }
          document.addEventListener('change', function(ev){
            var t=ev && ev.target;
            if(t && t.classList && t.classList.contains('txnSel')){ bulkSyncTxnIds(); }
          }, true);
          document.addEventListener('DOMContentLoaded', function(){ bulkSyncTxnIds(); });
          </script>
        </div>
        """
    # pagination (same style as balances)
    page_no = qs_int(qs, "page", 1, 1, 100000)
    page_size = qs_int(qs, "page_size", 1000,  100,  10000)
    offset = (page_no - 1) * page_size

    # edit mode (ADMIN only)
    edit_id = (qs.get("edit", [""])[0] or "").strip()
    edit_row = None
    if is_admin and edit_id.isdigit():
        con = db_connect()
        r = con.execute("SELECT * FROM Transactions WHERE id=?", (int(edit_id),)).fetchone()
        con.close()
        edit_row = dict(r) if r else None

    total_rows = count_txn(
        q_item=q_item, q_eq=q_eq, q_supplier=q_supplier, q_project=q_project, q_req=q_req, q_doc=q_doc, txn_type=txn_type,
        from_date=from_date, to_date=to_date,
        include_voided=voided in ("1","true","yes")
    )
    rows = list_txn(
        q_item=q_item, q_eq=q_eq, q_supplier=q_supplier, q_project=q_project, q_req=q_req, q_doc=q_doc, txn_type=txn_type,
        from_date=from_date, to_date=to_date,
        include_voided=voided in ("1","true","yes"),
        limit=page_size, offset=offset
    )
    total_pages = max(1, (int(total_rows or 0) + page_size - 1) // page_size)
    has_prev = page_no > 1
    has_next = page_no < total_pages
    pager = ""

    # datalists
    items, whs, eqs, sups = lookup_active_for_datalists()
    dl_items = "".join([f'<option value="{html_escape(x["item_code"])}">{html_escape(x["item_name"])}</option>' for x in items])
    dl_wh = "".join([f'<option value="{html_escape(x["wh_code"])}">{html_escape(x["wh_name"])}</option>' for x in whs])
    dl_eq = "".join([f'<option value="{html_escape(x["eq_code"])}">{html_escape(x["eq_name"])}</option>' for x in eqs])
    dl_sup = "".join([f'<option value="{html_escape(x["supplier_code"])}">{html_escape(x["supplier_name"])}</option>' for x in sups])
    try:
        projects = list_active_projects_for_datalist()
    except Exception:
        projects = []
    dl_project = "".join([f'<option value="{html_escape(x["project_code"])}">{html_escape(x["project_name"] or "")}</option>' for x in projects])


    # preserve filters for edit links / return redirects (drop edit only)
    qs_keep = {}
    for k, v in (qs or {}).items():
        if k in ("edit", "m"):
            continue
        if not v:
            continue
        vv = (v[0] or "").strip()
        if vv != "":
            qs_keep[k] = vv
    q_keep = ("?" + urlencode(qs_keep)) if qs_keep else ""
    next_url = "/txn" + q_keep
    qpart = ("&" + urlencode(qs_keep)) if qs_keep else ""


    # bulk select column (for bulk PDF attach)
    for r in rows:
        rid = str(r.get("id","") or "")
        try:
            is_voided = int(r.get("voided",0) or 0) == 1
        except Exception:
            is_voided = False
        if rid.isdigit() and not is_voided and can_add:
            r["sel"] = f"<input type='checkbox' class='txnSel' data-txn-id='{html_escape(rid)}' value='{html_escape(rid)}'>"
        else:
            r["sel"] = "<input type='checkbox' disabled style='opacity:.35'>"
    # table rows
    headers=["sel","id","ts","txn_type","issue_type","cost_allocation","project_code","item_code","item_name","qty","scrap_qty","unit_price","wh_from_code","wh_to_code","eq_code","supplier_code","req_no","po_no","doc_no","notes","attach","voided"]
    labels={"sel":"☑","id":"ID","ts":"TS","txn_type":t(lang,"type"),"issue_type":"Issue Type","cost_allocation":"Cost Allocation","project_code":"Project","item_code":t(lang,"item_code"),"item_name":t(lang,"item_name"),
            "qty":t(lang,"qty"),"scrap_qty":t(lang,"scrap_qty"),"unit_price":t(lang,"unit_price"),"wh_from_code":t(lang,"wh_from"),"wh_to_code":t(lang,"wh_to"),
            "eq_code":t(lang,"eq_code"),"supplier_code":t(lang,"supplier_code"),
            "req_no":t(lang,"req_no"),"po_no":t(lang,"po_no"),"doc_no":t(lang,"doc_no"),"notes":t(lang,"notes"),
            "attach":"📎 PDF",
            "voided":t(lang,"voided")}

    if is_admin:
        headers.append("actions")
        labels["actions"] = t(lang, "actions")

    # decorate actions (ADMIN only, and not on voided rows)
    if is_admin:
        for r in rows:
            rid = str(r.get("id",""))
            is_void = int(r.get("voided",0) or 0) == 1
            try:
                ttype = str(r.get("txn_type","") or "").upper()
            except Exception:
                ttype = ""
            # PDF attachment: allowed for all transaction types (RECEIVE / ISSUE / TRANSFER ...)
            has_pdf = bool(r.get("attachment_path"))
            tag = "📄✅" if has_pdf else "📄➕"
            r["attach"] = f"<a class='btn' style='padding:2px 6px' href='/txn/attach?txn_id={quote_plus(rid)}' title='PDF'>{tag}</a>"
            if (not rid.isdigit()) or is_void:
                r["actions"] = "<span class='small muted'>—</span>"
                continue

            edit_url = f"/txn?edit={quote_plus(rid)}{qpart}"
            delete_url = f"/txn?op=delete&id={quote_plus(rid)}{qpart}"
            r["actions"] = (
                "<div style='display:flex;gap:6px;flex-wrap:wrap'>"
                f"<a class='btn' href='{edit_url}'>✏️ {html_escape(t(lang,'edit'))}</a>"
                f"<a class='btn bad' href='{delete_url}'>🗑️ {html_escape(t(lang,'delete'))}</a>"
                "</div>"
            )

    tbl=table(rows, headers, labels)

    # form (add / edit)
    form = ""
    if can_add:
        show_edit = bool(edit_row) and is_admin and int(edit_row.get("voided",0) or 0) == 0
        form_title = f"✏️ {html_escape(t(lang,'edit'))}" if show_edit else f"🧾 {html_escape(t(lang,'txn'))}"
        submit_label = html_escape(t(lang,'update')) if show_edit else html_escape(t(lang,'save'))

        def _val(key, default=""):
            if show_edit:
                v = edit_row.get(key, default)
                return "" if v is None else str(v)
            qv = (qs.get(key, [""])[0] or "").strip() if isinstance(qs, dict) else ""
            if qv != "":
                return qv
            return default

        # txn_date is used for NEW entries only (update_txn keeps original timestamp)
        txn_date_value = today if not show_edit else (str(edit_row.get("ts",""))[:10] if edit_row.get("ts") else today)
        txn_date_attrs = "" if not show_edit else " readonly"

        hidden_id = f"<input type='hidden' name='id' value='{html_escape(edit_id)}'>" if show_edit else ""

        note_date = ""
        if show_edit:
            note_date = "<div class='small muted'>* تاريخ الحركة لا يتغير عند التعديل (التعديل يحافظ على التوقيت الأصلي)</div>"

