def compute_v81_purchase_suggestions(days=30):
    days = max(1, int(days or 30))
    con = db_connect()
    try:
        since = (_now() - timedelta(days=days)).date().isoformat()
        rows = con.execute("""
            SELECT i.item_code, i.item_name, i.unit, COALESCE(SUM(CASE WHEN t.txn_type='ISSUE' AND t.voided=0 THEN t.qty ELSE 0 END),0) AS issued_qty
            FROM Items i
            LEFT JOIN Transactions t ON t.item_id=i.id AND substr(t.ts,1,10) >= ?
            WHERE COALESCE(i.active,1)=1
            GROUP BY i.id
        """, (since,)).fetchall()
        bal_map = {}
        for r in balance_rows(limit=200000, offset=0):
            bal_map[r.get('item_code')] = bal_map.get(r.get('item_code'), 0.0) + float(r.get('balance') or 0.0)
        out = []
        for r in rows:
            issued = float(r['issued_qty'] or 0.0)
            if issued <= 0:
                continue
            daily = issued / float(days)
            current = float(bal_map.get(r['item_code'], 0.0) or 0.0)
            days_left = (current / daily) if daily > 1e-9 else 999999
            if days_left <= 21:
                out.append({
                    'item_code': r['item_code'],
                    'item_name': r['item_name'],
                    'unit': r['unit'],
                    'current_balance': round(current, 3),
                    'avg_daily_issue': round(daily, 3),
                    'days_left': round(days_left, 1),
                    'suggest_qty': round(max((30.0 * daily) - current, 0.0), 3),
                })
        out.sort(key=lambda x: (x['days_left'], -x['avg_daily_issue']))
        return out[:50]
    finally:
        con.close()

def compute_v81_abnormal_equipment(days=30):
    days=max(1,int(days or 30))
    qs={'days': str(days), 'limit': '15'}
    rows = compute_equipment_consumption(qs)
    vals=[float(r.get('total_cost') or 0.0) for r in rows if float(r.get('total_cost') or 0.0) > 0]
    if not vals:
        return []
    avg=sum(vals)/len(vals)
    threshold=avg*1.8
    out=[]
    for r in rows:
        val=float(r.get('total_cost') or 0.0)
        if val >= threshold and val>0:
            rr=dict(r)
            rr['alert']='مرتفع غير طبيعي'
            out.append(rr)
    return out[:10]

def render_v81(lang, user, role, qs):
    days = qs_int(qs, 'days', 30, 7, 365)
    wh = (qs.get('wh', [''])[0] or '').strip()
    suggestions = compute_v81_purchase_suggestions(days=days)
    abnormal_eq = compute_v81_abnormal_equipment(days=days)
    no_price = list_no_price_items(limit=50) if 'list_no_price_items' in globals() else []
    low_rows = low_stock_rows_global(limit=50, offset=0)
    rows_cc, meta_cc = compute_cost_centers({'wh_code': wh} if wh else {})
    warn_cards = []
    if suggestions:
        warn_cards.append(f"<div class='kpi'><div class='v'>{len(suggestions)}</div><div class='k'>اقتراحات شراء</div></div>")
    if abnormal_eq:
        warn_cards.append(f"<div class='kpi'><div class='v'>{len(abnormal_eq)}</div><div class='k'>معدات استهلاكها شاذ</div></div>")
    if no_price:
        warn_cards.append(f"<div class='kpi'><div class='v'>{len(no_price)}</div><div class='k'>أصناف بدون سعر</div></div>")
    if low_rows:
        warn_cards.append(f"<div class='kpi'><div class='v'>{len(low_rows)}</div><div class='k'>تحت الحد الأدنى</div></div>")
    sug_tbl = table(suggestions, ['item_code','item_name','current_balance','avg_daily_issue','days_left','suggest_qty'], {'item_code':'كود','item_name':'الصنف','current_balance':'الرصيد','avg_daily_issue':'متوسط الصرف اليومي','days_left':'أيام متبقية','suggest_qty':'اقتراح شراء'}) if suggestions else "<div class='muted'>لا توجد اقتراحات شراء حالياً.</div>"
    ab_tbl = table(abnormal_eq, ['eq_code','eq_name','issue_count','total_cost','alert'], {'eq_code':'المعدة','eq_name':'الاسم','issue_count':'عدد الحركات','total_cost':'إجمالي التكلفة','alert':'تنبيه'}) if abnormal_eq else "<div class='muted'>لا توجد معدات شاذة حالياً.</div>"
    np_tbl = table(no_price[:20], ['item_code','item_name','unit'], {'item_code':'كود','item_name':'الصنف','unit':'الوحدة'}) if no_price else "<div class='muted'>كل الأصناف المسعرة جيدة.</div>"
    low_tbl = table(low_rows[:20], ['item_code','item_name','balance','min_qty','shortage'], {'item_code':'كود','item_name':'الصنف','balance':'الرصيد','min_qty':'الحد الأدنى','shortage':'العجز'}) if low_rows else "<div class='muted'>لا يوجد Low Stock حالياً.</div>"
    cc_tbl = table(rows_cc[:20], ['wh_code','wh_name','in_value','out_value','net'], {'wh_code':'كود','wh_name':'المستودع','in_value':'الوارد','out_value':'الصادر','net':'الصافي'}) if rows_cc else "<div class='muted'>لا توجد بيانات تكلفة.</div>"
    body = f"""
    <div class='card no-print'>
      <h2 style='margin:0 0 10px'>🤖 V8.1 الذكاء التنفيذي</h2>
      <form method='get' action='/v8_1' class='grid2'>
        <div><label>عدد الأيام للتحليل</label><input type='number' min='7' max='365' name='days' value='{days}'></div>
        <div style='display:flex;align-items:end;gap:8px'><button class='btn' type='submit'>تحليل</button><a class='btn' href='/v8_1'>تفريغ</a></div>
      </form>
    </div>
    <div class='card'><div class='kpi-grid'>{''.join(warn_cards) or '<div class="muted">لا توجد تنبيهات حالياً.</div>'}</div></div>
    <div class='card'><div style='display:flex;justify-content:space-between;gap:10px;flex-wrap:wrap;align-items:center'><h3 style='margin:0'>اقتراح شراء تلقائي</h3><a class='btn' href='/balances'>فتح الأرصدة</a></div>{sug_tbl}</div>
    <div class='card'><h3 style='margin:0 0 10px'>معدة استهلاكها شاذ</h3>{ab_tbl}</div>
    <div class='card'><h3 style='margin:0 0 10px'>أصناف بدون سعر</h3>{np_tbl}</div>
    <div class='card'><h3 style='margin:0 0 10px'>أصناف تحت الحد الأدنى</h3>{low_tbl}</div>
    <div class='card'><h3 style='margin:0 0 10px'>ملخص مراكز التكلفة</h3>{cc_tbl}</div>
    """
    return page(lang, 'V8.1 الذكاء', body, user, role=role)



def _project_report_money(v):
    try:
        return fmt_money0(v)
    except Exception:
        try:
            return f"{float(v or 0):,.2f}"
        except Exception:
            return str(v or 0)

@ROUTER.get('/project_report')
def project_report(handler):
    user, role, lang = handler._need_login()
    if not user:
        return

    qs = parse_qs(urlparse(handler.path).query)
    q_project = normalize_code((qs.get('project_code', [''])[0] or '').strip())
    q_issue_type = (qs.get('issue_type', [''])[0] or '').strip().upper()
    q_cost_alloc = (qs.get('cost_allocation', [''])[0] or '').strip().upper()
    q_from = (qs.get('from_date', [''])[0] or '').strip()
    q_to = (qs.get('to_date', [''])[0] or '').strip()

    con = db_connect()
    try:
        projects = con.execute("SELECT project_code, project_name FROM Projects WHERE COALESCE(active,1)=1 ORDER BY project_code").fetchall()
        dl_projects = ''.join(
            f"<option value='{html_escape(r['project_code'])}'>{html_escape((r['project_name'] or ''))}</option>"
            for r in projects
        )

        where = ["T.voided=0", "T.txn_type='ISSUE'", "T.project_id IS NOT NULL"]
        params = []
        if q_project:
            where.append("P.project_code=?")
            params.append(q_project)
        if q_issue_type:
            where.append("UPPER(COALESCE(T.issue_type,''))=?")
            params.append(q_issue_type)
        if q_cost_alloc:
            where.append("UPPER(COALESCE(T.cost_allocation,''))=?")
            params.append(q_cost_alloc)
        _ts_sql, date_params = _sqlite_ts_range(q_from, q_to, field='T.ts')
        if _ts_sql:
            where.append(_ts_sql)
            params.extend(date_params)
        where_sql = ' AND '.join(where)

        summary = con.execute(f"""
            SELECT
              P.project_code,
              P.project_name,
              ROUND(COALESCE(SUM(T.qty * COALESCE(T.unit_price,0)),0),2) AS total_cost,
              ROUND(COALESCE(SUM(T.qty),0),3) AS total_qty,
              COUNT(T.id) AS txn_count,
              COUNT(DISTINCT T.item_id) AS item_count,
              COUNT(DISTINCT T.eq_id) AS eq_count,
              ROUND(COALESCE(SUM(CASE WHEN UPPER(COALESCE(T.issue_type,''))='MAINTENANCE' THEN T.qty * COALESCE(T.unit_price,0) ELSE 0 END),0),2) AS maintenance_cost,
              ROUND(COALESCE(SUM(CASE WHEN UPPER(COALESCE(T.issue_type,''))='PROJECT_DIRECT' THEN T.qty * COALESCE(T.unit_price,0) ELSE 0 END),0),2) AS direct_cost,
              ROUND(COALESCE(SUM(CASE WHEN UPPER(COALESCE(T.cost_allocation,''))='OVERHEAD' THEN T.qty * COALESCE(T.unit_price,0) ELSE 0 END),0),2) AS overhead_cost
            FROM Projects P
            LEFT JOIN Transactions T ON T.project_id=P.id
            WHERE {where_sql.replace('T.project_id IS NOT NULL AND ', '')}
            GROUP BY P.id
            HAVING COALESCE(SUM(CASE WHEN T.id IS NOT NULL THEN 1 ELSE 0 END),0) > 0
            ORDER BY total_cost DESC, P.project_code ASC
        """, params).fetchall()

        detail_items = []
        detail_eq = []
        detail_txn = []
        chosen = None
        if q_project:
            chosen = con.execute("SELECT id, project_code, project_name FROM Projects WHERE project_code=?", (q_project,)).fetchone()
            if chosen:
                dwhere = ["T.voided=0", "T.txn_type='ISSUE'", "T.project_id=?"]
                dparams = [chosen['id']]
                if q_issue_type:
                    dwhere.append("UPPER(COALESCE(T.issue_type,''))=?")
                    dparams.append(q_issue_type)
                if q_cost_alloc:
                    dwhere.append("UPPER(COALESCE(T.cost_allocation,''))=?")
                    dparams.append(q_cost_alloc)
                if _ts_sql:
                    dwhere.append(_ts_sql)
                    dparams.extend(date_params)
                dwhere_sql = ' AND '.join(dwhere)

                detail_items = con.execute(f"""
                    SELECT
                      I.item_code,
                      I.item_name,
                      ROUND(COALESCE(SUM(T.qty),0),3) AS total_qty,
                      ROUND(COALESCE(AVG(COALESCE(T.unit_price,0)),0),4) AS avg_price,
                      ROUND(COALESCE(SUM(T.qty * COALESCE(T.unit_price,0)),0),2) AS total_cost,
                      COUNT(T.id) AS txn_count
                    FROM Transactions T
                    JOIN Items I ON I.id=T.item_id
                    WHERE {dwhere_sql}
                    GROUP BY I.id
                    ORDER BY total_cost DESC, I.item_code ASC
                    LIMIT 300
                """, dparams).fetchall()

                detail_eq = con.execute(f"""
                    SELECT
                      COALESCE(E.eq_code,'') AS eq_code,
                      COALESCE(E.eq_name,'') AS eq_name,
                      ROUND(COALESCE(SUM(T.qty * COALESCE(T.unit_price,0)),0),2) AS total_cost,
                      ROUND(COALESCE(SUM(T.qty),0),3) AS total_qty,
                      COUNT(T.id) AS txn_count
                    FROM Transactions T
                    LEFT JOIN Equipment E ON E.id=T.eq_id
                    WHERE {dwhere_sql}
                    GROUP BY COALESCE(E.id,0), COALESCE(E.eq_code,''), COALESCE(E.eq_name,'')
                    ORDER BY total_cost DESC, eq_code ASC
                    LIMIT 200
                """, dparams).fetchall()

                detail_txn = con.execute(f"""
                    SELECT
                      T.id,
                      substr(T.ts,1,10) AS txn_date,
                      COALESCE(I.item_code,'') AS item_code,
                      COALESCE(I.item_name,'') AS item_name,
                      ROUND(COALESCE(T.qty,0),3) AS qty,
                      ROUND(COALESCE(T.unit_price,0),4) AS unit_price,
                      ROUND(COALESCE(T.qty,0) * COALESCE(T.unit_price,0),2) AS line_cost,
                      COALESCE(E.eq_code,'') AS eq_code,
                      COALESCE(T.issue_type,'') AS issue_type,
                      COALESCE(T.cost_allocation,'') AS cost_allocation,
                      COALESCE(T.doc_no,'') AS doc_no,
                      COALESCE(T.req_no,'') AS req_no,
                      COALESCE(T.po_no,'') AS po_no
                    FROM Transactions T
                    LEFT JOIN Items I ON I.id=T.item_id
                    LEFT JOIN Equipment E ON E.id=T.eq_id
                    WHERE {dwhere_sql}
                    ORDER BY T.ts DESC, T.id DESC
                    LIMIT 400
                """, dparams).fetchall()
    finally:
        con.close()

    def _badge(v):
        s = html_escape(v or '-')
        return f"<span class='badge'>{s}</span>"

    total_projects = len(summary)
    total_cost = sum(float(r['total_cost'] or 0) for r in summary)
    total_txn = sum(int(r['txn_count'] or 0) for r in summary)
    total_items = sum(int(r['item_count'] or 0) for r in summary)
    top_project = summary[0] if summary else None

    filters = f"""
    <div class='card'>
      <form method='get' action='/project_report' class='grid2'>
        <div><label>المشروع</label><input name='project_code' list='dl_projects' value='{html_escape(q_project)}' placeholder='مثال: GENERAL أو PRJ-001'></div>
        <div><label>نوع الصرف</label><select name='issue_type'>
            <option value=''>الكل</option>
            <option value='PROJECT_DIRECT' {'selected' if q_issue_type=='PROJECT_DIRECT' else ''}>PROJECT_DIRECT</option>
            <option value='MAINTENANCE' {'selected' if q_issue_type=='MAINTENANCE' else ''}>MAINTENANCE</option>
            <option value='INTERNAL' {'selected' if q_issue_type=='INTERNAL' else ''}>INTERNAL</option>
            <option value='SCRAP' {'selected' if q_issue_type=='SCRAP' else ''}>SCRAP</option>
        </select></div>
        <div><label>تحميل التكلفة</label><select name='cost_allocation'>
            <option value=''>الكل</option>
            <option value='PROJECT' {'selected' if q_cost_alloc=='PROJECT' else ''}>PROJECT</option>
            <option value='OVERHEAD' {'selected' if q_cost_alloc=='OVERHEAD' else ''}>OVERHEAD</option>
        </select></div>
        <div><label>من تاريخ</label><input type='date' name='from_date' value='{html_escape(q_from)}'></div>
        <div><label>إلى تاريخ</label><input type='date' name='to_date' value='{html_escape(q_to)}'></div>
        <div style='display:flex;align-items:end;gap:8px'><button class='btn pri' type='submit'>🔎 تحليل</button><a class='btn' href='/project_report'>↺ تفريغ</a></div>
      </form>
      <datalist id='dl_projects'>{dl_projects}</datalist>
    </div>
    """

    kpis = f"""
    <div class='grid4'>
      <div class='kpi'><div class='k'>عدد المشاريع</div><div class='v'>{total_projects}</div></div>
      <div class='kpi'><div class='k'>إجمالي الصرف</div><div class='v'>{html_escape(_project_report_money(total_cost))}</div></div>
      <div class='kpi'><div class='k'>عدد الحركات</div><div class='v'>{total_txn}</div></div>
      <div class='kpi'><div class='k'>الأصناف المختلفة</div><div class='v'>{total_items}</div></div>
    </div>
    """
    if top_project:
        kpis += f"<div class='card'><b>أعلى مشروع صرفًا:</b> {html_escape(top_project['project_code'])} — {html_escape(top_project['project_name'] or '')} <span class='muted'>({_project_report_money(top_project['total_cost'])})</span></div>"

    summary_rows = []
    for r in summary:
        summary_rows.append(f"""
        <tr>
          <td><a href='/project_report?project_code={quote_plus(r['project_code'])}{('&issue_type='+quote_plus(q_issue_type)) if q_issue_type else ''}{('&cost_allocation='+quote_plus(q_cost_alloc)) if q_cost_alloc else ''}{('&from_date='+quote_plus(q_from)) if q_from else ''}{('&to_date='+quote_plus(q_to)) if q_to else ''}'>{html_escape(r['project_code'])}</a></td>
          <td>{html_escape(r['project_name'] or '')}</td>
          <td>{html_escape(_project_report_money(r['total_cost']))}</td>
          <td>{html_escape(_project_report_money(r['maintenance_cost']))}</td>
          <td>{html_escape(_project_report_money(r['direct_cost']))}</td>
          <td>{html_escape(_project_report_money(r['overhead_cost']))}</td>
          <td>{r['txn_count']}</td>
          <td>{r['item_count']}</td>
          <td>{r['eq_count']}</td>
        </tr>
        """)

    summary_tbl = f"""
    <div class='card'>
      <h2 style='margin-top:0'>💰 ملخص صرف المشاريع</h2>
      <div class='table-wrap'><table class='table'><thead><tr>
        <th>كود المشروع</th><th>اسم المشروع</th><th>إجمالي الصرف</th><th>صيانة</th><th>مباشر</th><th>Overhead</th><th>الحركات</th><th>الأصناف</th><th>المعدات</th>
      </tr></thead><tbody>{''.join(summary_rows) if summary_rows else "<tr><td colspan='9' class='muted'>لا توجد بيانات</td></tr>"}</tbody></table></div>
    </div>
    """

    details_html = ""
    if q_project:
        title = html_escape(q_project)
        if chosen:
            title += " — " + html_escape(chosen['project_name'] or '')
        item_rows = ''.join(
            f"<tr><td>{html_escape(r['item_code'])}</td><td>{html_escape(r['item_name'])}</td><td>{r['total_qty']}</td><td>{r['avg_price']}</td><td>{html_escape(_project_report_money(r['total_cost']))}</td><td>{r['txn_count']}</td></tr>"
            for r in detail_items
        ) or "<tr><td colspan='6' class='muted'>لا توجد أصناف</td></tr>"
        eq_rows = ''.join(
            f"<tr><td>{html_escape(r['eq_code'] or '-')}</td><td>{html_escape(r['eq_name'] or '')}</td><td>{r['total_qty']}</td><td>{html_escape(_project_report_money(r['total_cost']))}</td><td>{r['txn_count']}</td></tr>"
            for r in detail_eq
        ) or "<tr><td colspan='5' class='muted'>لا توجد معدات</td></tr>"
        txn_rows = ''.join(
            f"<tr><td>{r['txn_date']}</td><td>{r['id']}</td><td>{html_escape(r['item_code'])}</td><td>{html_escape(r['item_name'])}</td><td>{r['qty']}</td><td>{r['unit_price']}</td><td>{html_escape(_project_report_money(r['line_cost']))}</td><td>{html_escape(r['eq_code'] or '-')}</td><td>{_badge(r['issue_type'])}</td><td>{_badge(r['cost_allocation'])}</td><td>{html_escape(r['doc_no'])}</td><td>{html_escape(r['req_no'])}</td></tr>"
            for r in detail_txn
        ) or "<tr><td colspan='12' class='muted'>لا توجد حركات</td></tr>"
        details_html = f"""
        <div class='card'>
          <h2 style='margin-top:0'>📌 تفاصيل المشروع: {title}</h2>
          <div class='grid2'>
            <div>
              <h3>📦 الأصناف المصروفة</h3>
              <div class='table-wrap'><table class='table'><thead><tr><th>الكود</th><th>الصنف</th><th>الكمية</th><th>متوسط السعر</th><th>إجمالي التكلفة</th><th>الحركات</th></tr></thead><tbody>{item_rows}</tbody></table></div>
            </div>
            <div>
              <h3>🚜 المعدات المستفيدة</h3>
              <div class='table-wrap'><table class='table'><thead><tr><th>كود المعدة</th><th>اسم المعدة</th><th>الكمية</th><th>إجمالي التكلفة</th><th>الحركات</th></tr></thead><tbody>{eq_rows}</tbody></table></div>
            </div>
          </div>
        </div>
        <div class='card'>
          <h3 style='margin-top:0'>🧾 آخر حركات المشروع</h3>
          <div class='table-wrap'><table class='table'><thead><tr><th>التاريخ</th><th>ID</th><th>كود الصنف</th><th>الصنف</th><th>الكمية</th><th>سعر الوحدة</th><th>التكلفة</th><th>المعدة</th><th>نوع الصرف</th><th>التحميل</th><th>رقم السند</th><th>رقم الطلب</th></tr></thead><tbody>{txn_rows}</tbody></table></div>
        </div>
        """

    body = filters + kpis + summary_tbl + details_html
    return handler._send_html(page(lang, 'تقرير المشاريع', body, user, role=role))

@ROUTER.get('/v8_1')
def _rt_v81(handler):
    user, role, lang = _router_need_login(handler)
    if not user:
        return
    parsed = urlparse(handler.path)
    qs = parse_qs(parsed.query)
    return handler._send_html(render_v81(lang, user, role, qs))

def render_requests(lang, username, role, qs):
    # flash messages
    msg=(qs.get("m",[""])[0] or "").strip()
    ok=(qs.get("ok",[""])[0] or "").strip()
    flash = msg or (t(lang,"ok") if ok else None)

    # filters
    req_date=(qs.get("req_date",[""])[0] or "").strip()
    status=(qs.get("status",["ALL"])[0] or "ALL").strip()
    q_wh=(qs.get("q_wh",[""])[0] or "").strip()
    q_maint=(qs.get("q_maint",[""])[0] or "").strip()
    q_whreq=(qs.get("q_whreq",[""])[0] or "").strip()
    q_po=(qs.get("q_po",[""])[0] or "").strip()
    q_eq=(qs.get("q_eq",[""])[0] or "").strip()
    limit=int((qs.get("limit",["500"])[0] or "500").strip() or "500")

    edit_id=(qs.get("edit",[""])[0] or "").strip()
    rec = get_request(edit_id) if edit_id else None
    page_no = qs_int(qs, "page", 1, 1, 100000)
    page_size = qs_int(qs, "page_size", 120, 20, 1000)
    offset = (page_no - 1) * page_size
    rows = list_requests(req_date=req_date, status=status, q_wh=q_wh, q_maint=q_maint, q_whreq=q_whreq, q_po=q_po, q_eq=q_eq, limit=page_size+1, offset=offset)
    has_next = len(rows) > page_size
    rows = rows[:page_size]
    pager = ""

    # status datalist from existing values
    try:
        con=db_connect()
        sts=[r["s"] for r in con.execute("SELECT DISTINCT COALESCE(status,'') AS s FROM StandaloneRequests WHERE COALESCE(status,'')<>'' ORDER BY s").fetchall()]
        con.close()
    except Exception:
        sts=[]
    dl_status="".join([f'<option value="{html_escape(s)}"></option>' for s in sts])

    headers=["req_date","warehouse_name","maint_req_no","wh_req_no","po_no","eq_code","status","notes","actions"]
    labels={
        "req_date":t(lang,"date"),
        "warehouse_name":t(lang,"wh_name"),
        "maint_req_no":t(lang,"maint_req_no"),
        "wh_req_no":t(lang,"wh_req_no"),
        "po_no":t(lang,"po_no"),
        "eq_code":t(lang,"eq_code"),
        "status":t(lang,"status"),
        "notes":t(lang,"notes"),
        "actions":t(lang,"actions"),
    }

    def act(r):
        rid=str(r.get("id"))
        return (
            f"<a class='btn sm' href='/requests?edit={quote_plus(rid)}'>✏️ {html_escape(t(lang,'edit'))}</a>"
            f"<button class='btn sm bad async-delete-btn' type='button' onclick='return window.__fastDelete ? window.__fastDelete(this) : false' data-confirm='هل أنت متأكد من الحذف النهائي؟' data-endpoint='/requests/delete_fast' data-id='{html_escape(rid)}'>🗑 {html_escape(t(lang,'delete'))}</button>"
        )

    trows=[]
    for r in rows:
        rr=dict(r)
        rr["actions"]=act(rr)
        trows.append(rr)

    # filters UI
    body=f"""
    <div class='card no-print'>
      {tools_bar('requests', qs, lang)}
      <form method='get' action='/requests'>
        <input type='hidden' name='page' value='1'>
        <input type='hidden' name='page_size' value='{html_escape(str(page_size))}'>
        <div class='grid'>
          <div class='col3'><label>{html_escape(t(lang,'date'))}</label><input type='date' name='req_date' value='{html_escape(req_date)}'></div>
          <div class='col3'><label>{html_escape(t(lang,'status'))}</label><input name='status' list='dl_status' value='{html_escape(status if status else "ALL")}' placeholder='ALL'><datalist id='dl_status'>{dl_status}</datalist></div>
          <div class='col3'><label>{html_escape(t(lang,'wh_name'))}</label><input name='q_wh' value='{html_escape(q_wh)}' placeholder='{html_escape(t(lang,"search"))}'></div>
          <div class='col3'><label>{html_escape(t(lang,'maint_req_no'))}</label><input name='q_maint' value='{html_escape(q_maint)}' placeholder='{html_escape(t(lang,"search"))}'></div>

          <div class='col3'><label>{html_escape(t(lang,'wh_req_no'))}</label><input name='q_whreq' value='{html_escape(q_whreq)}' placeholder='{html_escape(t(lang,"search"))}'></div>
          <div class='col3'><label>{html_escape(t(lang,'po_no'))}</label><input name='q_po' value='{html_escape(q_po)}' placeholder='{html_escape(t(lang,"search"))}'></div>
          <div class='col3'><label>{html_escape(t(lang,'eq_code'))}</label><input name='q_eq' value='{html_escape(q_eq)}' placeholder='{html_escape(t(lang,"search"))}'></div>
          <div class='col3'><label>Limit</label><input name='limit' value='{html_escape(str(limit))}'></div>
        </div>
        <div class='row' style='margin-top:10px'>
          <button class='btn pri' type='submit'>🔎 {html_escape(t(lang,'search'))}</button>
          <a class='btn' href='/requests'>↺ {html_escape(t(lang,'reset'))}</a>
        </div>
      </form>
    </div>

    <div class='card no-print'>
      <div class='row' style='justify-content:space-between; align-items:center'>
        <b>{html_escape(t(lang,'add'))} / {html_escape(t(lang,'edit'))}</b>
        <span class='small'>{html_escape("Standalone page (no links)")}</span>
      </div>
      <form method='post' action='/requests/save'>
        <input type='hidden' name='csrf_token' value=''>
        <input type='hidden' name='id' value='{html_escape(str(rec.get("id")) if rec else "")}'>
        <div class='grid'>
          <div class='col3'><label>{html_escape(t(lang,'date'))}</label><input type='date' name='req_date' value='{html_escape((rec.get("req_date") if rec else req_date) or _today_iso())}'></div>
          <div class='col3'><label>{html_escape(t(lang,'wh_name'))}</label><input name='warehouse_name' value='{html_escape((rec.get("warehouse_name") if rec else "") or "")}'></div>
          <div class='col3'><label>{html_escape(t(lang,'maint_req_no'))}</label><input name='maint_req_no' value='{html_escape((rec.get("maint_req_no") if rec else "") or "")}'></div>
          <div class='col3'><label>{html_escape(t(lang,'wh_req_no'))}</label><input name='wh_req_no' value='{html_escape((rec.get("wh_req_no") if rec else "") or "")}'></div>

          <div class='col3'><label>{html_escape(t(lang,'po_no'))}</label><input name='po_no' value='{html_escape((rec.get("po_no") if rec else "") or "")}'></div>
          <div class='col3'><label>{html_escape(t(lang,'eq_code'))}</label><input name='eq_code' value='{html_escape((rec.get("eq_code") if rec else "") or "")}'></div>
          <div class='col3'><label>{html_escape(t(lang,'status'))}</label><input name='status' value='{html_escape((rec.get("status") if rec else "") or "")}'></div>
          <div class='col3'><label>{html_escape(t(lang,'notes'))}</label><input name='notes' value='{html_escape((rec.get("notes") if rec else "") or "")}'></div>
        </div>
        <div class='row' style='margin-top:10px'>
          <button class='btn pri' type='submit'>💾 {html_escape(t(lang,'save'))}</button>
          <a class='btn' href='/requests'>✖ {html_escape(t(lang,'cancel'))}</a>
        </div>
      </form>
    </div>

    {table(trows, headers, labels, raw_cols={"actions"})}
    {pager}
    """
    return page(lang, t(lang,"requests"), body, username=username, flash=flash, role=role)

# =========================
# MODULES / STOCK & TRANSACTIONS
# =========================
_BALANCE_DEBUG_LOCK = threading.Lock()
_BALANCE_DEBUG_EVENTS = []
_BALANCE_DEBUG_MAX = 60

def _record_balance_debug_event(kind: str, message: str, *, item_code: str = '', wh_code: str = '', details: str = ''):
    try:
        ev = {
            'ts': _now().isoformat(timespec='seconds'),
            'kind': str(kind or 'info'),
            'message': str(message or '').strip(),
            'item_code': normalize_code(item_code or ''),
            'wh_code': normalize_code(wh_code or ''),
            'details': str(details or '').strip(),
        }
        if not ev['message']:
            return
        with _BALANCE_DEBUG_LOCK:
            _BALANCE_DEBUG_EVENTS.append(ev)
            if len(_BALANCE_DEBUG_EVENTS) > _BALANCE_DEBUG_MAX:
                del _BALANCE_DEBUG_EVENTS[:-_BALANCE_DEBUG_MAX]
    except Exception:
        pass

_BALANCE_AUTO_HEAL_STATE = {'last_try': 0.0}


def _try_auto_heal_balances(reason: str = '', *, username: str = 'system', item_code: str = '', wh_code: str = '', details: str = '') -> bool:
    """Best-effort self-heal for balances issues without exposing a rebuild button in /balances.
    Throttled to avoid repeated expensive kicks during page refreshes.
    Strategy:
    - If cache is already rebuilding, do nothing.
    - Otherwise force an async stockcache refresh.
    - Log the auto-heal action into Debug events.
    """
    now = time.time()
    try:
        with _BALANCE_DEBUG_LOCK:
            last_try = float(_BALANCE_AUTO_HEAL_STATE.get('last_try', 0.0) or 0.0)
            if now - last_try < 30.0:
                return False
            _BALANCE_AUTO_HEAL_STATE['last_try'] = now
    except Exception:
        pass
    try:
        with _STOCKCACHE_LOCK:
            if bool(_STOCKCACHE_STATE.get('running')):
                _record_balance_debug_event('auto_heal_skip', 'تم تجاهل الإصلاح التلقائي لأن إعادة البناء تعمل بالفعل', item_code=item_code, wh_code=wh_code, details=reason)
                return False
    except Exception:
        pass
    try:
        ensure_stockcache_async(username=username or 'system', force=True)
        _record_balance_debug_event('auto_heal', 'تم تشغيل الإصلاح التلقائي للأرصدة بالخلفية', item_code=item_code, wh_code=wh_code, details=(reason + (' | ' + details if details else '')).strip(' |'))
        return True
    except Exception as e:
        _record_balance_debug_event('auto_heal_error', 'فشل تشغيل الإصلاح التلقائي للأرصدة', item_code=item_code, wh_code=wh_code, details=str(e))
        return False


def _recent_balance_debug_events(limit: int = 20):
    try:
        with _BALANCE_DEBUG_LOCK:
            rows = list(_BALANCE_DEBUG_EVENTS[-max(1, int(limit)):])
        rows.reverse()
        return rows
    except Exception:
        return []

