@ROUTER.post('/fix/balances')
def _rt_fix_balances(handler):
    user, role, lang = _router_need_login(handler)
    if not user:
        return
    if not is_admin(role):
        return handler._send_html(page(lang, '403', "<div class='card'>🚫 Forbidden</div>", user, role=role), 403)
    try:
        form = handler._read_post_urlencoded()
    except Exception:
        form = {}
    next_url = (form.get('next', ['/balances'])[0] or '/balances').strip() or '/balances'
    try:
        rebuild_stockcache_sync(username=user)
        msg = '✅ تم إعادة حساب الأرصدة بنجاح'
    except Exception as e:
        safe_log_exception('fix_balances', e, username=user, role=role, ip=handler._client_ip())
        msg = f"❌ فشل إعادة الحساب: {str(e)}"
    return handler._redirect(_url_with_message(next_url, msg))

@ROUTER.get('/debug/item')
def _rt_debug_item(handler):
    user, role, lang = _router_need_login(handler)
    if not user:
        return
    parsed = urlparse(handler.path)
    qs = parse_qs(parsed.query)
    code = normalize_code((qs.get('code', [''])[0] or '').strip())
    wh = normalize_code((qs.get('wh', [''])[0] or '').strip())
    if not code:
        return handler._redirect('/debug-ui?m=' + quote_plus('اكتب كود الصنف أولاً'))
    con = db_connect()
    try:
        item = con.execute("SELECT id, item_code, item_name, unit FROM Items WHERE UPPER(TRIM(item_code))=? LIMIT 1", (code,)).fetchone()
        if not item:
            return handler._send_html(page(lang, 'Debug الأرصدة', f"<div class='card'>❌ الصنف غير موجود: {html_escape(code)}</div>", username=user, role=role), 404)
        item_id = int(item['id'])
        wh_row = None
        wh_id = None
        if wh:
            wh_row = con.execute("SELECT id, wh_code, wh_name FROM Warehouses WHERE UPPER(TRIM(wh_code))=? LIMIT 1", (wh,)).fetchone()
            wh_id = int(wh_row['id']) if wh_row else -999999
        tx_rows = con.execute("""
            SELECT t.id, substr(t.ts,1,10) AS tx_date, t.txn_type, t.qty, t.unit_price, t.doc_no, t.req_no, t.po_no,
                   COALESCE(wf.wh_code,'') AS wh_from_code, COALESCE(wf.wh_name,'') AS wh_from_name,
                   COALESCE(wt.wh_code,'') AS wh_to_code, COALESCE(wt.wh_name,'') AS wh_to_name,
                   COALESCE(t.voided,0) AS voided
            FROM Transactions t
            LEFT JOIN Warehouses wf ON wf.id=t.wh_from_id
            LEFT JOIN Warehouses wt ON wt.id=t.wh_to_id
            WHERE t.item_id=?
            ORDER BY t.ts ASC, t.id ASC
        """, (item_id,)).fetchall()
        running = 0.0
        rows_html = []
        issues = []
        for r in tx_rows:
            effect = 0.0
            include = True
            tx_type = str(r['txn_type'] or '').upper()
            qty = float(r['qty'] or 0.0)
            if int(r['voided'] or 0) == 1:
                include = False
            if include:
                if wh_id is None:
                    if tx_type == 'RECEIVE':
                        effect = qty
                    elif tx_type == 'ISSUE':
                        effect = -qty
                    elif tx_type == 'TRANSFER':
                        effect = 0.0
                else:
                    from_match = (wh_row and str(r['wh_from_code'] or '').upper() == str(wh_row['wh_code']).upper())
                    to_match = (wh_row and str(r['wh_to_code'] or '').upper() == str(wh_row['wh_code']).upper())
                    if tx_type == 'RECEIVE' and to_match:
                        effect = qty
                    elif tx_type == 'ISSUE' and from_match:
                        effect = -qty
                    elif tx_type == 'TRANSFER':
                        if from_match:
                            effect -= qty
                        if to_match:
                            effect += qty
                        if (not r['wh_to_code']) or (not r['wh_from_code']):
                            issues.append(f"⚠️ الحركة #{int(r['id'])} تحويل ببيانات مستودع ناقصة")
                running += effect
            rows_html.append(f"<tr>{'<td>'+html_escape(str(r['id']))+'</td>'}<td>{html_escape(str(r['tx_date'] or ''))}</td><td>{html_escape(tx_type)}</td><td>{html_escape(str(qty))}</td><td>{html_escape(str(effect))}</td><td>{html_escape(str(round(running,3)))}</td><td>{html_escape(str(r['wh_from_code'] or ''))}</td><td>{html_escape(str(r['wh_to_code'] or ''))}</td><td>{html_escape(str(r['doc_no'] or ''))}</td><td>{html_escape(str(r['req_no'] or ''))}</td><td>{'VOID' if int(r['voided'] or 0)==1 else ''}</td></tr>")
        live_rows = balance_rows_live(item_code=code, wh_code=(wh if wh else None), limit=500, offset=0)
        snap_rows = balance_rows(item_code=code, wh_code=(wh if wh else None), limit=500, offset=0)
        live_total = round(sum(float(x.get('balance') or 0) for x in live_rows), 3)
        snap_total = round(sum(float(x.get('balance') or 0) for x in snap_rows), 3)
        if wh_id is None:
            calc_total = round(sum(float(x.get('balance') or 0) for x in live_rows), 3)
        else:
            calc_total = round(running, 3)
        if abs(live_total - snap_total) > 0.0001:
            issues.append(f"⚠️ يوجد فرق بين الرصيد المباشر ({live_total}) ورصيد الكاش ({snap_total})")
        issue_html = ''.join([f"<div class='card' style='border-right:4px solid #f59e0b'>{html_escape(msg)}</div>" for msg in issues])
        wh_title = f" / {html_escape(str(wh_row['wh_code']))}" if wh_row else ''
        body = f"""
        <div class='card'>
          <h2 style='margin:0 0 10px 0'>🧠 تحليل الصنف: {html_escape(str(item['item_code']))} - {html_escape(str(item['item_name']))}{wh_title}</h2>
          <div class='row' style='gap:10px;flex-wrap:wrap'>
            <div class='kpi'><div class='k'>الرصيد المباشر</div><div class='v'>{live_total}</div></div>
            <div class='kpi'><div class='k'>رصيد الكاش</div><div class='v'>{snap_total}</div></div>
            <div class='kpi'><div class='k'>حالة الكاش</div><div class='v'>{'DIRTY' if stockcache_is_dirty() else 'OK'}</div></div>
          </div>
        </div>
        {issue_html}
        <div class='card'>
          <div class='row' style='margin-bottom:10px'>
            <a class='btn' href='/debug-ui?code={quote_plus(code)}&wh={quote_plus(wh)}'>⬅️ رجوع</a>
            <form method='post' action='/fix/balances' style='margin:0'>
              {csrf_field_html(user)}
              <input type='hidden' name='next' value='/debug/item?code={quote_plus(code)}&wh={quote_plus(wh)}'>
              <button class='btn' type='submit'>🔄 إعادة حساب الأرصدة</button>
            </form>
          </div>
          <table class='table'>
            <thead><tr><th>ID</th><th>التاريخ</th><th>النوع</th><th>الكمية</th><th>الأثر</th><th>الرصيد التراكمي</th><th>من مستودع</th><th>إلى مستودع</th><th>رقم السند</th><th>رقم الطلب</th><th>الحالة</th></tr></thead>
            <tbody>{''.join(rows_html) if rows_html else '<tr><td colspan="11">لا توجد حركات</td></tr>'}</tbody>
          </table>
        </div>
        """
        return handler._send_html(page(lang, 'Debug الأرصدة', body, username=user, role=role))
    finally:
        try:
            if not _in_atomic_db():
                con.close()
        except Exception:
            pass


def render_balances(lang, username, role, qs):
    sync_status_html = render_sync_status_card(lang, username=username, auto_kick=True, compact=False)
    try:
        ensure_stockcache_async(username=username or 'system')
    except Exception as e:
        _record_balance_debug_event('stockcache_async', 'فشل تشغيل تحديث الكاش الخلفي', item_code=(qs.get("q_item", [""])[0] or ''), wh_code=(qs.get("q_wh", [""])[0] or ''), details=str(e))
    q_item=(qs.get("q_item",[""])[0] or "").strip()
    q_wh=(qs.get("q_wh",[""])[0] or "").strip()
    page_no = qs_int(qs, "page", 1, 1, 100000)
    page_size = qs_int(qs, "page_size", 1000,  100,  10000)
    offset = (page_no - 1) * page_size
    stale_balances = False
    try:
        stale_balances = stockcache_is_dirty()
    except Exception:
        stale_balances = False
    rows = []
    balance_rows_error = ''
    try:
        rows = balance_rows(item_code=q_item or None, wh_code=q_wh or None, limit=page_size+1, offset=offset)
    except Exception as e:
        balance_rows_error = str(e)
        _record_balance_debug_event('snapshot_error', 'فشل قراءة أرصدة الكاش حسب المستودع', item_code=q_item, wh_code=q_wh, details=balance_rows_error)
        _try_auto_heal_balances('snapshot_error', username=username or 'system', item_code=q_item, wh_code=q_wh, details=balance_rows_error)
        rows = []
    used_live_fallback = False
    live_fallback_error = ''
    if (not rows) and (q_item or q_wh):
        try:
            rows = balance_rows_live(item_code=q_item or None, wh_code=q_wh or None, limit=page_size+1, offset=offset)
            used_live_fallback = True if rows else False
            if rows:
                _record_balance_debug_event('live_fallback', 'تم التحويل للحساب المباشر حسب المستودع لأن نتيجة الكاش الحالية لم تُرجع بيانات لهذا الفلتر', item_code=q_item, wh_code=q_wh)
                _try_auto_heal_balances('live_fallback', username=username or 'system', item_code=q_item, wh_code=q_wh)
        except Exception as e:
            live_fallback_error = str(e)
            _record_balance_debug_event('live_error', 'فشل الحساب المباشر حسب المستودع من الحركات', item_code=q_item, wh_code=q_wh, details=live_fallback_error)
            _try_auto_heal_balances('live_error', username=username or 'system', item_code=q_item, wh_code=q_wh, details=live_fallback_error)
            rows = []
    has_next = len(rows) > page_size
    rows = rows[:page_size]
    pager = ""
    if page_no > 1 or has_next:
        prev_qs = dict(qs)
        next_qs = dict(qs)
        prev_qs["page"] = [str(page_no - 1)]
        next_qs["page"] = [str(page_no + 1)]
        prev_url = "/balances?" + urlencode([(k, v) for k, vals in prev_qs.items() for v in (vals if isinstance(vals, list) else [vals])], doseq=True)
        next_url = "/balances?" + urlencode([(k, v) for k, vals in next_qs.items() for v in (vals if isinstance(vals, list) else [vals])], doseq=True)
        prev_btn = f"<a class='btn' href='{html_escape(prev_url)}'>◀ السابق</a>" if page_no > 1 else ""
        next_btn = f"<a class='btn' href='{html_escape(next_url)}'>التالي ▶</a>" if has_next else ""
        pager = f"<div class='card no-print'><div class='row' style='justify-content:space-between'><div>Page {page_no}</div><div>{prev_btn} {next_btn}</div></div></div>"
    stale_html = ""
    if stale_balances:
        _record_balance_debug_event('dirty_cache', 'الكاش الحالي قديم أو تحت إعادة بناء', item_code=q_item, wh_code=q_wh)
        _try_auto_heal_balances('dirty_cache', username=username or 'system', item_code=q_item, wh_code=q_wh)
        stale_html = f"<div class='card' style='border-right:4px solid #f59e0b'>⏳ {html_escape('يتم عرض آخر كاش معتمد حالياً لحين اكتمال التحديث بالخلفية. صفحة الأرصدة هنا تعرض الرصيد لكل مستودع بشكل منفصل.' if (lang or 'en').lower().startswith('ar') else 'The last verified cache is being shown while the background rebuild finishes. This balances page shows stock per warehouse separately.')}</div>"
    else:
        stale_html = f"<div class='card' style='border-right:4px solid #2563eb'>📦 {html_escape('صفحة الأرصدة هنا تعرض كمية كل صنف داخل كل مستودع بشكل منفصل. التجميع على مستوى كل المستودعات موجود فقط في Low Stock والتنبيهات المرتبطة به.' if (lang or 'en').lower().startswith('ar') else 'This balances page shows each item quantity inside each warehouse separately. Cross-warehouse aggregation is only used in Low Stock and related alerts.')}</div>"
    if used_live_fallback:
        stale_html += "<div class='card' style='border-right:4px solid #2563eb'>🧠 تم استخدام الحساب المباشر حسب المستودع من الحركات لأن نتيجة الكاش الحالية لم تُرجع بيانات لهذا الفلتر.</div>"
    if balance_rows_error:
        stale_html += f"<div class='card' style='border-right:4px solid #dc2626'>❌ فشل قراءة الكاش: {html_escape(balance_rows_error)}</div>"
    if live_fallback_error:
        stale_html += f"<div class='card' style='border-right:4px solid #dc2626'>❌ فشل الحساب المباشر: {html_escape(live_fallback_error)}</div>"

    headers=["item_code","item_name","unit","wh_code","wh_name","balance","avg_cost","value","min_qty","last_supplier","last_date"]
    labels={
        "item_code":t(lang,"item_code"),"item_name":t(lang,"item_name"),"unit":t(lang,"unit"),
        "wh_code":t(lang,"warehouse"),"wh_name":t(lang,"warehouse"),
        "balance":t(lang,"balance"),"avg_cost":t(lang,"avg_cost"),"value":t(lang,"value"),
        "min_qty":t(lang,"min_qty"),"last_supplier":t(lang,"supplier"),"last_date":t(lang,"date"),
    }

    itms=list_rows("Items", "", order_by="item_code")
    whs=list_rows("Warehouses", "", order_by="wh_code")
    dl_items="".join([f'<option value="{html_escape(x["item_code"])}">{html_escape(x["item_name"])}</option>' for x in itms])
    dl_whs="".join([f'<option value="{html_escape(x["wh_code"])}">{html_escape(x["wh_name"])}</option>' for x in whs])

    body=f"""
    {sync_status_html}
    {stale_html}
    <div class='card no-print'>
      {tools_bar('balances', qs, lang)}
      <form method='get' action='/balances'>
        <input type='hidden' name='page' value='1'>
        <input type='hidden' name='page_size' value='{html_escape(str(page_size))}'>
        <div class='grid'>
          <div class='col6'>
            <label>{html_escape(t(lang,'item_code'))}</label>
            <input name='q_item' list='dl_items' value='{html_escape(q_item)}' placeholder='{html_escape(t(lang,"search"))}'>
            <datalist id='dl_items'>{dl_items}</datalist>
          </div>
          <div class='col6'>
            <label>{html_escape(t(lang,'warehouse'))}</label>
            <input name='q_wh' list='dl_whs' value='{html_escape(q_wh)}' placeholder='{html_escape(t(lang,"search"))}'>
            <datalist id='dl_whs'>{dl_whs}</datalist>
          </div>
        </div>
        <div class='row' style='margin-top:10px'>
          <button class='btn pri' type='submit'>🔎 {html_escape(t(lang,'search'))}</button>
          <a class='btn' href='/balances'>↺ {html_escape(t(lang,'reset'))}</a>
        </div>
      </form>
    </div>

    {table(rows, headers, labels, view="balances", qs=qs)}
    {pager}
    """
    return page(lang, t(lang,"balances"), body, username=username, role=role)

def scrap_rows(q_item="", q_wh="", q_eq="", from_date="", to_date="", limit=50000, offset=0):
    """
    Scrap availability by item + warehouse.

    Generated scrap still comes from Transactions.scrap_qty on ISSUE rows.
    Available scrap per warehouse = generated + transferred_in - transferred_out - sold.
    Legacy sales without warehouse stay visible as a separate "غير محدد" bucket to avoid corrupting warehouse balances.
    """
    q_item=(q_item or "").strip()
    q_wh=(q_wh or "").strip()
    q_eq=(q_eq or "").strip()
    from_date=(from_date or "").strip()
    to_date=(to_date or "").strip()

    where=["t.voided=0", "t.txn_type='ISSUE'", "COALESCE(t.scrap_qty,0) > 0"]
    params=[]

    def _smart_code_or_name_filter(code_sql: str, name_sql: str, raw_value: str):
        raw_value = (raw_value or "").strip()
        if not raw_value:
            return None, []
        norm_value = normalize_code(raw_value)
        looks_like_code = bool(re.fullmatch(r"[A-Z0-9][A-Z0-9_./\- ]{1,}", norm_value or ""))
        if looks_like_code:
            return f"({code_sql} = ? OR {code_sql} LIKE ? OR {name_sql} LIKE ?)", [norm_value, f"{norm_value}%", f"%{raw_value}%"]
        like = f"%{raw_value}%"
        return f"({code_sql} LIKE ? OR {name_sql} LIKE ?)", [like, like]

    if q_item:
        sql, sql_params = _smart_code_or_name_filter("i.item_code", "i.item_name", q_item)
        where.append(sql)
        params.extend(sql_params)
    if q_wh:
        sql, sql_params = _smart_code_or_name_filter("w.wh_code", "w.wh_name", q_wh)
        where.append(sql)
        params.extend(sql_params)
    if q_eq:
        sql, sql_params = _smart_code_or_name_filter("e.eq_code", "e.eq_name", q_eq)
        where.append(sql)
        params.extend(sql_params)

    ts_where, ts_params = _sqlite_ts_range(from_date, to_date, field="t.ts")
    if ts_where:
        where.append(ts_where)
        params.extend(ts_params)

    where_sql = " AND ".join(where)
    con = db_connect()
    try:
        rows = con.execute(f"""
            WITH generated AS (
                SELECT
                  i.id AS item_id,
                  i.item_code AS item_code,
                  i.item_name AS item_name,
                  i.unit AS unit,
                  w.id AS wh_id,
                  w.wh_code AS wh_code,
                  w.wh_name AS wh_name,
                  ROUND(SUM(COALESCE(t.scrap_qty,0)),3) AS generated_scrap_qty,
                  COUNT(*) AS issue_count,
                  COALESCE(MAX(substr(t.ts,1,10)), '') AS last_issue
                FROM Transactions t
                JOIN Items i ON i.id=t.item_id
                LEFT JOIN Warehouses w ON w.id=t.wh_from_id
                LEFT JOIN Equipment e ON e.id=t.eq_id
                WHERE {where_sql}
                GROUP BY i.id, w.id
            ),
            sold AS (
                SELECT
                  ss.item_id,
                  ss.wh_id,
                  ROUND(SUM(COALESCE(ss.qty_sold,0)),3) AS sold_qty,
                  COALESCE(MAX(substr(ss.sold_at,1,10)), '') AS last_sold_at
                FROM ScrapSales ss
                GROUP BY ss.item_id, ss.wh_id
            ),
            moved_out AS (
                SELECT st.item_id, st.wh_from_id AS wh_id,
                       ROUND(SUM(COALESCE(st.qty,0)),3) AS moved_out_qty,
                       COALESCE(MAX(substr(st.moved_at,1,10)), '') AS last_moved_out
                FROM ScrapTransfers st
                GROUP BY st.item_id, st.wh_from_id
            ),
            moved_in AS (
                SELECT st.item_id, st.wh_to_id AS wh_id,
                       ROUND(SUM(COALESCE(st.qty,0)),3) AS moved_in_qty,
                       COALESCE(MAX(substr(st.moved_at,1,10)), '') AS last_moved_in
                FROM ScrapTransfers st
                GROUP BY st.item_id, st.wh_to_id
            ),
            key_rows AS (
                SELECT item_id, wh_id FROM generated WHERE wh_id IS NOT NULL
                UNION
                SELECT item_id, wh_id FROM sold WHERE wh_id IS NOT NULL
                UNION
                SELECT item_id, wh_id FROM moved_out WHERE wh_id IS NOT NULL
                UNION
                SELECT item_id, wh_id FROM moved_in WHERE wh_id IS NOT NULL
            )
            SELECT
              i.id AS item_id,
              i.item_code,
              i.item_name,
              i.unit,
              k.wh_id,
              COALESCE(w.wh_code, '') AS wh_code,
              COALESCE(w.wh_name, '') AS wh_name,
              COALESCE(g.generated_scrap_qty, 0) AS generated_scrap_qty,
              COALESCE(mi.moved_in_qty, 0) AS moved_in_qty,
              COALESCE(mo.moved_out_qty, 0) AS moved_out_qty,
              COALESCE(sw.sold_qty, 0) AS sold_qty,
              ROUND(MAX(0, COALESCE(g.generated_scrap_qty, 0) + COALESCE(mi.moved_in_qty, 0) - COALESCE(mo.moved_out_qty, 0) - COALESCE(sw.sold_qty, 0)), 3) AS scrap_qty,
              COALESCE(g.issue_count, 0) AS issue_count,
              COALESCE(g.last_issue, '') AS last_issue,
              COALESCE(sw.last_sold_at, '') AS last_sold_at,
              COALESCE(mi.last_moved_in, '') AS last_moved_in,
              COALESCE(mo.last_moved_out, '') AS last_moved_out,
              COALESCE(cfg.sale_threshold_qty, 0) AS sale_threshold_qty
            FROM key_rows k
            JOIN Items i ON i.id=k.item_id
            LEFT JOIN Warehouses w ON w.id=k.wh_id
            LEFT JOIN generated g ON g.item_id=k.item_id AND IFNULL(g.wh_id,-1)=IFNULL(k.wh_id,-1)
            LEFT JOIN sold sw ON sw.item_id=k.item_id AND IFNULL(sw.wh_id,-1)=IFNULL(k.wh_id,-1)
            LEFT JOIN moved_in mi ON mi.item_id=k.item_id AND IFNULL(mi.wh_id,-1)=IFNULL(k.wh_id,-1)
            LEFT JOIN moved_out mo ON mo.item_id=k.item_id AND IFNULL(mo.wh_id,-1)=IFNULL(k.wh_id,-1)
            LEFT JOIN ScrapSettings cfg ON cfg.item_id=k.item_id
            WHERE ROUND(MAX(0, COALESCE(g.generated_scrap_qty, 0) + COALESCE(mi.moved_in_qty, 0) - COALESCE(mo.moved_out_qty, 0) - COALESCE(sw.sold_qty, 0)), 3) > 0
            ORDER BY scrap_qty DESC, i.item_code, w.wh_code, w.wh_name
            LIMIT ? OFFSET ?;
        """, tuple(params+[int(limit), int(offset)])).fetchall()

        out = []
        for r in rows:
            d = dict(r)
            avail = float(d.get("scrap_qty") or 0)
            threshold = float(d.get("sale_threshold_qty") or 0)
            if threshold > 0 and avail >= threshold:
                status = "جاهز للبيع"
                status_class = "ok"
            elif threshold > 0:
                status = "تحت التجميع"
                status_class = "warn"
            else:
                status = "بدون حد"
                status_class = "muted"
            d["status"] = status
            d["status_class"] = status_class
            out.append(d)
        return out
    finally:
        con.close()


def scrap_sales_rows(limit=200):
    con = db_connect()
    try:
        rows = con.execute("""
            SELECT
              ss.id,
              substr(ss.sold_at,1,10) AS sold_date,
              i.item_code,
              i.item_name,
              i.unit,
              COALESCE(w.wh_code,'') AS wh_code,
              COALESCE(w.wh_name, CASE WHEN ss.wh_id IS NULL THEN 'غير محدد' ELSE '' END) AS wh_name,
              ROUND(ss.qty_sold,3) AS qty_sold,
              ROUND(ss.unit_sale_price,3) AS unit_sale_price,
              ROUND(ss.total_sale_value,3) AS total_sale_value,
              COALESCE(ss.notes,'') AS notes,
              COALESCE(ss.username,'') AS username
            FROM ScrapSales ss
            JOIN Items i ON i.id=ss.item_id
            LEFT JOIN Warehouses w ON w.id=ss.wh_id
            ORDER BY ss.sold_at DESC, ss.id DESC
            LIMIT ?;
        """, (int(limit),)).fetchall()
        return [dict(r) for r in rows]
    finally:
        con.close()


def scrap_transfer_rows(limit=200):
    con = db_connect()
    try:
        rows = con.execute("""
            SELECT st.id,
                   st.wh_from_id,
                   st.wh_to_id,
                   substr(st.moved_at,1,10) AS moved_date,
                   i.item_code,
                   i.item_name,
                   i.unit,
                   wf.wh_code AS wh_from_code,
                   wf.wh_name AS wh_from_name,
                   wt.wh_code AS wh_to_code,
                   wt.wh_name AS wh_to_name,
                   ROUND(st.qty,3) AS qty,
                   COALESCE(st.notes,'') AS notes,
                   COALESCE(st.username,'') AS username
            FROM ScrapTransfers st
            JOIN Items i ON i.id=st.item_id
            JOIN Warehouses wf ON wf.id=st.wh_from_id
            JOIN Warehouses wt ON wt.id=st.wh_to_id
            ORDER BY st.moved_at DESC, st.id DESC
            LIMIT ?;
        """, (int(limit),)).fetchall()
        return [dict(r) for r in rows]
    finally:
        con.close()


def scrap_set_threshold(item_id, threshold_qty, username="system"):
    item_id = int(item_id)
    threshold_qty = max(0.0, float(threshold_qty or 0))
    con = db_connect()
    try:
        con.execute("""
            INSERT INTO ScrapSettings(item_id, sale_threshold_qty, updated_at, updated_by)
            VALUES(?,?,?,?)
            ON CONFLICT(item_id) DO UPDATE SET
                sale_threshold_qty=excluded.sale_threshold_qty,
                updated_at=excluded.updated_at,
                updated_by=excluded.updated_by
        """, (item_id, threshold_qty, _now().isoformat(timespec="seconds"), str(username or "")))
        if not _in_atomic_db():
            con.commit()
    finally:
        con.close()


def scrap_available_qty(item_id, wh_id=None, con=None):
    own_con = con is None
    con = con or db_connect()
    try:
        item_id = int(item_id)
        if wh_id is None:
            row = con.execute("""
                WITH generated AS (
                    SELECT ROUND(COALESCE(SUM(COALESCE(t.scrap_qty,0)),0), 3) AS generated_qty
                    FROM Transactions t
                    WHERE t.voided=0 AND t.txn_type='ISSUE' AND t.item_id=? AND COALESCE(t.scrap_qty,0) > 0
                ),
                sold AS (
                    SELECT ROUND(COALESCE(SUM(COALESCE(ss.qty_sold,0)),0), 3) AS sold_qty
                    FROM ScrapSales ss
                    WHERE ss.item_id=?
                )
                SELECT MAX(0, COALESCE(g.generated_qty,0) - COALESCE(s.sold_qty,0)) AS available_qty
                FROM generated g, sold s;
            """, (item_id, item_id)).fetchone()
        else:
            wh_id = int(wh_id)
            row = con.execute("""
                WITH generated AS (
                    SELECT ROUND(COALESCE(SUM(COALESCE(t.scrap_qty,0)),0), 3) AS generated_qty
                    FROM Transactions t
                    WHERE t.voided=0 AND t.txn_type='ISSUE' AND t.item_id=? AND t.wh_from_id=? AND COALESCE(t.scrap_qty,0) > 0
                ),
                sold AS (
                    SELECT ROUND(COALESCE(SUM(COALESCE(ss.qty_sold,0)),0), 3) AS sold_qty
                    FROM ScrapSales ss
                    WHERE ss.item_id=? AND ss.wh_id=?
                ),
                moved_out AS (
                    SELECT ROUND(COALESCE(SUM(COALESCE(st.qty,0)),0), 3) AS qty
                    FROM ScrapTransfers st
                    WHERE st.item_id=? AND st.wh_from_id=?
                ),
                moved_in AS (
                    SELECT ROUND(COALESCE(SUM(COALESCE(st.qty,0)),0), 3) AS qty
                    FROM ScrapTransfers st
                    WHERE st.item_id=? AND st.wh_to_id=?
                )
                SELECT MAX(0, COALESCE(g.generated_qty,0) + COALESCE(mi.qty,0) - COALESCE(mo.qty,0) - COALESCE(s.sold_qty,0)) AS available_qty
                FROM generated g, sold s, moved_out mo, moved_in mi;
            """, (item_id, wh_id, item_id, wh_id, item_id, wh_id, item_id, wh_id)).fetchone()
        return float((row[0] if row else 0) or 0)
    finally:
        if own_con:
            con.close()


def scrap_mark_sold(item_id, qty_sold, unit_sale_price=0, sold_at="", notes="", username="system", wh_id=None):
    item_id = int(item_id)
    qty_sold = float(qty_sold or 0)
    unit_sale_price = max(0.0, float(unit_sale_price or 0))
    sold_at = (sold_at or "").strip() or _now().isoformat(timespec="seconds")
    notes = (notes or "").strip()
    wh_id = int(wh_id) if str(wh_id or "").strip().isdigit() else None
    if qty_sold <= 0:
        raise ValueError("الكمية المباعة يجب أن تكون أكبر من صفر")

    con = db_connect()
    try:
        available_qty = scrap_available_qty(item_id, wh_id=wh_id, con=con)
        if qty_sold - available_qty > 1e-9:
            raise ValueError(f"الكمية المتاحة غير كافية. المتاح الحالي: {available_qty:g}")
        total = round(qty_sold * unit_sale_price, 3)
        con.execute("""
            INSERT INTO ScrapSales(sold_at, item_id, wh_id, qty_sold, unit_sale_price, total_sale_value, notes, username)
            VALUES(?,?,?,?,?,?,?,?)
        """, (sold_at, item_id, wh_id, qty_sold, unit_sale_price, total, notes, str(username or "")))
        if not _in_atomic_db():
            con.commit()
    finally:
        con.close()


def scrap_transfer(item_id, wh_from_id, wh_to_id, qty, moved_at="", notes="", username="system"):
    item_id = int(item_id)
    wh_from_id = int(wh_from_id)
    wh_to_id = int(wh_to_id)
    qty = float(qty or 0)
    moved_at = (moved_at or "").strip() or _now().isoformat(timespec="seconds")
    notes = (notes or "").strip()
    if qty <= 0:
        raise ValueError("كمية التحويل يجب أن تكون أكبر من صفر")
    if wh_from_id == wh_to_id:
        raise ValueError("المستودع المصدر والمستودع الهدف لا يمكن أن يكونا نفس المستودع")
    con = db_connect()
    try:
        available_qty = scrap_available_qty(item_id, wh_id=wh_from_id, con=con)
        if qty - available_qty > 1e-9:
            raise ValueError(f"كمية السكراب غير كافية في المستودع المصدر. المتاح الحالي: {available_qty:g}")
        con.execute("""
            INSERT INTO ScrapTransfers(moved_at, item_id, wh_from_id, wh_to_id, qty, notes, username)
            VALUES(?,?,?,?,?,?,?)
        """, (moved_at, item_id, wh_from_id, wh_to_id, qty, notes, str(username or "")))
        if not _in_atomic_db():
            con.commit()
    finally:
        con.close()


