def scrap_sale_update(sale_id, qty_sold, unit_sale_price=0, sold_at="", notes="", username="system"):
    sale_id = int(sale_id)
    qty_sold = float(qty_sold or 0)
    unit_sale_price = max(0.0, float(unit_sale_price or 0))
    sold_at = (sold_at or "").strip() or _now().isoformat(timespec="seconds")
    notes = (notes or "").strip()
    if qty_sold <= 0:
        raise ValueError("الكمية المباعة يجب أن تكون أكبر من صفر")
    if unit_sale_price <= 0:
        raise ValueError("سعر البيع يجب أن يكون أكبر من صفر")
    con = db_connect()
    try:
        old = con.execute("SELECT * FROM ScrapSales WHERE id=?", (sale_id,)).fetchone()
        if not old:
            raise ValueError("سجل بيع السكراب غير موجود")
        old = dict(old)
        item_id = int(old['item_id'])
        wh_id = old['wh_id']
        available_qty = scrap_available_qty(item_id, wh_id=wh_id, con=con) + float(old.get('qty_sold') or 0)
        if qty_sold - available_qty > 1e-9:
            raise ValueError(f"الكمية المتاحة غير كافية بعد التعديل. المتاح الحالي: {available_qty:g}")
        total = round(qty_sold * unit_sale_price, 3)
        con.execute(
            """
            UPDATE ScrapSales
               SET sold_at=?, qty_sold=?, unit_sale_price=?, total_sale_value=?, notes=?, username=?
             WHERE id=?
            """,
            (sold_at, qty_sold, unit_sale_price, total, notes, str(username or ""), sale_id),
        )
        if not _in_atomic_db():
            con.commit()
        return old
    finally:
        con.close()


