def scrap_transfer_update(transfer_id, qty, moved_at="", notes="", username="system", wh_from_id=None, wh_to_id=None):
    transfer_id = int(transfer_id)
    qty = float(qty or 0)
    moved_at = (moved_at or "").strip() or _now().isoformat(timespec="seconds")
    notes = (notes or "").strip()
    if qty <= 0:
        raise ValueError("كمية التحويل يجب أن تكون أكبر من صفر")
    con = db_connect()
    try:
        old = con.execute("SELECT * FROM ScrapTransfers WHERE id=?", (transfer_id,)).fetchone()
        if not old:
            raise ValueError("سجل تحويل السكراب غير موجود")
        old = dict(old)
        item_id = int(old['item_id'])
        old_from = int(old['wh_from_id'])
        old_to = int(old['wh_to_id'])
        new_from = int(wh_from_id) if str(wh_from_id or '').strip().isdigit() else old_from
        new_to = int(wh_to_id) if str(wh_to_id or '').strip().isdigit() else old_to
        if new_from == new_to:
            raise ValueError("المستودع المصدر والمستودع الهدف لا يمكن أن يكونا نفس المستودع")
        available_qty = scrap_available_qty(item_id, wh_id=new_from, con=con)
        old_qty = float(old.get('qty') or 0)
        if new_from == old_from:
            available_qty += old_qty
        if new_from == old_to:
            available_qty -= old_qty
        if qty - available_qty > 1e-9:
            raise ValueError(f"كمية السكراب غير كافية بعد التعديل. المتاح الحالي: {available_qty:g}")
        con.execute(
            """
            UPDATE ScrapTransfers
               SET moved_at=?, wh_from_id=?, wh_to_id=?, qty=?, notes=?, username=?
             WHERE id=?
            """,
            (moved_at, new_from, new_to, qty, notes, str(username or ""), transfer_id),
        )
        if not _in_atomic_db():
            con.commit()
        return old
    finally:
        con.close()


def scrap_transfer_delete(transfer_id):
    transfer_id = int(transfer_id)
    con = db_connect()
    try:
        old = con.execute("SELECT * FROM ScrapTransfers WHERE id=?", (transfer_id,)).fetchone()
        if not old:
            raise ValueError("سجل تحويل السكراب غير موجود")
        old = dict(old)
        con.execute("DELETE FROM ScrapTransfers WHERE id=?", (transfer_id,))
        if not _in_atomic_db():
            con.commit()
        return old
    finally:
        con.close()


def render_scrap(lang, username, role, qs):
    from urllib.parse import urlencode
    q_item=(qs.get("q_item",[""])[0] or "").strip()
    q_wh=(qs.get("q_wh",[""])[0] or "").strip()
    q_eq=(qs.get("q_eq",[""])[0] or "").strip()
    from_date=(qs.get("from_date",[""])[0] or "").strip()
    to_date=(qs.get("to_date",[""])[0] or "").strip()

    page_no = qs_int(qs, "page", 1, 1, 100000)
    page_size = qs_int(qs, "page_size", 2000, 200, 50000)
    offset = (page_no - 1) * page_size

    rows = scrap_rows(q_item=q_item, q_wh=q_wh, q_eq=q_eq, from_date=from_date, to_date=to_date,
                      limit=page_size+1, offset=offset)
    sales = scrap_sales_rows(limit=100)
    transfers = scrap_transfer_rows(limit=100)
    has_next = len(rows) > page_size
    rows = rows[:page_size]

    pager = ""
    if has_next or page_no > 1:
        base="/scrap"
        qs2={k:v[:] for k,v in (qs or {}).items()}
        qs2["page"]=[str(page_no-1 if page_no>1 else 1)]
        prev_url = base + "?" + urlencode({k:(v[0] if isinstance(v,list) else v) for k,v in qs2.items() if v and k})
        qs2["page"]=[str(page_no+1)]
        next_url = base + "?" + urlencode({k:(v[0] if isinstance(v,list) else v) for k,v in qs2.items() if v and k})
        pager = f"""
        <div class='card no-print' style='display:flex;gap:10px;align-items:center;justify-content:flex-end'>
          <a class='btn' href='{html_escape(prev_url)}' {'style="pointer-events:none;opacity:.5"' if page_no<=1 else ''}>◀ Prev</a>
          <div class='badge'>Page {page_no}</div>
          <a class='btn' href='{html_escape(next_url)}' {'style="pointer-events:none;opacity:.5"' if not has_next else ''}>Next ▶</a>
        </div>
        """

    itms=list_rows("Items", "", order_by="item_code")
    whs=list_rows("Warehouses", "", order_by="wh_code")
    eqs=list_rows("Equipment", "", order_by="eq_code")

