def list_stale_items(days=3, limit=1500):
    """Return stale received rows within the last N days (inclusive), even if item repeats.

    Definition here (per your request):
    - Consider RECEIVE rows whose date is between (today - N days) and today.
    - Show each RECEIVE row separately (no grouping by item).
    - Compute remaining per RECEIVE using FIFO allocation against total ISSUE/TRANSFER out
      up to today for the same (item, warehouse).
    - Include only rows where remaining_qty > 0.
    """
    try:
        days = int(days or 3)
    except Exception:
        days = 3
    days = max(1, min(days, 365))

    try:
        limit = int(limit or 1500)
    except Exception:
        limit = 1500
    limit = max(1, min(limit, 20000))

    import datetime as _dt
    today = _dt.date.today()
    start_date = (today - _dt.timedelta(days=max(0, days-1))).isoformat()
    end_date = today.isoformat()

    con = db_connect()
    try:
        rows = con.execute(
            """
            WITH recv_all AS (
              SELECT
                t.id,
                t.item_id,
                t.wh_to_id AS wh_id,
                t.ts,
                t.qty AS recv_qty,
                SUM(t.qty) OVER (
                  PARTITION BY t.item_id, t.wh_to_id
                  ORDER BY t.ts, t.id
                  ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW
                ) AS recv_cum
              FROM Transactions t
              WHERE t.voided=0
                AND t.txn_type='RECEIVE'
                AND t.wh_to_id IS NOT NULL
                AND substr(t.ts,1,10) <= ?
            ),
            issued AS (
              SELECT
                t.item_id,
                t.wh_from_id AS wh_id,
                SUM(t.qty) AS issued_total
              FROM Transactions t
              WHERE t.voided=0
                AND t.txn_type IN ('ISSUE','TRANSFER')
                AND t.wh_from_id IS NOT NULL
                AND substr(t.ts,1,10) <= ?
              GROUP BY t.item_id, t.wh_from_id
            ),
            calc AS (
              SELECT
                r.*,
                COALESCE(i.issued_total, 0) AS issued_total,
                (r.recv_cum - r.recv_qty) AS recv_before,
                MAX(0, COALESCE(i.issued_total,0) - (r.recv_cum - r.recv_qty)) AS need_from_this,
                MIN(r.recv_qty, MAX(0, COALESCE(i.issued_total,0) - (r.recv_cum - r.recv_qty))) AS out_alloc
              FROM recv_all r
              LEFT JOIN issued i
                ON i.item_id=r.item_id AND i.wh_id=r.wh_id
            )
            SELECT
              it.item_code AS item_code,
              it.item_name AS item_name,
              w.wh_code AS wh_code,
              w.wh_name AS wh_name,
              c.ts AS last_receive_date,
              c.recv_qty AS recv_qty,
              ROUND(c.out_alloc, 3) AS out_after_qty,
              ROUND(c.recv_qty - c.out_alloc, 3) AS remaining_qty
            FROM calc c
            JOIN Items it ON it.id=c.item_id
            JOIN Warehouses w ON w.id=c.wh_id
            WHERE substr(c.ts,1,10) >= ?
              AND substr(c.ts,1,10) <= ?
              AND (c.recv_qty - c.out_alloc) > 0
            ORDER BY c.ts DESC, it.item_code
            LIMIT ?;
            """,
            (end_date, end_date, start_date, end_date, int(limit)),
        ).fetchall()
        return [dict(r) for r in rows]
    finally:
        con.close()




