# =========================
# MODULES / BACKUP + RESTORE
# =========================
def backup_make():
    """Create a consistent DB backup without VACUUM-in-transaction issues.

    Strategy:
    1) Prefer SQLite backup API from a dedicated read connection.
    2) Fallback to VACUUM INTO on a clean connection (no explicit BEGIN).
    3) Final fallback to plain file copy.
    """
    bdir = os.path.join(BASE_DIR, "backups")
    os.makedirs(bdir, exist_ok=True)
    ts = _now().strftime("%Y%m%d_%H%M%S")
    name = f"warehouse_erp_backup_{ts}.db"
    src = DB_FILE
    dst = os.path.join(bdir, name)

    if os.path.exists(dst):
        try:
            os.remove(dst)
        except Exception:
            pass

    # 1) Best path: sqlite online backup API.
    src_con = None
    dst_con = None
    try:
        src_con = sqlite3.connect(src, timeout=30, check_same_thread=False)
        dst_con = sqlite3.connect(dst, timeout=30, check_same_thread=False)
        src_con.backup(dst_con)
        dst_con.commit()
        try:
            prune_backups()
        except Exception:
            pass
        return name
    except Exception:
        try:
            if dst_con is not None:
                dst_con.close()
        except Exception:
            pass
        try:
            if src_con is not None:
                src_con.close()
        except Exception:
            pass
        try:
            if os.path.exists(dst):
                os.remove(dst)
        except Exception:
            pass

    # 2) Fallback: VACUUM INTO on a clean dedicated connection (without BEGIN IMMEDIATE).
    con = None
    try:
        con = sqlite3.connect(src, timeout=30, check_same_thread=False)
        con.execute("VACUUM INTO ?", (dst,))
        try:
            prune_backups()
        except Exception:
            pass
        return name
    except Exception:
        try:
            if con is not None:
                con.close()
        except Exception:
            pass
        try:
            if os.path.exists(dst):
                os.remove(dst)
        except Exception:
            pass

    # 3) Final fallback: plain file copy.
    shutil.copy2(src, dst)
    try:
        prune_backups()
    except Exception:
        pass
    return name

def list_backups():
    bdir=os.path.join(BASE_DIR,"backups")
    if not os.path.isdir(bdir):
        return []
    files=[f for f in os.listdir(bdir) if f.lower().endswith(".db")]
    files.sort(reverse=True)
    return files[:50]


def prune_backups():
    bdir=os.path.join(BASE_DIR,"backups")
    if not os.path.isdir(bdir):
        return
    db_files=sorted([f for f in os.listdir(bdir) if f.lower().endswith(".db")], reverse=True)
    for f in db_files[BACKUP_RETENTION_DB:]:
        try: os.remove(os.path.join(bdir,f))
        except Exception: pass
    xlsx_files=sorted([f for f in os.listdir(bdir) if f.lower().endswith(".xlsx")], reverse=True)
    for f in xlsx_files[BACKUP_RETENTION_XLSX:]:
        try: os.remove(os.path.join(bdir,f))
        except Exception: pass

def delete_user(username: str, *, deleted_by: str | None = None, role: str | None = None, ip: str | None = None, hard: bool = True):
    username = (username or "").strip()
    if not username:
        raise ValueError("Invalid username")
    if normalize_code(username) == normalize_code("admin"):
        raise ValueError("Cannot delete default admin")

    con = db_connect()
    try:
        cols = {r[1] for r in con.execute("PRAGMA table_info(Users)").fetchall()}
        has_id = "id" in cols

        if has_id:
            row = con.execute("SELECT id, role, active FROM Users WHERE username=?", (username,)).fetchone()
            if not row:
                raise ValueError("User not found")
            row_id = row[0]
            user_role_val = str(row[1] or "").strip().upper()
        else:
            row = con.execute("SELECT username, role, active FROM Users WHERE username=?", (username,)).fetchone()
            if not row:
                raise ValueError("User not found")
            row_id = row[0]
            user_role_val = str(row[1] or "").strip().upper()

        if user_role_val == "ADMIN":
            admins = int(con.execute("SELECT COUNT(*) FROM Users WHERE UPPER(role)='ADMIN' AND active=1").fetchone()[0] or 0)
            if admins <= 1:
                raise ValueError("Cannot delete last ADMIN user")

        if hard:
            if has_id:
                con.execute("DELETE FROM Users WHERE id=?", (row_id,))
            else:
                con.execute("DELETE FROM Users WHERE username=?", (username,))
        else:
            if has_id:
                con.execute("UPDATE Users SET active=0 WHERE id=?", (row_id,))
            else:
                con.execute("UPDATE Users SET active=0 WHERE username=?", (username,))

        if not _in_atomic_db():
            con.commit()
    finally:
        try:
            con.close()
        except Exception:
            pass

    drop_user_sessions(username)

def drop_user_sessions(username: str):
    """Remove active sessions for a given username (used after user deactivation/rename)."""
    with _lock:
        dead = [k for k,v in _sessions.items() if v.get("user") == username]
        for k in dead:
            _sessions.pop(k, None)

def backup_restore(fname: str) -> str:
    """Restore DB from a backup file under BASE_DIR/backups. Returns safety-copy filename."""
    bdir = os.path.join(BASE_DIR, "backups")
    if not fname or ".." in fname or "/" in fname or "\\" in fname:
        raise ValueError("Bad file")
    src = os.path.join(bdir, fname)
    if not os.path.isfile(src):
        raise FileNotFoundError("Backup not found")

    try:
        con = db_connect()
        con.execute("PRAGMA wal_checkpoint(TRUNCATE);")
        con.commit()
        con.close()
    except Exception:
        pass

    os.makedirs(bdir, exist_ok=True)
    ts = _now().strftime("%Y%m%d_%H%M%S")
    safety_name = f"before_restore_{ts}.db"
    safety_path = os.path.join(bdir, safety_name)

    if os.path.isfile(DB_FILE):
        try:
            shutil.copy2(DB_FILE, safety_path)
        except Exception:
            pass

    for suf in ("-wal", "-shm"):
        p = DB_FILE + suf
        if os.path.isfile(p):
            try:
                os.remove(p)
            except Exception:
                pass

    shutil.copy2(src, DB_FILE)
    return safety_name



