def _local_supplier_statement_data(con, supplier_id, qs=None):
    qs = qs or {}
    if not str(supplier_id).isdigit():
        raise ValueError('مورد غير صحيح')
    _ensure_local_suppliers_schema(con)
    supplier = con.execute("SELECT * FROM LocalSuppliers WHERE id=?", (int(supplier_id),)).fetchone()
    if not supplier:
        raise ValueError('المورد المحلي غير موجود')

    entry_type = (qs.get('entry_type', [''])[0] or '').strip().upper()
    from_date = (qs.get('from_date', [''])[0] or '').strip()
    to_date = (qs.get('to_date', [''])[0] or '').strip()
    q_item = (qs.get('q_item', [''])[0] or '').strip()

    where = ["supplier_id=?"]
    params = [int(supplier_id)]
    if entry_type in ('TRANSFER','PURCHASE','ADJUST','RETURN'):
        where.append("entry_type=?")
        params.append(entry_type)
    if from_date:
        where.append("substr(ts,1,10)>=?")
        params.append(from_date)
    if to_date:
        where.append("substr(ts,1,10)<=?")
        params.append(to_date)
    if q_item:
        like = '%' + q_item.upper() + '%'
        where.append("(UPPER(COALESCE(item_code,'')) LIKE ? OR UPPER(COALESCE(item_name,'')) LIKE ?)")
        params.extend([like, like])

    rows = con.execute(f"""
        SELECT *
        FROM LocalSupplierLedger
        WHERE {' AND '.join(where)}
        ORDER BY ts ASC, id ASC
    """, tuple(params)).fetchall()

    total_in = sum(float(r['amount_in'] or 0) for r in rows)
    total_out = sum(float(r['amount_out'] or 0) for r in rows)
    current_balance = _ls_current_balance(con, int(supplier_id))
    return {
        'supplier': supplier,
        'rows': rows,
        'total_in': total_in,
        'total_out': total_out,
        'current_balance': current_balance,
        'entries_count': len(rows),
        'entry_type': entry_type,
        'from_date': from_date,
        'to_date': to_date,
        'q_item': q_item,
    }


