def _import_needs_stock_refresh(view: str) -> bool:
    v = _normalize_imp_exp_view(view)
    return v in {
        'txn', 'transactions', 'history', 'items', 'warehouses', 'suppliers',
        'equipment', 'projects', 'requests', 'standalone_requests',
        'local-suppliers', 'local_suppliers', 'assets', 'tools'
    }


def _after_successful_import(view: str, username: str = 'system'):
    """Best-effort refresh after non-dry-run imports.

    We intentionally keep this lightweight: mark caches dirty and kick the async
    rebuild only once the import completed successfully. This improves balances
    freshness after Excel imports without blocking the request on a synchronous
    snapshot rebuild.
    """
    if not _import_needs_stock_refresh(view):
        return
    try:
        mark_stockcache_dirty(reason=f'import_{_normalize_imp_exp_view(view)}', username=username or 'system')
    except Exception:
        pass
    try:
        ensure_stockcache_async(username=username or 'system')
    except Exception:
        pass


