def _normalize_imp_exp_view(view: str) -> str:
    v = (view or '').strip().lower().replace('_', '-').replace(' ', '-')
    aliases = {
        'assets': 'assets-master',
        'asset-master': 'assets-master',
        'tools': 'tools-master',
        'tool-master': 'tools-master',
        'local-suppliers': 'local-suppliers',
        'local-supplier-statement': 'local-supplier-statement',
        'local-suppliers-statement': 'local-supplier-statement',
        'stale-items': 'stale-items',
        'stale-items-report': 'stale-items',
        'stale-items-page': 'stale-items',
        'stale-items-rows': 'stale-items',
        'stale-items-view': 'stale-items',
        'stale-itemslist': 'stale-items',
        'stale-itemsreport': 'stale-items',
        'stale-itemsrows': 'stale-items',
        'stale-itemsview': 'stale-items',
        'stale-itemspage': 'stale-items',
        'stale-itemslistreport': 'stale-items',
        'stale-items-list': 'stale-items',
        'stale-items-report-page': 'stale-items',
        'stale-items-report-view': 'stale-items',
        'stale-items-page-view': 'stale-items',
        'stale_items': 'stale-items',
        'lowstock': 'low-stock',
        'low-stock': 'low-stock',
        'no-price-items': 'no-price-items',
        'item-card': 'item_card',
        'equipment-card': 'equipment_card',
        'v8-1': 'v8_1',
    }
    v = aliases.get(v, v)
    back = {
        'assets-master': 'assets_master',
        'tools-master': 'tools_master',
        'local-supplier-statement': 'local_supplier_statement',
    }
    return back.get(v, v)


def _normalize_master_code_for_import(col, val):
    if val is None:
        return val
    if col in ('item_code','eq_code','wh_code','supplier_code','project_code','asset_code','tool_code'):
        try:
            return normalize_code(val)
        except Exception:
            return val
    return val


def _query_rows_dict(sql, params=()):
    con = db_connect()
    try:
        return [dict(r) for r in con.execute(sql, params).fetchall()]
    finally:
        try:
            con.close()
        except Exception:
            pass


def _dashboard_export_rows():
    con = db_connect()
    try:
        rows = []
        metrics = [
            ('active_items', "SELECT COUNT(*) c FROM Items WHERE COALESCE(active,1)=1"),
            ('inactive_items', "SELECT COUNT(*) c FROM Items WHERE COALESCE(active,1)=0"),
            ('active_equipment', "SELECT COUNT(*) c FROM Equipment WHERE COALESCE(active,1)=1"),
            ('inactive_equipment', "SELECT COUNT(*) c FROM Equipment WHERE COALESCE(active,1)=0"),
            ('active_warehouses', "SELECT COUNT(*) c FROM Warehouses WHERE COALESCE(active,1)=1"),
            ('inactive_warehouses', "SELECT COUNT(*) c FROM Warehouses WHERE COALESCE(active,1)=0"),
            ('open_transactions', "SELECT COUNT(*) c FROM Transactions WHERE COALESCE(voided,0)=0"),
            ('today_transactions', "SELECT COUNT(*) c FROM Transactions WHERE COALESCE(voided,0)=0 AND date(ts)=date('now','localtime')"),
            ('projects', "SELECT COUNT(*) c FROM Projects WHERE COALESCE(active,1)=1"),
            ('local_suppliers', "SELECT COUNT(*) c FROM LocalSuppliers WHERE COALESCE(active,1)=1"),
        ]
        for label, sql in metrics:
            try:
                val = con.execute(sql).fetchone()['c']
            except Exception:
                val = 0
            rows.append({'metric': label, 'value': val})
        try:
            inv_total, _warn = inventory_value_mavg_per_wh(con)
            rows.append({'metric': 'inventory_value', 'value': float(inv_total or 0.0)})
        except Exception:
            pass
        return rows
    finally:
        try:
            con.close()
        except Exception:
            pass



def _low_stock_export_rows(qs):
    q_item=(qs.get('q_item',[''])[0] or '').strip()
    return low_stock_rows_global(item_code=q_item or None, limit=50000, offset=0)


def _audit_export_rows(qs):
    q_user=(qs.get('q_user',[''])[0] or '').strip()
    q_action=(qs.get('q_action',[''])[0] or '').strip()
    from_date=(qs.get('from_date',[''])[0] or '').strip()
    to_date=(qs.get('to_date',[''])[0] or '').strip()
    where=[]; params=[]
    if q_user:
        where.append("COALESCE(username,'') LIKE ?"); params.append(f'%{q_user}%')
    if q_action:
        where.append("COALESCE(action,'') LIKE ?"); params.append(f'%{q_action}%')
    if from_date:
        where.append('date(created_at) >= date(?)'); params.append(from_date)
    if to_date:
        where.append('date(created_at) <= date(?)'); params.append(to_date)
    wsql=("WHERE " + " AND ".join(where)) if where else ''
    return _query_rows_dict(f"SELECT id, created_at, COALESCE(username,'') AS username, COALESCE(ip,'') AS ip, COALESCE(action,'') AS action, COALESCE(entity,'') AS entity, COALESCE(details,'') AS details FROM AuditLog {wsql} ORDER BY id DESC LIMIT 50000", tuple(params))


def _local_suppliers_summary_rows(qs):
    con=db_connect()
    try:
        _ensure_local_suppliers_schema(con)
        rows=con.execute("""
            SELECT s.id, s.supplier_code, s.supplier_name, s.phone, s.notes,
                   COALESCE(SUM(l.amount_in),0) AS total_in,
                   COALESCE(SUM(l.amount_out),0) AS total_out,
                   COALESCE(SUM(l.amount_in-l.amount_out),0) AS balance,
                   COUNT(l.id) AS entries_count
            FROM LocalSuppliers s
            LEFT JOIN LocalSupplierLedger l ON l.supplier_id=s.id
            GROUP BY s.id, s.supplier_code, s.supplier_name, s.phone, s.notes
            ORDER BY s.supplier_name, s.supplier_code
        """).fetchall()
        return [dict(r) for r in rows]
    finally:
        try:
            con.close()
        except Exception:
            pass


