def _v81_export_rows(qs):
    days = qs_int(qs, 'days', 30, 7, 365)
    out=[]
    for r in compute_v81_purchase_suggestions(days=days):
        d=dict(r); d['section']='purchase_suggestions'; out.append(d)
    for r in compute_v81_abnormal_equipment(days=days):
        d=dict(r); d['section']='abnormal_equipment'; out.append(d)
    for r in compute_cost_centers({} if not (qs.get('wh',[''])[0] or '').strip() else {'wh_code': (qs.get('wh',[''])[0] or '').strip()})[0]:
        d=dict(r); d['section']='cost_centers'; out.append(d)
    return out


def _template_headers_for_view(view: str):
    v = _normalize_imp_exp_view(view)
    if v == 'assets':
        v = 'assets_master'
    if v == 'tools':
        v = 'tools_master'
    readonly = {'balances','history','stale-items','stale_items','scrap','low-stock','no-price-items','item_card','equipment_card','audit','dashboard','cost_centers','equipment_consumption','v8_1','local_supplier_statement'}
    if v in readonly:
        raise ValueError('Template is not available for this page.')
    if v in ('local-suppliers','local_suppliers'):
        return ['supplier_code','supplier_name','phone','notes','active']
    if v == 'projects':
        return ['project_code','project_name','active']
    if v == 'assets_master':
        return ['asset_code','asset_name','category','model','serial_no','purchase_date','purchase_cost','quantity','current_condition','location_label','current_wh_code','current_wh_name','custodian_name','notes','active']
    if v == 'tools_master':
        return ['tool_code','tool_name','category','unit','min_qty','current_condition','location_label','current_wh_code','current_wh_name','custodian_name','notes','active']
    return __orig_template_headers_for_view(v)


def _available_template_cols_for_view(view: str):
    try:
        return _template_headers_for_view(view)
    except Exception:
        return []


def _available_cols_for_view(view: str, qs=None):
    v = _normalize_imp_exp_view(view)
    base = dict(__orig_available_cols_for_view(v, qs) or []) if False else None
    cols = __orig_available_cols_for_view(v, qs) or []
    if cols:
        return cols
    extra = {
        'users': ['username','role','active','created_at'],
        'projects': ['project_code','project_name','active'],
        'assets_master': ['asset_code','asset_name','category','model','serial_no','purchase_date','purchase_cost','quantity','current_condition','location_label','current_wh_code','current_wh_name','custodian_name','notes'],
        'tools_master': ['tool_code','tool_name','category','unit','min_qty','current_condition','location_label','current_wh_code','current_wh_name','custodian_name','notes'],
        'local-suppliers': ['supplier_code','supplier_name','phone','notes','total_in','total_out','balance','entries_count'],
        'local_supplier_statement': ['ts','entry_type','item_code','item_name','qty','unit_price_before_tax','subtotal_before_tax','tax_amount','total_amount','amount_in','amount_out','balance_after','ref_no','notes'],
        'balances': ['item_code','item_name','unit','wh_code','wh_name','balance','avg_cost','value','min_qty','last_supplier','last_date'],
        'low-stock': ['item_code','item_name','unit','balance','min_qty','shortage'],
        'stale-items': ['item_code','item_name','wh_code','wh_name','last_receive_date','recv_qty','out_after_qty','remaining_qty'],
        'audit': ['id','created_at','username','ip','action','entity','details'],
        'dashboard': ['metric','value'],
        'v8_1': ['section','item_code','item_name','current_balance','avg_daily_issue','days_left','suggest_qty','eq_code','eq_name','issue_count','total_cost','alert','wh_code','wh_name','in_value','out_value','net'],
    }
    return extra.get(v, [])


def _auto_map_import_headers(view: str, upload_headers):
    v = _normalize_imp_exp_view(view)
    mapping = __orig_auto_map_import_headers(v, upload_headers)
    target_cols = _available_template_cols_for_view(v) or _available_cols_for_view(v, {}) or []
    target_norm = {_norm_import_key(c): c for c in target_cols}
    alias_map = {}
    if v == 'projects':
        alias_map = {'project':'project_code','projectcode':'project_code','كودالمشروع':'project_code','name':'project_name','projectname':'project_name','اسم':'project_name','اسمالمشروع':'project_name','active':'active','فعال':'active'}
    elif v in ('local-suppliers','local_suppliers'):
        alias_map = {'code':'supplier_code','suppliercode':'supplier_code','كودالمورد':'supplier_code','name':'supplier_name','suppliername':'supplier_name','اسم':'supplier_name','phone':'phone','mobile':'phone','جوال':'phone','notes':'notes','ملاحظات':'notes','active':'active','فعال':'active'}
    elif v == 'assets_master':
        alias_map = {
            'code':'asset_code','assetcode':'asset_code','كودالاصل':'asset_code',
            'name':'asset_name','assetname':'asset_name','اسمالاصل':'asset_name',
            'wh':'current_wh_code','warehouse':'current_wh_code','currentwarehouse':'current_wh_code','currentwhcode':'current_wh_code',
            'currentwarehousename':'current_wh_name','currentwhname':'current_wh_name','warehousename':'current_wh_name',
            'المستودعالحالي':'current_wh_code','كودالمستودعالحالي':'current_wh_code','اسمالمستودعالحالي':'current_wh_name',
            'currentlocation':'location_label','location':'location_label','الموقعالحالي':'location_label',
            'qty':'quantity','quantity':'quantity','الكمية':'quantity'
        }
    elif v == 'tools_master':
        alias_map = {
            'code':'tool_code','toolcode':'tool_code','كودالاداة':'tool_code',
            'name':'tool_name','toolname':'tool_name','اسمالاداة':'tool_name',
            'wh':'current_wh_code','warehouse':'current_wh_code','currentwarehouse':'current_wh_code','currentwhcode':'current_wh_code',
            'currentwarehousename':'current_wh_name','currentwhname':'current_wh_name','warehousename':'current_wh_name',
            'المستودعالحالي':'current_wh_code','كودالمستودعالحالي':'current_wh_code','اسمالمستودعالحالي':'current_wh_name',
            'currentlocation':'location_label','location':'location_label','الموقعالحالي':'location_label'
        }
    if alias_map:
        for h in upload_headers or []:
            hn = _norm_import_key(h)
            if mapping.get(str(h)):
                continue
            mapped = target_norm.get(hn) or target_norm.get(hn.replace('_','')) or alias_map.get(hn)
            if mapped:
                mapping[str(h)] = mapped
    return mapping


def export_view_as_xlsx(view, qs):
    v = _normalize_imp_exp_view(view)
    cols = _parse_cols_from_qs(qs)
    if v == 'assets':
        v = 'assets_master'
    if v == 'tools':
        v = 'tools_master'
    if v == 'users':
        rows = _query_rows_dict("SELECT username, role, active, created_at FROM Users ORDER BY username")
        return _xlsx_write(rows, _apply_cols(['username','role','active','created_at'], cols), 'Users')
    if v == 'projects':
        rows = _query_rows_dict("SELECT project_code, project_name, active FROM Projects ORDER BY project_code")
        return _xlsx_write(rows, _apply_cols(['project_code','project_name','active'], cols), 'Projects')
    if v in ('local-suppliers','local_suppliers'):
        rows = _local_suppliers_summary_rows(qs)
        return _xlsx_write(rows, _apply_cols(['supplier_code','supplier_name','phone','notes','total_in','total_out','balance','entries_count'], cols), 'LocalSuppliers')
    if v == 'local_supplier_statement':
        rows = _local_supplier_statement_rows(qs)
        return _xlsx_write(rows, _apply_cols(['ts','entry_type','item_code','item_name','qty','unit_price_before_tax','subtotal_before_tax','tax_amount','total_amount','amount_in','amount_out','balance_after','ref_no','notes'], cols), 'LocalSupplierStmt')
    if v == 'balances':
        rows = balance_rows(item_code=(qs.get('q_item',[''])[0] or '').strip() or None,
                            wh_code=(qs.get('q_wh',[''])[0] or '').strip() or None,
                            limit=50000, offset=0)
        return _xlsx_write(rows, _apply_cols(['item_code','item_name','unit','wh_code','wh_name','balance','avg_cost','value','min_qty','last_supplier','last_date'], cols), 'Balances')
    if v == 'low-stock':
        rows = _low_stock_export_rows(qs)
        return _xlsx_write(rows, _apply_cols(['item_code','item_name','unit','balance','min_qty','shortage'], cols), 'LowStock')
    if v in ('stale-items','stale_items'):
        days = (qs.get('days',['3'])[0] or '3').strip()
        try:
            days_i = max(1, min(int(days), 60))
        except Exception:
            days_i = 3
        rows = list_stale_items(days=days_i, limit=50000)
        return _xlsx_write(rows, _apply_cols(['item_code','item_name','wh_code','wh_name','last_receive_date','recv_qty','out_after_qty','remaining_qty'], cols), 'StaleItems')
    if v == 'audit':
        rows = _audit_export_rows(qs)
        return _xlsx_write(rows, _apply_cols(['id','created_at','username','ip','action','entity','details'], cols), 'Audit')
    if v == 'dashboard':
        rows = _dashboard_export_rows()
        return _xlsx_write(rows, _apply_cols(['metric','value'], cols), 'Dashboard')
    if v == 'v8_1':
        rows = _v81_export_rows(qs)
        return _xlsx_write(rows, _apply_cols(_available_cols_for_view('v8_1', qs), cols), 'V81')
    return __orig_export_view_as_xlsx(v, qs)


def import_view_from_xlsx(view, lang, username, file_bytes, dry_run=True, import_mode='add_update'):
    v = _normalize_imp_exp_view(view)
    master_map = {
        'projects': ('Projects', 'project_code'),
        'assets_master': ('Assets', 'asset_code'),
        'tools_master': ('Tools', 'tool_code'),
        'local-suppliers': ('LocalSuppliers', 'supplier_code'),
        'local_suppliers': ('LocalSuppliers', 'supplier_code'),
    }
    if v in master_map:
        table, unique_col = master_map[v]
        headers, data = _xlsx_read(file_bytes)
        counts = {'ok':0,'add':0,'update':0,'skipped':0}
        errors=[]; failed=[]
        def _is_empty(vv):
            return vv is None or str(vv).strip()=='' or str(vv).strip().lower() in ('none','null','nan')
        def _norm_key(k):
            import re as _re
            k = '' if k is None else str(k)
            k = k.replace(' ', ' ').strip().lower()
            k = _re.sub(r'[\s\-/]+', '_', k)
            k = _re.sub(r'[^0-9a-zA-Z_؀-ۿ]+', '', k)
            return k.strip('_')
        def _to_text(vv):
            return '' if vv is None else str(vv).strip()
        def _find_wh_id(conn, code_text='', name_text=''):
            code_text = normalize_code(code_text or '')
            name_text = str(name_text or '').strip()
            row = None
            if code_text:
                row = conn.execute("SELECT id FROM Warehouses WHERE UPPER(TRIM(COALESCE(wh_code,'')))=? LIMIT 1", (code_text,)).fetchone()
            if (not row) and name_text:
                row = conn.execute("SELECT id FROM Warehouses WHERE UPPER(TRIM(COALESCE(wh_name,'')))=? LIMIT 1", (str(name_text).strip().upper(),)).fetchone()
            if not row:
                return None
            try:
                return int(row['id']) if isinstance(row, sqlite3.Row) else int(row[0])
            except Exception:
                return None
        def _location_type_from_label(label_text='', has_wh=False, has_person=False):
            s = str(label_text or '').strip().lower()
            if has_wh and has_person:
                return 'mixed'
            if has_person:
                return 'person'
            if has_wh:
                return 'warehouse'
            if any(tok in s for tok in ('mixed','distributed','موزع')):
                return 'mixed'
            if any(tok in s for tok in ('person','custodian','holder','مع شخص','بعهدة','عهدة')):
                return 'person'
            return 'warehouse'
        con = db_connect()
        try:
            cols = con.execute(f'PRAGMA table_info({table})').fetchall()
            col_names = [c['name'] if isinstance(c, sqlite3.Row) else c[1] for c in cols]
            writable = [c for c in col_names if c.lower() != 'id']
            writable_norm = {_norm_key(c): c for c in writable}
            for row_no, rec in enumerate(data or [], start=2):
                try:
                    if not isinstance(rec, dict):
                        counts['skipped'] += 1
                        continue
                    rec_norm = {_norm_key(k): rec.get(k) for k in rec.keys()}
                    payload = {}
                    for nk, vv in rec_norm.items():
                        real = writable_norm.get(nk)
                        if real:
                            payload[real] = _normalize_master_code_for_import(real, _to_text(vv))
                    wh_code_in = _to_text(rec_norm.get('current_wh_code'))
                    wh_name_in = _to_text(rec_norm.get('current_wh_name'))
                    loc_label_in = _to_text(rec_norm.get('location_label'))
                    person_in = _to_text(rec_norm.get('custodian_name'))
                    if v in ('assets_master', 'tools_master'):
                        wh_id = _find_wh_id(con, wh_code_in, wh_name_in)
                        if (wh_code_in or wh_name_in) and wh_id is None:
                            raise ValueError(f"المستودع الحالي غير موجود: {wh_code_in or wh_name_in}")
                        if 'current_wh_id' in writable:
                            payload['current_wh_id'] = wh_id
                        if 'current_location_type' in writable:
                            payload['current_location_type'] = _location_type_from_label(loc_label_in, has_wh=bool(wh_id), has_person=bool(person_in))
                        if 'custodian_name' in writable:
                            payload['custodian_name'] = person_in if payload.get('current_location_type') in ('person','mixed') else ''
                        if 'status' in writable and _is_empty(payload.get('status')):
                            cc = _to_text(rec_norm.get('current_condition'))
                            if cc:
                                payload['status'] = cc
                        if 'current_condition' in writable and _is_empty(payload.get('current_condition')):
                            cc = _to_text(rec_norm.get('status'))
                            if cc:
                                payload['current_condition'] = cc
                    if unique_col not in payload or _is_empty(payload.get(unique_col)):
                        counts['skipped'] += 1
                        continue
                    if 'active' in writable and _is_empty(payload.get('active')):
                        payload['active'] = 1
                    unique_val = payload.get(unique_col)
                    row = con.execute(f'SELECT id FROM {table} WHERE {unique_col}=?', (unique_val,)).fetchone()
                    exists_id = int(row['id']) if row else None
                    if dry_run:
                        counts['ok'] += 1
                        counts['update' if exists_id else 'add'] += 1
                        continue
                    if import_mode == 'add_only' and exists_id:
                        counts['skipped'] += 1
                        continue
                    if import_mode == 'update_only' and not exists_id:
                        counts['skipped'] += 1
                        continue
                    upsert_row(table, exists_id, payload)
                    counts['ok'] += 1
                    counts['update' if exists_id else 'add'] += 1
                except Exception as e:
                    counts['skipped'] += 1
                    errors.append(f'Row {row_no}: {e}')
                    failed.append({'row_number': row_no, 'view': v, 'error': str(e)})
        finally:
            try:
                con.close()
            except Exception:
                pass
        if (not dry_run) and int(counts.get('ok', 0) or 0) > 0:
            _after_successful_import(v, username=username)
        return {'ok': counts['ok'], 'add': counts['add'], 'update': counts['update'], 'skipped': counts['skipped'], 'errors': errors, 'failed': failed}
    return __orig_import_view_from_xlsx(v, lang, username, file_bytes, dry_run=dry_run, import_mode=import_mode)


def tools_bar(view, qs, lang):
    v = _normalize_imp_exp_view(view)
    flat={}
    for k,vv in (qs or {}).items():
        if vv:
            flat[k]=vv[0]
    from urllib.parse import urlencode
    base_q=urlencode(flat)
    export_url=f"/excel/wizard?mode=export&view={v}" + (("&"+base_q) if base_q else '')
    print_url=f"/pdf/print?view={v}" + (("&"+base_q) if base_q else '')
    template_url=f"/excel/wizard?mode=template&view={v}"
    import_action=f"/excel/import?view={v}"
    readonly = {'balances','history','stale-items','stale_items','scrap','low-stock','no-price-items','item_card','equipment_card','audit','cost_centers','equipment_consumption','dashboard','v8_1','local_supplier_statement'}
    if v in readonly:
        return f"<div class=\"no-print\" style=\"display:flex;gap:8px;flex-wrap:wrap;align-items:center;margin:8px 0 14px 0\"><a class=\"btn\" href=\"{export_url}\">📤 {html_escape(t(lang,'export'))}</a><a class=\"btn\" href=\"{print_url}\" target=\"_blank\">🖨️ {html_escape(t(lang,'print'))} {html_escape(t(lang,'pdf'))}</a></div>"
    return f"<div class=\"no-print\" style=\"display:flex;gap:8px;flex-wrap:wrap;align-items:center;margin:8px 0 14px 0\"><a class=\"btn\" href=\"{export_url}\">📤 {html_escape(t(lang,'export'))}</a><a class=\"btn\" href=\"{template_url}\">📄 {html_escape(t(lang,'template'))}</a><a class=\"btn\" href=\"{print_url}\" target=\"_blank\">🖨️ {html_escape(t(lang,'print'))} {html_escape(t(lang,'pdf'))}</a><a class=\"btn\" href=\"{import_action}\">⬆️ {html_escape(t(lang,'import'))}</a></div>"


def _inject_tools_into_page(html, view, qs, lang):
    try:
        bar = tools_bar(view, qs, lang)
        marker = "<div class='card'"
        if marker in html and bar not in html:
            return html.replace(marker, bar + marker, 1)
    except Exception:
        pass
    return html


