# =========================
# Transaction Lines Document System (fixed with document attachment + safe delete)
# =========================
__orig_init_db_lines = init_db

def init_db():
    __orig_init_db_lines()
    con = db_connect()
    cur = con.cursor()
    try:
        cur.executescript("""
        CREATE TABLE IF NOT EXISTS TransactionDocs(
          id INTEGER PRIMARY KEY AUTOINCREMENT,
          ts TEXT NOT NULL,
          txn_type TEXT NOT NULL CHECK (txn_type IN ('RECEIVE','ISSUE','TRANSFER')),
          wh_from_id INTEGER,
          wh_to_id INTEGER,
          eq_id INTEGER,
          supplier_id INTEGER,
          project_id INTEGER,
          issue_type TEXT,
          cost_allocation TEXT,
          req_no TEXT,
          po_no TEXT,
          doc_no TEXT,
          notes TEXT,
          attachment_path TEXT,
          username TEXT,
          created_at TEXT NOT NULL,
          updated_at TEXT NOT NULL
        );
        CREATE INDEX IF NOT EXISTS idx_txndocs_ts ON TransactionDocs(ts DESC, id DESC);
        CREATE INDEX IF NOT EXISTS idx_txndocs_type_ts ON TransactionDocs(txn_type, ts DESC, id DESC);
        CREATE INDEX IF NOT EXISTS idx_txndocs_doc_no ON TransactionDocs(doc_no);
        CREATE INDEX IF NOT EXISTS idx_txndocs_req_no ON TransactionDocs(req_no);

        CREATE TABLE IF NOT EXISTS TransactionDocLines(
          id INTEGER PRIMARY KEY AUTOINCREMENT,
          doc_id INTEGER NOT NULL,
          line_no INTEGER NOT NULL,
          item_id INTEGER NOT NULL,
          qty REAL NOT NULL CHECK (qty > 0),
          scrap_qty REAL NOT NULL DEFAULT 0 CHECK (scrap_qty >= 0),
          unit_price REAL,
          notes TEXT,
          ledger_txn_id INTEGER,
          created_at TEXT NOT NULL,
          FOREIGN KEY(doc_id) REFERENCES TransactionDocs(id) ON DELETE CASCADE,
          FOREIGN KEY(item_id) REFERENCES Items(id),
          FOREIGN KEY(ledger_txn_id) REFERENCES Transactions(id)
        );
        CREATE INDEX IF NOT EXISTS idx_txndoclines_doc_line ON TransactionDocLines(doc_id, line_no);
        CREATE INDEX IF NOT EXISTS idx_txndoclines_item_doc ON TransactionDocLines(item_id, doc_id);
        """)
        cols_d = [r['name'] for r in cur.execute("PRAGMA table_info(TransactionDocs)").fetchall()]
        if 'attachment_path' not in cols_d:
            cur.execute("ALTER TABLE TransactionDocs ADD COLUMN attachment_path TEXT")
        cols_l = [r['name'] for r in cur.execute("PRAGMA table_info(TransactionDocLines)").fetchall()]
        if 'eq_id' not in cols_l:
            cur.execute("ALTER TABLE TransactionDocLines ADD COLUMN eq_id INTEGER")
        cols_t = [r['name'] for r in cur.execute("PRAGMA table_info(Transactions)").fetchall()]
        if 'doc_id' not in cols_t:
            cur.execute("ALTER TABLE Transactions ADD COLUMN doc_id INTEGER")
        if 'line_id' not in cols_t:
            cur.execute("ALTER TABLE Transactions ADD COLUMN line_id INTEGER")
        cur.execute("CREATE INDEX IF NOT EXISTS idx_txn_doc_id ON Transactions(doc_id)")
        cur.execute("CREATE INDEX IF NOT EXISTS idx_txn_line_id ON Transactions(line_id)")
        con.commit()
        clear_schema_cache()
    finally:
        con.close()


def _txn_doc_validate_and_save_pdf(pdf_tuple, lang='ar'):
    if not pdf_tuple:
        return None
    filename = (pdf_tuple[0] if len(pdf_tuple) > 0 else '') or ''
    data = (pdf_tuple[1] if len(pdf_tuple) > 1 else b'') or b''
    if not filename:
        return None
    ext = _safe_ext(filename)
    if ext != '.pdf':
        raise ValueError('PDF فقط' if (lang or 'en').lower().startswith('ar') else 'PDF only')
    if len(data) > MAX_TXN_PDF_BYTES:
        raise ValueError('الملف كبير' if (lang or 'en').lower().startswith('ar') else 'PDF too large')
    if not _looks_like_pdf(data):
        raise ValueError('PDF غير صالح' if (lang or 'en').lower().startswith('ar') else 'Invalid PDF')
    _ensure_upload_dirs()
    fs_path = os.path.join(TXN_PDF_DIR, _rand_name('txn_doc', '.pdf'))
    _safe_write_file_atomic(fs_path, data)
    return fs_path


def _txn_doc_cleanup_file(fs_path):
    try:
        if fs_path and os.path.exists(fs_path):
            _safe_unlink_file(fs_path, allowed_roots=[ITEM_IMG_DIR, TXN_PDF_DIR])
    except Exception:
        pass


def _is_attachment_path_shared(conn, fs_path: str, *, exclude_txn_id: int | None = None) -> bool:
    fs_path = str(fs_path or '').strip()
    if not fs_path:
        return False
    try:
        sql = "SELECT 1 FROM Transactions WHERE attachment_path=?"
        params = [fs_path]
        if exclude_txn_id is not None:
            sql += " AND id<>?"
            params.append(int(exclude_txn_id))
        sql += " LIMIT 1"
        if conn.execute(sql, tuple(params)).fetchone():
            return True
    except Exception:
        pass
    try:
        if _txndoc_has_attachment_column(conn):
            if conn.execute("SELECT 1 FROM TransactionDocs WHERE attachment_path=? LIMIT 1", (fs_path,)).fetchone():
                return True
    except Exception:
        pass
    return False


def _txn_attachment_cleanup_if_unreferenced(conn, fs_path: str, *, exclude_txn_id: int | None = None):
    fs_path = str(fs_path or '').strip()
    if not fs_path:
        return
    if _is_attachment_path_shared(conn, fs_path, exclude_txn_id=exclude_txn_id):
        return
    _txn_doc_cleanup_file(fs_path)


def _txndoc_sync_attachment_to_txns_conn(conn, doc_id: int, fs_path: str | None):
    try:
        conn.execute("UPDATE Transactions SET attachment_path=? WHERE doc_id=?", (fs_path, int(doc_id)))
    except Exception:
        pass


def _txndoc_has_attachment_column(con=None):
    close_after = False
    if con is None:
        con = db_connect()
        close_after = True
    try:
        cols = [r['name'] for r in con.execute("PRAGMA table_info(TransactionDocs)").fetchall()]
        return 'attachment_path' in cols
    finally:
        if close_after:
            try:
                con.close()
            except Exception:
                pass


def _form_values_any(form: dict, *names):
    for name in names:
        if name in (form or {}):
            val = form.get(name)
            if isinstance(val, list):
                return ["" if x is None else str(x) for x in val]
            return ["" if val is None else str(val)]
    return []


def _parse_txn_lines_from_form(form: dict):
    item_codes = _form_values_any(form, 'line_item_code[]', 'line_item_code')
    eq_codes = _form_values_any(form, 'line_eq_code[]', 'line_eq_code')
    qtys = _form_values_any(form, 'line_qty[]', 'line_qty')
    scraps = _form_values_any(form, 'line_scrap_qty[]', 'line_scrap_qty')
    prices = _form_values_any(form, 'line_unit_price[]', 'line_unit_price')
    notes = _form_values_any(form, 'line_notes[]', 'line_notes')
    mx = max(len(item_codes), len(eq_codes), len(qtys), len(scraps), len(prices), len(notes), 0)
    lines = []
    for i in range(mx):
        row = {
            'item_code': normalize_code(item_codes[i] if i < len(item_codes) else ''),
            'eq_code': normalize_code(eq_codes[i] if i < len(eq_codes) else ''),
            'qty': (qtys[i] if i < len(qtys) else '').strip(),
            'scrap_qty': (scraps[i] if i < len(scraps) else '').strip(),
            'unit_price': (prices[i] if i < len(prices) else '').strip(),
            'notes': (notes[i] if i < len(notes) else '').strip(),
        }
        if not any(row.values()):
            continue
        lines.append(row)
    return lines
def list_txn_documents(limit=20):
    con = db_connect()
    try:
        select_attach = 'd.attachment_path' if _txndoc_has_attachment_column(con) else 'NULL AS attachment_path'
        rows = con.execute(f"""
            SELECT d.id, d.ts, d.txn_type, d.doc_no, d.req_no, d.po_no, {select_attach},
                   wf.wh_code AS wh_from_code, wt.wh_code AS wh_to_code,
                   e.eq_code, s.supplier_code,
                   COUNT(l.id) AS lines_count,
                   COALESCE(SUM(l.qty),0) AS total_qty
            FROM TransactionDocs d
            LEFT JOIN TransactionDocLines l ON l.doc_id=d.id
            LEFT JOIN Warehouses wf ON wf.id=d.wh_from_id
            LEFT JOIN Warehouses wt ON wt.id=d.wh_to_id
            LEFT JOIN Equipment e ON e.id=d.eq_id
            LEFT JOIN Suppliers s ON s.id=d.supplier_id
            GROUP BY d.id
            ORDER BY d.ts DESC, d.id DESC
            LIMIT ?
        """, (int(limit),)).fetchall()
        return [dict(r) for r in rows]
    finally:
        con.close()


def get_txn_document(doc_id: int):
    con = db_connect()
    try:
        select_attach = 'd.attachment_path' if _txndoc_has_attachment_column(con) else 'NULL AS attachment_path'
        head = con.execute(f"""
            SELECT d.id, d.ts, d.txn_type, d.wh_from_id, d.wh_to_id, d.eq_id, d.supplier_id, d.project_id,
                   d.issue_type, d.cost_allocation, d.req_no, d.po_no, d.doc_no, d.notes, d.username,
                   d.created_at, d.updated_at, {select_attach},
                   wf.wh_code AS wh_from_code, wt.wh_code AS wh_to_code,
                   e.eq_code, e.eq_name, s.supplier_code, s.supplier_name,
                   p.project_code, p.project_name
            FROM TransactionDocs d
            LEFT JOIN Warehouses wf ON wf.id=d.wh_from_id
            LEFT JOIN Warehouses wt ON wt.id=d.wh_to_id
            LEFT JOIN Equipment e ON e.id=d.eq_id
            LEFT JOIN Suppliers s ON s.id=d.supplier_id
            LEFT JOIN Projects p ON p.id=d.project_id
            WHERE d.id=?
        """, (int(doc_id),)).fetchone()
        if not head:
            return None
        lines = con.execute("""
            SELECT l.line_no, l.id, l.qty, l.scrap_qty, l.unit_price, l.notes, l.ledger_txn_id,
                   i.item_code, i.item_name, i.unit,
                   e.eq_code, e.eq_name,
                   t.voided
            FROM TransactionDocLines l
            JOIN Items i ON i.id=l.item_id
            LEFT JOIN Equipment e ON e.id=l.eq_id
            LEFT JOIN Transactions t ON t.id=l.ledger_txn_id
            WHERE l.doc_id=?
            ORDER BY l.line_no ASC, l.id ASC
        """, (int(doc_id),)).fetchall()
        return {'head': dict(head), 'lines': [dict(r) for r in lines]}
    finally:
        con.close()


def save_txn_document(lang, username, role, ip, form: dict, files: dict | None = None) -> str:
    svc = get_container().txn_service
    is_ar = (lang or 'en').lower().startswith('ar')

    def _line_err(idx: int, msg: str) -> str:
        msg = str(msg or '').strip() or ('Unknown error' if not is_ar else 'سبب غير معروف')
        return (f"سطر {idx}: {msg}" if is_ar else f"Line {idx}: {msg}")

    def _build_result_message(saved_count: int, failed: list[dict], doc_id: int | None = None) -> str:
        if saved_count <= 0:
            if failed:
                details = ' | '.join(str(x.get('error') or '') for x in failed[:8] if str(x.get('error') or '').strip())
                prefix = '❌ لم يتم حفظ أي سطر' if is_ar else '❌ No lines were saved'
                return (prefix + (f": {details}" if details else ''))[:4000]
            return '❌ لم يتم حفظ أي سطر' if is_ar else '❌ No lines were saved'
        if not failed:
            if doc_id:
                return (f"تمت إضافة مستند حركة رقم {doc_id} بعدد {saved_count} سطر" if is_ar else f"Transaction document #{doc_id} added with {saved_count} lines")
            return (f"تمت إضافة مستند حركة بعدد {saved_count} سطر" if is_ar else f"Transaction document added with {saved_count} lines")
        head = (f"تم حفظ {saved_count} سطر وفشل {len(failed)} سطر" if is_ar else f"Saved {saved_count} lines and failed {len(failed)} lines")
        if doc_id:
            head += (f" في المستند رقم {doc_id}" if is_ar else f" in document #{doc_id}")
        details = ' | '.join(str(x.get('error') or '') for x in failed[:8] if str(x.get('error') or '').strip())
        more = len(failed) - 8
        if more > 0:
            details += (f" | و {more} سطر آخر" if is_ar else f" | and {more} more lines")
        return (head + (f": {details}" if details else ''))[:4000]

    header = {
        'txn_type': (form.get('txn_type', ['RECEIVE'])[0] or 'RECEIVE').strip().upper(),
        'txn_date': (form.get('txn_date', [''])[0] or '').strip(),
        'wh_from': normalize_code((form.get('wh_from', [''])[0] or '')),
        'wh_to': normalize_code((form.get('wh_to', [''])[0] or '')),
        'eq_code': normalize_code((form.get('eq_code', [''])[0] or '')),
        'supplier_code': normalize_code((form.get('supplier_code', [''])[0] or '')),
        'project_code': normalize_code((form.get('project_code', [''])[0] or '')),
        'issue_type': (form.get('issue_type', [''])[0] or '').strip(),
        'cost_allocation': (form.get('cost_allocation', [''])[0] or '').strip(),
        'req_no': (form.get('req_no', [''])[0] or '').strip(),
        'po_no': (form.get('po_no', [''])[0] or '').strip(),
        'doc_no': (form.get('doc_no', [''])[0] or '').strip(),
        'notes': (form.get('notes', [''])[0] or '').strip(),
    }
    raw_lines = _parse_txn_lines_from_form(form)
    pdf = files.get('pdf') if isinstance(files, dict) else None
    if not raw_lines:
        raise ValueError('❌ يجب إدخال سطر واحد على الأقل' if is_ar else 'At least one line is required')

    parsed_lines = []
    failed_lines = []
    for idx, line in enumerate(raw_lines, start=1):
        try:
            line_eq_code = normalize_code(line.get('eq_code', '') or header['eq_code'])
            line_form = {
                'txn_type': [header['txn_type']], 'txn_date': [header['txn_date']], 'item_code': [line['item_code']],
                'qty': [line['qty']], 'scrap_qty': [line['scrap_qty']], 'unit_price': [line['unit_price']],
                'wh_from': [header['wh_from']], 'wh_to': [header['wh_to']], 'eq_code': [line_eq_code],
                'supplier_code': [header['supplier_code']], 'project_code': [header['project_code']],
                'issue_type': [header['issue_type']], 'cost_allocation': [header['cost_allocation']],
                'req_no': [header['req_no']], 'po_no': [header['po_no']], 'doc_no': [header['doc_no']],
                'notes': [line['notes'] or header['notes']],
            }
            payload, base = svc._validate_form(form=line_form, lang=lang)
            scrap_qty_val = svc._parse_scrap_qty(payload['txn_type'], payload['scrap_qty'], lang)
            if scrap_qty_val - float(base['qty']) > 1e-9:
                raise ValueError('السكراب أكبر من الكمية' if is_ar else 'scrap exceeds qty')
            unit_price_val = svc._parse_unit_price(payload['unit_price'])
            parsed_lines.append({
                'idx': idx,
                'raw': dict(line),
                'payload': payload,
                'base': base,
                'scrap_qty_val': scrap_qty_val,
                'unit_price_val': unit_price_val,
                'line_note': line['notes'],
            })
        except Exception as e:
            failed_lines.append({'idx': idx, 'error': _line_err(idx, e)})

    if not parsed_lines:
        raise ValueError(_build_result_message(0, failed_lines))

    ts = svc._build_txn_ts(header['txn_date'])

    def _db_work(conn):
        created_at = _now().isoformat(timespec='seconds')
        attachment_path = None
        doc_id = None
        doc_eq_ids = set()
        saved_count = 0
        saved_txn_ids = []
        saved_item_codes = []
        runtime_failed = list(failed_lines)

        def _ensure_doc(header_base: dict):
            nonlocal doc_id, attachment_path
            if doc_id is not None:
                return doc_id
            if pdf and pdf[0]:
                attachment_path = _txn_doc_validate_and_save_pdf(pdf, lang)
            cur = conn.execute("""
                INSERT INTO TransactionDocs(ts, txn_type, wh_from_id, wh_to_id, eq_id, supplier_id, project_id, issue_type, cost_allocation, req_no, po_no, doc_no, notes, attachment_path, username, created_at, updated_at)
                VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
            """, (
                ts,
                header['txn_type'],
                header_base.get('wh_from_id'),
                header_base.get('wh_to_id'),
                None,
                header_base.get('supplier_id'),
                header_base.get('project_id'),
                header_base.get('issue_type'),
                header_base.get('cost_allocation'),
                header['req_no'] or None,
                header['po_no'] or None,
                header['doc_no'] or None,
                header['notes'] or None,
                attachment_path,
                username,
                created_at,
                created_at,
            ))
            doc_id = int(cur.lastrowid)
            return doc_id

        try:
            for ln in parsed_lines:
                try:
                    base = ln['base']
                    if base['txn_type'] in ('ISSUE', 'TRANSFER'):
                        ok, available = ensure_stock_available_for_change(
                            old_txn={'voided': 1, 'txn_type': 'ISSUE', 'item_id': base['item_id'], 'wh_from_id': base['wh_from_id'], 'qty': 0},
                            new_txn={'voided': 0, **base},
                            con=conn,
                        )
                        if not ok:
                            raise ValueError(t(lang, 'insufficient', wh=(header['wh_from'] or ''), bal=available))

                    current_doc_id = _ensure_doc(base)
                    eq_id_val = int(base.get('eq_id') or 0)
                    if eq_id_val > 0:
                        doc_eq_ids.add(eq_id_val)
                    cur_line = conn.execute("""
                        INSERT INTO TransactionDocLines(doc_id, line_no, item_id, eq_id, qty, scrap_qty, unit_price, notes, created_at)
                        VALUES (?,?,?,?,?,?,?,?,?)
                    """, (
                        current_doc_id,
                        saved_count + 1,
                        base['item_id'],
                        base.get('eq_id'),
                        base['qty'],
                        ln['scrap_qty_val'],
                        ln['unit_price_val'],
                        ln['line_note'] or None,
                        created_at,
                    ))
                    line_id = int(cur_line.lastrowid)
                    effective_unit_price = svc._resolve_effective_unit_price(
                        conn,
                        txn_type=base['txn_type'],
                        item_id=base['item_id'],
                        explicit_price=ln['unit_price_val'],
                        wh_from_id=base.get('wh_from_id'),
                    )
                    txn_id = svc.txn_repo._insert_txn_conn(
                        conn,
                        ts=ts,
                        base=base,
                        scrap_qty_val=ln['scrap_qty_val'],
                        unit_price_val=effective_unit_price,
                        req_no=header['req_no'],
                        po_no=header['po_no'],
                        doc_no=header['doc_no'],
                        notes=(ln['line_note'] or header['notes']),
                        username=username,
                    )
                    conn.execute("UPDATE Transactions SET doc_id=?, line_id=?, attachment_path=? WHERE id=?", (current_doc_id, line_id, attachment_path, txn_id))
                    conn.execute("UPDATE TransactionDocLines SET ledger_txn_id=? WHERE id=?", (txn_id, line_id))
                    txn_ctx = dict(base)
                    txn_ctx.update({'id': txn_id, 'ts': ts, 'unit_price': effective_unit_price, 'qty': base['qty']})
                    if not _cost_state_apply_add_txn(conn, txn_ctx):
                        _cost_state_recompute_pairs(conn, _cost_state_pairs_for_txn(txn_ctx))
                    saved_count += 1
                    saved_txn_ids.append(txn_id)
                    saved_item_codes.append(str(ln.get('payload', {}).get('item_code') or ''))
                except Exception as e:
                    runtime_failed.append({'idx': ln['idx'], 'error': _line_err(ln['idx'], e)})

            if saved_count <= 0 or doc_id is None:
                if attachment_path:
                    _txn_doc_cleanup_file(attachment_path)
                raise ValueError(_build_result_message(0, runtime_failed))

            doc_eq_id = None
            if len(doc_eq_ids) == 1:
                doc_eq_id = next(iter(doc_eq_ids))
            conn.execute("UPDATE TransactionDocs SET eq_id=?, updated_at=? WHERE id=?", (doc_eq_id, _now().isoformat(timespec='seconds'), doc_id))
            _txndoc_sync_attachment_to_txns_conn(conn, doc_id, attachment_path)
            return {
                'doc_id': doc_id,
                'lines_count': saved_count,
                'txn_ids': saved_txn_ids,
                'failed_lines': runtime_failed,
                'saved_item_codes': [x for x in saved_item_codes if x],
            }
        except Exception:
            if attachment_path:
                _txn_doc_cleanup_file(attachment_path)
            raise

    def _audit(ctx):
        audit_log(username, 'ADD_TXN_DOC', entity='TransactionDocs', entity_id=ctx['doc_id'], details={
            'txn_type': header['txn_type'],
            'lines_count': ctx['lines_count'],
            'failed_count': len(ctx.get('failed_lines') or []),
            'failed_lines': ctx.get('failed_lines') or [],
            'saved_item_codes': ctx.get('saved_item_codes') or [],
            'doc_no': header['doc_no'] or None,
            'req_no': header['req_no'] or None,
            'po_no': header['po_no'] or None,
            'txn_ids': ctx['txn_ids'],
        }, ip=ip, role=role)

    ctx = svc._run_write(db_work=_db_work, audit_work=_audit, username=username, role=role, ip=ip, stock_tag='TXN_DOC_ADD_STOCKCACHE_REFRESH')
    return _build_result_message(ctx['lines_count'], ctx.get('failed_lines') or [], ctx.get('doc_id'))


__orig_render_txn_with_lines = render_txn

def _render_txn_lines_extra(lang, username, role, qs):
    if role not in ('ADMIN', 'EDITOR'):
        return ''
    txn_type = (qs.get('txn_type', [''])[0] or '').strip().upper() if isinstance(qs, dict) else ''
    if txn_type not in ('RECEIVE', 'ISSUE', 'TRANSFER'):
        txn_type = 'RECEIVE'
    today = _now().date().isoformat()
    doc_id = (qs.get('doc_id', [''])[0] or '') if isinstance(qs, dict) else ''
    docs_rows = list_txn_documents(limit=20)
