        dheaders = ['id', 'ts', 'txn_type', 'doc_no', 'req_no', 'po_no', 'lines_count', 'total_qty', 'wh_from_code', 'wh_to_code', 'eq_code', 'supplier_code', 'attach']
        dlabels = {'id':'DOC','ts':'TS','txn_type':t(lang,'type'),'doc_no':t(lang,'doc_no'),'req_no':t(lang,'req_no'),'po_no':t(lang,'po_no'),'lines_count':'Lines','total_qty':t(lang,'qty'),'wh_from_code':t(lang,'wh_from'),'wh_to_code':t(lang,'wh_to'),'eq_code':t(lang,'eq_code'),'supplier_code':t(lang,'supplier_code'),'attach':'PDF'}
