if __name__ == "__main__":
    if "--selftest" in sys.argv or "--deep-validate" in sys.argv:
        result = _run_cli_selftests()
        print(json.dumps(result, ensure_ascii=False, indent=2))
        raise SystemExit(0 if result.get('ok') else 1)
    start_server()
